# Create custom session with proxy settings
async def create_bot_session():
    """Create aiohttp session with proxy configuration"""
    timeout = ClientTimeout(total=30, connect=10)
    
    connector = aiohttp.TCPConnector(
        ssl=False,  # Disable SSL verification if proxy has issues
        limit=100,
        limit_per_host=10,
        ttl_dns_cache=300,
        use_dns_cache=True,
    )
    
    session = ClientSession(
        connector=connector,
        timeout=timeout,
        trust_env=True  # Use environment proxy settings
    )
    
    return session

# Initialize bot with custom session
async def initialize_bot():
    """Initialize bot with proper proxy setup"""
    session = await create_bot_session()
    
    bot = Bot(
        token=BOT_TOKEN,
        session=session,
        proxy=PROXY_URL
    )
    
    return bot


