# Domain lookup cache for dashboard_login_domain (5-min TTL)
DOMAIN_LOOKUP_CACHE: Dict[str, dict] = {}
DOMAIN_LOOKUP_CACHE_TS: Dict[str, float] = {}
DOMAIN_LOOKUP_CACHE_TTL = 300  # 5 minutes


async def lookup_nik_in_domain(nik: str) -> Optional[dict]:
    """
    Look up NIK in dashboard_login_domain table.
    Returns {'nik': ..., 'name': ..., 'title': ...} or None.
    Uses a small TTL cache to avoid repeated DB hits.
    """
    # Check cache first
    now = time.time()
    if nik in DOMAIN_LOOKUP_CACHE and (now - DOMAIN_LOOKUP_CACHE_TS.get(nik, 0)) < DOMAIN_LOOKUP_CACHE_TTL:
        return DOMAIN_LOOKUP_CACHE[nik]

    row = demo_backend.get_domain_user(nik)
    if row:
        DOMAIN_LOOKUP_CACHE[nik] = row
        DOMAIN_LOOKUP_CACHE_TS[nik] = now
    return row


def invalidate_domain_lookup_cache(nik: str = None):
    """Invalidate domain lookup cache. If nik is None, clear all."""
    if nik:
        DOMAIN_LOOKUP_CACHE.pop(nik, None)
        DOMAIN_LOOKUP_CACHE_TS.pop(nik, None)
    else:
        DOMAIN_LOOKUP_CACHE.clear()
        DOMAIN_LOOKUP_CACHE_TS.clear()


def sanitize_csv_value(value: str) -> str:
    """Prevent CSV formula injection by prefixing dangerous first characters with a single quote."""
    if value and value[0] in ('=', '+', '-', '@', '\t', '\r'):
        return "'" + value
    return value


def escape_markdown_v2(text: str) -> str:
    """Escapes characters for Telegram's MarkdownV2 parse mode."""
    # Remove backtick ` from escape_chars
    escape_chars = r'\_*[]()~>#+-=|{}.!'  # Removed the backtick
    return re.sub(f'([{re.escape(escape_chars)}])', r'\\\1', text)


def split_text(text, max_length=4096):
    """Split text into chunks of max_length"""
    return [text[i:i + max_length] for i in range(0, len(text), max_length)]



async def send_long_message(bot: Bot, chat_id: int, messages_iterable: list, 
                            parse_mode: str = None, telegram_api_max_len: int = 4096, 
                            reply_markup=None):
    """
    Sends messages. If a message is too long, uses split_message to chunk it.
    """
    for item_idx, item in enumerate(messages_iterable):
        text_content: str
        current_item_reply_markup = None

        if isinstance(item, tuple) and len(item) == 2:
            text_content, current_item_reply_markup = item
        else:
            text_content = str(item)
        
        final_reply_markup_for_message_group = current_item_reply_markup if current_item_reply_markup else reply_markup

        if not text_content.strip():
            continue

        if len(text_content) > telegram_api_max_len:
            max_content_length_for_splitter = telegram_api_max_len
            is_code_block_input = text_content.startswith("```\n") and text_content.endswith("\n```")

            if is_code_block_input:
                
                # Content length for splitter = API limit - 8 characters for "```\\n" and "\\n```"
                max_content_length_for_splitter = telegram_api_max_len - (len("```\n") + len("\n```"))
            
            chunks_to_send = split_message(text_content, max_content_length_for_splitter)
            
            for chunk_idx, chunk_text in enumerate(chunks_to_send):
                if chunk_text.strip():
                    current_chunk_reply_markup = final_reply_markup_for_message_group if chunk_idx == len(chunks_to_send) - 1 else None
                    try:
                        await bot.send_message(chat_id=chat_id, text=chunk_text, 
                                               parse_mode=parse_mode, reply_markup=current_chunk_reply_markup)
                    except Exception as e:
                        logging.error(f"Failed to send message chunk (len {len(chunk_text)}): {e}")
        else: 
            try:
                await bot.send_message(chat_id=chat_id, text=text_content, 
                                       parse_mode=parse_mode, reply_markup=final_reply_markup_for_message_group)
            except Exception as e:
                logging.error(f"Failed to send message (len {len(text_content)}): {e}")


def abbreviate_area(area_name):
    if area_name.startswith("AREA "):
        return f"A{area_name.split(' ')[1]}"
    return area_name  # Return as is if it doesn't match the pattern


def abbreviate_name(name):
    if not name or name.upper() == "N/A":
        return "N/A"
    
    # Convert to uppercase.
    name = name.upper()
    parts = name.split()
    if not parts:
        return "N/A"
    
    # Check for "[TECHNICIAN]" prefix.
    if parts[0].startswith("[TECH"):
        # Group 1: remove the prefix, and set flag to "[TECH]"
        flag = "[TECH]"
        remaining = parts[1:]
        if not remaining:
            return flag
        first_word = remaining[0]
        # If first word is >= 8 characters, abbreviate all remaining words.
        if len(first_word) >= 8:
            abbreviated = [word[0] for word in remaining]
            result = flag + " " + ".".join(abbreviated)
        else:
            # Otherwise, keep full first word and abbreviate subsequent ones.
            abbreviated = [word[0] for word in remaining[1:]]
            if abbreviated:
                result = flag + " " + first_word + " " + ".".join(abbreviated)
            else:
                result = flag + " " + first_word
        return result.strip()
    else:
        # Group 2: no "[TECHNICIAN]" prefix.
        combined_length = sum(len(word) for word in parts)
        if combined_length > 12:
            abbreviated = [word[0] for word in parts[1:]]
            if abbreviated:
                result = parts[0] + " " + ".".join(abbreviated)
            else:
                result = parts[0]
        else:
            result = name
        return result.strip()


