async def get_username(user_id):
    """Async version using cache - maintains backward compatibility"""
    try:
        # Use the existing cache instead of reading CSV directly
        user_record = await get_cached_user_data(user_id)
        
        if not user_record:
            logger.debug(f"No record found for user_id {user_id}")
            return "Unknown User"
        
        username = user_record.get('username', '').strip()
        logger.debug(f"Found username '{username}' for user_id {user_id}")
        return username if username else "Unknown User"
        
    except Exception as e:
        logger.error(f"Error retrieving username for user {user_id}: {e}")
        return "Unknown User"


async def sync_username_if_changed(user_id: int, live_username: str):
    """
    If the user changed their Telegram @username, update it in the CSV and invalidate cache.
    Called once per /start for registered users.
    """
    global USER_DATA_CACHE, CACHE_TIMESTAMP
    try:
        cached = await get_cached_user_data(user_id)
        if not cached:
            return
        stored = cached.get('username', '')
        # Normalize for comparison: strip @ and lowercase
        stored_norm = stored.lstrip('@').lower()
        live_norm = live_username.lstrip('@').lower()
        if not live_username or stored_norm == live_norm:
            return  # No change needed
        # Update the CSV
        user_data = await read_user_data_async()
        if user_data is None:
            return
        uid_str = str(user_id)
        mask = user_data['user_id'].astype(str) == uid_str
        if not mask.any():
            return
        # Store with @ prefix if it's a real handle (no spaces), else plain name
        new_stored = f"@{live_username}" if ' ' not in live_username else live_username
        user_data.loc[mask, 'username'] = new_stored
        user_data.to_csv(USER_DATA_FILE, index=False)
        # Invalidate cache
        USER_DATA_CACHE = {}
        CACHE_TIMESTAMP = 0
        logger.info(f"Username updated for user {user_id}: '{stored}' → '{new_stored}'")
    except Exception as e:
        logger.error(f"Error in sync_username_if_changed for user {user_id}: {e}")


async def check_sf_user_access(user_id, order_data=None):
    """
    Combined function for SF user validation and order access check
    Returns: (is_sf: bool, agency_name: str, can_access: bool, error_message: str)
    
    Args:
        user_id: User ID to check
        order_data: Optional order data for access validation
        
    Returns:
        - is_sf: True if user is SF type (employer='sf' and has agency_name)
        - agency_name: User's agency name (None if not SF user or no agency_name)
        - can_access: True if user can access the order (True for non-SF users, or SF users with matching sf_company_name)
        - error_message: Error message if access denied (empty string if access allowed)
    """
    try:
        user_record = await get_cached_user_data(user_id)
        
        if not user_record:
            logger.debug(f"No record found for user_id {user_id}")
            return False, None, True, ""
        
        employer = user_record.get('employer', '').strip().lower()
        agency_name = user_record.get('agency_name', '').strip()
        
        # Check if user is SF type (employer='sf' and has agency_name)
        is_sf = employer == 'sf' and bool(agency_name)
        
        if not is_sf:
            # Non-SF users have full access
            return False, None, True, ""
        
        # For SF users, check order access if order_data provided
        if order_data is None:
            # No order data to check, SF user is valid
            return True, agency_name, True, ""
        
        # Check order access for SF user
        if not order_data:
            return True, agency_name, False, "❌ Data order tidak ditemukan"
        
        # Get sf_company_name from first row
        first_row = order_data[0] if isinstance(order_data, list) else order_data
        order_sf_company_name = first_row.get('sf_company_name', '').strip() if isinstance(first_row, dict) else ''
        
        if not order_sf_company_name:
            return True, agency_name, False, "❌ SF company name tidak ditemukan pada order ini"
        
        # Check if user's agency_name matches order's sf_company_name
        if agency_name == order_sf_company_name:
            return True, agency_name, True, ""
        else:
            return True, agency_name, False, f"❌ Akses ditolak: Order ini tidak dalam lingkup Agency anda\n(Agency: {agency_name})"
            
    except Exception as e:
        logger.error(f"Error checking SF user access for user {user_id}: {e}")
        return False, None, False, "❌ Terjadi kesalahan saat memverifikasi akses"


async def get_user_level(user_id: int) -> str:
    """Get user level from cached data"""
    try:
        user_record = await get_cached_user_data(user_id)
        
        if not user_record:
            return "user"  # Default to regular user
        
        user_level = user_record.get('user_level', 'user').strip().lower()
        return user_level
        
    except Exception as e:
        logger.error(f"Error getting user level for user {user_id}: {e}")
        return "user"


async def get_user_employer(user_id: int) -> str:
    """Get user employer from CSV file"""
    csv_path = USER_DATA_FILE
    try:
        if not os.path.exists(csv_path):
            logger.error("User data file not found")
            return "unknown"
        
        logger.debug(f"Looking up employer for user_id: {user_id}")
        # Use asyncio to run pandas operations in thread pool
        import asyncio
        user_data = await asyncio.get_event_loop().run_in_executor(None, lambda: pd.read_csv(csv_path, dtype=str))

        # Fetch employer - normalize user_id to strip float suffix (e.g. '483825168.0' -> '483825168')
        user_data['user_id'] = user_data['user_id'].apply(
            lambda x: str(int(float(x))) if str(x).strip() not in ('', 'nan', 'None') else x
        )
        user_record = user_data[user_data['user_id'] == str(user_id)]
        
        if not user_record.empty:
            # Assuming the employer column exists in your CSV
            employer = user_record.iloc[0].get('employer', 'unknown')
            if pd.isna(employer):
                return "unknown"
            employer = str(employer).strip().lower()
            logger.debug(f"Found employer '{employer}' for user_id {user_id}")
            return employer
        else:
            logger.debug(f"No record found for user_id {user_id}")
            return "unknown"
            
    except Exception as e:
        logger.error(f"Error retrieving employer for user {user_id}: {e}")
        return "unknown" 


def filter_rows_by_date_range(rows, start_date, end_date, filter_type="daily"):
    """Filter database rows by date range with different logic for daily vs monthly data."""
    if not rows:
        return rows
    
    if filter_type == "monthly":
        # For monthly summary data, no day-specific filtering needed
        logging.debug(f"[FILTER] Monthly filter: returning all {len(rows)} rows (no day filtering)")
        return rows
    
    # Daily filtering logic (existing)
    filtered_rows = []
    logging.debug(f"[FILTER] Daily filter: {len(rows)} rows, range {start_date.date()} to {end_date.date()}")
    
    for row in rows:
        # Try different date field names
        date_value = (row.get('date') or 
                     row.get('full_date') or      
                     row.get('short_date') or 
                     row.get('created_date') or
                     row.get('start_date') or
                     row.get('end_date'))
        
        if date_value and is_date_in_selected_range(date_value, start_date, end_date):
            filtered_rows.append(row)
    
    logging.debug(f"[FILTER] Daily filter result: {len(filtered_rows)} rows remain")
    return filtered_rows


def is_date_in_selected_range(date_value, start_date, end_date):
    """Check if a date is within the selected range."""
    if not date_value:
        return False
    
    # Simple counter to limit debug spam (only log first few calls)
    if not hasattr(is_date_in_selected_range, '_debug_count'):
        is_date_in_selected_range._debug_count = 0
    
    try:
        # Handle different date formats from database
        if isinstance(date_value, str):
            # Try different date formats
            for date_format in ['%Y-%m-%d', '%d/%b/%y', '%d/%b/%Y', '%Y-%m-%d %H:%M:%S']:
                try:
                    check_date = datetime.strptime(date_value, date_format).date()
                    break
                except ValueError:
                    continue
            else:
                # Only log parsing failures
                if is_date_in_selected_range._debug_count < 3:
                    logging.debug(f"[DATE_CHECK] Could not parse '{date_value}' - including by default")
                    is_date_in_selected_range._debug_count += 1
                return True  # Include if we can't parse
        elif hasattr(date_value, 'date'):
            check_date = date_value.date()
        else:
            check_date = date_value
        
        result = start_date.date() <= check_date <= end_date.date()
        
        # Only log first few results or failures
        if is_date_in_selected_range._debug_count < 3 or not result:
            logging.debug(f"[DATE_CHECK] '{date_value}' → {check_date} in [{start_date.date()}, {end_date.date()}] = {result}")
            is_date_in_selected_range._debug_count += 1
        
        return result
        
    except (ValueError, AttributeError) as e:
        # Always log actual errors
        logging.debug(f"[DATE_CHECK] Error parsing '{date_value}': {e}")
        return True 




