async def get_user_selected_period(user_id: int) -> str:
    """Get user's selected period or default to current month.
    Now works with calendar date range system.
    Returns: period string that works with new date range system.
    """
    # Check if user has calendar date range set
    date_range = await get_user_calendar_date_range(user_id)
    if date_range:
        start_date, end_date = date_range
        # Return a special format that indicates custom date range
        return f"RANGE:{start_date.strftime('%Y%m%d')}-{end_date.strftime('%Y%m%d')}"
    
    # Default: current month from day 1 to current day
    return datetime.now().strftime('%Y%m')


async def get_period_date_range(selected_period=None):
    """Updated to handle both old YYYYMM format and new RANGE format."""
    # Set current year and month as default if selected_period is None
    if selected_period is None:
        selected_period = datetime.today().strftime("%Y%m")
    
    logging.debug(f"Received selected_period: {selected_period}")
    
    # Handle new RANGE format: "RANGE:20240701-20240715"
    if selected_period.startswith("RANGE:"):
        try:
            date_part = selected_period.split(":", 1)[1]
            start_str, end_str = date_part.split("-")
            
            start_date = datetime.strptime(start_str, "%Y%m%d")
            end_date = datetime.strptime(end_str, "%Y%m%d")
            
            logging.debug(f"Calculated start_date: {start_date}, end_date: {end_date}")
            return start_date, end_date
            
        except ValueError as e:
            logging.error(f"Invalid RANGE format for selected_period: {selected_period}, error: {e}")
            return None, None
    
    # Handle old YYYYMM format: "202407"
    try:
        # Convert selected_period to a date
        start_date = datetime.strptime(selected_period, "%Y%m")
    except ValueError:
        logging.error(f"Invalid format for selected_period: {selected_period}")
        return None, None  # Return None to signal an invalid format
    
    end_of_month = start_date + relativedelta(months=1) - timedelta(days=1)
    today = datetime.today()
    
    # Set end_date as the last elapsed date if the period is the current month
    if start_date.year == today.year and start_date.month == today.month:
        end_date = today
    else:
        end_date = end_of_month
    
    logging.debug(f"Calculated start_date: {start_date}, end_date: {end_date}")
    return start_date, end_date


async def get_period_date_range_v2(selected_period):
    """Replacement for old get_period_date_range_v2 that works with new calendar system.
    Maintains exact same output format for compatibility.
    """
    if selected_period.startswith("RANGE:"):
        # Custom date range format: "RANGE:20240701-20240715"
        date_part = selected_period.split(":", 1)[1]
        start_str, end_str = date_part.split("-")
        
        start_date = datetime.strptime(start_str, "%Y%m%d")
        end_date = datetime.strptime(end_str, "%Y%m%d")
        
        return start_date, end_date
    else:
        # Old format compatibility: "202407" 
        # Default behavior: start = day 1, end = current day (if current month) or end of month
        try:
            start_date = datetime.strptime(selected_period, "%Y%m")
        except ValueError:
            logging.error(f"Invalid format for selected_period: {selected_period}")
            return None, None
        
        end_of_month = start_date + relativedelta(months=1) - timedelta(days=1)
        today = datetime.now()
        
        # If it's current month, end at current day, otherwise end of month
        if start_date.year == today.year and start_date.month == today.month:
            end_date = today
        else:
            end_date = end_of_month
        
        return start_date, end_date


