def get_loading_bar_style() -> 'LoadingBarStyle':
    """Convert string constant to LoadingBarStyle enum"""
    style_mapping = {
        'CLASSIC': LoadingBarStyle.CLASSIC,
        'MODERN': LoadingBarStyle.MODERN,
        'GRADIENT': LoadingBarStyle.GRADIENT,
        'SPINNER_DOTS': LoadingBarStyle.SPINNER_DOTS,
        'SPINNER_BARS': LoadingBarStyle.SPINNER_BARS
    }
    return style_mapping.get(LOADING_BAR_STYLE.upper(), LoadingBarStyle.CLASSIC)

class LoadingBarStyle(Enum):
    """Different loading bar styles - optimized selection"""
    CLASSIC = "classic"
    MODERN = "modern"
    GRADIENT = "gradient"
    SPINNER_DOTS = "spinner_dots"
    SPINNER_BARS = "spinner_bars"

class FancyLoadingBar:
    """Enhanced ASCII loading bar system with animation support"""
    
    # ASCII characters for different styles - OPTIMIZED SELECTION
    STYLES = {
        LoadingBarStyle.CLASSIC: {
            'filled': '█',
            'empty': '░',
            'partial': ['▏', '▎', '▍', '▌', '▋', '▊', '▉'],
            'brackets': ['', ''],
            'spinners': ['|', '/', '-', '\\']  # Simple spinner
        },
        LoadingBarStyle.MODERN: {
            'filled': '■',
            'empty': '□',
            'partial': ['▪', '▫'],
            'brackets': ['', ''],
            'spinners': ['◐', '◓', '◑', '◒']  # Circle spinner
        },
        LoadingBarStyle.GRADIENT: {
            'filled': '█',
            'empty': '·',
            'partial': ['░', '▒', '▓'],
            'brackets': ['', ''],
            'spinners': ['◢', '◣', '◤', '◥']  # Triangle spinner
        },
        # Optimized for spinning animations
        LoadingBarStyle.SPINNER_DOTS: {
            'filled': '●',
            'empty': '○',
            'partial': ['◐', '◑', '◒', '◓'],
            'brackets': ['', ''],
            'spinners': ['⠋', '⠙', '⠹', '⠸', '⠼', '⠴', '⠦', '⠧']  # Braille spinner
        },
        LoadingBarStyle.SPINNER_BARS: {
            'filled': '━',
            'empty': '━',
            'partial': ['╾', '╼'],
            'brackets': ['', ''],
            'spinners': ['⣾', '⣽', '⣻', '⢿', '⡿', '⣟', '⣯', '⣷']  # Block spinner
        }
    }
    
    @staticmethod
    def get_loading_bar(progress_percentage: float, 
                       style: LoadingBarStyle = LoadingBarStyle.CLASSIC,
                       width: int = 20,
                       show_percentage: bool = True,
                       show_fraction: bool = False) -> str:
        """
        Generate a fancy ASCII loading bar
        
        Args:
            progress_percentage: Progress from 0 to 100
            style: Loading bar style from LoadingBarStyle enum
            width: Width of the loading bar in characters
            show_percentage: Whether to show percentage
            show_fraction: Whether to show fraction (e.g., 15/20)
        """
        # Clamp progress between 0 and 100
        progress = max(0, min(100, progress_percentage))
        
        # Get style configuration
        style_config = FancyLoadingBar.STYLES[style]
        filled_char = style_config['filled']
        empty_char = style_config['empty']
        partial_chars = style_config.get('partial', [])
        brackets = style_config['brackets']
        
        # Calculate filled and empty portions
        filled_width = (progress / 100) * width
        filled_full = int(filled_width)
        filled_partial = filled_width - filled_full
        
        # Build the bar
        bar_content = filled_char * filled_full
        
        # Add partial character if available and needed
        if partial_chars and filled_partial > 0 and filled_full < width:
            partial_index = int(filled_partial * len(partial_chars))
            if partial_index < len(partial_chars):
                bar_content += partial_chars[partial_index]
                filled_full += 1
        
        # Add empty portion
        empty_width = width - filled_full
        bar_content += empty_char * empty_width
        
        # Truncate if needed (safety)
        bar_content = bar_content[:width]
        
        # Build final bar with brackets
        progress_bar = f"{brackets[0]}{bar_content}{brackets[1]}"
        
        # Add percentage and/or fraction
        info_parts = []
        if show_percentage:
            info_parts.append(f"{progress:.1f}%")
        if show_fraction:
            current = int((progress / 100) * width)
            info_parts.append(f"({current}/{width})")
        
        info_text = " " + " ".join(info_parts) if info_parts else ""
        
        return progress_bar + info_text
    
    @staticmethod
    def get_animated_loading_bar(progress_percentage: float,
                                animation_frame: int = 0,
                                style: LoadingBarStyle = LoadingBarStyle.CLASSIC,
                                width: int = 8) -> str:
        """
        Generate an animated loading bar with spinning indicator - Mobile optimized
        
        Args:
            progress_percentage: Progress from 0 to 100
            animation_frame: Frame number for animation (0-7)
            style: Loading bar style
            width: Width of the loading bar (default 8 for mobile)
        """
        # Get spinners from style configuration
        style_config = FancyLoadingBar.STYLES[style]
        spinner_chars = style_config.get('spinners', ['|', '/', '-', '\\'])
        
        # Get spinner character for this frame
        spinner = spinner_chars[animation_frame % len(spinner_chars)]
        
        # Get base loading bar with specified width
        base_bar = FancyLoadingBar.get_loading_bar(progress_percentage, style, width)
        
        return f"{spinner} {base_bar}"
    
    @staticmethod
    def get_multi_line_progress(progress_percentage: float,
                               title: str = "Progress",
                               style: LoadingBarStyle = LoadingBarStyle.CLASSIC) -> str:
        """
        Generate a multi-line fancy progress display
        """
        progress = max(0, min(100, progress_percentage))
        
        # Create frame
        frame_width = 30
        title_line = f"╔{'═' * (frame_width - 2)}╗"
        title_content = f"║ {title.center(frame_width - 4)} ║"
        separator = f"╠{'═' * (frame_width - 2)}╣"
        
        # Progress bar
        bar = FancyLoadingBar.get_loading_bar(progress, style, frame_width - 6)
        progress_line = f"║  {bar}  ║"
        
        # Status line
        status_text = f"{progress:.1f}% Complete"
        status_line = f"║ {status_text.center(frame_width - 4)} ║"
        
        bottom_line = f"╚{'═' * (frame_width - 2)}╝"
        
        return "\n".join([
            title_line,
            title_content,
            separator,
            progress_line,
            status_line,
            bottom_line
        ])


class ProgressMessageManager:
    """Consolidated progress message manager for all bot operations"""
    
    def __init__(self, bot, chat_id: int, message_id: int, 
                 style: LoadingBarStyle = LoadingBarStyle.CLASSIC):
        self.bot = bot
        self.chat_id = chat_id
        self.message_id = message_id
        self.style = style
        self.animation_frame = 0
    
    async def update_progress(self, progress: int, status: str, 
                            operation_type: str = "generic",
                            use_animation: bool = True,
                            delay: float = 0.3) -> bool:
        """
        Universal progress update method - Bahasa Indonesia
        
        Args:
            progress: Progress percentage (0-100)
            status: Status message
            operation_type: Type of operation for custom icons
            use_animation: Whether to use animated loading bar
            delay: Delay after update
        """
        try:
            # Operation type icons and titles in Bahasa Indonesia
            operation_configs = {
                "generic": {"icon": "🔄", "title": "Memproses"},
                "image": {"icon": "📸", "title": "Memproses Gambar"},
                "search": {"icon": "🔍", "title": "Mencari"},
                "odp": {"icon": "📍", "title": "Mencari ODP & Site"},
                "report": {"icon": "📊", "title": "Membuat Laporan"},
                "upload": {"icon": "📤", "title": "Mengunggah"},
                "download": {"icon": "📥", "title": "Mengunduh"},
                "analysis": {"icon": "🔬", "title": "Menganalisis Data"}
            }
            
            config = operation_configs.get(operation_type, operation_configs["generic"])
            
            # Generate loading bar
            if use_animation:
                loading_bar = FancyLoadingBar.get_animated_loading_bar(
                    progress, self.animation_frame, self.style
                )
                self.animation_frame = (self.animation_frame + 1) % 8
            else:
                loading_bar = FancyLoadingBar.get_loading_bar(
                    progress, self.style, show_percentage=True
                )
            
            # Escape special characters in status and loading bar
            escaped_status = escape_markdown_v2(status)
            escaped_title = escape_markdown_v2(config['title'])
            escaped_loading_bar = escape_markdown_v2(loading_bar)
            
            # Create progress message WITHOUT code block
            progress_text = f"""{config['icon']} {escaped_title}\\.\\.\\.

{escaped_loading_bar}

📋 {escaped_status}"""
            
            await self.bot.edit_message_text(
                chat_id=self.chat_id,
                message_id=self.message_id,
                text=progress_text,
                parse_mode="MarkdownV2"
            )
            
            # Delay for visibility
            if delay > 0:
                await asyncio.sleep(delay)
            
            return True
            
        except Exception as e:
            logging.warning(f"Could not update progress message: {e}")
            return False
    
    async def complete_progress(self, success: bool = True, 
                            final_message: str = "Operasi selesai!"):
        """Mark progress as complete - Bahasa Indonesia"""
        try:
            # Only delete if successful
            if success:
                await self.bot.delete_message(
                    chat_id=self.chat_id,
                    message_id=self.message_id
                )
            else:
                # Show error message on failure
                escaped_message = escape_markdown_v2(final_message)
                final_text = f"❌ {escaped_message}"
                
                await self.bot.edit_message_text(
                    chat_id=self.chat_id,
                    message_id=self.message_id,
                    text=final_text,
                    parse_mode="MarkdownV2"
                )
                
        except Exception as e:
            logging.warning(f"Could not update progress message: {e}")


# Global animation frame counter for consistency
_animation_frame = 0

def get_next_animation_frame() -> int:
    """Get next animation frame and increment counter"""
    global _animation_frame
    current_frame = _animation_frame
    _animation_frame = (_animation_frame + 1) % 8  # 8 frame cycle
    return current_frame

