async def get_user_registration_status(user_id: int) -> Tuple[bool, Optional[str]]:
    """
    Get user registration status and employer.
    Returns: (is_registered, employer or None)
    Uses existing get_cached_user_data function.
    """
    try:
        user_record = await get_cached_user_data(user_id)
        
        if not user_record:
            return False, None
        
        employer = user_record.get('employer', '').strip().lower()
        return True, employer if employer else None
        
    except Exception as e:
        logger.error(f"Error checking user registration status: {e}")
        return False, None

def has_permission(employer: str, permission: str) -> bool:
    """Check if an employer has a specific permission"""
    if not employer or employer not in EMPLOYER_PERMISSIONS:
        return False
    
    permissions = EMPLOYER_PERMISSIONS[employer]
    return (permission in permissions.get("commands", []) or 
            permission in permissions.get("callbacks", []))

def get_user_permissions(employer: str) -> Set[str]:
    """Get all permissions for a specific employer"""
    if not employer or employer not in EMPLOYER_PERMISSIONS:
        return set()
    
    permissions = EMPLOYER_PERMISSIONS[employer]
    all_perms = set(permissions.get("commands", []))
    all_perms.update(permissions.get("callbacks", []))
    return all_perms


def can_show_button(employer: str, button_key: str, is_registered: bool = True) -> bool:
    """Check if a button should be shown to a specific employer"""
    if button_key not in BUTTON_CONFIGS:
        return False
    
    button_config = BUTTON_CONFIGS[button_key]
    
    # Special handling for registration button
    if button_key == "registration":
        return not is_registered  # Only show to unregistered users
    
    # If user is not registered, don't show any other buttons
    if not is_registered:
        return False
    
    required_perms = button_config.get("required_permissions", [])
    
    # If no permissions required, show to registered users
    if not required_perms:
        return True
    
    # Check if user has any of the required permissions
    user_perms = get_user_permissions(employer)
    return any(perm in user_perms for perm in required_perms)


def can_show_heatmap_button(employer: str, button_key: str) -> bool:
    """Check if a heatmap sub-menu button should be shown"""
    if button_key not in HEATMAP_BUTTON_CONFIGS:
        return False
    
    button_config = HEATMAP_BUTTON_CONFIGS[button_key]
    required_perms = button_config.get("required_permissions", [])
    
    user_perms = get_user_permissions(employer)
    return any(perm in user_perms for perm in required_perms)


def can_show_map_button(employer: str, button_key: str, is_registered: bool = True) -> bool:
    if button_key not in MAP_GENERATOR_BUTTON_CONFIGS:
        return False
    
    if not is_registered:
        return False
    
    button_config = MAP_GENERATOR_BUTTON_CONFIGS[button_key]
    required_perms = button_config.get("required_permissions", [])
    
    if not required_perms:
        return True
    
    user_perms = get_user_permissions(employer)
    return any(perm in user_perms for perm in required_perms)

