async def create_dynamic_main_keyboard(user_id: int) -> InlineKeyboardMarkup:
    """
    Create a personalized main menu keyboard based on user's registration and employer.
    This is the main function to replace your existing create_main_keyboard().
    """
    try:
        # Get user registration status and employer
        is_registered, employer = await get_user_registration_status(user_id)
        
        logger.debug(f"Creating dynamic keyboard for user {user_id}: registered={is_registered}, employer={employer}")
        
        keyboard_rows = []
        
        for row_buttons in MAIN_MENU_LAYOUT:
            current_row = []
            
            for button_key in row_buttons:
                if can_show_button(employer, button_key, is_registered):
                    button_config = BUTTON_CONFIGS[button_key]
                    current_row.append(
                        InlineKeyboardButton(
                            text=button_config["text"],
                            callback_data=button_config["callback_data"]
                        )
                    )
            
            # Only add the row if it has buttons
            if current_row:
                keyboard_rows.append(current_row)
        
        return InlineKeyboardMarkup(inline_keyboard=keyboard_rows)
        
    except Exception as e:
        logger.error(f"Error creating dynamic main keyboard for user {user_id}: {e}")
        # Fallback to minimal keyboard with just registration
        return InlineKeyboardMarkup(inline_keyboard=[
            [InlineKeyboardButton(text="🔐 Register", callback_data="registration")]
        ])


