async def create_summarize_menu_keyboard(user_id: int) -> InlineKeyboardMarkup:
    """Create Summarize menu with available options"""
    is_registered, employer = await get_user_registration_status(user_id)
    
    if not is_registered or employer != "tsel":
        return InlineKeyboardMarkup(inline_keyboard=[
            [InlineKeyboardButton(text="🔙 Back to Main Menu", callback_data="main_menu")]
        ])
    
    keyboard_rows = []
    
    # Add available summarize buttons (2 per row)
    row = []
    for key, config in SUMMARIZE_BUTTON_CONFIGS.items():
        if config.get("disabled", False):
            # Show disabled buttons with strikethrough
            row.append(InlineKeyboardButton(
                text=f"🔒 {config['text']} (Soon)",
                callback_data="feature_disabled"
            ))
        else:
            row.append(InlineKeyboardButton(
                text=config["text"],
                callback_data=config["callback_data"]
            ))
        
        if len(row) == 2:
            keyboard_rows.append(row)
            row = []
    
    if row:  # Add remaining buttons
        keyboard_rows.append(row)
    
    # Back button
    keyboard_rows.append([
        InlineKeyboardButton(text="🔙 Back to Main Menu", callback_data="main_menu")
    ])
    
    return InlineKeyboardMarkup(inline_keyboard=keyboard_rows)


async def create_wok_selection_keyboard(wok_list, selected_woks, chosen_region):
    """Creates multi-selection keyboard for WOKs"""
    builder = InlineKeyboardBuilder()
    
    # Add WOK selection buttons
    for wok in wok_list:
        if wok in selected_woks:
            text = f"✅ {wok}"
        else:
            text = f"{wok}"
        
        builder.button(
            text=text,
            callback_data=f"toggle_wok:{chosen_region}:{wok}"
        )
    
    builder.adjust(1)  # One WOK per row
    
    # Add control buttons
    builder.row(
        InlineKeyboardButton(text="✅ Lanjut", callback_data=f"continue_wok:{chosen_region}"),
        InlineKeyboardButton(text="❌ Batal", callback_data="cancel_wok_agency")
    )
    
    return builder.as_markup()
    

