def get_dynamic_bot_commands(employer: str) -> List[BotCommand]:
    """
    Generate bot commands list based on employer permissions.
    You can use this for employer-level command filtering if needed.
    """
    
    all_commands = {
        "start": BotCommand(command="start", description="Memulai bot"),
        "odpmap": BotCommand(command="odpmap", description="Generate ODP Mapping"),
        "rutedjp": BotCommand(command="rutedjp", description="Generate Rute DJP"),
        "a3": BotCommand(command="a3", description="Summary Branch A3"),
        "nas": BotCommand(command="nas", description="Summary Nasional"),
        "wok": BotCommand(command="wok", description="Report WOK A3"),
        "c3mr": BotCommand(command="c3mr", description="Report C3MR"),
        "pranpc": BotCommand(command="pranpc", description="Report PraNPC"),
        "summarize": BotCommand(command="summarize", description="Executive Summary"),
        "calcpdd": BotCommand(command="calcpdd", description="Simulasi perhitungan biaya PDD"),
        "agency": BotCommand(command="agency", description="Report Agency/SF"),
        "cvm": BotCommand(command="cvm", description="Report 10 Segments"),
        "churn": BotCommand(command="churn", description="Churn Analysis"),
        #"generategtm": BotCommand(command="generategtm", description="GTM Heatmapping"),
        #"trackgtm": BotCommand(command="trackgtm", description="Track GTM"),
        "id": BotCommand(command="id", description="Cek Order History"),
        "ticket": BotCommand(command="ticket", description="Cek Ticket History"),
        "daterange": BotCommand(command="Date_Range", description="Pilih periode laporan"),
        "cekodp": BotCommand(command="cekodp", description="Cari riwayat ODP"),
        "odpterdekat": BotCommand(command="odpterdekat", description="Cari ODP terdekat"),
        #"golive": BotCommand(command="golive", description="Cari ODP GoLive"),
        "lapor": BotCommand(command="lapor", description="Lapor kompetitor"),
        "info": BotCommand(command="info", description="Cek kompetitor"),
        "register": BotCommand(command="register", description="Registrasi user baru"),
        "req": BotCommand(command="req", description="Request fitur & Kirim feedback"),
        "about": BotCommand(command="about", description="Tentang bot")
    }
    
    user_commands = get_user_permissions(employer) if employer else set()
    available_commands = [all_commands["start"]]  # Always include start
    
    # Add commands based on permissions
    for command_name in user_commands:
        if command_name in all_commands:
            available_commands.append(all_commands[command_name])
    
    # Always include about and register
    always_include = ["about", "register"]
    for cmd in always_include:
        if all_commands[cmd] not in available_commands:
            available_commands.append(all_commands[cmd])
    
    return available_commands

