# Function to check if a user is a super user
async def is_super_user(user_id: int) -> bool:
    """
    Check if user is a super user or admin (async version using cache).
    Returns True if user_level is 'super_user' or 'admin'.
    """
    try:
        user_record = await get_cached_user_data(user_id)
        
        if not user_record:
            logger.debug(f"No record found for user {user_id} in super user check.")
            return False

        # Check the 'user_level' column
        user_level = user_record.get('user_level', '').strip().lower()
        
        # =========================== MODIFY USER LEVEL HERE =========================== #
        has_privilege = user_level in ['super_user', 'admin']
        # ============================================================================== #

        logger.debug(f"Privilege check (super_user or admin) for user {user_id}: {has_privilege} (level: '{user_level}')")
        return has_privilege

    except Exception as e:
        logger.error(f"Error in is_super_user function: {e}")
        return False


