# 📂 30. Helper: Bot Performance Logger Decorator
# ==============================================================================
def measure_performance(command_name: str = None):
    """
    Enhanced decorator to measure command execution time and log to CSV with better error handling.
    """
    def decorator(func):
        @wraps(func)
        async def wrapper(*args, **kwargs):
            if not ENABLE_PERFORMANCE_TIMING:
                return await func(*args, **kwargs)
            
            # Record start time
            start_time = time.time()
            
            # Extract user information from arguments with enhanced detection
            user_id = None
            username = None
            chat_id = None
            
            # Try to find Message or CallbackQuery objects in arguments
            message_obj = None
            for arg in args:
                if isinstance(arg, Message):
                    user_id = arg.from_user.id
                    username = arg.from_user.username or arg.from_user.first_name or "Unknown"
                    chat_id = arg.chat.id
                    message_obj = arg
                    break
                elif isinstance(arg, CallbackQuery):
                    user_id = arg.from_user.id
                    username = arg.from_user.username or arg.from_user.first_name or "Unknown"
                    chat_id = arg.message.chat.id if arg.message else arg.from_user.id
                    message_obj = arg
                    break
            
            # Also check kwargs
            if not message_obj:
                message_obj = kwargs.get('message') or kwargs.get('call') or kwargs.get('event')
                if message_obj:
                    if hasattr(message_obj, 'from_user'):
                        user_id = message_obj.from_user.id
                        username = message_obj.from_user.username or message_obj.from_user.first_name or "Unknown"
                        if hasattr(message_obj, 'chat'):
                            chat_id = message_obj.chat.id
                        elif hasattr(message_obj, 'message') and message_obj.message:
                            chat_id = message_obj.message.chat.id
            
            # Determine command name
            cmd_name = command_name or func.__name__.replace('_', ' ').title()
            
            # Enhanced logging with user info
            logging.info(f"⏱️ Performance timing started for '{cmd_name}' - User: {user_id} ({username})")
            
            success = True
            error_message = None
            execution_time = 0
            
            try:
                # Execute the original function
                result = await func(*args, **kwargs)
                
                # Calculate execution time
                end_time = time.time()
                execution_time = end_time - start_time
                
                # Log completion
                logging.info(f"⏱️ Performance timing completed for '{cmd_name}' - User: {user_id} - Time: {execution_time:.3f}s")
                
                return result
                
            except Exception as e:
                # Calculate execution time for failed commands too
                end_time = time.time()
                execution_time = end_time - start_time
                
                success = False
                error_message = str(e)[:500]  # Limit error message length
                
                # Log error with full traceback
                logging.error(f"⏱️ Performance timing failed for '{cmd_name}' - User: {user_id} - Time: {execution_time:.3f}s")
                logging.error(f"Error details: {traceback.format_exc()}")
                
                # Re-raise the exception
                raise
            
            finally:
                # Always log to CSV regardless of success/failure
                try:
                    log_performance_to_csv(
                        timestamp=datetime.now(),
                        user_id=user_id,
                        username=username,
                        chat_id=chat_id,
                        command_name=cmd_name,
                        function_name=func.__name__,
                        execution_time=execution_time,
                        success=success,
                        error_message=error_message
                    )
                except Exception as csv_error:
                    logging.error(f"Failed to log performance to CSV: {csv_error}")
        
        return wrapper
    return decorator


def log_performance_to_csv(timestamp, user_id, username, chat_id, command_name, function_name, execution_time, success, error_message):
    """
    Enhanced CSV logging with better error handling and debugging.
    """
    try:
        # Ensure directory exists
        csv_dir = os.path.dirname(PERFORMANCE_CSV_PATH)
        if not os.path.exists(csv_dir):
            os.makedirs(csv_dir, exist_ok=True)
            logging.info(f"Created directory for performance CSV: {csv_dir}")
        
        # Check if file exists to determine if we need headers
        file_exists = os.path.exists(PERFORMANCE_CSV_PATH)
        
        # Debug logging
        logging.debug(f"CSV logging attempt - File exists: {file_exists}, Path: {PERFORMANCE_CSV_PATH}")
        
        # Thread-safe CSV writing
        with csv_lock:
            with open(PERFORMANCE_CSV_PATH, 'a', newline='', encoding='utf-8') as csvfile:
                fieldnames = [
                    'timestamp',
                    'user_id', 
                    'username',
                    'chat_id',
                    'command_name',
                    'function_name',
                    'execution_time_seconds',
                    'success',
                    'error_message'
                ]
                
                writer = csv.DictWriter(csvfile, fieldnames=fieldnames)
                
                # Write headers if file is new
                if not file_exists:
                    writer.writeheader()
                    logging.info(f"Created new performance CSV with headers: {PERFORMANCE_CSV_PATH}")
                
                # Prepare row data
                row_data = {
                    'timestamp': timestamp.strftime('%Y-%m-%d %H:%M:%S.%f')[:-3],
                    'user_id': user_id or 'Unknown',
                    'username': username or 'Unknown',
                    'chat_id': chat_id or 'Unknown',
                    'command_name': command_name,
                    'function_name': function_name,
                    'execution_time_seconds': f"{execution_time:.3f}",
                    'success': success,
                    'error_message': error_message or ''
                }
                
                # Write performance data
                writer.writerow(row_data)
        
        # Confirm successful logging
        logging.info(f"✅ Performance data logged to CSV: {command_name} - {execution_time:.3f}s - Success: {success}")
        
        # Verify file size (optional debug info)
        file_size = os.path.getsize(PERFORMANCE_CSV_PATH)
        logging.debug(f"CSV file size after write: {file_size} bytes")
        
    except Exception as e:
        logging.error(f"❌ Failed to log performance data to CSV: {e}")
        logging.error(f"CSV path: {PERFORMANCE_CSV_PATH}")
        logging.error(f"Error traceback: {traceback.format_exc()}")


def enable_performance_timing():
    """Enable performance timing globally"""
    global ENABLE_PERFORMANCE_TIMING
    ENABLE_PERFORMANCE_TIMING = True
    logging.info("Performance timing enabled")


def disable_performance_timing():
    """Disable performance timing globally"""
    global ENABLE_PERFORMANCE_TIMING
    ENABLE_PERFORMANCE_TIMING = False
    logging.info("Performance timing disabled")


def get_performance_stats():
    """
    Get basic performance statistics from the CSV file.
    Returns a dictionary with stats or None if file doesn't exist.
    """
    try:
        if not os.path.exists(PERFORMANCE_CSV_PATH):
            return None
        
        with open(PERFORMANCE_CSV_PATH, 'r', encoding='utf-8') as csvfile:
            reader = csv.DictReader(csvfile)
            data = list(reader)
        
        if not data:
            return None
        
        # Calculate basic stats
        total_commands = len(data)
        successful_commands = sum(1 for row in data if row['success'] == 'True')
        failed_commands = total_commands - successful_commands
        
        execution_times = [float(row['execution_time_seconds']) for row in data if row['execution_time_seconds']]
        avg_execution_time = sum(execution_times) / len(execution_times) if execution_times else 0
        max_execution_time = max(execution_times) if execution_times else 0
        min_execution_time = min(execution_times) if execution_times else 0
        
        # Most used commands
        command_counts = {}
        for row in data:
            cmd = row['command_name']
            command_counts[cmd] = command_counts.get(cmd, 0) + 1
        
        most_used_command = max(command_counts, key=command_counts.get) if command_counts else None
        
        return {
            'total_commands': total_commands,
            'successful_commands': successful_commands,
            'failed_commands': failed_commands,
            'success_rate': (successful_commands / total_commands * 100) if total_commands > 0 else 0,
            'avg_execution_time': avg_execution_time,
            'max_execution_time': max_execution_time,
            'min_execution_time': min_execution_time,
            'most_used_command': most_used_command,
            'command_usage': command_counts
        }
        
    except Exception as e:
        logging.error(f"Error getting performance stats: {e}")
        return None


