async def is_user_registered(user_id):
    logger.debug(f"Checking registration status for user {user_id}")
    try:
        await ensure_cache_fresh()
        user_id_str = str(user_id)
        for record in USER_DATA_CACHE.values():
            try:
                cached_uid = str(int(float(record.get('user_id', ''))))
            except (ValueError, TypeError):
                cached_uid = str(record.get('user_id', ''))
            if cached_uid == user_id_str:
                logger.debug(f"User {user_id} is already registered.")
                return True
    except Exception as e:
        logger.error(f"Error checking registration status for user {user_id}: {e}")
    logger.debug(f"User {user_id} is not registered.")
    return False


async def is_admin_user(user_id: int) -> bool:
    """
    Asynchronously checks for admin level using the centralized read_user_data_async function.
    """
    logger.debug(f"Initiating admin check for user {user_id} using centralized async reader.")
    
    # 1. Use the new centralized async function to get the data
    user_data = await read_user_data_async()

    # 2. Check if data was read successfully
    if user_data is None:
        logger.warning(f"Could not check admin status for {user_id}; data read failed.")
        return False
    
    # 3. Perform the check on the DataFrame
    try:
        # Normalize user_id column to handle float-formatted strings (e.g. '483825168.0')
        normalized_ids = user_data['user_id'].apply(
            lambda x: str(int(float(x))) if str(x).strip() not in ('', 'nan', 'None') else x
        )
        user_record = user_data[normalized_ids == str(user_id)]
        if user_record.empty:
            return False

        user_level = user_record.iloc[0].get('user_level', '')
        return user_level.strip().lower() == 'admin'
    except Exception as e:
        logger.error(f"Error processing DataFrame for admin check on user {user_id}: {e}")
        return False
    

async def save_feedback(user_id, username, feedback):
    async with aiofiles.open(FEEDBACK_FILE, 'a', newline='', encoding='utf-8') as csvfile:
        # Create CSV content in memory first
        output = StringIO()
        fieldnames = ['User_ID', 'Username', 'Feedback']
        writer = csv.DictWriter(output, fieldnames=fieldnames)
        writer.writerow({
            'User_ID': user_id,
            'Username': username,
            'Feedback': feedback
        })
        
        # Write the content to file
        await csvfile.write(output.getvalue())
        
    logger.info(f"Feedback from {username} (ID: {user_id}) saved successfully.") 

async def get_user_data(user_id):
    logger.debug(f"Retrieving user data for user {user_id}")
    try:
        async with aiofiles.open(USER_DATA_FILE, 'r', encoding='utf-8') as csvfile:
            content = await csvfile.read()
            reader = csv.DictReader(StringIO(content))
            for row in reader:
                if int(float(row['user_id'])) == user_id:
                    return row
    except Exception as e:
        logger.error(f"Error retrieving user data for user {user_id}: {e}")
    return {}


