async def check_user_agency_access(user_id, order_data=None):
    """
    Universal function for user validation and order access control
    Returns: (is_restricted: bool, company_name: str, can_access: bool, error_message: str)
    
    Args:
        user_id: User ID to check
        order_data: Optional order data for access validation
        
    Returns:
        - is_restricted: True if user is in restricted employer group
        - company_name: User's agency/company name (None if not restricted user or no company name)  
        - can_access: True if user can access the order (True for unrestricted users, or restricted users with matching sf_company_name)
        - error_message: Error message if access denied (empty string if access allowed)
        
    Configuration:
        To change restrictions, simply modify RESTRICTED_EMPLOYERS tuple:
        RESTRICTED_EMPLOYERS = ('sf',)              # Only SF restricted
        RESTRICTED_EMPLOYERS = ('sf', 'admin', 'ta') # Multiple restricted
        RESTRICTED_EMPLOYERS = ()                   # No restrictions
    """
    try:
        user_record = await get_cached_user_data(user_id)
        
        if not user_record:
            logger.debug(f"No record found for user_id {user_id}")
            return False, None, True, ""
        
        employer = user_record.get('employer', '').strip().lower()
        agency_name = user_record.get('agency_name', '').strip()
        
        # Check if user is in restricted employer group
        is_restricted = employer in RESTRICTED_EMPLOYERS and bool(agency_name)
        
        if not is_restricted:
            # Unrestricted users have full access
            return False, None, True, ""
        
        # For restricted users, check order access if order_data provided
        if order_data is None:
            # No order data to check, restricted user is valid
            return True, agency_name, True, ""
        
        # Check order access for restricted user
        if not order_data:
            return True, agency_name, False, "❌ Data order tidak ditemukan"
        
        # Get sf_company_name from first row
        first_row = order_data[0] if isinstance(order_data, list) else order_data
        order_sf_company_name = first_row.get('sf_company_name', '').strip() if isinstance(first_row, dict) else ''
        
        if not order_sf_company_name:
            return True, agency_name, False, "❌ SF company name tidak ditemukan pada order ini"
        
        # Check if user's agency_name matches order's sf_company_name
        if agency_name == order_sf_company_name:
            return True, agency_name, True, ""
        else:
            return True, agency_name, False, f"❌ Akses ditolak: Order ini tidak dalam lingkup Agency anda\n(Agency: {agency_name})"
            
    except Exception as e:
        logger.error(f"Error checking user order access for user {user_id}: {e}")
        return False, None, False, "❌ Terjadi kesalahan saat memverifikasi akses"


