async def approve_user_notification(nik_tsel: str):
    """
    Approves a user by NIK, following the correct Read-Modify-Overwrite pattern.
    """
    try:
        # --- STEP 1: READ ---
        user_data = await read_user_data_async()
        if user_data is None:
            logger.error(f"Approval failed for NIK {nik_tsel}: Cannot read user data.")
            return False, None, None

        # --- STEP 2: MODIFY ---
        # Find user records matching this NIK
        nik_mask = user_data['nik_tsel'] == str(nik_tsel)
        user_indices = user_data.index[nik_mask].tolist()

        if not user_indices:
            logger.warning(f"Approval failed: NIK {nik_tsel} not found.")
            return False, None, None

        # Prefer the unapproved record (the one waiting for approval)
        unapproved_indices = [
            i for i in user_indices
            if str(user_data.at[i, 'is_authorized']).lower() != 'yes'
        ]

        if not unapproved_indices:
            # All matches are already approved
            user_index = user_indices[0]
            registrant_id = user_data.at[user_index, 'user_id']
            username = user_data.at[user_index, 'username']
            logger.info(f"User with NIK {nik_tsel} is already approved.")
            return False, registrant_id, username

        if len(unapproved_indices) > 1:
            logger.warning(f"Multiple unapproved users with NIK {nik_tsel} found ({len(unapproved_indices)}), approving first match")

        user_index = unapproved_indices[0]
        registrant_id = user_data.at[user_index, 'user_id']
        username = user_data.at[user_index, 'username']

        # Modify the user's data in the DataFrame
        logger.info(f"Approving NIK {nik_tsel} (user_id={registrant_id}). Setting is_authorized=yes and user_level=user.")
        user_data.at[user_index, 'is_authorized'] = 'yes'
        user_data.at[user_index, 'user_level'] = 'user'

        # --- STEP 3: OVERWRITE (with file locking) ---
        await write_csv_with_lock(user_data)

        logger.info(f"Successfully approved NIK {nik_tsel} and overwrote user_data.csv.")

        # Invalidate the cache since the underlying file has changed
        invalidate_cache()
        
        return True, registrant_id, username  # Approval was successful

    except Exception as e:
        logger.error(f"An unexpected error occurred in approve_user_notification for NIK {nik_tsel}: {e}", exc_info=True)
        return False, None, None


async def update_user_nik(user_id: int, new_nik: str) -> bool:
    """Update nik_tsel for a user in user_data.csv using Read-Modify-Overwrite with file locking."""
    try:
        user_data = await read_user_data_async()
        if user_data is None:
            return False

        # Find user by user_id
        mask = user_data['user_id'].astype(str).str.strip() == str(user_id)
        match_count = mask.sum()
        if match_count == 0:
            return False
        if match_count > 1:
            logger.warning(f"update_user_nik: found {match_count} rows for user_id {user_id}, updating first match only")
            # Only update the first matching row
            first_idx = user_data.index[mask][0]
            user_data.at[first_idx, 'nik_tsel'] = new_nik
        else:
            user_data.loc[mask, 'nik_tsel'] = new_nik

        await write_csv_with_lock(user_data)
        invalidate_cache()
        return True
    except Exception as e:
        logger.error(f"Error updating NIK for user {user_id}: {e}", exc_info=True)
        return False


async def delete_own_user_record(user_id_to_delete):
    """
    Reads the user data CSV, removes the specified user ID, and rewrites the file.

    Args:
        user_id_to_delete (int): The ID of the user to remove.

    Returns:
        bool: True if deletion and rewrite were successful, False otherwise.
    """
    logger.info(f"Attempting to delete record for user_id: {user_id_to_delete}")
    rows_to_keep = []
    header = []
    user_found = False
    user_id_str = str(user_id_to_delete)  # Convert target ID to string for comparison

    try:
        # Step 1: Read the existing data and filter out the target user
        async with aiofiles.open(USER_DATA_FILE, 'r', encoding='utf-8') as csvfile:
            content = await csvfile.read()
            
        # Parse CSV content
        csv_reader = csv.reader(StringIO(content))
        header = next(csv_reader)  # Read the header row
        user_id_col_index = -1
        
        try:
            # Find the index of the 'user_id' column
            user_id_col_index = header.index('user_id')
        except ValueError:
            logger.error("'user_id' column not found in header.")
            return False

        # Read remaining rows and filter
        for row in csv_reader:
            if row:  # Ensure row is not empty
                raw_uid = row[user_id_col_index].strip()
                try:
                    current_user_id = str(int(float(raw_uid)))
                except (ValueError, TypeError):
                    current_user_id = raw_uid
                if current_user_id == user_id_str:
                    user_found = True
                    logger.debug(f"Found user {user_id_str} for deletion. Skipping row.")
                else:
                    rows_to_keep.append(row)
            else:
                logger.warning("Skipping empty row found in CSV.")

        if not user_found:
            logger.warning(f"User {user_id_str} not found in CSV during deletion process.")
            return False  # Indicate user wasn't present to be deleted

        # Step 2: Write the filtered data back to the file (overwrite) with locking
        df = pd.DataFrame(rows_to_keep, columns=header)
        await write_csv_with_lock(df)

        logger.info(f"Successfully removed user {user_id_str} and rewrote {USER_DATA_FILE}")
        
        # Invalidate cache since we modified the file
        global USER_DATA_CACHE, CACHE_TIMESTAMP
        USER_DATA_CACHE = {}
        CACHE_TIMESTAMP = 0
        
        return True

    except FileNotFoundError:
        logger.error(f"CSV file not found during deletion: {USER_DATA_FILE}")
        return False
    except Exception as e:
        logger.error(f"Error processing CSV for deletion of user {user_id_str}: {e}")
        return False
    

async def notify_super_users(user_id, username, nik_tsel, region_level, bot: Bot, nik_verified=None):
    """
    Notify super users in specific region about new registration (cache version).
    If nik_verified is False, also notifies admin-level users with a warning.

    Notifies the registering user themselves (for self-approval testing).
    """
    try:
        # Ensure cache is fresh
        await ensure_cache_fresh()

        # Get additional user data from the current registration
        user_name = ""
        employer = ""
        is_uid_fallback = str(nik_tsel).startswith("UID_")
        for user_record in USER_DATA_CACHE.values():
            try:
                normalized_uid = str(int(float(user_record.get('user_id', ''))))
            except (ValueError, TypeError):
                normalized_uid = str(user_record.get('user_id', ''))
            if normalized_uid == str(user_id) and (
                user_record.get('nik_tsel') == nik_tsel or is_uid_fallback
            ):
                user_name = user_record.get('user_name', '')
                employer = user_record.get('employer', '')
                break

        # Guard: reject if too many pending approvals (memory protection)
        if len(PENDING_APPROVALS) >= PENDING_APPROVALS_MAX_SIZE:
            logger.error(f"PENDING_APPROVALS at max capacity ({PENDING_APPROVALS_MAX_SIZE}). Cannot queue NIK {nik_tsel}.")
            return

        # Store pending approval with timestamp
        PENDING_APPROVALS[nik_tsel] = {
            'timestamp': datetime.now(),
            'user_id': user_id,
            'username': username,
            'user_name': user_name,
            'employer': employer,
            'region_level': region_level
        }

        # Start auto-reject timer (3 days = 72 hours)
        asyncio.create_task(auto_reject_timer(nik_tsel, bot))

        # Demo mode: notify the registering user themselves for self-approval
        logger.info(f"[DEMO] Sending approval notification to registering user {user_id}")
        notify_targets = [{'user_id': user_id, 'is_self': True}]

        # Send notifications with detailed information
        for target in notify_targets:
            target_user_id = target['user_id']
            nik_display = "(tidak diisi)" if str(nik_tsel).startswith("UID_") else (nik_tsel if nik_tsel else '-')
            display_un = f"@{username}" if username and username != "N/A" and " " not in username else (username or "N/A")

            # Add warning if NIK was not verified against domain table
            nik_warning = ""
            if nik_verified is False:
                nik_warning = "\n⚠️ *NIK tidak ditemukan di database karyawan!*\n"

            # Demo mode header for self-approval
            demo_prefix = "🧪 [DEMO] " if target.get('is_self') else ""

            approval_message = (
                f"{demo_prefix}🔔 *User {display_un} (ID: {user_id}) meminta persetujuan pendaftaran baru!*\n\n"
                f"• *Nama Lengkap:* {user_name or '-'}\n"
                f"• *Employer:* {employer.upper() if employer else '-'}\n"
                f"• *NIK:* {nik_display}\n"
                f"• *Region:* {region_level.upper() if region_level else '-'}\n"
                f"{nik_warning}\n"
                f"📝 *Pilihan respon:*\n"
                f"• Setujui: `/approve {nik_tsel}`\n"
                f"• Tolak: `/reject {nik_tsel} <alasan penolakan>`\n\n"
                f"⏰ *Batas Waktu:* 3x24 jam (auto-reject jika tidak ada respon)\n\n"
                f"💡 *Tip:* Pastikan validitas pendaftar sebelum melakukan approval."
            )
            try:
                await bot.send_message(target_user_id, approval_message, parse_mode='Markdown')
                logger.info(f"Approval message sent to user {target_user_id}.")
            except Exception as e:
                if "chat not found" in str(e).lower():
                    logger.error(f"Cannot send message to user {target_user_id}: Chat not found. Ask them to start a chat with the bot.")
                else:
                    logger.error(f"Error sending approval message to user {target_user_id}: {e}")

    except Exception as e:
        logger.error(f"Error in notify_super_users: {e}")

async def auto_reject_timer(nik_tsel, bot: Bot, remaining_seconds=None):
    """
    Auto-reject user after 3x24 hours if not approved.
    """
    global USER_DATA_CACHE, CACHE_TIMESTAMP

    try:
        if remaining_seconds is None:
            remaining_seconds = AUTO_REJECT_SECONDS
        await asyncio.sleep(remaining_seconds)
        
        # Check if still pending (not approved/rejected)
        if nik_tsel in PENDING_APPROVALS:
            pending_data = PENDING_APPROVALS[nik_tsel]
            user_id = pending_data['user_id']
            username = pending_data['username']
            
            # Remove from pending list
            del PENDING_APPROVALS[nik_tsel]

            # Delete the user record from CSV (same as manual rejection)
            deleted = await delete_own_user_record(user_id)
            if deleted:
                logger.info(f"Auto-reject: deleted user {user_id} (NIK: {nik_tsel}) from CSV")
            else:
                logger.warning(f"Auto-reject: failed to delete user {user_id} (NIK: {nik_tsel}) from CSV")

            # Invalidate cache
            USER_DATA_CACHE = {}
            CACHE_TIMESTAMP = 0
            
            # Send auto-reject notification to user
            auto_reject_message = (
                "❌ *Pendaftaran Otomatis Ditolak*\n\n"
                "Pendaftaran anda belum disetujui admin dalam 3x24 Jam,"
                "Silahkan lakukan registrasi ulang atau hubungi HCOT/SRM/GTM Region/Area anda."
            )
            
            try:
                await bot.send_message(user_id, auto_reject_message, parse_mode='Markdown')
                logger.info(f"Auto-reject notification sent to user {user_id} (NIK: {nik_tsel})")
            except Exception as e:
                logger.error(f"Failed to send auto-reject notification to user {user_id}: {e}")
            
            # Log the auto-rejection
            logger.warning(f"Auto-rejected user {username} (NIK: {nik_tsel}) due to timeout")
            
    except asyncio.CancelledError:
        logger.info(f"Auto-reject timer cancelled for NIK: {nik_tsel}")
    except Exception as e:
        logger.error(f"Error in auto_reject_timer for NIK {nik_tsel}: {e}")


async def cleanup_pending_approvals():
    """Periodic task: remove PENDING_APPROVALS entries older than 72 hours."""
    while True:
        try:
            await asyncio.sleep(3600)  # Run every hour
            now = datetime.now()
            expired_keys = [
                k for k, v in PENDING_APPROVALS.items()
                if (now - v.get('timestamp', now)).total_seconds() > AUTO_REJECT_SECONDS
            ]
            for key in expired_keys:
                del PENDING_APPROVALS[key]
                logger.info(f"cleanup_pending_approvals: removed stale entry {key}")
        except asyncio.CancelledError:
            break
        except Exception as e:
            logger.error(f"Error in cleanup_pending_approvals: {e}")


async def migrate_csv_add_registered_at():
    """One-time idempotent migration: adds 'registered_at' column to user_data.csv if missing."""
    try:
        csv_path = str(USER_DATA_FILE)
        if not os.path.exists(csv_path):
            return

        with open(csv_path, 'r', encoding='utf-8', newline='') as f:
            content = f.read()

        if not content.strip():
            return

        lines = content.splitlines()
        header = lines[0]

        if 'registered_at' in header.split(','):
            logger.info("migrate_csv_add_registered_at: column already exists, skipping")
            return

        # Append new column to header and empty value to each data row
        lines[0] = header + ',registered_at'
        for i in range(1, len(lines)):
            if lines[i].strip():
                lines[i] = lines[i] + ','

        new_content = '\n'.join(lines) + '\n'

        # Atomic write via temp file + os.replace
        tmp_path = csv_path + '.tmp'
        with open(tmp_path, 'w', encoding='utf-8', newline='') as f:
            f.write(new_content)
        os.replace(tmp_path, csv_path)

        logger.info("migrate_csv_add_registered_at: added 'registered_at' column successfully")
    except Exception as e:
        logger.error(f"Error in migrate_csv_add_registered_at: {e}")


async def recover_pending_approvals_on_startup(bot: Bot):
    """On bot startup, recover auto-reject timers using persistent registered_at from CSV."""
    try:
        # Clear in-memory state since all timers are lost on restart
        PENDING_APPROVALS.clear()

        await ensure_cache_fresh()
        now = datetime.now()
        immediate_reject_delay = 5  # seconds grace period to avoid API flood

        for record in USER_DATA_CACHE.values():
            is_auth = (record.get('is_authorized') or 'no').strip().lower()
            if is_auth == 'no':
                nik = record.get('nik_tsel', '')
                user_id_raw = record.get('user_id', '')
                try:
                    user_id = int(float(user_id_raw))
                except (ValueError, TypeError):
                    continue

                # Calculate remaining time from persistent registered_at
                registered_at_str = (record.get('registered_at') or '').strip()
                remaining = 0
                if registered_at_str:
                    try:
                        registered_at = datetime.fromisoformat(registered_at_str)
                        elapsed = (now - registered_at).total_seconds()
                        remaining = AUTO_REJECT_SECONDS - elapsed
                    except (ValueError, TypeError):
                        logger.warning(f"Startup recovery: malformed registered_at '{registered_at_str}' for NIK {nik}, treating as expired")
                        remaining = 0
                else:
                    # Legacy row without registered_at — treat as expired
                    logger.info(f"Startup recovery: no registered_at for NIK {nik}, treating as expired")
                    remaining = 0

                # Clamp to minimum grace period
                if remaining <= 0:
                    remaining = immediate_reject_delay

                PENDING_APPROVALS[nik] = {
                    'timestamp': now,
                    'user_id': user_id,
                    'username': record.get('username', 'N/A'),
                    'user_name': record.get('user_name', ''),
                    'employer': record.get('employer', ''),
                    'region_level': record.get('region_level', '')
                }
                asyncio.create_task(auto_reject_timer(nik, bot, remaining_seconds=remaining))
                logger.info(f"Startup recovery: timer for NIK {nik} (user {user_id}) with {remaining:.0f}s remaining")
    except Exception as e:
        logger.error(f"Error in recover_pending_approvals_on_startup: {e}")


# Function to perform the actual user deletion based on username
async def perform_user_deletion(username_to_delete: str):
    """
    Deletes the user record based on username.
    This function modifies data, so it reads from file, updates, saves, and invalidates cache.
    """
    try:
        # Read current data from file (since we're modifying it)
        user_data = await read_user_data_async()
        if user_data is None:
            logger.error("Failed to read user data during deletion.")
            return False
        
        # Clean username data
        user_data['username'] = user_data['username'].astype(str).str.strip()
        initial_count = len(user_data)
        
        # Handle both @username and username formats
        # First try exact match
        username_exact = username_to_delete.strip()
        user_data_filtered = user_data[user_data['username'] != username_exact]
        
        # If no deletion happened and input doesn't have @, try with @
        if len(user_data_filtered) == initial_count and not username_to_delete.startswith('@'):
            username_with_at = f"@{username_to_delete}"
            user_data_filtered = user_data[user_data['username'] != username_with_at]
            logger.info(f"Tried with @ prefix: {username_with_at}")
        
        # If still no deletion and input has @, try without @
        elif len(user_data_filtered) == initial_count and username_to_delete.startswith('@'):
            username_without_at = username_to_delete.lstrip('@')
            user_data_filtered = user_data[user_data['username'] != username_without_at]
            logger.info(f"Tried without @ prefix: {username_without_at}")
        
        final_count = len(user_data_filtered)
        
        if initial_count == final_count:
            logger.warning(f"User {username_to_delete} not found for deletion")
            return False
        
        # Save updated data
        user_data_filtered.to_csv(USER_DATA_FILE, index=False)
        
        # Invalidate cache so it refreshes with new data
        invalidate_cache()
        
        deleted_count = initial_count - final_count
        logger.info(f"User {username_to_delete} successfully deleted ({deleted_count} record(s))")
        return True
        
    except Exception as e:
        logger.error(f"Error in perform_user_deletion: {e}")
        return False
    
