def parse_short_date(s: str | None) -> date:
    if not s:
        return date(1900, 1, 1)          
    parts = s.split('/')
    if len(parts) == 2:                 
        s = f"{s}/{datetime.now():%y}"  
    try:
        return datetime.strptime(s, "%d/%b/%y").date()
    except Exception:
        return date(1900, 1, 1)  

def safe_format_percentage(value):
    if value is None:
        return "N/A"
    try:
        return f"{float(value):.1f}%"
    except (ValueError, TypeError):
        return "N/A"

def safe_format_percentage_from_decimal(value):
    """Formats a decimal value as percentage (converts 0.18 to 18.0%)"""
    if value is None:
        return "N/A"
    try:
        return f"{float(value) * 100:.1f}%"
    except (ValueError, TypeError):
        return "N/A"

def safe_format_decimal(value, decimals=1):
    if value is None:
        return "N/A"
    try:
        return f"{float(value):.{decimals}f}"
    except (ValueError, TypeError):
        return "N/A"

def safe_format_integer(value):
    if value is None:
        return "N/A"
    try:
        return f"{int(value):,}"
    except (ValueError, TypeError):
        return "N/A"
    
# Format FUP consumption with visual indicators
def safe_format_fup_consumption(usage_gb, fup):
    if usage_gb is None or fup is None or fup == '0':
        return "N/A"
    try:
        usage = float(usage_gb)
        fup_limit = float(fup)
        
        if fup_limit == 0:
            return "N/A"
            
        percentage = (usage / fup_limit) * 100
        
        # Create visual indicator proportionate to the percentage
        if percentage > 100:
            category = "Over Usage ❌"
            visual = "🟥🟥🟥🟥🟥"  # Red blocks for over usage
        else:
            # Calculate number of filled blocks (0-5) based on percentage
            blocks_filled = min(int(percentage / 20) + 1, 5)  # +1 to ensure at least 1 block at low percentages
            
            # Determine category based on specified buckets
            if percentage >= 50:
                category = "High Usage"
            elif percentage >= 20:
                category = "Normal"
            else:
                category = "Low Usage"
            
            # Create the visual bar
            visual = "🟧" * blocks_filled + "⬜️" * (5 - blocks_filled)
        
        return f"{percentage:.1f}% {visual} ({category})"
    except Exception:
        return "N/A"

# Convert event_date to month name
def safe_event_date_to_month(event_date):
    if event_date is None or len(str(event_date)) < 6:
        return "N/A"
    try:
        year = str(event_date)[:4]
        month_num = int(str(event_date)[4:6])
        month_names = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec']
        month_name = month_names[month_num - 1]
        return f"{year}-{month_name}"
    except Exception:
        return "N/A"
    
# Format timestamps - remove decimal seconds
def safe_format_timestamp(timestamp):
    if timestamp is None or timestamp == 'N/A':
        return "N/A"
    try:
        if isinstance(timestamp, str):
            dt = datetime.strptime(timestamp, "%Y-%m-%d %H:%M:%S")
        else:
            dt = timestamp
        return dt.strftime("%Y-%m-%d %H:%M:%S")
    except Exception:
        return "N/A"

# Format currency values
def safe_format_currency(value):
    if value is None:
        return "Rp. N/A"
    try:
        return f"Rp. {float(value):,.0f}".replace(",", ".")
    except Exception:
        return "N/A"    

# Format value to integer
def safe_int(value, default=0):
    """Safely convert value to int."""
    try:
        return int(value)
    except (ValueError, TypeError):
        return default

# Format value to decimal
def convert_decimal(value):
    if isinstance(value, Decimal):
        return float(value)
    return value


# JSON serialization helper for numpy types
def convert_numpy_types(obj):
    """
    Convert numpy types to native Python types for JSON serialization.
    """
    if isinstance(obj, dict):
        return {key: convert_numpy_types(value) for key, value in obj.items()}
    elif isinstance(obj, list):
        return [convert_numpy_types(item) for item in obj]
    elif isinstance(obj, np.integer):
        return int(obj)
    elif isinstance(obj, np.floating):
        return float(obj)
    elif isinstance(obj, np.ndarray):
        return obj.tolist()
    elif pd.isna(obj):
        return None
    else:
        return obj

def safe_json_dumps(obj):
    """Safely convert object to JSON string, handling numpy types."""
    try:
        converted_obj = convert_numpy_types(obj)
        return json.dumps(converted_obj)
    except (TypeError, ValueError) as e:
        logging.error(f"JSON serialization error: {e}")
        logging.error(f"Problematic object type: {type(obj)}")
        logging.error(f"Object content (first 200 chars): {str(obj)[:200]}")
        # Return empty object as fallback
        return json.dumps({})


# Safe message sending with retry logic
async def safe_send_message(bot, chat_id, text, max_retries=3, timeout=10):
    """
    Send message with retry logic and timeout handling.
    """
    for attempt in range(max_retries):
        try:
            return await asyncio.wait_for(
                bot.send_message(chat_id, text),
                timeout=timeout
            )
        except asyncio.TimeoutError:
            logging.warning(f"Message send timeout (attempt {attempt + 1}/{max_retries})")
            if attempt == max_retries - 1:
                raise
            await asyncio.sleep(1)
        except Exception as e:
            logging.error(f"Error sending message (attempt {attempt + 1}/{max_retries}): {e}")
            if attempt == max_retries - 1:
                raise
            await asyncio.sleep(1)


# Safe message editing with retry logic
async def safe_edit_message(bot, chat_id, message_id, text, max_retries=3, timeout=10):
    """
    Edit message with retry logic and timeout handling.
    """
    for attempt in range(max_retries):
        try:
            return await asyncio.wait_for(
                bot.edit_message_text(chat_id=chat_id, message_id=message_id, text=text),
                timeout=timeout
            )
        except asyncio.TimeoutError:
            logging.warning(f"Message edit timeout (attempt {attempt + 1}/{max_retries})")
            if attempt == max_retries - 1:
                return None  # Don't raise, just return None
            await asyncio.sleep(1)
        except Exception as e:
            logging.warning(f"Error editing message (attempt {attempt + 1}/{max_retries}): {e}")
            if attempt == max_retries - 1:
                return None  # Don't raise, just return None
            await asyncio.sleep(1)


def format_sensitive_data(value, has_privilege: bool) -> str:
    """
    Format sensitive data based on user privileges — preserves character count
    """
    if not value or value == 'N/A' or value == 'NULL':
        return '-'

    s = str(value)
    if has_privilege:
        return s
    else:
        return '*' * len(s)

def format_partial_censor_name(value, has_privilege: bool, visible_chars: int = 3) -> str:
    """Partial censor for names — show last N chars, preserve length (e.g., 'Azaria' -> '***ria')"""
    if not value or value in ('N/A', 'NULL', ''):
        return '-'
    s = str(value).strip().title()
    if has_privilege:
        return s
    if len(s) <= visible_chars:
        return '*' * len(s)
    return '*' * (len(s) - visible_chars) + s[-visible_chars:]

def format_partial_censor_msisdn(value, has_privilege: bool, visible_chars: int = 4) -> str:
    """Partial censor for MSISDN — show last N digits, preserve length (e.g., '6282232323390' -> '*********3390')"""
    if not value or value in ('N/A', 'NULL', ''):
        return '-'
    s = str(value).strip()
    if has_privilege:
        return s
    if len(s) <= visible_chars:
        return '*' * len(s)
    return '*' * (len(s) - visible_chars) + s[-visible_chars:]

def format_coordinates(latitude, longitude, has_privilege: bool) -> tuple:
    """
    Format coordinates and return both display text and maps URL
    Returns: (display_text, maps_url)
    """
    if not latitude or not longitude or latitude == 'N/A' or longitude == 'N/A' or \
       latitude == 'NULL' or longitude == 'NULL':
        return '-', None
    
    try:
        lat_val = float(latitude)
        lon_val = float(longitude)
        if not has_privilege:
            lat_str = str(lat_val)
            lon_str = str(lon_val)
            return f"{'*' * len(lat_str)},{'*' * len(lon_str)}", None
        coords_text = f"{lat_val},{lon_val}"
        maps_url = f"https://www.google.com/maps?q={lat_val},{lon_val}"
        return coords_text, maps_url
    except (ValueError, TypeError):
        return '-', None
    

async def validate_sf_code(sf_code: str) -> tuple[bool, str]:
    """
    Validates SF Code: Mixed numeric and alphabet with NO space
    Returns: (is_valid, error_message)
    """
    # Run validation in executor to maintain async compatibility
    return await asyncio.get_event_loop().run_in_executor(None, _validate_sf_code_sync, sf_code)

def _validate_sf_code_sync(sf_code: str) -> tuple[bool, str]:
    """Synchronous SF code validation logic."""
    sf_code = sf_code.strip()
    
    # Check if empty
    if not sf_code:
        return False, "Kode SF tidak boleh kosong."
    
    # Check for spaces
    if ' ' in sf_code:
        return False, "Kode SF tidak boleh mengandung spasi."
    
    return True, ""


async def validate_nik_tsel(nik: str, employer: str = "TSEL") -> tuple[bool, str]:
    """
    Validates NIK based on employer type:
    - TSEL: All numeric with 4-8 character length
    - TIF/TA: Flexible alphanumeric (letters only, numbers only, or mixed) with 4-12 character length
    Returns: (is_valid, error_message)
    """
    # Run validation in executor to maintain async compatibility
    return await asyncio.get_event_loop().run_in_executor(None, _validate_nik_tsel_sync, nik, employer)

def _validate_nik_tsel_sync(nik: str, employer: str = "TSEL") -> tuple[bool, str]:
    """Synchronous NIK validation logic based on employer."""
    nik = nik.strip()
    employer = employer.upper()
    
    # Check if empty
    if not nik:
        return False, f"NIK {employer} tidak boleh kosong."
    
    # Validation rules based on employer
    if employer == "TSEL":
        # TSEL specific length: 4-8 characters
        if len(nik) < 4:
            return False, f"NIK {employer} minimal 4 digit."
        
        if len(nik) > 8:
            return False, f"NIK {employer} maksimal 8 digit."
            
    elif employer in ["TIF", "TA"]:
        # TIF/TA: Flexible - can be numeric only, alphabetic only, or mixed
        if not nik.isalnum():
            return False, f"NIK {employer} hanya boleh mengandung huruf dan/atau angka dan terdiri dari 4-12 digit."
        
        # TIF/TA specific length: 4-12 characters
        if len(nik) < 4:
            return False, f"NIK {employer} minimal 4 karakter."
        
        if len(nik) > 12:
            return False, f"NIK {employer} maksimal 12 karakter."
    
    return True, ""

            
