def calculate_radius_radians(self) -> float:
    # For haversine distance, radius should be in radians
    earth_radius_m = 6371000  # meters
    radius_radians = self.radius_meters / earth_radius_m  # Proper conversion
    return radius_radians


async def process_data(rows, group_by):
    logging.debug("Doing process_data function...")
    data_by_key = {}
    daily_data = {}

    try:
        for row in rows:
            # Updated key extraction based on your query structure
            key = row.get('branch') if group_by == 'branch' else row.get('region')
            if key is None:
                logging.warning(f"Missing expected key for group '{group_by}' in row: {row}")
                continue

            # Updated date processing to handle datetime.date objects
            date_str = row.get('full_date')
            if date_str is None:
                logging.warning("Missing 'full_date' in row: {row}")
                continue
            
            # Convert to string format if date_str is not already a string
            if isinstance(date_str, date):
                date_str = date_str.strftime('%Y-%m-%d')
                
            date_obj = datetime.strptime(date_str, '%Y-%m-%d')
            date_formatted = date_obj.strftime('%Y-%m-%d')

            # Numeric field handling
            ps = safe_int(row.get('ps'))
            io = safe_int(row.get('io'))
            re = safe_int(row.get('re'))
            tgt_sales = safe_int(row.get('tgt_sales'))


            # Set area field if grouped by region
            area = row.get('area', 'Unknown') if group_by == 'region' else row.get('region', 'Unknown')

            # Initialize entry in data_by_key if it doesn't exist
            if key not in data_by_key:
                data_by_key[key] = {
                    'tgt_sales': tgt_sales,
                    'io_sum': 0,
                    're_sum': 0,
                    'ps_sum': 0,
                    'records': []
                }
                if group_by == 'region':
                    data_by_key[key]['area'] = area

            # Aggregate sums
            data_by_key[key]['io_sum'] += io
            data_by_key[key]['re_sum'] += re
            data_by_key[key]['ps_sum'] += ps

            # Append daily record
            data_by_key[key]['records'].append({
                'date': date_formatted,
                'full_date': date_str,
                'io': io,
                're': re,
                'ps': ps
            })

            # Aggregate daily PS data by date
            if date_formatted not in daily_data:
                daily_data[date_formatted] = {}
            if key not in daily_data[date_formatted]:
                daily_data[date_formatted][key] = 0
            daily_data[date_formatted][key] += ps

        logging.debug(f"Keys in data_by_key after processing by '{group_by}': {list(data_by_key.keys())}")

    except Exception as e:
        logging.error(f"Error while processing data: {e}")
        logging.error(traceback.format_exc())

    logging.debug("Data processed successfully.")
    return data_by_key, daily_data


def process_region_data(rows):
    logging.debug("Processing region data...")
    data_by_region, daily_data_region = process_data(rows, group_by='region')
    logging.debug(f"Processed region data: {data_by_region}")
    return data_by_region, daily_data_region


def calculate_cumulative(daily_data, start_date, end_date):
    logging.debug(f"Calculating cumulative data from {start_date.strftime('%Y-%m-%d')} to {end_date.strftime('%Y-%m-%d')}")
    cumulative = {}
    
    # Sort dates in daily_data and filter by start_date to end_date
    sorted_dates = sorted(daily_data.keys(), key=lambda d: datetime.strptime(d, '%Y-%m-%d'))

    logging.debug(f"Sorted dates in daily_data: {sorted_dates}")

    for date in sorted_dates:
        date_obj = datetime.strptime(date, '%Y-%m-%d')
        
        # Only accumulate data within the selected period
        if date_obj < start_date:
            continue
        if date_obj > end_date:
            break
        
        # Log each date within range
        logging.debug(f"Processing date within range: {date}")

        # Accumulate values for each branch or key
        for key, ps in daily_data[date].items():
            cumulative[key] = cumulative.get(key, 0) + ps

    logging.debug(f"Cumulative Data Calculated: {cumulative}")
    return cumulative


async def assign_ranks(ach_data):
    logging.debug("Assigning ranks based on achievement data.")
    sorted_keys = sorted(ach_data.items(), key=lambda item: item[1], reverse=True)
    ranks = {}
    for idx, (key, _) in enumerate(sorted_keys, start=1):
        ranks[key] = idx
    logging.debug("Ranks assigned successfully.")
    return ranks


