async def format_a3_summary_message(start_date, end_date):
    """A3 summary - filters by specific day range."""
    selected_period = start_date.strftime("%Y%m")
    logging.debug(f"[A3] Using daily filtering for period: {selected_period}")
    
    # UI Element
    separator = "━" * 15

    # Fetch data
    branch_summary_rows = await fetch_bot_branch_a3_summary(selected_period)
    a3_daily_rows = await fetch_bot_a3_daily(selected_period)
    jatengdiy_rows = await fetch_bot_jatengdiy_daily(selected_period)
    jatim_rows = await fetch_bot_jatim_daily(selected_period)
    balinusra_rows = await fetch_bot_balinusra_daily(selected_period)
    max_io_ts_rows = await fetch_max_io_ts()
    
    if not a3_daily_rows or not branch_summary_rows:
        return ["❌ Data tidak tersedia, Silahkan atur ulang tanggal laporan anda dengan /daterange"]
    
    # Process max_io_ts data
    region_ts_map = {}  # Maps region to max timestamp
    overall_max_ts = None
    
    for row in max_io_ts_rows:
        region = row.get('region')
        ts = row.get('max_io_ts')
        
        if region and ts:
            region_ts_map[region] = ts
        
        # Track overall max
        if ts and (overall_max_ts is None or ts > overall_max_ts):
            overall_max_ts = ts
    
    def format_timestamp(ts):
        """Format timestamp as 'YYYY-MM-DD HH:MM'"""
        if ts is None:
            return "N/A"
        if isinstance(ts, str):
            return ts[:16]  # Truncate to 'YYYY-MM-DD HH:MM'
        return ts.strftime("%Y-%m-%d %H:%M")
    
    # Check if this is a full month selection or partial date range
    year = start_date.year
    month = start_date.month
    first_day_of_month = datetime(year, month, 1)
    last_day_of_month = datetime(year, month, calendar.monthrange(year, month)[1])
    is_full_month = (start_date.date() == first_day_of_month.date() and 
                     end_date.date() == last_day_of_month.date())
    
    # Apply filtering to daily data (always filter these for consistency)
    a3_daily_rows = filter_rows_by_date_range(a3_daily_rows, start_date, end_date, filter_type="daily")
    jatengdiy_rows = filter_rows_by_date_range(jatengdiy_rows, start_date, end_date, filter_type="daily")
    jatim_rows = filter_rows_by_date_range(jatim_rows, start_date, end_date, filter_type="daily")
    balinusra_rows = filter_rows_by_date_range(balinusra_rows, start_date, end_date, filter_type="daily")
    
    if not a3_daily_rows:
        return ["❌ Data tidak tersedia, Silahkan atur ulang tanggal laporan anda dengan /daterange"]
    
    # Sort and get date range
    a3_daily_rows.sort(key=lambda x: parse_short_date(x.get('short_date') or "01/Jan"))
    min_date_str = a3_daily_rows[0].get('short_date', "N/A")
    max_date_str = a3_daily_rows[-1].get('short_date', "N/A")

    # Branch Summary
    branch_lines = []
    for row in branch_summary_rows:
        try:
            # --- RANK AND MEDAL LOGIC ---
            rk = row.get('rank')
            if rk is None:
                rank_formatted = "N/A"
            else:
                medal = "🥇" if rk == 1 else "🥈" if rk == 2 else "🥉" if rk == 3 else ""
                space_padding = '' if 1 <= rk <= 3 else '  ' if 4 <= rk <= 9 else ' '
                rank_formatted = f"{rk}{medal}{space_padding}"
            
            brch = row.get('branch') or "N/A"
            
            # Use safe formatting functions to handle potential None values
            io_sum = safe_format_integer(row.get('io'))
            re_sum = safe_format_integer(row.get('re'))
            ps_sum = safe_format_integer(row.get('ps'))
            ps_day = safe_format_integer(row.get('ps_day'))
            run_rate = safe_format_decimal(row.get('run_rate'), decimals=1)
            io_mom = safe_format_decimal(row.get('io_mom'), decimals=1)
            re_mom = safe_format_decimal(row.get('re_mom'), decimals=1)
            ps_mom = safe_format_decimal(row.get('ps_mom'), decimals=1)

            
            branch_lines.append(
                "{:<2} {:<3} {:>5} {:>5} {:>5} {:>3} {:>5} {:>5}".format(
                    rank_formatted, brch, io_sum, re_sum, ps_sum, ps_day, run_rate, ps_mom
                )
            )
        except (KeyError, TypeError, ValueError) as e:
            logging.warning(f"Skipping a branch summary row due to formatting error: {e}")
            branch_lines.append(
                "{:<2} {:<3} {:>5} {:>5} {:>5} {:>3} {:>5} {:>5}".format(
                    "N/A", "N/A", "N/A", "N/A", "N/A", "N/A", "N/A", "N/A"
                )
            )
            
    header = "{:<3} {:<3} {:>5} {:>5} {:>5} {:>3} {:>5} {:>5}".format(
          "#", "Brc", "IO", "RE", "PS", "P/D", "DRR%", "MoM%"
    )
    branch_summary = (
        f"📍 AREA 3 - All 16 Branches\n"
        + separator + "\n"
        f"{min_date_str} - {max_date_str}\n\n"
        f"🕒 Last Updated - {format_timestamp(overall_max_ts)}\n\n"
        + header + "\n"
        + "\n".join(branch_lines)
    )
    
    # A3 Daily Summary
    try:
        if is_full_month and len(a3_daily_rows) > 0:
            d_first = a3_daily_rows[0]
            tgt_fm_a3daily = safe_format_integer(d_first.get('tgt_fm'))
            ps_total_a3daily = safe_format_integer(d_first.get('ps_total'))
            ps_per_io_a3daily = safe_format_decimal(d_first.get('ps_per_io'))
            ps_per_re_a3daily = safe_format_decimal(d_first.get('ps_per_re'))
            ach_a3daily = safe_format_percentage(d_first.get('ach'))
            run_rate_a3daily = safe_format_percentage(d_first.get('run_rate'))
            io_mom_a3daily = safe_format_percentage(d_first.get('io_mom'))
            re_mom_a3daily = safe_format_percentage(d_first.get('re_mom'))
            ps_mom_a3daily = safe_format_percentage(d_first.get('ps_mom'))
        elif a3_daily_rows:
            total_io = sum(row.get('io', 0) or 0 for row in a3_daily_rows)
            total_re = sum(row.get('re', 0) or 0 for row in a3_daily_rows)
            total_ps = sum(row.get('ps', 0) or 0 for row in a3_daily_rows)
            
            tgt_fm_value = a3_daily_rows[0].get('tgt_fm') or 0
            tgt_fm_a3daily = safe_format_integer(tgt_fm_value)
            
            ps_per_io_calc = (total_ps / total_io * 100) if total_io > 0 else 0
            ps_per_re_calc = (total_ps / total_re * 100) if total_re > 0 else 0
            ach_calc = (total_ps / tgt_fm_value * 100) if tgt_fm_value > 0 else 0
            
            ps_total_a3daily = safe_format_integer(total_ps)
            ps_per_io_a3daily = safe_format_decimal(ps_per_io_calc)
            ps_per_re_a3daily = safe_format_decimal(ps_per_re_calc)
            ach_a3daily = safe_format_percentage(ach_calc)
            
            run_rate_a3daily = safe_format_percentage(a3_daily_rows[-1].get('run_rate'))
            io_mom_a3daily = safe_format_percentage(a3_daily_rows[-1].get('io_mom'))
            re_mom_a3daily = safe_format_percentage(a3_daily_rows[-1].get('re_mom'))
            ps_mom_a3daily = safe_format_percentage(a3_daily_rows[-1].get('ps_mom'))
        else:
            tgt_fm_a3daily = ps_total_a3daily = ps_per_io_a3daily = ps_per_re_a3daily = "N/A"
            ach_a3daily = run_rate_a3daily = ps_mom_a3daily = "N/A"
    except (IndexError, TypeError, ZeroDivisionError):
        tgt_fm_a3daily = ps_total_a3daily = ps_per_io_a3daily = ps_per_re_a3daily = "N/A"
        ach_a3daily = run_rate_a3daily = ps_mom_a3daily = "N/A"
    
    daily_lines_a3daily = []
    for row in a3_daily_rows:
        try:
            date = row.get('short_date', "N/A")
            io_daily = safe_format_integer(row.get('io'))
            re_daily = safe_format_integer(row.get('re'))
            ps_daily = safe_format_integer(row.get('ps'))
            daily_line = f"{date:<10} {io_daily:>6} {re_daily:>6} {ps_daily:>6}"
            daily_lines_a3daily.append(daily_line)
        except (KeyError, TypeError, ValueError):
            daily_lines_a3daily.append("N/A        N/A   N/A   N/A")
    
    a3_daily_summary = (
        f"📍 AREA 3 - All 16 Branches\n"
        + separator + "\n"
        f"{min_date_str} - {max_date_str}\n\n"
        f"🕒 Last Updated - {format_timestamp(overall_max_ts)}\n\n"
        f"Tgt PS 7K: {tgt_fm_a3daily}\n"
        f"PS: {ps_total_a3daily}\n"
        f"IO→PS: {ps_per_io_a3daily}%\n"
        f"RE→PS: {ps_per_re_a3daily}%\n"
        f"Ach: {ach_a3daily}\n"
        f"DRR: {run_rate_a3daily}\n"
        f"IO MoM: {io_mom_a3daily}\n"
        f"RE MoM: {re_mom_a3daily}\n"
        f"PS MoM: {ps_mom_a3daily}\n\n"
        "Date          IO     RE     PS\n"
        + "\n".join(daily_lines_a3daily)
    )
    
    def build_region_block(region_name, rows, region_key):
        if not rows:
            return ""
        rows.sort(key=lambda x: parse_short_date(x.get('short_date') or "01/Jan"))

        min_d = rows[0].get('short_date', "N/A")
        max_d = rows[-1].get('short_date', "N/A")
        region_ts = region_ts_map.get(region_key)
        
        try:
            if is_full_month and len(rows) > 0:
                first_r = rows[0]
                tgt_fm = safe_format_integer(first_r.get('tgt_fm'))
                ps_total = safe_format_integer(first_r.get('ps_total'))
                ps_per_io = safe_format_decimal(first_r.get('ps_per_io'))
                ps_per_re = safe_format_decimal(first_r.get('ps_per_re'))
                ach = safe_format_percentage(first_r.get('ach'))
                run_rate = safe_format_percentage(first_r.get('run_rate'))
                io_mom = safe_format_percentage(first_r.get('io_mom'))
                re_mom = safe_format_percentage(first_r.get('re_mom'))
                ps_mom = safe_format_percentage(first_r.get('ps_mom'))
            elif rows:
                total_io = sum(row.get('io', 0) or 0 for row in rows)
                total_re = sum(row.get('re', 0) or 0 for row in rows)
                total_ps = sum(row.get('ps', 0) or 0 for row in rows)
                
                tgt_fm_value = rows[0].get('tgt_fm') or 0
                tgt_fm = safe_format_integer(tgt_fm_value)
                
                ps_per_io_calc = (total_ps / total_io * 100) if total_io > 0 else 0
                ps_per_re_calc = (total_ps / total_re * 100) if total_re > 0 else 0
                ach_calc = (total_ps / tgt_fm_value * 100) if tgt_fm_value > 0 else 0
                
                ps_total = safe_format_integer(total_ps)
                ps_per_io = safe_format_decimal(ps_per_io_calc)
                ps_per_re = safe_format_decimal(ps_per_re_calc)
                ach = safe_format_percentage(ach_calc)
                
                run_rate = safe_format_percentage(rows[-1].get('run_rate'))
                io_mom = safe_format_percentage(rows[-1].get('io_mom'))
                re_mom = safe_format_percentage(rows[-1].get('re_mom'))
                ps_mom = safe_format_percentage(rows[-1].get('ps_mom'))
            else:
                tgt_fm = ps_total = ps_per_io = ps_per_re = "N/A"
                ach = run_rate = ps_mom = "N/A"
        except (IndexError, TypeError, ZeroDivisionError):
            tgt_fm = ps_total = ps_per_io = ps_per_re = "N/A"
            ach = run_rate = ps_mom = "N/A"
        
        daily_lines = []
        for row in rows:
            try:
                date = row.get('short_date', "N/A")
                io_daily = safe_format_integer(row.get('io'))
                re_daily = safe_format_integer(row.get('re'))
                ps_daily = safe_format_integer(row.get('ps'))
                daily_line = f"{date:<10} {io_daily:>6} {re_daily:>6} {ps_daily:>6}"
                daily_lines.append(daily_line)
            except (KeyError, TypeError, ValueError):
                daily_lines.append("N/A        N/A   N/A   N/A")
        
        return (
            f"📍 Region {region_name}\n"
            + separator + "\n"
            f"{min_d} - {max_d}\n\n"
            f"🕒 Last Updated - {format_timestamp(region_ts)}\n\n"
            f"Tgt PS 7K: {tgt_fm}\n"
            f"PS: {ps_total}\n"
            f"IO→PS: {ps_per_io}%\n"
            f"RE→PS: {ps_per_re}%\n"
            f"Ach: {ach}\n"
            f"DRR: {run_rate}\n"
            f"IO MoM: {io_mom}\n"
            f"RE MoM: {re_mom}\n"
            f"PS MoM: {ps_mom}\n\n"
            "Date           IO     RE     PS\n"
            + "\n".join(daily_lines)
        )
    
    # Build region summaries
    jatengdiy_summary = build_region_block("JATENG-DIY", jatengdiy_rows, "JATENG-DIY")
    jatim_summary = build_region_block("JATIM", jatim_rows, "JATIM")
    balinusra_summary = build_region_block("BALI NUSRA", balinusra_rows, "BALI NUSRA")
    
    # Return each block as a separate message
    return [
        f"```\n{branch_summary}```",
        f"```\n{a3_daily_summary}```",
        f"```\n{jatengdiy_summary}```",
        f"```\n{jatim_summary}```",
        f"```\n{balinusra_summary}```"
    ]



async def format_nas_summary_message(start_date, end_date):
    """NAS summary - uses month data regardless of specific day selection."""
    selected_period = start_date.strftime("%Y%m")
    logging.debug(f"[NAS] Using monthly data for period: {selected_period}")
    
    # Fetch data
    region_nas_summary_rows = await fetch_bot_region_nas_summary(selected_period)
    
    # NAS is monthly summary data - no day filtering
    region_nas_summary_rows = filter_rows_by_date_range(region_nas_summary_rows, start_date, end_date, filter_type="monthly")
    
    if not region_nas_summary_rows:
        return ["❌ Data tidak tersedia, Silahkan atur ulang tanggal laporan anda dengan /daterange"]
    
    # Format dates for display (show selected range for user reference)
    selected_start = start_date.strftime("%d %B %Y")
    selected_end = end_date.strftime("%d %B %Y")
    
    try:
        # For monthly data, show the month instead of specific date range
        month_year = start_date.strftime("%B %Y")
        min_date_str = f"📅 {month_year} (Monthly Data)"
        max_date_str = f"Selected: {selected_start} - {selected_end}"
    except (IndexError, TypeError):
        min_date_str = max_date_str = "N/A"

    # Region NAS Summary
    region_nas_lines = []
    for row in region_nas_summary_rows:
        try:
            rk = row.get('rank')
            if rk is None:
                rank_formatted = "N/A"
            else:
                medal = "🥇" if rk == 1 else "🥈" if rk == 2 else "🥉" if rk == 3 else ""
                space_padding = '' if 1 <= rk <= 3 else '  ' if 4 <= rk <= 9 else ' '
                rank_formatted = f"{rk}{medal}{space_padding}"
            
            ar = row.get('ar', "N/A")
            reg = row.get('reg', "N/A")
            
            io_sum = row.get('io')
            io_sum = safe_format_integer(io_sum).replace(",", "")

            re_sum = row.get('re')
            re_sum = safe_format_integer(re_sum).replace(",", "")

            ps_sum = row.get('ps')
            ps_sum = safe_format_integer(ps_sum).replace(",", "")

            ps_day = row.get('ps_day')
            ps_day = safe_format_integer(ps_day)

            run_rate = safe_format_decimal(row.get('run_rate'))
            ps_mom = safe_format_decimal(row.get('ps_mom'))

            region_nas_lines.append(
                "{:<1} {:<2} {:<3} {:>5} {:>5} {:>5} {:>3} {:>4} {:>5}".format(
                    rank_formatted, ar, reg, io_sum, re_sum, ps_sum, ps_day, run_rate, ps_mom
                )
            )

        except (KeyError, TypeError, ValueError):
            # In case of unexpected errors, append a line with all fields as "N/A"
            region_nas_lines.append(
                "{:<1} {:<2} {:<3} {:>5} {:>5} {:>5} {:>3} {:>4} {:>5}".format(
                    "N/A", "N/A", "N/A", "N/A", "N/A", "N/A", "N/A", "N/A", "N/A"
                )
            )

    header = "{:<3} {:<2} {:<3} {:>5} {:>5} {:>5} {:>3} {:>4} {:>5}".format(
            "#", "Ar", "Reg", "IO", "RE", "PS", "P/D", "RR%", "MoM%"
    )

    regional_nas_summary = (
        f"Nasional - 13 Region Performance\n"
        "__________\n"
        f"{min_date_str}\n\n"
        + header + "\n"
        + "\n".join(region_nas_lines)
    )

    return [
        f"```\n{regional_nas_summary}```"
    ]


async def format_branch_wok_performance_message(start_date, end_date, selected_branch):
    """WOK performance - filters by specific day range."""
    selected_period = start_date.strftime("%Y%m")
    final_messages = []

    logging.debug(f"[WOK] Using daily filtering for period: {selected_period}")
    
    # Fetch data
    branch_rows = await fetch_bot_a3_period_branches(selected_period, selected_branch)
    wok_rows = await fetch_bot_a3_period_woks(selected_period, selected_branch)
    
    # WOK daily data - filter by specific date range
    branch_rows = filter_rows_by_date_range(branch_rows, start_date, end_date, filter_type="daily")
    wok_rows = filter_rows_by_date_range(wok_rows, start_date, end_date, filter_type="daily")
    
    if not branch_rows:
        return ["❌ Data tidak tersedia, Silahkan atur ulang tanggal laporan anda dengan /daterange"]

    # --- Branch Summary ---
    branch_rows.sort(key=lambda r: r.get("full_date") or "")
    min_date_str = (branch_rows[0].get("short_date") or "N/A")
    max_date_str = (branch_rows[-1].get("short_date") or "N/A")

    first = branch_rows[0]
    branch_name = (first.get("branch") or "N/A").capitalize()
    branch_abbr_map = {
        'YOGYAKARTA': 'YOG', 'SEMARANG': 'SMG', 'SURAKARTA': 'SUR', 'PURWOKERTO': 'PWT',
        'MAGELANG': 'MGL', 'PEKALONGAN': 'PKL', 'SURABAYA': 'SBY', 'SIDOARJO': 'SDA',
        'MALANG': 'MLG', 'JEMBER': 'JBR', 'MADIUN': 'MDN', 'LAMONGAN': 'LMG',
        'DENPASAR': 'DPS', 'MATARAM': 'MTR', 'KUPANG': 'KUP', 'FLORES': 'FLR'
    }
    branch_raw = first.get("branch") or ""
    branch_abbr = branch_abbr_map.get(branch_raw.upper(), branch_raw[:3].upper())

    tgt_fm   = safe_format_integer(first.get("tgt_sales"))
    ps_total = safe_format_integer(first.get("ps_total"))
    ps_per_io = safe_format_percentage(first.get("ps_per_io"))
    ps_per_re = safe_format_percentage(first.get("ps_per_re"))
    ach      = safe_format_percentage(first.get("ach"))
    run_rate = safe_format_percentage(first.get("run_rate"))
    io_mom   = safe_format_percentage(first.get("io_mom"))
    re_mom   = safe_format_percentage(first.get("re_mom"))
    ps_mom   = safe_format_percentage(first.get("ps_mom"))

    # Only one branch is shown, so assume rank 1.
    run_rate_with_medal = f"{run_rate}🥇"

    daily_lines_branch = []
    for r in branch_rows:
        daily_lines_branch.append("{:<10} {:>4} {:>5} {:>5}".format(
            r.get("short_date") or "N/A",
            r.get("io") or 0,
            r.get("re") or 0,
            r.get("ps") or 0
        ))
    daily_summary_branch = "\n".join(daily_lines_branch)

    branch_summary = (
        f"{branch_name} ({branch_abbr})\n"
        "________\n"
        f"{min_date_str} - {max_date_str}\n"
        f"Tgt PS 7K: {tgt_fm}\n"
        f"PS: {ps_total}\n"
        f"IO→PS: {ps_per_io}\n"
        f"RE→PS: {ps_per_re}\n"
        f"Ach: {ach}\n"
        f"DRR: {run_rate}\n"
        f"IO MoM: {io_mom}\n"
        f"RE MoM: {re_mom}\n"
        f"PS MoM: {ps_mom}\n\n"
        "Date        IO    RE    PS\n"
        f"{daily_summary_branch}"
    )
    final_messages.append(f"```\n{branch_summary}\n```")

    # --- WOK Summaries ---
    if wok_rows:
        wok_groups = defaultdict(list)
        for r in wok_rows:
            wok_key = r.get("wok") or "UNKNOWN"
            wok_groups[wok_key].append(r)

        wok_ranks = {}
        wok_list = []
        for wok, rows in wok_groups.items():
            try:
                run_rate_val = float(rows[0].get("run_rate") or 0)
            except Exception:
                run_rate_val = 0
            wok_list.append((wok, run_rate_val))
        wok_list.sort(key=lambda x: x[1], reverse=True)
        for idx, (wok, _) in enumerate(wok_list, start=1):
            wok_ranks[wok] = idx

        for wok, rows in wok_groups.items():
            rows.sort(key=lambda r: r.get("full_date") or "")
            min_date_wok = rows[0].get("short_date") or "N/A"
            max_date_wok = rows[-1].get("short_date") or "N/A"
            first_wok = rows[0]

            tgt_fm_wok   = safe_format_integer(first_wok.get("tgt_sales"))
            ps_total_wok = safe_format_integer(first_wok.get("ps_total"))
            ps_per_io_wok = safe_format_percentage(first_wok.get("ps_per_io"))
            ps_per_re_wok = safe_format_percentage(first_wok.get("ps_per_re"))
            ach_wok      = safe_format_percentage(first_wok.get("ach"))
            run_rate_wok = safe_format_percentage(first_wok.get("run_rate"))
            io_mom_wok   = safe_format_percentage(first_wok.get("io_mom"))
            re_mom_wok   = safe_format_percentage(first_wok.get("re_mom"))
            ps_mom_wok   = safe_format_percentage(first_wok.get("ps_mom"))

            rank = wok_ranks.get(wok, 0)
            medal = ""
            if rank == 1:
                medal = "🥇"
            elif rank == 2:
                medal = "🥈"
            elif rank == 3:
                medal = "🥉"
            run_rate_wok_with_medal = f"{run_rate_wok}{medal}"

            daily_lines_wok = []
            for r in rows:
                daily_lines_wok.append("{:<10} {:>4} {:>5} {:>5}".format(
                    r.get("short_date") or "N/A",
                    r.get("io") or 0,
                    r.get("re") or 0,
                    r.get("ps") or 0
                ))
            daily_summary_wok = "\n".join(daily_lines_wok)

            wok_summary = (
                f"WOK - {wok.title()}\n"
                "________\n"
                f"Tgt PS 7K: {tgt_fm_wok}\n"
                f"PS: {ps_total_wok}\n"
                f"IO→PS: {ps_per_io_wok}\n"
                f"RE→PS: {ps_per_re_wok}\n"
                f"Ach: {ach_wok}\n"
                f"DRR: {run_rate_wok_with_medal}\n"
                f"IO MoM: {io_mom_wok}\n"
                f"RE MoM: {re_mom_wok}\n"
                f"PS MoM: {ps_mom_wok}\n\n"
                "Date        IO    RE    PS\n"
                f"{daily_summary_wok}"
            )
            final_messages.append(f"```\n{wok_summary}\n```")

    return final_messages



async def format_wok_summary_message(start_date, end_date, selected_region):
    selected_period = start_date.strftime("%Y%m")

    # Fetch data
    wok_summary_rows = await fetch_bot_wok_summary(selected_period, selected_region)
    
    # Fix: Add filter_type parameter
    wok_summary_rows = filter_rows_by_date_range(wok_summary_rows, start_date, end_date, filter_type="monthly")

    if not wok_summary_rows:
        return ["❌ Data tidak tersedia, Silahkan atur ulang tanggal laporan anda dengan /daterange"]

    # Parse the selected_period (assumed to be in YYYYMM format)
    try:
        year = int(selected_period[:4])
        month = int(selected_period[4:])
    except Exception:
        now = datetime.now()
        year, month = now.year, now.month

    # Compute the first day of the period
    first_day = datetime(year, month, 1)
    now = datetime.now()
    if now.year == year and now.month == month:
        current_day = now.day
    else:
        current_day = calendar.monthrange(year, month)[1]
    
    min_date_str = first_day.strftime("%d/%b/%y")  # e.g., "01/Feb/25"
    max_date = datetime(year, month, current_day)
    max_date_str = max_date.strftime("%d/%b/%y")    # e.g., "26/Feb/25"
    
    # Build header for the table (inside the code block)
    header_line1 = "#  WOK"
    header_line2 = "IO   RE   PS   PS/D   DRR%   MoM%"
    underline = "_" * max(len(header_line1), len(header_line2))
    
    # Build row lines in two parts per row
    row_lines = []
    for row in wok_summary_rows:
        try:
            rk = row.get('rank')
            if rk is None:
                rank_formatted = "N/A"
            else:
                medal = "🥇" if rk == 1 else "🥈" if rk == 2 else "🥉" if rk == 3 else ""
                rank_formatted = f"{rk}.{medal}"
            
            wok_val = row.get('wok') or "N/A"
            io_sum = safe_format_integer(row.get('io'))
            re_sum = safe_format_integer(row.get('re'))
            ps_sum = safe_format_integer(row.get('ps'))
            ps_day = safe_format_integer(row.get('ps_day'))
            run_rate = safe_format_decimal(row.get('run_rate'), decimals=1)
            ps_mom = safe_format_decimal(row.get('ps_mom'), decimals=1)
            
            # First line: ranking and WOK name
            line1 = "{:<2} {}".format(rank_formatted, wok_val)
            # Second line: performance numbers
            line2 = "{:>7} {:>6} {:>6} {:>4} {:>6} {:>6}".format(
                io_sum, re_sum, ps_sum, ps_day, run_rate, ps_mom
            )
            row_lines.append(line1)
            row_lines.append(line2)
            row_lines.append("")  # Blank line between rows
        except (KeyError, TypeError, ValueError):
            row_lines.append("N/A")
    
    # Build the table inside a MarkdownV2 code block (triple backticks)
    # Remove escaping since we'll escape later in the main function
    table = header_line1 + "\n" + header_line2 + "\n" + underline + "\n\n" + "\n".join(row_lines) 
    
    # Build the final message without escaping here
    region_header = f"Region - {selected_region.upper()}"
    date_range = f"{min_date_str} - {max_date_str}"
    underline_outside = "_____"
    message_text = "```\n" + region_header + "\n" + underline_outside + "\n" + date_range + "\n\n" + table + "\n```"
    
    return [message_text]



async def format_agency_summary_message(start_date, end_date, user_employer=None, user_sf_code=None, user_agency_name=None, user_region_level=None, chosen_region=None, chosen_woks=None):
    """Agency summary - uses month data regardless of specific day selection."""
    selected_period = start_date.strftime("%Y%m")
    logging.debug(f"[AGENCY] Using monthly data for period: {selected_period}")
    
    agency_summary_rows = await fetch_bot_agency_summary(selected_period)
    
    # Agency is monthly summary data - no day filtering
    agency_summary_rows = filter_rows_by_date_range(agency_summary_rows, start_date, end_date, filter_type="monthly")
    
    logger.debug(f"[Format] Fetched {len(agency_summary_rows)} rows for period {selected_period} (monthly data)")
    
    if not agency_summary_rows:
        return ["❌ Data tidak tersedia, Silahkan atur ulang tanggal laporan anda dengan /daterange"]

    # --- Filtering (case-insensitive) ---
    if user_sf_code and user_sf_code.strip():
        # Enhanced debugging for SF code filtering
        user_sf_code_clean = user_sf_code.strip().lower()
        logger.debug(f"[Format] Filtering by sf_code: '{user_sf_code}' -> cleaned: '{user_sf_code_clean}'")
        
        filtered_rows = []
        matching_sf_codes = []
        
        for row in agency_summary_rows:
            row_sf_code = row.get('sf_code', '').strip().lower()
            if row_sf_code == user_sf_code_clean:
                filtered_rows.append(row)
                matching_sf_codes.append(row.get('sf_code', ''))
        
        logger.debug(f"[Format] SF filter: {len(filtered_rows)} rows match sf_code '{user_sf_code}'")
        if matching_sf_codes:
            logger.debug(f"[Format] Matching sf_codes found: {matching_sf_codes[:5]}")  # Show first 5
        else:
            # Find similar sf_codes for debugging
            similar_sf_codes = [
                row.get('sf_code', '') for row in agency_summary_rows 
                if user_sf_code_clean in row.get('sf_code', '').strip().lower()
            ][:5]
            logger.debug(f"[Format] No exact matches. Similar sf_codes: {similar_sf_codes}")
            
            # Check for case sensitivity issues
            exact_case_matches = [
                row.get('sf_code', '') for row in agency_summary_rows 
                if row.get('sf_code', '').strip() == user_sf_code.strip()
            ]
            if exact_case_matches:
                logger.debug(f"[Format] Case-sensitive matches found: {exact_case_matches}")
            
    elif user_employer == 'admin' and user_agency_name and user_agency_name.strip():
        # Enhanced debugging for agency name filtering
        user_agency_clean = user_agency_name.strip().lower()
        logger.debug(f"[Format] Filtering by agency_name: '{user_agency_name}' -> cleaned: '{user_agency_clean}'")
        
        # Show unique agency names for debugging
        unique_agencies = list(set(row.get('sf_company_name', '') for row in agency_summary_rows))[:10]
        logger.debug(f"[Format] Sample agencies in data: {unique_agencies}")
        
        filtered_rows = []
        matching_agencies = []
        
        for row in agency_summary_rows:
            row_agency = row.get('sf_company_name', '').strip().lower()
            if row_agency == user_agency_clean:
                filtered_rows.append(row)
                matching_agencies.append(row.get('sf_company_name', ''))
        
        logger.debug(f"[Format] Admin by agency_name: {len(filtered_rows)} rows match agency_name '{user_agency_name}'")
        if matching_agencies:
            logger.debug(f"[Format] Matching agencies found: {list(set(matching_agencies))}")
        else:
            # Find similar agency names
            similar_agencies = [
                row.get('sf_company_name', '') for row in agency_summary_rows 
                if user_agency_clean in row.get('sf_company_name', '').strip().lower()
            ][:5]
            logger.debug(f"[Format] No exact matches. Similar agencies: {similar_agencies}")
            
    elif user_employer == 'admin' and user_region_level and user_region_level.strip():
        # Enhanced debugging for region filtering
        user_region_clean = user_region_level.strip().lower()
        logger.debug(f"[Format] Filtering by region: '{user_region_level}' -> cleaned: '{user_region_clean}'")
        
        # Show unique regions for debugging
        unique_regions = list(set(row.get('region', '') for row in agency_summary_rows))
        logger.debug(f"[Format] Available regions in data: {unique_regions}")
        
        filtered_rows = [
            row for row in agency_summary_rows
            if row.get('region', '').strip().lower() == user_region_clean
        ]
        logger.debug(f"[Format] Admin by region_level: {len(filtered_rows)} rows match region_level '{user_region_level}'")
        
    elif user_employer in ('tsel', 'ta', 'tif'):
        if chosen_region is None:
            region_list = get_region_names()  # e.g. ["JATIM", "JATENG-DIY", "BALI NUSRA"]
            logger.debug(f"[Format] No chosen_region; region_list: {region_list}")
            if not region_list:
                return ["Gagal memuat daftar region."]
            
            # Fixed keyboard creation for aiogram 3.x
            # Using InlineKeyboardBuilder (recommended approach)
            builder = InlineKeyboardBuilder()
            for region in region_list:
                builder.button(
                    text=region,
                    callback_data=f"agency_region:{region}"
                )
            builder.adjust(1)  # 1 button per row
            keyboard = builder.as_markup()
            
            return [("Silakan pilih salah satu region:", keyboard)]
        elif chosen_woks is None:
            # Show WOK multi-selection for the chosen region - THIS TRIGGERS FSM STATE
            chosen_region_clean = chosen_region.strip().lower()
            logger.debug(f"[Format] Chosen region: '{chosen_region}', now showing WOK multi-selection")
            
            # Get unique WOKs for the chosen region
            region_filtered_rows = [
                row for row in agency_summary_rows
                if row.get('region', '').strip().lower() == chosen_region_clean
            ]
            
            if not region_filtered_rows:
                return [f"❌ Tidak ada data ditemukan untuk region: {chosen_region}"]
            
            # Extract unique WOKs from the filtered data
            wok_list = sorted(list(set(row.get('wok', '') for row in region_filtered_rows if row.get('wok', ''))))
            logger.debug(f"[Format] Available WOKs for region '{chosen_region}': {wok_list}")
            
            if not wok_list:
                return [f"❌ Tidak ada WOK ditemukan untuk region: {chosen_region}"]
            
            # Return special indicator to trigger FSM state in the calling function
            return [("TRIGGER_MULTI_WOK_SELECTION", chosen_region, wok_list)]
        else:
            # Filter by region and multiple WOKs
            chosen_region_clean = chosen_region.strip().lower()
            chosen_woks_clean = [wok.strip().lower() for wok in chosen_woks]
            logger.debug(f"[Format] Filtering by chosen_region: '{chosen_region}' and chosen_woks: {chosen_woks}")
            
            filtered_rows = [
                row for row in agency_summary_rows
                if (row.get('region', '').strip().lower() == chosen_region_clean and 
                    row.get('wok', '').strip().lower() in chosen_woks_clean)
            ]
            logger.debug(f"[Format] Chosen region '{chosen_region}' and WOKs {chosen_woks}: {len(filtered_rows)} rows")
    else:
        # More specific error messages based on user profile
        logger.debug(f"[Format] No valid filtering condition met. employer='{user_employer}', sf_code='{user_sf_code}', agency_name='{user_agency_name}'")
        
        if user_employer == 'sf':
            if not user_sf_code or not user_sf_code.strip():
                return ["❌ SF Code tidak ditemukan di profil Anda.\n\n"
                       "Untuk mengakses data agency summary, SF Code harus terdaftar di sistem.\n"
                       "Silakan hubungi admin untuk mendaftarkan SF Code Anda."]
            else:
                return ["❌ SF Code tidak valid atau tidak ditemukan dalam data.\n\n"
                       f"SF Code: {user_sf_code}\n"
                       "Silakan periksa kembali atau hubungi admin."]
        elif user_employer == 'admin':
            if not user_agency_name or not user_agency_name.strip():
                return ["❌ Agency Name tidak ditemukan di profil admin Anda.\n\n"
                       "Untuk mengakses data agency summary, Agency Name harus terdaftar di sistem.\n"
                       "Silakan hubungi super admin untuk memperbarui profil Anda."]
            else:
                return ["❌ Agency Name tidak valid atau tidak ditemukan dalam data.\n\n"
                       f"Agency Name: {user_agency_name}\n"
                       "Silakan periksa kembali atau hubungi super admin."]
        else:
            return ["❌ Akses tidak diizinkan.\n\n"
                   f"Employer: {user_employer or 'Unknown'}\n"
                   "Silakan hubungi admin untuk mendapatkan akses yang sesuai."]

    if not filtered_rows:
        logger.error("[Format] No rows after filtering")
        # More specific no data message
        if user_sf_code and user_sf_code.strip():
            return [f"❌ Tidak ada data ditemukan untuk SF Code: {user_sf_code}\n\n"
                   f"Periode: {selected_period}\n"
                   "Pastikan SF Code benar dan aktif pada periode tersebut."]
        elif user_employer == 'admin' and user_agency_name and user_agency_name.strip():
            return [f"❌ Tidak ada data ditemukan untuk Agency: {user_agency_name}\n\n"
                   f"Periode: {selected_period}\n"
                   "Pastikan nama agency benar dan memiliki data pada periode tersebut."]
        elif chosen_region and chosen_woks:
            return [f"❌ Tidak ada data ditemukan untuk Region: {chosen_region}, WOKs: {', '.join(chosen_woks)}\n\n"
                   f"Periode: {selected_period}"]
        else:
            return ["❌ Tidak ada data ditemukan sesuai dengan filter yang diterapkan."]

    # Debug: Show what we're about to process
    logger.debug(f"[Format] Processing {len(filtered_rows)} filtered rows")
    if filtered_rows:
        first_filtered = filtered_rows[0]
        logger.debug(f"[Format] First filtered row - sf_code: '{first_filtered.get('sf_code', '')}', company: '{first_filtered.get('sf_company_name', '')}', wok: '{first_filtered.get('wok', '')}'")

    messages = []

    # Group by company then by wok.
    filtered_rows.sort(key=lambda x: (x.get('sf_company_name', '').strip().lower(), 
                                        x.get('wok', '').strip().lower()))
    for company, company_iter in groupby(filtered_rows, key=lambda x: x.get('sf_company_name', '').strip()):
        company_list = list(company_iter)
        company_list.sort(key=lambda x: x.get('wok', '').strip().lower())
        for wok, wok_iter in groupby(company_list, key=lambda x: x.get('wok', '').strip()):
            group_rows = list(wok_iter)
            if not group_rows:
                continue
            # Extract extra info from the first row
            first_row = group_rows[0]
            extra_info = {
                'target_wok_agency': first_row.get('target_wok_agency', 'N/A'),
                'ps_cummulative': first_row.get('ps_cummulative', 'N/A'),
                'run_rate': first_row.get('run_rate', 'N/A')
            }
            header_lines = []
            period_date = datetime.strptime(selected_period, "%Y%m")
            formatted_date = period_date.strftime("%Y/%b")  # e.g. "2025/Mar"
            # General header printed only once per company/wok group:
            header_lines.append("📅 " + formatted_date)
            header_lines.append("🏣 " + (company or "N/A"))
            header_lines.append("📍 " + (wok or "N/A"))
            header_lines.append("")
            header_lines.append(" • Tgt WOK : " + str(extra_info.get('target_wok_agency', 'N/A')))
            header_lines.append(" • PS WOK  : " + str(extra_info.get('ps_cummulative', 'N/A')))
            header_lines.append(" • DRR     : " + safe_format_percentage(extra_info.get('run_rate', 0)))
            header_lines.append("")

            # --- New subheader: group by spv_name ---
            spv_groups = defaultdict(list)
            for r in group_rows:
                spv = r.get('spv_name', 'N/A')
                spv_groups[spv].append(r)
            
            data_lines = []
            # Updated row_format to include two new columns for ps_to_re and ps_mom
            row_format = "{:<10} {:<18} {:<3} {:<3} {:<3} {:<6} {:>6}"
            # Updated header to include the new column names
            col_header = row_format.format("SF Code", "SF Name", "IO", "RE", "PS", "PS/RE", "PSMoM")
            data_lines.append(col_header)
            separator = "━" * 15
            data_lines.append(separator)
            # For each spv group, add a subheader and its rows
            for spv in sorted(spv_groups.keys()):
                data_lines.append(f"👨🏼‍💻 Supervisor: -")
                data_lines.append(col_header)
                data_lines.append(separator)
                # Sort rows for this spv group by ps descending.
                sorted_group = sorted(spv_groups[spv], key=lambda r: int(r.get('ps', '0')), reverse=True)
                for r in sorted_group:
                    sf_code = r.get('sf_code', 'N/A')
                    sf_name = abbreviate_name(r.get('sf_name', 'N/A'))
                    io_val  = safe_format_integer(r.get('io'))
                    re_val  = safe_format_integer(r.get('re'))
                    ps_val  = safe_format_integer(r.get('ps'))
                    ps_to_re_val = safe_format_percentage((r.get('ps_to_re') or 0))
                    ps_mom_val = safe_format_percentage(r.get('ps_mom', 0))
                    data_lines.append(row_format.format(sf_code, sf_name, io_val, re_val, ps_val, ps_to_re_val, ps_mom_val))
                data_lines.append("")
            
            all_lines = header_lines + data_lines + ["", ""]  # Two blank lines at the end
            message_text = "\n".join(all_lines)
            messages.append(f"```\n{message_text}\n```")
    
    logger.debug(f"[Format] Final messages count: {len(messages)}")
    return messages


async def format_odp_history(rows):
    if not rows:
        return "Data tidak ditemukan."

    # Ensure rows is a list
    if isinstance(rows, dict):
        rows = [rows]

    # Validate that each item is a dictionary
    if not all(isinstance(row, dict) for row in rows):
        return "Data tidak valid."

    # Define a helper function to parse the event date
    def parse_event_date(row):
        event_date = row.get('event_date')
        if isinstance(event_date, datetime):
            return event_date
        elif isinstance(event_date, date):
            return datetime.combine(event_date, datetime.min.time())
        elif isinstance(event_date, str):
            try:
                return datetime.fromisoformat(event_date.replace('Z', '+00:00'))
            except ValueError:
                try:
                    return datetime.strptime(event_date, '%Y-%m-%d %H:%M:%S')
                except ValueError:
                    try:
                        return datetime.strptime(event_date, '%Y-%m-%d')
                    except ValueError:
                        return datetime.min # Fallback
        else:
            return datetime.min

    # Define columns for the history table
    columns = [
        ("Date", 7, "<"),
        ("Occ%", 4, "^"), # Adjusted width for 100%
        ("", 0, "<"),
        ("Sisa_Port", 7, "^"),
        ("STO", 3, "<"),
        ("Brch", 4, "<"), # Adjusted width
        ("Kota", 12, "<"), # Adjusted width
    ]

    # Group rows by 'odp_name'
    odp_groups = defaultdict(list)
    for row in rows:
        odp_name = row.get('odp_name', 'Unknown ODP')
        odp_groups[odp_name].append(row)

    messages = []
    separator = "━" * 15

    for odp_name, odp_rows in odp_groups.items():
        # Sort rows by event_date (most recent first)
        sorted_rows = sorted(odp_rows, key=parse_event_date, reverse=True)
        most_recent_row = sorted_rows[0]

        is_newodp = most_recent_row.get('is_newodp')
        golive_date = most_recent_row.get('golive_date', 'N/A')

        # Format golive date
        golive_formatted = 'N/A'
        if golive_date and golive_date != 'N/A':
            try:
                if isinstance(golive_date, (datetime, date)):
                    golive_formatted = golive_date.strftime('%Y-%m-%d')
                elif isinstance(golive_date, str):
                    parsed_date = datetime.strptime(golive_date.split(' ')[0], '%Y-%m-%d')
                    golive_formatted = parsed_date.strftime('%Y-%m-%d')
            except (ValueError, TypeError):
                golive_formatted = str(golive_date).split(' ')[0]

        # Create ODP header
        if is_newodp == 1 or str(is_newodp).lower() == 'true':
            status_text = "✅ New ODP"
        else:
            status_text = "\\-"

        # Build the main information header
        golive_formatted_escaped = escape_markdown_v2(golive_formatted) if golive_formatted != 'N/A' else 'N/A'
        odp_header_text = (
            f"*ODP Name*     :  `{str(odp_name)}`\n"
            f"*Status*              :  {status_text}\n"
            f"*Golive Date*   :  {golive_formatted_escaped}\n"
            f"{separator}"
        )

        # Create the history table (limited to the last 5 records)
        table_rows_to_display = sorted_rows[:5]
        header_fmt_str = " ".join([f"{{:{align}{width}}}" for _, width, align in columns])
        row_fmt_str = " ".join([f"{{:{align}{width}}}" for _, width, align in columns])
        table_header_str = header_fmt_str.format(*[col[0] for col in columns])

        table_body_lines = []
        for row in table_rows_to_display:
            occ_val = 0
            # Try to get occupancy from multiple possible keys
            if 'used' in row and 'total_port' in row and row['total_port']:
                occ_val = (int(row['used']) / int(row['total_port'])) * 100
            elif 'occ_1' in row:
                occ_val = float(row['occ_1']) * 100

            # Add special handling for 0%
            if occ_val == 0:
                occ_status = 'BLACK'
            elif occ_val >= 80:
                occ_status = 'RED'
            elif 60 <= occ_val < 80:
                occ_status = 'YELLOW'
            else:
                occ_status = 'GREEN'

            row_values = [
                parse_event_date(row).strftime('%d/%b'),
                f"{int(occ_val)}%",
                odp_color_status.get(row.get('status', occ_status).upper(), '❓'),
                f"{int(row.get('avai_port', row.get('avai', 0)))}/{int(row.get('total_port', 0))}",
                row.get('sto', 'N/A'),
                BRANCH_ABBR.get(str(row.get('branch')).upper(), str(row.get('branch'))),
                row.get('kab_tsel', 'N/A')
            ]
            table_body_lines.append(row_fmt_str.format(*row_values))

        table_body_str = "\n".join(table_body_lines)

        table_content = (
            f"```\n"
            f"{table_header_str}\n"
            f"{table_body_str}\n"
            f"```"
        )

        ct0_info_block = ""
        try:
            potential_port = int(most_recent_row.get('old_ct0_potential_port', 0))
            if potential_port > 0:
                # Format Average LoS (the dot in 'Avg.' needs escaping)
                avg_los_val = float(most_recent_row.get('avg_ct0_los', 0.0))
                avg_los_formatted = f"{avg_los_val:.1f}".replace('.', ',')
                avg_los_line = f"⏳ Rata\\-rata Umur CT0 : *{avg_los_formatted} Bln*"

                # Format Suspect Header (parentheses need escaping)
                suspect_header_line = f"⚠️ Suspect CT0 di ODP ini \\(*{potential_port} SSL*\\) :"

                # Format BB ID list with bullet points
                bb_ids_str = most_recent_row.get('ct0_bb_id')
                bb_ids_list_str = ""
                if bb_ids_str and str(bb_ids_str).upper() != 'NULL':
                    # Prepend each ID with a MarkdownV2-escaped bullet point
                    bb_ids_list = [f"• `{bb_id.strip()}`" for bb_id in bb_ids_str.split(';')]
                    bb_ids_list_str = "\n".join(bb_ids_list)

                # Assemble the block (separator is already safe, no escaping needed)
                ct0_info_block = (
                    f"\n{separator}\n"
                    f"{avg_los_line}\n"
                    f"{suspect_header_line}\n"
                    f"{bb_ids_list_str}"
                )
        except (ValueError, TypeError) as e:
            # In case of data conversion error, log it properly
            logger.error(f"Could not process CT0 data for {odp_name}. Error: {e}", exc_info=True)
            ct0_info_block = ""


        # Handle the latitude and longitude for the location link
        latitude = most_recent_row.get('latitude')
        longitude = most_recent_row.get('longitude')

        location_link_text = ""
        if latitude and longitude:
            try:
                lat_f = float(latitude)
                lon_f = float(longitude)
                if -90 <= lat_f <= 90 and -180 <= lon_f <= 180:
                    gmaps_url = f"https://www.google.com/maps?q={lat_f},{lon_f}"
                    # No need to escape a valid URL for markdown
                    location_link_text = f"\n\n📍 [Cek Lokasi ODP]({gmaps_url})"
                else:
                    location_link_text = "\n\nKoordinat tidak valid\\."
            except (ValueError, TypeError):
                location_link_text = "\n\nKoordinat tidak valid \\(format salah\\)\\."
        else:
            location_link_text = "\n\nKoordinat belum tersedia\\."

        # Combine all parts for the final message for this ODP
        result_message = (
            f"{odp_header_text}"
            f"{table_content}"
            f"{ct0_info_block}"  # The new block is inserted here
            f"{location_link_text}"
        )
        messages.append(result_message)

    final_message = '\n\n\n'.join(messages)
    return final_message


async def format_odp_golive(data):
    odp_points = []
    for row in data:
        odp_point = {
            'odp_name': str(row['odp_name']) if row['odp_name'] is not None else '',
            'port_avail': int(row['port_avail']) if row['port_avail'] is not None else 0,
            'port_used': int(row['port_used']) if row['port_used'] is not None else 0,
            'port_total': int(row['port_total']) if row['port_total'] is not None else 0,
            'occ_1': str(row['occ_1']) if row['occ_1'] is not None else '',
            'occ_2': str(row['occ_2']) if row['occ_2'] is not None else '',
            'sto': str(row['sto']) if row['sto'] is not None else '',
            'tsel_region': str(row['tsel_region']) if row['tsel_region'] is not None else '',
            'tsel_branch': str(row['tsel_branch']) if row['tsel_branch'] is not None else '',
            'kab_tsel': str(row['kab_tsel']) if row['kab_tsel'] is not None else '',
            'tomps_progress_pct': float(row['tomps_progress_pct']) if row['tomps_progress_pct'] is not None else 0.0,
            'project_status': str(row['project_status']) if row['project_status'] is not None else '',
            'program_type': str(row['program_type']) if row['program_type'] is not None else '',
            'program_batch': str(row['program_batch']) if row['program_batch'] is not None else '',
            'latitude': float(row['latitude']) if row['latitude'] else None,
            'longitude': float(row['longitude']) if row['longitude'] else None,
            'min_event_date': row['min_event_date'].strftime('%Y-%m-%d') if row.get('min_event_date') else None
        }
        # Only include points with valid coordinates
        if odp_point['latitude'] and odp_point['longitude']:
            odp_points.append(odp_point)
    return odp_points



async def format_summary_odp_golive(summary_data):
    # Validate input data
    if not isinstance(summary_data, list):
        raise ValueError("Expected 'summary_data' to be a list of dictionaries.")

    # Organize data into a nested OrderedDict
    date_range_dict = OrderedDict()
    try:
        for row in summary_data:
            # Extract required fields with default fallbacks
            date_range = row.get('date_range')
            program_batch = row.get('program_batch', 'Other')  # Default to 'Other' if missing
            tsel_region = row.get('tsel_region', 'Unknown Region')
            tsel_branch = row.get('tsel_branch', 'Unknown Branch')
            count = row.get('COUNT', 0)

            if not date_range:
                raise ValueError("Each row must have a 'date_range' field.")

            # Initialize nested dictionaries
            if date_range not in date_range_dict:
                date_range_dict[date_range] = OrderedDict()
            if program_batch not in date_range_dict[date_range]:
                date_range_dict[date_range][program_batch] = OrderedDict()
            if tsel_region not in date_range_dict[date_range][program_batch]:
                date_range_dict[date_range][program_batch][tsel_region] = {
                    'total': 0,
                    'branches': OrderedDict()
                }
            if tsel_branch not in date_range_dict[date_range][program_batch][tsel_region]['branches']:
                date_range_dict[date_range][program_batch][tsel_region]['branches'][tsel_branch] = 0

            # Accumulate counts for regions and branches
            date_range_dict[date_range][program_batch][tsel_region]['branches'][tsel_branch] += count
            date_range_dict[date_range][program_batch][tsel_region]['total'] += count
    except Exception as e:
        raise ValueError(f"Error processing summary data: {e}")

    # Build the summary text
    summary_lines = []
    try:
        for date_range, batches in date_range_dict.items():
            # Add the date header with emoji and divider
            summary_lines.append(f"🚩 {date_range}\n_____ \n")
            
            for program_batch, regions in batches.items():
                # Add the program batch header
                summary_lines.append(f"❇️ {program_batch}\n")
                
                for tsel_region, data in regions.items():
                    total_region_count = data['total']
                    # Add region name and total count
                    summary_lines.append(f"{tsel_region:<15}{total_region_count}")
                    
                    for tsel_branch, branch_count in data['branches'].items():
                        # Add branch details with indentation
                        summary_lines.append(f"  {tsel_branch:<13}{branch_count}")
                    summary_lines.append("")  # Empty line between regions
                
                summary_lines.append("")  # Empty line between program batches
    except Exception as e:
        raise ValueError(f"Error formatting summary data: {e}")

    # Join the lines with newline and return as text
    summary_text = "\n".join(summary_lines)
    return summary_text


async def format_odp_map_data(data):
    """
    Format ODP Map data for KML display
    """
    odp_points = []
    for row in data:
        odp_point = {
            'odp_name': str(row['odp_name']) if row['odp_name'] is not None else '',
            'odp_index': str(row['odp_index']) if row['odp_index'] is not None else '',
            'is_total': int(row['is_total']) if row['is_total'] is not None else 0,
            'used': int(row['used']) if row['used'] is not None else 0,
            'avai': int(row['avai']) if row['avai'] is not None else 0,
            'status': str(row['status']) if row['status'] is not None else '',
            'sto': str(row['sto']) if row['sto'] is not None else '',
            'region_sap': str(row['region_sap']) if row['region_sap'] is not None else '',
            'branch': str(row['branch']) if row['branch'] is not None else '',
            'cluster': str(row['cluster']) if row['cluster'] is not None else '',
            'kab_tsel': str(row['kab_tsel']) if row['kab_tsel'] is not None else '',
            'latitude': float(row['latitude']) if row['latitude'] else None,
            'longitude': float(row['longitude']) if row['longitude'] else None,
            'los_months': int(row['los_months']) if row['los_months'] is not None else 0,
            'new_status': str(row['new_status']) if row['new_status'] is not None else 'Unknown',
            'los_group': str(row['los_group']) if row['los_group'] is not None else 'Unknown',
            'golive_date': row['golive_date'].strftime('%Y-%m-%d') if row.get('golive_date') else None,
            'update_date': row['update_date'].strftime('%Y-%m-%d') if row.get('update_date') else None
        }
        # Only include points with valid coordinates
        if odp_point['latitude'] and odp_point['longitude']:
            odp_points.append(odp_point)
    return odp_points


async def format_summary_odp_map_data(summary_data, is_region_selection=False):
    """
    Format ODP Map summary data for display with improved readability and grouping.
    For region selections, it aggregates data into 3 layers: Unique status, 
    Unique LOS status (New or Not_New), and Unique LOS group.
    """
    if not isinstance(summary_data, list):
        raise ValueError("Expected 'summary_data' to be a list of dictionaries.")

    if not summary_data:
        return "📭 Data tidak tersedia"

    def _get_status_emoji(status):
        """Return emoji for status color"""
        status_upper = status.upper() if status else 'UNKNOWN'
        emoji_map = {
            'RED': '🔴', 'ORANGE': '🟠', 'YELLOW': '🟡', 'GREEN': '🟢',
            'BLUE': '🔵', 'PURPLE': '🟣', 'GREY': '⚪', 'GRAY': '⚪',
            'BLACK': '⚫', 'UNKNOWN': '❓'
        }
        return emoji_map.get(status_upper, '❓')

    def _get_new_status_emoji(new_status):
        """Return emoji only for 'New' status"""
        return '🆕' if new_status == 'New' else ''

    def _get_los_sort_order(los_group):
        """Return sort order for LOS groups (newer to older)"""
        los_order = {'0-3': 1, '3-6': 2, '6-12': 3, '12-24': 4, '24-48': 5, '>48': 6, 'Unknown': 99}
        return los_order.get(los_group, 99)

    def _get_status_sort_order(status):
        """Return sort order for status (BLACK, GREEN, YELLOW, ORANGE, RED)"""
        status_upper = status.upper() if status else 'UNKNOWN'
        status_order = {'BLACK': 1, 'GREEN': 2, 'YELLOW': 3, 'ORANGE': 4, 'RED': 5, 'BLUE': 6, 'PURPLE': 7, 'GREY': 8, 'GRAY': 8, 'UNKNOWN': 99}
        return status_order.get(status_upper, 99)
    
    def _get_new_status_sort_order(new_status):
        """Return sort order for 'New' vs 'Not_New'"""
        return 1 if new_status == 'New' else 2

    if is_region_selection:
        grouped_data = {}
        for row in summary_data:
            branch = row.get('branch', 'Unknown Branch')
            if branch not in grouped_data:
                grouped_data[branch] = {
                    'total_odp_count': 0, 'total_ports': 0, 'total_used': 0,
                    'total_available': 0, 'sto_set': set(), 'entries': []
                }
            
            grouped_data[branch]['total_odp_count'] += row.get('odp_count', 0)
            grouped_data[branch]['total_ports'] += row.get('all_port', 0)
            grouped_data[branch]['total_used'] += row.get('total_used_port', 0)
            grouped_data[branch]['total_available'] += row.get('total_avai_port', 0)
            if row.get('sto'):
                grouped_data[branch]['sto_set'].add(row.get('sto'))
            grouped_data[branch]['entries'].append(row)
        
        summary_lines = []
        
        for branch in sorted(grouped_data.keys()):
            branch_data = grouped_data[branch]
            
            total_ports = branch_data['total_ports']
            total_used = branch_data['total_used']
            branch_occupancy = (total_used / total_ports * 100) if total_ports > 0 else 0
            
            summary_lines.append(f"📍 {branch} ({len(branch_data['sto_set'])} STOs, {branch_data['total_odp_count']:,} ODPs total)")
            summary_lines.append("━" * 15)
            summary_lines.append(f"   • Total Port: {branch_data['total_ports']:,} | Used: {branch_data['total_used']:,} | Available: {branch_data['total_available']:,}")
            summary_lines.append(f"   • Branch Occupancy: {branch_occupancy:.1f}%")
            summary_lines.append("")

            aggregated_groups = {}
            for row in branch_data['entries']:
                status = row.get('status', 'Unknown')
                new_status = 'New' if row.get('new_status') == 'New' else 'Not_New'
                los_group = row.get('los_group', 'Unknown')
                
                key = (status, new_status, los_group)

                if key not in aggregated_groups:
                    aggregated_groups[key] = {
                        'odp_count': 0,
                        'all_port': 0,
                        'total_used_port': 0,
                        'weighted_los_sum': Decimal('0.0'),
                    }
                
                odp_count_row = row.get('odp_count', 0)

                # Get the value, which could be a Decimal, float, int, or None
                los_value = row.get('avg_los_odp_month')

                # Safely convert to Decimal. If los_value is None or 0, default to Decimal('0.0')
                # The str() cast handles cases where the value might be a float.
                avg_los_row = Decimal(str(los_value)) if los_value else Decimal('0.0')

                aggregated_groups[key]['odp_count'] += odp_count_row
                aggregated_groups[key]['all_port'] += row.get('all_port', 0)
                aggregated_groups[key]['total_used_port'] += row.get('total_used_port', 0)
                aggregated_groups[key]['weighted_los_sum'] += avg_los_row * odp_count_row

            sorted_groups = sorted(
                aggregated_groups.items(),
                key=lambda item: (
                    _get_status_sort_order(item[0][0]),
                    _get_new_status_sort_order(item[0][1]),
                    _get_los_sort_order(item[0][2]),
                )
            )

            for i, (key, data) in enumerate(sorted_groups):
                status, new_status, los_group = key
                
                group_odps = data['odp_count']
                group_ports = data['all_port']
                group_used = data['total_used_port']
                
                group_occ = (group_used / group_ports * 100) if group_ports > 0 else 0.0
                avg_los = (data['weighted_los_sum'] / group_odps) if group_odps > 0 else Decimal('0.0')
                
                status_emoji = _get_status_emoji(status)
                new_emoji = _get_new_status_emoji(new_status)
                display_new_status = f"{new_emoji} {new_status}".strip()

                summary_lines.append(f"    {i+1}. Status: {status_emoji} {status} | {display_new_status} | LOS: {los_group}")
                summary_lines.append(f"       • ODPs: {group_odps:,} | Ports: {group_ports:,} | Occ: {group_occ:.1f}% | Avg LOS: {avg_los:.1f} bulan")
            
            summary_lines.append("")
    
    else:
        # Original STO-based grouping for single branch selections
        grouped_data = {}
        for row in summary_data:
            sto_key = f"{row.get('sto', 'Unknown STO')} ({row.get('cluster', 'Unknown Cluster')})"
            if sto_key not in grouped_data:
                grouped_data[sto_key] = []
            grouped_data[sto_key].append(row)
        
        summary_lines = []
        for sto_key in sorted(grouped_data.keys()):
            sto_entries = grouped_data[sto_key]
            sto_entries.sort(key=lambda x: (_get_los_sort_order(x.get('los_group', 'Unknown')), _get_status_sort_order(x.get('status', 'Unknown'))))
            
            total_odp_count = sum(entry.get('odp_count', 0) for entry in sto_entries)
            summary_lines.append(f"🏢 {sto_key} ({total_odp_count} ODPs total)")
            summary_lines.append("━" * 15)
            
            for i, row in enumerate(sto_entries):
                status_emoji = _get_status_emoji(row.get('status', 'Unknown Status'))
                new_emoji = _get_new_status_emoji(row.get('new_status', 'Unknown'))
                new_status_display = f"{new_emoji} {row.get('new_status', 'Unknown')}" if row.get('new_status') == 'New' else row.get('new_status', 'Unknown')
                occ_percentage = f"{row.get('avg_occ_sto', 0) * 100:.1f}%" if row.get('avg_occ_sto') else "0.0%"
                
                # Proactively fixing the same potential issue here
                los_value = row.get('avg_los_odp_month')
                los_numeric = float(los_value) if los_value is not None else 0.0
                los_text = f"{los_numeric:.1f} bulan"
                
                summary_lines.append(f"  {i+1:2d}. Status: {status_emoji} {row.get('status', 'Unknown')} | {new_status_display} | LOS: {row.get('los_group', 'Unknown')}")
                summary_lines.append(f"      • ODP Count: {row.get('odp_count', 0):,}")
                summary_lines.append(f"      • Total Port: {row.get('all_port', 0):,} | Used: {row.get('total_used_port', 0):,} | Available: {row.get('total_avai_port', 0):,}")
                summary_lines.append(f"      • Avg Occupancy: {occ_percentage}")
                summary_lines.append(f"      • Avg LOS: {los_text}")
                
                if i < len(sto_entries) - 1:
                    summary_lines.append("")
            summary_lines.append("")
    
    return "\n".join(summary_lines).strip()


# Implemented latlong sensor (updated: 2025/08/25)
async def format_ordering_history(order_id_value, wonum_value, user_id=None):
    """Refactored to use queue system with coordinate visibility control"""
    try:
        # STEP 1: Create sync wrapper functions for database calls
        def fetch_ordering_history_orderid_sync(order_id):
            """Sync wrapper for orderid lookup"""
            import asyncio
            loop = asyncio.new_event_loop()
            asyncio.set_event_loop(loop)
            try:
                result = loop.run_until_complete(fetch_ordering_history_orderid(order_id))
                # Convert all values to strings to handle Decimal objects
                for row in result:
                    for key, value in row.items():
                        if value is not None:
                            row[key] = str(value)
                        else:
                            row[key] = 'N/A'
                return result
            finally:
                loop.close()
        
        def fetch_ordering_history_wonum_sync(wonum):
            """Sync wrapper for wonum lookup"""
            import asyncio
            loop = asyncio.new_event_loop()
            asyncio.set_event_loop(loop)
            try:
                result = loop.run_until_complete(fetch_ordering_history_wonum(wonum))
                # Convert all values to strings to handle Decimal objects
                for row in result:
                    for key, value in row.items():
                        if value is not None:
                            row[key] = str(value)
                        else:
                            row[key] = 'N/A'
                return result
            finally:
                loop.close()
        
        # STEP 2: Submit tasks to queue based on input type
        ordering_history_orderid_rows = []
        ordering_history_wonum_rows = []
        
        if order_id_value:
            task_id = f"orderid_history_{order_id_value}_{time.time()}"
            success = bot_queue.submit_task(
                task_id=task_id,
                func=fetch_ordering_history_orderid_sync,
                args=(order_id_value,),
                priority=TaskPriority.HIGH,
                timeout=180.0
            )
            
            if not success:
                return ["❌ System overloaded. Please try again."]
            
            ordering_history_orderid_rows = bot_queue.get_task_result(task_id, timeout=200.0)
        
        if wonum_value:
            task_id = f"wonum_history_{wonum_value}_{time.time()}"
            success = bot_queue.submit_task(
                task_id=task_id,
                func=fetch_ordering_history_wonum_sync,
                args=(wonum_value,),
                priority=TaskPriority.HIGH,
                timeout=180.0
            )
            
            if not success:
                return ["❌ System overloaded. Please try again."]
            
            ordering_history_wonum_rows = bot_queue.get_task_result(task_id, timeout=200.0)
        
    except TimeoutError:
        input_value = order_id_value if order_id_value else wonum_value
        return [f"⏱️ Timeout retrieving history for `{input_value}`. Please try again."]
    except Exception as e:
        input_value = order_id_value if order_id_value else wonum_value
        logging.error(f"Error in format_ordering_history for {input_value}: {e}")
        return [f"❌ Error retrieving history for `{input_value}`: {str(e)}"]
    
    # STEP 3: Rest of your original logic UNCHANGED
    # Use whichever set of rows is available
    rows = ordering_history_orderid_rows if ordering_history_orderid_rows else ordering_history_wonum_rows
    
    if not rows:
        input_value = order_id_value if order_id_value else wonum_value
        return [f"❌ Mohon maaf, data untuk `{input_value}` tidak ditemukan."]
    
    # Check coordinate visibility permissions
    show_coordinates = await can_view_coordinates(user_id) if user_id else True
    
    # Order details section
    order_details = {}
    last_status = []
    last_process_state = []
    fallout_rows = []
    
    # Process data from the available rows
    for row in rows:
        order_rank = safe_int(row.get('order_rank', 0))

        # Get order details from rank 1
        if order_rank == 1:
            order_details = row
        
        # Collect status rows for last 3 status
        if 1 <= order_rank <= 3:
            last_status.append(row)
            last_process_state.append(row)
        
        # Collect fallout rows
        if row.get('provi_group') == 'FALLOUT':
            fallout_rows.append(row)
    
    # Sort last 3 status by order_rank (newest first)
    last_status.sort(key=lambda x: safe_int(x.get('order_rank', 0)))
    last_process_state.sort(key=lambda x: safe_int(x.get('order_rank', 0)))
    
    # Format timestamps - remove decimal seconds
    def format_timestamp(timestamp):
        if not timestamp or timestamp == 'N/A':
            return 'N/A'
        try:
            if isinstance(timestamp, str):
                dt = datetime.strptime(timestamp, "%Y-%m-%d %H:%M:%S.%f")
            else:
                dt = timestamp
            return dt.strftime("%Y-%m-%d %H:%M:%S")
        except Exception:
            return str(timestamp)  # Convert to string safely
    
    # Format order details section
    separator = "━" * 15  # Making all separators the same length
    
    # Prepare coordinate display based on user permissions
    latitude_display = order_details.get('latitude', 'N/A') if show_coordinates else '***'
    longitude_display = order_details.get('longitude', 'N/A') if show_coordinates else '***'
    
    # Prepare combined message block (order details + location + status)
    combined_message = (
        f"📊 Data Customer\n"
        f"{separator}\n"
        f"Order ID        : {order_details.get('order_id', 'N/A')}\n"
        f"WO Num          : {order_details.get('c_wonum', 'N/A')}\n"
        f"Region          : {order_details.get('region', 'N/A')}\n"
        f"Branch          : {order_details.get('branch', 'N/A')}\n"
        f"WOK             : {order_details.get('wok', 'N/A')}\n"
        f"STO             : {order_details.get('sto_co', 'N/A')}\n"
        f"Kab/Kota        : {order_details.get('kabupaten', 'N/A')}\n"
        f"No. Inet        : {order_details.get('service_id', 'N/A')}\n"
        f"Product Name    : {order_details.get('product_commercial_name', 'N/A')}\n"
        f"Channel Name    : {order_details.get('channel_name', 'N/A')}\n"
        f"SF Code         : {order_details.get('sf_code', 'N/A')}\n"
        f"Agency          : {order_details.get('sf_company_name', 'N/A')}\n"
        f"Tech Name       : {order_details.get('c_chief_name', 'N/A')}\n"
        f"ODP Name        : {order_details.get('odp_name', 'N/A')}\n"
        f"Latitude        : {latitude_display}\n"
        f"Longitude       : {longitude_display}\n\n\n"
        f"♻️ Order Flow:\n"
        f"{separator}\n"
        f"Order Date      : {format_timestamp(order_details.get('order_ts', 'N/A'))}\n"
        f"RE Date         : {format_timestamp(order_details.get('re_ts', 'N/A'))}\n"
        f"PS Date         : {format_timestamp(order_details.get('ps_ts', 'N/A'))}\n"
        f"Completed Date  : {format_timestamp(order_details.get('completed_ts', 'N/A'))}\n\n\n"
    )
    
    # Add last 3 status
    combined_message += (
        f"🔖 Last 3 Provi Status:\n"
        f"{separator}\n"
    )
    
    for row in last_status:
        provi_group = row.get('provi_group', 'N/A')
        if provi_group == 'FALLOUT':
            fallout_category = row.get('fallout_category', 'N/A')
            status = f"{provi_group} - {fallout_category}"
        else:
            status = provi_group
        formatted_time = format_timestamp(row.get('last_update', 'N/A'))
        
        if status == "COMPLETED":
            combined_message += f"{formatted_time} | {status} ✅\n"
        else:
            combined_message += f"{formatted_time} | {status}\n"
    
    # Add last 3 process states section
    combined_message += (
        f"\n\n🔖 Last 3 Process State:\n"
        f"{separator}\n"
    )
    
    for row in last_process_state:
        process_state = row.get('process_state', 'N/A')
        formatted_time = format_timestamp(row.get('last_update', 'N/A'))
        
        if process_state == "COMPLETED":
            combined_message += f"{formatted_time} | {process_state} ✅\n"
        else:
            combined_message += f"{formatted_time} | {process_state}\n"
    
    # Format fallout reason section: sort by latest_update (newest first)
    rows.sort(key=lambda x: x.get('latest_update', ''), reverse=True)
    fallout_reason = rows[0].get('fallout_reason', 'N/A') if rows else 'N/A'
    
    combined_message += f"\n\n✂️ Fallout Reason:\n{separator}\n{fallout_reason}"
    
    # Extract latitude and longitude for ODP suggestions (always use actual coordinates for functionality)
    order_location_link = None
    fallout_location_link = None
    
    # Order location link from order_details
    latitude = order_details.get('latitude', 'N/A')
    longitude = order_details.get('longitude', 'N/A')
    if latitude != 'N/A' and longitude != 'N/A':
        order_location_link = f"https://www.google.com/maps?q={latitude},{longitude}"
    
    # Robust coordinate extraction from fallout_reason
    def extract_coordinates(text):
        if not isinstance(text, str) or text == 'N/A':
            return None, None
        
        # Normalize text: replace multiple spaces with a single space
        text = re.sub(r'\s+', ' ', text)
        
        # List of patterns to try, from most specific to most general
        patterns = [
            # Standard formats with period as decimal separator (including no space after comma)
            r"(-?\d{1,3}\\.\d+),(-?\d{1,3}\\.\d+)",      # -7.257654,112.795062 (no space)
            r"(-?\d{1,3}\\.\d+)\s*,\s*(-?\d{1,3}\\.\d+)",  # -7.257654, 112.795062
            r"(-?\d{1,3}\\.\d+)\s+(-?\d{1,3}\\.\d+)",      # -7.257654 112.795062
            
            # Formats with comma as decimal separator (including no space after comma)
            r"(-?\d{1,3},\d+),(-?\d{1,3},\d+)",        # -7,257654,112,795062 (no space)
            r"(-?\d{1,3},\d+)\s*,\s+(-?\d{1,3},\d+)",    # -7,257654, 112,795062
            r"(-?\d{1,3},\d+)\s+(-?\d{1,3},\d+)",        # -7,257654 112,795062
            r"(-?\d{1,3},\d+)\s*;\s*(-?\d{1,3},\d+)",    # -7,257654; 112,795062
            
            # Mixed formats (one with comma, one with period)
            r"(-?\d{1,3}[.,]\d+),(-?\d{1,3}[.,]\d+)",  # Mixed with no space
            r"(-?\d{1,3}[.,]\d+)\s*[,;]\s*(-?\d{1,3}[.,]\d+)",  # Mixed separators
            r"(-?\d{1,3}[.,]\d+)\s+(-?\d{1,3}[.,]\d+)",        # Mixed with space
            
            # Indonesia-specific formats (latitude 5-8, longitude 110-112)
            r"(-?[5-8][.,]\d+),([1][1][0-2][.,]\d+)",  # Exact Indonesia format
            r"([5-8][.,]\d+),([1][1][0-2][.,]\d+)",    # Missing negative in latitude
            
            # Indonesia format with missing decimal points
            r"(-?[5-8])(\d+),([1][1][0-2])(\d+)",      # Missing decimal points
            r"(-?[5-8])(\d+)\s+([1][1][0-2])(\d+)",    # Missing decimal with space separator
            
            # Formats with degrees/minutes/seconds or special indicators
            r"(\d+\\.\d+)\s*°?\s*([NS])[,\s]+(\d+\\.\d+)\s*°?\s*([EW])",  # 7.25°N, 112.79°E
            r"([NS])\s*(\d+\\.\d+)\s*°?[,\s]+([EW])\s*(\d+\\.\d+)\s*°?",  # N 7.25°, E 112.79°
            
            # Very general patterns as last resort
            r"(-?\d+[.,]\d+)[,;\s](-?\d+[.,]\d+)",     # Any decimal numbers separated somehow
            r"\b(-?\d+)[,;\s]+(-?\d+)\b"                # Even just integers
        ]
        
        # Try each pattern and collect all possible matches
        all_matches = []
        for pattern in patterns:
            matches = re.findall(pattern, text)
            if matches:
                for match in matches:
                    # Special handling for Indonesia-specific patterns with missing decimal points
                    if len(match) == 4 and pattern in [
                        r"(-?[5-8])(\d+),([1][1][0-2])(\d+)",
                        r"(-?[5-8])(\d+)\s+([1][1][0-2])(\d+)"
                    ]:
                        # Add decimal point after first digit for lat and after third digit for lng
                        lat = match[0] + "." + match[1]
                        lng = match[2] + "." + match[3]
                        all_matches.append((float(lat), float(lng)))
                        continue
                    
                    # Normalize the match format based on pattern
                    if len(match) == 2:  # Simple lat,long format
                        lat, lng = match
                        # Special handling for Indonesia - missing negative sign in latitude
                        if pattern == r"([5-8][.,]\d+),([1][1][0-2][.,]\d+)":
                            lat = "-" + lat  # Add negative sign
                    elif len(match) == 4:  # With cardinal directions
                        if match[1] in 'NS' and match[3] in 'EW':  # 7.25°N, 112.79°E
                            lat, lat_dir, lng, lng_dir = match
                            lat = float(lat.replace(',', '.'))
                            lng = float(lng.replace(',', '.'))
                            lat = lat if lat_dir == 'N' else -lat
                            lng = lng if lng_dir == 'E' else -lng
                        else:  # N 7.25°, E 112.79°
                            lat_dir, lat, lng_dir, lng = match
                            lat = float(lat.replace(',', '.'))
                            lng = float(lng.replace(',', '.'))
                            lat = lat if lat_dir == 'N' else -lat
                            lng = lng if lng_dir == 'E' else -lng
                    else:
                        continue
                    
                    # Normalize decimal separator
                    if isinstance(lat, str):
                        lat = lat.replace(',', '.')
                    if isinstance(lng, str):
                        lng = lng.replace(',', '.')
                    
                    try:
                        lat_float = float(lat)
                        lng_float = float(lng)
                        
                        # For Indonesia, latitude should be negative (-5 to -8)
                        # If it's positive in the range of 5-8, make it negative
                        if 5 <= lat_float <= 8:
                            lat_float = -lat_float
                        
                        # Validate and possibly swap coordinates if they seem reversed
                        if -90 <= lat_float <= 90 and -180 <= lng_float <= 180:
                            # Valid as is
                            all_matches.append((lat_float, lng_float))
                        elif -90 <= lng_float <= 90 and -180 <= lat_float <= 180:
                            # Swapped coordinates
                            all_matches.append((lng_float, lat_float))
                    except (ValueError, TypeError):
                        continue
        
        # If we have any valid matches, return the last one (often the most complete)
        if all_matches:
            # Filter to only include matches where latitude is between -8 and -5 (Indonesia)
            # and longitude is between 110 and 112
            indonesia_matches = [m for m in all_matches if -8 <= m[0] <= -5 and 110 <= m[1] <= 112]
            
            # If we have Indonesia-specific matches, prefer those
            if indonesia_matches:
                final_match = indonesia_matches[-1]
            else:
                final_match = all_matches[-1]
            
            return str(final_match[0]), str(final_match[1])
        
        # As a last resort, try to find any numbers that look like coordinates
        coords = re.findall(r'-?\d+[.,]?\d*', text)
        if len(coords) >= 2:
            # Try to convert and validate
            try:
                # Get the last two numbers in the string
                potential_lat = coords[-2].replace(',', '.')
                potential_lng = coords[-1].replace(',', '.')
                
                # For Indonesia: Handle missing decimal point cases
                # If latitude is just a single digit 5-8, add decimal point
                if re.match(r'^-?[5-8]$', potential_lat):
                    potential_lat += '.0'
                # If latitude is a longer number without decimal, insert one after first digit
                elif re.match(r'^-?[5-8]\d{2,}$', potential_lat) and '.' not in potential_lat:
                    potential_lat = potential_lat[0] + '.' + potential_lat[1:]
                
                # If longitude is just 3 digits (110-112), add decimal point
                if re.match(r'^1[1][0-2]$', potential_lng):
                    potential_lng += '.0'
                # If longitude is longer than 3 digits without decimal, insert after first 3
                elif re.match(r'^1[1][0-2]\d{1,}$', potential_lng) and '.' not in potential_lng:
                    potential_lng = potential_lng[:3] + '.' + potential_lng[3:]
                
                lat_float = float(potential_lat)
                lng_float = float(potential_lng)
                
                # For Indonesia, latitude should always be negative
                if 5 <= lat_float <= 8:
                    lat_float = -lat_float
                
                # Simple validation
                if -8 <= lat_float <= -5 and 110 <= lng_float <= 112:
                    return str(lat_float), str(lng_float)
                elif 110 <= lat_float <= 112 and -8 <= lng_float <= -5:
                    # Swapped coordinates - specific to Indonesia
                    return str(lng_float), str(lat_float)
            except (ValueError, TypeError):
                pass
        
        return None, None
    
    fallout_coords = extract_coordinates(fallout_reason)
    if fallout_coords and fallout_coords[0] and fallout_coords[1]:
        fallout_lat, fallout_long = fallout_coords
        fallout_location_link = f"https://www.google.com/maps?q={fallout_lat},{fallout_long}"
    
    # Create ODP suggestion message with Markdown formatting
    odp_suggestions = []
    if order_location_link:
        odp_suggestions.append(f"📍 Cek Lokasi ODP terdekat order ini dengan:\n/odpterdekat {order_location_link}")
    if fallout_location_link:
        odp_suggestions.append(f"📍 Cek Lokasi ODP terdekat kondisi fallout dengan:\n/odpterdekat {fallout_location_link}")
    
    coffee_note = "\n\n☕️ Klik link untuk melakukan copy. Silahkan copy dan paste command di atas."
    odpterdekat_message = "\n\n".join(odp_suggestions) + coffee_note if odp_suggestions else "Tidak ada koordinat lokasi untuk cek ODP terdekat."
    
    return [
        f"```\n{combined_message}```",
        odpterdekat_message
    ]


# Generate "/id" command output in correct format for customer CB history including payload/usage and billing/payment details
async def format_customer_history(bb_id_value, user_id: int):
    """Fully asynchronous function with corrected multi-period data handling and sensitive data protection"""
    rows = demo_backend.fetch_customer_history(bb_id_value)
    if not rows:
        return [f"❌ Mohon maaf, data untuk `{bb_id_value}` tidak ditemukan."]
    latest = rows[-1]
    address = latest.get("customer_address", "N/A")
    mobile = latest.get("mobile_no", "N/A")
    maps_url = f"https://www.google.com/maps?q={latest.get('latitude')},{latest.get('longitude')}"
    summary = (
        f"📊 Data Customer\n"
        f"━━━━━━━━━━━━━━━\n"
        f"No. Inet        : {bb_id_value}\n"
        f"Customer        : {latest.get('customer_name', 'N/A')}\n"
        f"Paket           : {latest.get('package_name', 'N/A')}\n"
        f"Alamat          : {address}\n"
        f"MSISDN          : {mobile}\n\n"
        f"Riwayat 4 Bulan:\n"
    )
    for row in rows:
        summary += (
            f"- {row.get('periode')} | Bill: {row.get('bill_amount')} | "
            f"Status: {row.get('payment_status')} | Usage: {row.get('usage_gb')} GB ({row.get('usage_pct')})\n"
        )
    return [f"```\n{summary}```", f"🌏 Buka alamat di tautan berikut ini:\n{maps_url}"]


async def format_ticketing_history(bb_id_value, ticket_id_value, user_id=None):
    """Format ticketing history data for display"""
    try:
        # Direct async calls to fetch functions
        rows = []
        
        if bb_id_value:
            rows = await fetch_ticketing_history_bbid(bb_id_value)
        elif ticket_id_value:
            rows = await fetch_ticketing_history_ticketid(ticket_id_value)
        
        # Convert all values to strings to handle Decimal objects
        for row in rows:
            for key, value in row.items():
                row[key] = str(value) if value is not None else 'N/A'
        
        if not rows:
            input_value = bb_id_value if bb_id_value else ticket_id_value
            return [f"❌ Mohon maaf, data untuk `{input_value}` tidak ditemukan."]
        
        # Get service number for display (from any row since they should all have the same service number)
        service_number = rows[0].get('c_service_no', 'N/A')
        
        # Sort rows by creation date (newest first) and limit to last 3
        rows.sort(key=lambda x: x.get('datecreated', ''), reverse=True)
        last_3_tickets = rows[:3]
        
        # Format timestamps - remove decimal seconds if present
        def format_timestamp(timestamp):
            if not timestamp or timestamp == 'N/A':
                return 'N/A'
            try:
                if isinstance(timestamp, str):
                    # Handle different timestamp formats
                    if '.' in timestamp:
                        dt = datetime.strptime(timestamp, "%Y-%m-%d %H:%M:%S.%f")
                    else:
                        dt = datetime.strptime(timestamp, "%Y-%m-%d %H:%M:%S")
                else:
                    dt = timestamp
                return dt.strftime("%Y-%m-%d %H:%M:%S")
            except Exception:
                return str(timestamp)  # Convert to string safely
        
        # Function to wrap long text with indentation
        def wrap_ticket_details(text, width=50):
            if not text or text == 'N/A':
                return 'N/A'
            
            # Split into words and rebuild with line breaks
            words = text.split()
            lines = []
            current_line = ""
            
            for word in words:
                if len(current_line + word) + 1 <= width:
                    current_line += word + " "
                else:
                    if current_line:
                        lines.append(current_line.strip())
                    current_line = word + " "
            
            if current_line:
                lines.append(current_line.strip())
            
            # Join with indentation for continuation lines
            if not lines:
                return 'N/A'
            
            result = lines[0]
            for line in lines[1:]:
                result += "\n" + " " * 3 + line  # 3 spaces to align with "Ticket Details   :"
            
            return result
        
        # Format customer data section
        separator = "━" * 15
        
        customer_section = (
            f"📊 Data Customer\n"
            f"{separator}\n"
            f"No. Inet         : {service_number}\n\n\n"
        )
        
        # Format last 3 tickets section
        tickets_section = (
            f"📈 Last 3 Ticket\n"
            f"{separator}\n"
        )
        
        for i, ticket in enumerate(last_3_tickets, 1):
            ticket_id = ticket.get('c_id_ticket', 'N/A')
            ticket_gamas = ticket.get('c_ticket_id_gamas', 'N/A')
            if ticket_gamas == 'null' or ticket_gamas is None:
                ticket_gamas = 'N/A'
            
            created_date = format_timestamp(ticket.get('datecreated', 'N/A'))
            modified_date = format_timestamp(ticket.get('datemodified', 'N/A'))
            ticket_details = wrap_ticket_details(ticket.get('c_details', 'N/A'))
            ticket_status = ticket.get('c_action_status', 'N/A')
            
            tickets_section += (
                f"🎫 Ticket ID {i} : {ticket_id}\n"
                f"Ticket Gamas    : {ticket_gamas}\n"
                f"Created         : {created_date}\n"
                f"Last Updated    : {modified_date}\n"
                f"Status          : {ticket_status}\n"
                f"Ticket Details  :\n"
                f"{ticket_details}\n"
            )
            
            # Add separator between tickets except for the last one
            if i < len(last_3_tickets):
                tickets_section += "\n"
        
        # Combine all sections
        combined_message = customer_section + tickets_section
        
        return [f"```\n{combined_message}```"]
        
    except Exception as e:
        input_value = bb_id_value if bb_id_value else ticket_id_value
        logging.error(f"Error in format_ticketing_history for {input_value}: {e}")
        return [f"❌ Error retrieving ticket history for {input_value}: {str(e)}"]


async def format_churn_data_multiple_stos(chat_id: int, bot: 'Bot', user_id: int, sto_names: list, risk_level: str, branch_name: str, region_name: str):
    """
    Analisis churn data untuk multiple STO dengan clustering dan prioritas revenue.
    """
    progress_message = None
    try:
        logging.debug(f"=== Starting churn clustering analysis for user {user_id} ===")
        
        # Batasi ke 3 STO pertama untuk performa
        original_sto_count = len(sto_names)
        limited_sto_names = sto_names[:3]
        
        if original_sto_count > 3:
            logging.info(f"Limited processing from {original_sto_count} STOs to {len(limited_sto_names)} STOs for performance")

        # 1. Progress Message
        initial_progress = get_loading_bar(0)
        sto_list = ", ".join([s.upper() for s in limited_sto_names])
        
        if original_sto_count > 3:
            progress_text = f"Memproses Analisis Clustering Churn\n\n{initial_progress}\n\nMemproses {len(limited_sto_names)} dari {original_sto_count} STO yang dipilih..."
        else:
            progress_text = f"Memproses Analisis Clustering Churn\n\n{initial_progress}\n\nMemulai analisis clustering..."
        
        progress_message = await bot.send_message(chat_id, progress_text)

        # 2. Ambil Data Koordinat dengan Revenue
        await update_progress_message(bot, chat_id, progress_message.message_id, 10, "Mengambil data koordinat...")
        
        all_coordinates = []
        basic_summary_data = {}
        
        months = await get_last_n_months(user_id, 3)  # Last 3 months including current

        for idx, sto_name in enumerate(limited_sto_names):
            progress_pct = 10 + (idx / len(limited_sto_names)) * 30
            await update_progress_message(bot, chat_id, progress_message.message_id, progress_pct, f"Memproses data {sto_name.upper()}...")
            
            # Ambil data koordinat dengan revenue
            coordinate_data = []
            
            # Pass the 'months' list we calculated at the start of this function
            if risk_level == "HIGH":
                coordinate_data = await fetch_ten_segment_cvm_churn_high(usr_selected_sto=sto_name, user_id=user_id, months=months)
                for item in coordinate_data:
                    item['risk_level'] = 'HIGH'
            elif risk_level == "LOW-MID":
                coordinate_data = await fetch_ten_segment_cvm_churn_lowmid(usr_selected_sto=sto_name, user_id=user_id, months=months)
                for item in coordinate_data:
                    item['risk_level'] = 'LOW-MID'
            elif risk_level == "BOTH":
                high_data = await fetch_ten_segment_cvm_churn_high(usr_selected_sto=sto_name, user_id=user_id, months=months)
                low_data = await fetch_ten_segment_cvm_churn_lowmid(usr_selected_sto=sto_name, user_id=user_id, months=months)
                for item in high_data:
                    item['risk_level'] = 'HIGH'
                for item in low_data:
                    item['risk_level'] = 'LOW-MID'
                coordinate_data = high_data + low_data

            # TEMPORARY DEBUG ONLY - DELETE LATER
            logging.info(f"DEBUG - STO {sto_name}: Total coordinate_data after fetch: {len(coordinate_data)}")
            
            if coordinate_data:
                for coord in coordinate_data:
                    coord['sto_group'] = sto_name
                all_coordinates.extend(coordinate_data)

            # TEMPORARY DEBUG ONLY - DELETE LATER
            logging.info(f"DEBUG - Total all_coordinates before Python validation: {len(all_coordinates)}")

            
            # Ambil summary data
            summary_data = await fetch_ten_segment_cvm_summary_churnrisk(usr_selected_sto=sto_name, months=months)
            if summary_data:
                basic_summary_data[sto_name] = summary_data

        if not all_coordinates:
            await bot.edit_message_text(
                text="Tidak ada data koordinat untuk analisis clustering churn risk. Jika ini awal bulan kemungkinan data belum lengkap. Silahkan atur ulang periode laporan dengan /daterange ke bulan sebelumnya.",
                chat_id=chat_id,
                message_id=progress_message.message_id
            )
            return

        # 3. ANALISIS CLUSTERING dengan Revenue
        await update_progress_message(bot, chat_id, progress_message.message_id, 40, "Melakukan analisis clustering...")
        
        analyzer = ChurnClusteringAnalyzer(radius_meters=300, min_cluster_size=5)
        
        # Siapkan data untuk clustering dengan revenue
        valid_coordinates = []
        total_fetched = len(all_coordinates)

        failed_float_conversion = 0
        failed_zero_check = 0
        failed_range_check = 0
        failed_near_zero = 0
        failed_combined = 0
        
        for row in all_coordinates:
            try:
                lat = float(row.get("latitude", 0))
                lon = float(row.get("longitude", 0))
                revenue = int(row.get("rev_all", 0))
                
                # SEPARATE validation checks for debugging
                if lat == 0 or lon == 0:
                    failed_zero_check += 1
                    continue
                
                # Check for near-zero values (floating point issues)
                if abs(lat) < 0.000001 or abs(lon) < 0.000001:
                    failed_near_zero += 1
                    logging.debug(f"Near-zero coord: lat={lat}, lon={lon}, bb_id={row.get('bb_id')}")
                    continue
                
                # Check range validity
                if not (-90 <= lat <= 90 and -180 <= lon <= 180):
                    failed_range_check += 1
                    logging.debug(f"Out of range: lat={lat}, lon={lon}, bb_id={row.get('bb_id')}")
                    continue
                
                # All checks passed - add to valid coordinates
                valid_coordinates.append({
                    'bb_id': row.get("bb_id", "N/A"),
                    'latitude': lat,
                    'longitude': lon,
                    'latlong': f"{lat},{lon}",
                    'customer_segment': row.get("customer_segment", "Unknown"),
                    'sto': row.get("sto_group", "Unknown"),
                    'risk_level': row.get("risk_level", risk_level),
                    'revenue': revenue,
                    'city': row.get("city", "N/A")
                })
                
            except (ValueError, TypeError) as e:
                failed_float_conversion += 1
                logging.debug(f"Conversion error: {e}, bb_id={row.get('bb_id')}")
                continue

        logging.info(f"DEBUG VALIDATION RESULTS:")
        logging.info(f"  - Total fetched: {total_fetched}")
        logging.info(f"  - Valid coordinates: {len(valid_coordinates)}")
        logging.info(f"  - Failed float conversion: {failed_float_conversion}")
        logging.info(f"  - Failed exact zero check: {failed_zero_check}")
        logging.info(f"  - Failed near-zero check: {failed_near_zero}")
        logging.info(f"  - Failed range check: {failed_range_check}")
        logging.info(f"  - Total filtered: {failed_float_conversion + failed_zero_check + failed_near_zero + failed_range_check}")
        logging.info(f"  - Unaccounted: {total_fetched - len(valid_coordinates) - (failed_float_conversion + failed_zero_check + failed_near_zero + failed_range_check)}")

        logging.info(f"Data fetched: {total_fetched}, Valid: {len(valid_coordinates)}")
        
        if len(valid_coordinates) < 5:
            await bot.edit_message_text(
                text=f"Data koordinat tidak cukup untuk analisis clustering.\nFetched: {total_fetched}, Valid: {len(valid_coordinates)} (minimum 5 titik).",
                chat_id=chat_id,
                message_id=progress_message.message_id
            )
            return

        # Buat DataFrame dan lakukan clustering
        df = pd.DataFrame(valid_coordinates)
        
        # Filter untuk clustering (HIGH-risk saja jika BOTH)
        if risk_level == "BOTH":
            df_for_clustering = df[df['risk_level'] == 'HIGH'].copy()
        else:
            df_for_clustering = df.copy()
        
        clustering_results = None
        df_clustered = None
        cluster_revenue_summary = {}
        
        if len(df_for_clustering) >= 5:
            logging.info(f"Performing clustering on {len(df_for_clustering)} users")
            df_clustered = analyzer.perform_clustering(df_for_clustering)
            clustering_results = analyzer.analyze_clusters(df_clustered)
            
            # Hitung Revenue per Cluster
            cluster_mapping = {}
            if df_clustered is not None and len(df_clustered) > 0:
                for _, row in df_clustered.iterrows():
                    coord_key = f"{row['latitude']:.6f},{row['longitude']:.6f}"
                    cluster_mapping[coord_key] = row['cluster_id']
            
            # Apply cluster IDs dan hitung revenue
            cluster_revenues = {}
            clustered_count = 0
            
            for coord in valid_coordinates:
                coord_key = f"{coord['latitude']:.6f},{coord['longitude']:.6f}"
                if coord_key in cluster_mapping:
                    cluster_id = cluster_mapping[coord_key]
                    coord['cluster_id'] = cluster_id
                    if cluster_id != -1:
                        clustered_count += 1
                        # Hitung revenue per cluster
                        if cluster_id not in cluster_revenues:
                            cluster_revenues[cluster_id] = {'total_revenue': 0, 'user_count': 0}
                        cluster_revenues[cluster_id]['total_revenue'] += coord['revenue']
                        cluster_revenues[cluster_id]['user_count'] += 1
                else:
                    coord['cluster_id'] = -1
            
            # Sort clusters by revenue (prioritas)
            sorted_clusters = sorted(cluster_revenues.items(), 
                                   key=lambda x: x[1]['total_revenue'], 
                                   reverse=True)
            
            # Buat revenue summary dengan ranking
            for rank, (cluster_id, data) in enumerate(sorted_clusters, 1):
                cluster_revenue_summary[cluster_id] = {
                    'rank': rank,
                    'total_revenue': data['total_revenue'],
                    'user_count': data['user_count'],
                    'avg_revenue_per_user': data['total_revenue'] / data['user_count'] if data['user_count'] > 0 else 0
                }
            
            logging.info(f"Cluster revenue analysis: {len(sorted_clusters)} clusters dengan total revenue")
            
        else:
            # Tidak cukup data untuk clustering
            logging.info(f"Insufficient data for clustering: {len(df_for_clustering)} users")
            for coord in valid_coordinates:
                coord['cluster_id'] = -1
            clustering_results = {
                'total_high_risk_users': len(df_for_clustering),
                'clustered_users': 0,
                'isolated_users': len(df_for_clustering),
                'clustering_rate': 0,
                'total_clusters': 0,
                'significant_clusters': 0,
                'max_cluster_size': 0,
                'avg_cluster_size': 0,
                'cluster_details': [],
                'significant_cluster_details': []
            }

        # 4. Generate Summary dengan Revenue Prioritas
        await update_progress_message(bot, chat_id, progress_message.message_id, 60, "Menyusun summary clustering...")
        
        summary_lines = []
        
        # Header
        if original_sto_count > 3:
            summary_lines.extend([
                f"📊 Analisis Clustering Churn Risk",
                "━━━━━━━━━━━━━━━",
                f"Region        : {region_name.upper()}",
                f"Branch        : {branch_name.upper()}",
                f"STO Dipilih   : {original_sto_count} STO",
                f"STO Diproses  : {len(limited_sto_names)} STO (Max 3)",
                f"Daftar STO    : {sto_list}",
                f"Risk Level    : {risk_level.upper()}",
                ""
            ])
        else:
            summary_lines.extend([
                f"📊 Analisis Clustering Churn Risk",
                "━━━━━━━━━━━━━━━",
                f"Region        : {region_name.upper()}",
                f"Branch        : {branch_name.upper()}",
                f"Daftar STO    : {sto_list}",
                f"Risk Level    : {risk_level.upper()}",
                ""
            ])

        # CLUSTERING OVERVIEW
        # Dynamic labels based on risk_level
        if risk_level == "BOTH":
            high_count = len([c for c in valid_coordinates if c.get('risk_level') == 'HIGH'])
            lowmid_count = len([c for c in valid_coordinates if c.get('risk_level') == 'LOW-MID'])
            total_both = high_count + lowmid_count
            risk_label = f"Mappable Users Analyzed  : {total_both:,}\n" \
                        f"  ├─ HIGH Risk           : {high_count:,}\n" \
                        f"  └─ LOW-MID Risk        : {lowmid_count:,}\n" \
                        f"Clustering Scope         : HIGH Risk only"
        elif risk_level == "HIGH":
            risk_label = f"Mappable HIGH-Risk Users : {clustering_results['total_high_risk_users']:,}"
        else:  # LOW-MID
            risk_label = f"Mappable LOW-MID Users   : {clustering_results['total_high_risk_users']:,}"

        summary_lines.extend([
            "RINGKASAN CLUSTERING",
            "━━━━━━━━━━━━━━━",
            risk_label,
            f"Users dalam Cluster      : {clustering_results['clustered_users']:,}",
            f"Users Terisolasi         : {clustering_results['isolated_users']:,}",
            f"Tingkat Clustering       : {clustering_results['clustering_rate']:.1f}%",
            f"Total Cluster Ditemukan  : {clustering_results['total_clusters']}",
            f"Cluster Signifikan       : {clustering_results['significant_clusters']}",
            f"Konsentrasi Maksimal     : {clustering_results['max_cluster_size']} users dalam 300m",
            f"Rata-rata Ukuran Cluster : {clustering_results['avg_cluster_size']:.1f} users",
            ""
        ])

        # PRIORITAS CLUSTER BERDASARKAN REVENUE
        if cluster_revenue_summary:
            total_clustered_revenue = sum([data['total_revenue'] for data in cluster_revenue_summary.values()])
            
            summary_lines.extend([
                "💰 PRIORITAS CLUSTER BERDASARKAN REVENUE",
                "━━━━━━━━━━━━━━━"
            ])
            
            for cluster_id, data in sorted(cluster_revenue_summary.items(), key=lambda x: x[1]['rank']):
                revenue_pct = (data['total_revenue'] / total_clustered_revenue * 100) if total_clustered_revenue > 0 else 0
                summary_lines.extend([
                    f"Rank {data['rank']}. Cluster {cluster_id}",
                    f"   • Users: {data['user_count']} orang",
                    f"   • Total Revenue: Rp {data['total_revenue']:,}",
                    f"   • Rata-rata Revenue: Rp {data['avg_revenue_per_user']:,.0f}/user",
                    f"   • Kontribusi: {revenue_pct:.1f}% dari total cluster revenue",
                    ""
                ])
            
            summary_lines.extend([
                f"Total Revenue dalam Cluster: Rp {total_clustered_revenue:,}",
                f"Rata-rata Revenue per Cluster: Rp {total_clustered_revenue / len(cluster_revenue_summary):,.0f}",
                ""
            ])
        else:
            summary_lines.extend([
                "💰 PRIORITAS CLUSTER BERDASARKAN REVENUE",
                "━━━━━━━━━━━━━━━",
                "Tidak ada cluster signifikan untuk analisis revenue.",
                "Users tersebar secara geografis tanpa konsentrasi major.",
                ""
            ])

        # TOP AREA KONSENTRASI
        if clustering_results['significant_cluster_details']:
            summary_lines.extend([
                "🔥 TOP AREA KONSENTRASI (radius 300m)",
                "━━━━━━━━━━━━━━━"
            ])

            risk_label_display = "HIGH-RISK" if risk_level == "HIGH" else ("LOW-MID RISK" if risk_level == "LOW-MID" else "CHURN RISK")

            for i, cluster in enumerate(clustering_results['significant_cluster_details'][:5], 1):
                dominant_sto = cluster['dominant_sto']
                user_count = cluster['user_count']
                lat_center = cluster['lat_center']
                lng_center = cluster['lng_center']
                
                # Tambahkan info revenue jika ada
                revenue_info = ""
                if cluster.get('cluster_id') in cluster_revenue_summary:
                    rev_data = cluster_revenue_summary[cluster['cluster_id']]
                    revenue_info = f" | Revenue: Rp {rev_data['total_revenue']:,} (Rank {rev_data['rank']})"
                
                summary_lines.extend([
                    f"{i}. {user_count} {risk_label_display} users dalam satu area{revenue_info}",
                    f"   • Center: {lat_center:.4f}, {lng_center:.4f}",
                    f"   • STO Dominan: {dominant_sto}",
                    ""
                ])

        # PENILAIAN RISIKO
        clustering_rate = clustering_results['clustering_rate']
        max_concentration = clustering_results['max_cluster_size']
        
        summary_lines.extend([
            "⚠️ PENILAIAN RISIKO CLUSTERING",
            "━━━━━━━━━━━━━━━"
        ])
        
        if clustering_rate > 60:
            summary_lines.extend([
                "RISIKO CLUSTERING TINGGI",
                "   Terdeteksi pola clustering geografis yang kuat!",
                "   Users membentuk area konsentrasi yang padat."
            ])
        elif clustering_rate > 30:
            summary_lines.extend([
                "RISIKO CLUSTERING SEDANG",
                "   Beberapa pola konsentrasi geografis teramati.",
                "   Monitor perkembangan clustering lebih lanjut."
            ])
        else:
            summary_lines.extend([
                "RISIKO CLUSTERING RENDAH",
                "   Users terdistribusi geografis dengan baik.",
                "   Tidak ada pola konsentrasi yang mengkhawatirkan."
            ])
            
        if max_concentration >= 10:
            # ADD THIS: Dynamic risk label
            risk_label_display = "HIGH-RISK" if risk_level == "HIGH" else ("LOW-MID RISK" if risk_level == "LOW-MID" else "CHURN RISK")
            
            summary_lines.extend([
                "",
                f"HOTSPOT KRITIS TERDETEKSI",
                f"   {max_concentration} {risk_label_display} users dalam area 300m tunggal!",
                f"   Disarankan investigasi segera."
            ])
        elif max_concentration >= 5:
            # ADD THIS: Dynamic risk label
            risk_label_display = "churn risk" if risk_level == "BOTH" else (risk_level.lower() + " risk")
            
            summary_lines.extend([
                "",
                f"Perlu Perhatian",
                f"   {max_concentration} {risk_label_display} users terkonsentrasi dalam satu area.",
                f"   Pertimbangkan intervensi tertarget."
            ])
        
        summary_lines.append("")

        # RINGKASAN BERDASARKAN TEN SEGMENT
        if basic_summary_data:
            summary_lines.extend([
                "📊 RINGKASAN BERDASARKAN TEN SEGMENT",
                "━━━━━━━━━━━━━━━",
                "(Data keseluruhan dari database, termasuk user tanpa koordinat valid)",
                ""
            ])
            
            combined_segments = {}
            combined_total = 0
            combined_high_risk = 0
            
# Find this section (around line 360):
            for sto_name, sto_data in basic_summary_data.items():
                latest_event_date = max([row.get("event_date", "") for row in sto_data]) if sto_data else ""
                latest_data = [row for row in sto_data if row.get("event_date") == latest_event_date]
                
                for row in latest_data:
                    seg = row.get("customer_segment", "Unknown")
                    user_count = int(row.get("user_count", 0))
                    combined_total += user_count
                    
                    if seg not in combined_segments:
                        combined_segments[seg] = {'total': 0, 'high': 0, 'lowmid': 0}  # ADD lowmid
                    
                    combined_segments[seg]['total'] += user_count
                    
                    # Count based on risk_level
                    propensity = row.get("propensity_group", "")
                    if propensity == "03. High":
                        combined_segments[seg]['high'] += user_count
                        if risk_level in ["HIGH", "BOTH"]:
                            combined_high_risk += user_count
                    elif propensity in ["01. Low", "02. Mid"]:
                        combined_segments[seg]['lowmid'] += user_count
                        if risk_level in ["LOW-MID", "BOTH"]:
                            combined_high_risk += user_count  # This variable name is misleading, but it's the "target risk" count
            
            # Display based on risk_level
            for seg in sorted(combined_segments.keys()):
                seg_total = combined_segments[seg]['total']
                
                if risk_level == "HIGH":
                    seg_risk = combined_segments[seg]['high']
                    risk_label = "high-risk"
                elif risk_level == "LOW-MID":
                    seg_risk = combined_segments[seg]['lowmid']
                    risk_label = "low-mid risk"
                else:  # BOTH
                    seg_risk = combined_segments[seg]['high'] + combined_segments[seg]['lowmid']
                    risk_label = "at-risk"
                
                seg_rate = (seg_risk / seg_total * 100) if seg_total > 0 else 0
                summary_lines.append(f"• {seg}: {seg_total:,} total ({seg_risk:,} {risk_label}, {seg_rate:.1f}%)")
            
            # Calculate difference for reconciliation note
            if risk_level == "BOTH":
                total_mappable = len(valid_coordinates)
                unmappable = combined_total - total_mappable
                unmappable_pct = (unmappable / combined_total * 100) if combined_total > 0 else 0
                
                summary_lines.extend([
                    "",
                    f"TOTAL DATABASE: {combined_total:,} users ({combined_high_risk:,} at-risk, {(combined_high_risk/combined_total*100):.1f}%)",
                    f"  ├─ Risky Customer: {total_mappable:,} users",
                    f"  └─ Non-risk Customer: {unmappable:,} users ({unmappable_pct:.1f}%)",
                    ""
                ])
            else:
                risk_label_final = "high-risk" if risk_level == "HIGH" else "low-mid risk"
                summary_lines.extend([
                    "",
                    f"KESELURUHAN: {combined_total:,} total ({combined_high_risk:,} {risk_label_final}, {(combined_high_risk/combined_total*100):.1f}%)",
                    ""
                ])

        summary_lines.extend([
            "💡 ANALISIS DETAIL",
            "━━━━━━━━━━━━━━━",
            "Breakdown segment detail, visualisasi clustering,",
            "dan peta interaktif tersedia dalam file HTML di bawah.",
            ""
        ])

        summary_content = "\n".join(summary_lines)

        # 5. Kirim Summary dengan Formatting Khusus
        await update_progress_message(bot, chat_id, progress_message.message_id, 70, "Mengirim analisis clustering...")
        await send_churn_report_stos_with_formatting(bot, chat_id, summary_content)

        # 6. Generate Enhanced Heatmap dengan Revenue Data
        await update_progress_message(bot, chat_id, progress_message.message_id, 80, f"Generate clustering heatmap ({len(valid_coordinates):,} points)...")
        
        output_html_path = await generate_churn_heatmap_html_multiple_stos_with_clustering(
            user_id, valid_coordinates, limited_sto_names, risk_level, branch_name, region_name,
            clustering_results, df_clustered,
            basic_summary_data,
            progress_callback=lambda p, s: update_progress_message(bot, chat_id, progress_message.message_id, 80 + p * 0.15, s)
        )

        if not os.path.exists(output_html_path):
            await bot.edit_message_text(
                text="Gagal membuat file heatmap clustering.",
                chat_id=chat_id,
                message_id=progress_message.message_id
            )
            return

        # 7. Kirim file heatmap
        file_size_mb = os.path.getsize(output_html_path) / (1024 * 1024)
        await update_progress_message(bot, chat_id, progress_message.message_id, 95, f"Upload clustering visualization ({file_size_mb:.1f} MB)...")

        input_file = FSInputFile(output_html_path, filename=os.path.basename(output_html_path))
        
        caption_lines = [
            f"📊 Churn Risk CLUSTERING Map dengan Revenue Priority",
            f"Buka file dengan Desktop untuk experience terbaik\n",
            f" • STO: {sto_list}"
        ]
        
        if original_sto_count > 3:
            caption_lines.append(f"📊 Diproses: {len(limited_sto_names)}/{original_sto_count} STO")
        
        caption_lines.extend([
            f" • Risk Level: {risk_level}",
            f" • {len(valid_coordinates):,} data points",
            f" • {clustering_results['total_clusters']} cluster ditemukan",
            f" • Tingkat clustering: {clustering_results['clustering_rate']:.1f}%"
        ])
        
        if cluster_revenue_summary:
            total_cluster_revenue = sum([data['total_revenue'] for data in cluster_revenue_summary.values()])
            caption_lines.append(f" • Total cluster revenue: Rp {total_cluster_revenue:,}")
        
        caption_lines.append(f"\n📁 {file_size_mb:.1f} MB")

        await bot.send_document(chat_id, input_file, caption="\n".join(caption_lines))
        logging.info(f"Churn clustering analysis sent to user {user_id} for {len(limited_sto_names)} STOs")

        await bot.delete_message(chat_id, progress_message.message_id)

        # Cleanup
        try:
            os.remove(output_html_path)
            logging.debug(f"Cleaned up clustering HTML file: {output_html_path}")
        except Exception as cleanup_error:
            logging.warning(f"Could not clean up HTML file: {cleanup_error}")

    except Exception as e:
        logging.error(f"Error in churn clustering analysis: {e}", exc_info=True)
        error_message = "Terjadi kesalahan saat memproses analisis clustering churn risk."
        if progress_message:
            try:
                await bot.edit_message_text(text=error_message, chat_id=chat_id, message_id=progress_message.message_id)
            except Exception:
                await bot.send_message(chat_id, error_message)
        else:
            await bot.send_message(chat_id, error_message)


async def format_churn_data_sharelocation(chat_id: int, bot: 'Bot', user_id: int, latitude: float, longitude: float, risk_level: str, is_live: bool):
    """
    Analisis churn data berdasarkan lokasi dengan analisis clustering dan revenue.
    """
    progress_message = None
    try:
        logging.debug(f"=== Starting location churn clustering analysis for user {user_id} ===")
        
        # 1. Progress Message
        initial_progress = get_loading_bar(0)
        progress_text = f"Memproses Analisis Clustering Churn Berdasarkan Lokasi\n\n{initial_progress}\n\nMemulai analisis clustering..."
        progress_message = await bot.send_message(chat_id, progress_text)

        # 2. Ambil data churn berdasarkan risk level
        await update_progress_message(bot, chat_id, progress_message.message_id, 20, "Mengambil data churn risk...")
        
        months = await get_last_n_months(user_id, 3)  # Last 3 months including current

        churn_data = []
        if risk_level == "HIGH":
            churn_data = await get_churn_data_by_location_high(latitude, longitude, user_id=user_id)
            for item in churn_data:
                item['risk_level'] = 'HIGH'
        elif risk_level == "LOW-MID":
            churn_data = await get_churn_data_by_location_lowmid(latitude, longitude, user_id=user_id)
            for item in churn_data:
                item['risk_level'] = 'LOW-MID'

        elif risk_level == "BOTH":
            high_data = await get_churn_data_by_location_high(latitude, longitude, user_id=user_id)
            low_data = await get_churn_data_by_location_lowmid(latitude, longitude, user_id=user_id)
            for item in high_data:
                item['risk_level'] = 'HIGH'
            for item in low_data:
                item['risk_level'] = 'LOW-MID'
            churn_data = high_data + low_data

        if not churn_data:
            await bot.edit_message_text(
                text="Tidak ada data churn risk ditemukan di lokasi sekitar Anda.",
                chat_id=chat_id,
                message_id=progress_message.message_id
            )
            return

        # 3. ANALISIS CLUSTERING dengan Revenue
        await update_progress_message(bot, chat_id, progress_message.message_id, 40, "Melakukan analisis clustering lokasi...")
        
        analyzer = ChurnClusteringAnalyzer(radius_meters=300, min_cluster_size=5)
        
        # Siapkan data untuk clustering dengan revenue
        valid_churn_data = []
        for row in churn_data:
            try:
                lat = float(row.get("latitude", 0))
                lon = float(row.get("longitude", 0))
                revenue = int(row.get("rev_all", 0))
                
                if lat != 0 and lon != 0 and -90 <= lat <= 90 and -180 <= lon <= 180:
                    valid_churn_data.append({
                        'bb_id': row.get("bb_id", "N/A"),
                        'latitude': lat,
                        'longitude': lon,
                        'latlong': f"{lat},{lon}",
                        'customer_segment': row.get("customer_segment", "Unknown"),
                        'sto': row.get("sto", "N/A"),
                        'risk_level': row.get("risk_level", risk_level),
                        'revenue': revenue,
                        'city': row.get("city", "N/A")
                    })
            except (ValueError, TypeError):
                continue

        clustering_results = None
        df_clustered = None
        cluster_revenue_summary = {}

        if len(valid_churn_data) >= 5:
            df = pd.DataFrame(valid_churn_data)
            df_for_clustering = df[df['risk_level'] == 'HIGH'].copy() if risk_level == "BOTH" else df.copy()
            
            if len(df_for_clustering) >= 5:
                logging.info(f"Location clustering on {len(df_for_clustering)} users")
                df_clustered = analyzer.perform_clustering(df_for_clustering)
                clustering_results = analyzer.analyze_clusters(df_clustered)
                
                # Hitung revenue per cluster
                cluster_mapping = {}
                if df_clustered is not None and len(df_clustered) > 0:
                    for _, row in df_clustered.iterrows():
                        coord_key = f"{row['latitude']:.6f},{row['longitude']:.6f}"
                        cluster_mapping[coord_key] = row['cluster_id']
                
                cluster_revenues = {}
                for item in valid_churn_data:
                    coord_key = f"{item['latitude']:.6f},{item['longitude']:.6f}"
                    if coord_key in cluster_mapping:
                        cluster_id = cluster_mapping[coord_key]
                        item['cluster_id'] = cluster_id
                        if cluster_id != -1:
                            if cluster_id not in cluster_revenues:
                                cluster_revenues[cluster_id] = {'total_revenue': 0, 'user_count': 0}
                            cluster_revenues[cluster_id]['total_revenue'] += item['revenue']
                            cluster_revenues[cluster_id]['user_count'] += 1
                    else:
                        item['cluster_id'] = -1
                
                # Sort clusters by revenue and add rank info to coordinate data
                sorted_clusters = sorted(cluster_revenues.items(), 
                                       key=lambda x: x[1]['total_revenue'], 
                                       reverse=True)
                
                cluster_ranks = {}
                for rank, (cluster_id, data) in enumerate(sorted_clusters, 1):
                    cluster_ranks[cluster_id] = rank
                    cluster_revenue_summary[cluster_id] = {
                        'rank': rank,
                        'total_revenue': data['total_revenue'],
                        'user_count': data['user_count'],
                        'avg_revenue_per_user': data['total_revenue'] / data['user_count'] if data['user_count'] > 0 else 0
                    }
                
                # Add rank information to coordinate data for HTML display
                for item in valid_churn_data:
                    if item.get('cluster_id', -1) != -1:
                        item['cluster_rank'] = cluster_ranks.get(item['cluster_id'], 0)
                        item['cluster_total_revenue'] = cluster_revenues.get(item['cluster_id'], {}).get('total_revenue', 0)
                    else:
                        item['cluster_rank'] = 0
                        item['cluster_total_revenue'] = 0
            else:
                clustering_results = None
                for item in valid_churn_data:
                    item['cluster_id'] = -1
        else:
            clustering_results = None
            for item in valid_churn_data:
                item['cluster_id'] = -1

        # 4. Ambil data ODP
        await update_progress_message(bot, chat_id, progress_message.message_id, 50, "Mengambil data ODP...")
        odp_data = await get_odp_data_by_location(latitude, longitude)

        # 5. Generate Summary dengan Fokus Clustering dan Revenue
        await update_progress_message(bot, chat_id, progress_message.message_id, 60, "Menyusun summary clustering...")
        
        summary_lines = [
            f"📊 Analisis Clustering Churn Risk Berdasarkan Lokasi",
            "━━━━━━━━━━━━━━━",
            f"Lokasi Anda   : {latitude:.6f}, {longitude:.6f}",
            f"Risk Level    : {risk_level}",
            f"Radius Pencarian : ~500m bounding box",
            ""
        ]
        
        if clustering_results:
            # Dynamic labels based on risk_level
            if risk_level == "BOTH":
                high_count = len([c for c in valid_churn_data if c.get('risk_level') == 'HIGH'])
                lowmid_count = len([c for c in valid_churn_data if c.get('risk_level') == 'LOW-MID'])
                total_both = high_count + lowmid_count
                risk_label = f"Mappable Users di Area   : {total_both:,}\n" \
                            f"  ├─ HIGH Risk           : {high_count:,}\n" \
                            f"  └─ LOW-MID Risk        : {lowmid_count:,}\n" \
                            f"Clustering Scope         : HIGH Risk only"
            elif risk_level == "HIGH":
                risk_label = f"Mappable HIGH-Risk Users : {clustering_results['total_high_risk_users']:,}"
            else:  # LOW-MID
                risk_label = f"Mappable LOW-MID Users   : {clustering_results['total_high_risk_users']:,}"

            summary_lines.extend([
                "RINGKASAN CLUSTERING",
                "━━━━━━━━━━━━━━━",
                risk_label,
                f"Users dalam Cluster        : {clustering_results['clustered_users']:,}",
                f"Users Terisolasi          : {clustering_results['isolated_users']:,}",
                f"Tingkat Clustering        : {clustering_results['clustering_rate']:.1f}%",
                f"Cluster di Area Anda      : {clustering_results['total_clusters']}",
                f"Konsentrasi Maksimal      : {clustering_results['max_cluster_size']} users dalam 300m",
                ""
            ])

            # REVENUE PRIORITAS CLUSTER DEKAT ANDA
            if cluster_revenue_summary:
                total_cluster_revenue = sum([data['total_revenue'] for data in cluster_revenue_summary.values()])
                
                summary_lines.extend([
                    "💰 PRIORITAS CLUSTER BERDASARKAN REVENUE DI AREA ANDA",
                    "━━━━━━━━━━━━━━━"
                ])
                
                for cluster_id, data in sorted(cluster_revenue_summary.items(), key=lambda x: x[1]['rank']):
                    revenue_pct = (data['total_revenue'] / total_cluster_revenue * 100) if total_cluster_revenue > 0 else 0
                    summary_lines.extend([
                        f"Rank {data['rank']}. Cluster {cluster_id} (dekat Anda)",
                        f"   • Users: {data['user_count']} orang",
                        f"   • Total Revenue: Rp {data['total_revenue']:,}",
                        f"   • Rata-rata: Rp {data['avg_revenue_per_user']:,.0f}/user",
                        f"   • Kontribusi: {revenue_pct:.1f}%",
                        ""
                    ])
                
                summary_lines.extend([
                    f"Total Revenue Cluster Area: Rp {total_cluster_revenue:,}",
                    ""
                ])

            # AREA KONSENTRASI DEKAT ANDA
            if clustering_results['significant_cluster_details']:
                summary_lines.extend([
                    "🔥 AREA KONSENTRASI DEKAT ANDA",
                    "━━━━━━━━━━━━━━━"
                ])
                
                risk_label_display = "HIGH-RISK" if risk_level == "HIGH" else ("LOW-MID RISK" if risk_level == "LOW-MID" else "CHURN RISK")
                
                for i, cluster in enumerate(clustering_results['significant_cluster_details'][:3], 1):
                    user_count = cluster['user_count']
                    lat_center = cluster['lat_center']
                    lng_center = cluster['lng_center']
                    
                    # Hitung jarak dari lokasi user
                    distance = geodesic((latitude, longitude), (lat_center, lng_center)).meters
                    
                    # Info revenue jika ada
                    revenue_info = ""
                    if cluster.get('cluster_id') in cluster_revenue_summary:
                        rev_data = cluster_revenue_summary[cluster['cluster_id']]
                        revenue_info = f" | Revenue: Rp {rev_data['total_revenue']:,}"
                    
                    summary_lines.extend([
                        f"{i}. {user_count} {risk_label_display} users dalam cluster{revenue_info}",  # CHANGED
                        f"   • Jarak dari Anda: ~{distance:.0f}m",
                        f"   • Center: {lat_center:.4f}, {lng_center:.4f}",
                        ""
                    ])
            
            # PENILAIAN RISIKO UNTUK AREA ANDA
            clustering_rate = clustering_results['clustering_rate']
            max_concentration = clustering_results['max_cluster_size']
            
            summary_lines.extend([
                "⚠️ PENILAIAN RISIKO UNTUK AREA ANDA",
                "━━━━━━━━━━━━━━━"
            ])
            
            if clustering_rate > 60:
                summary_lines.extend([
                    "RISIKO CLUSTERING TINGGI DI AREA ANDA",
                    "   Pola clustering churn kuat dekat lokasi Anda!",
                    "   Terdeteksi multiple area konsentrasi."
                ])
            elif clustering_rate > 30:
                summary_lines.extend([
                    "RISIKO CLUSTERING SEDANG",
                    "   Beberapa pola konsentrasi churn di area Anda.",
                    "   Monitor kualitas layanan setempat."
                ])
            else:
                summary_lines.extend([
                    "RISIKO CLUSTERING RENDAH",
                    "   Risiko churn terdistribusi baik di area Anda.",
                    "   Tidak ada concern konsentrasi major."
                ])
                
            if max_concentration >= 10:
                risk_label_display = "HIGH-RISK" if risk_level == "HIGH" else ("LOW-MID RISK" if risk_level == "LOW-MID" else "CHURN RISK")
                
                summary_lines.extend([
                    "",
                    f"HOTSPOT KRITIS DEKAT ANDA",
                    f"   {max_concentration} {risk_label_display} users dalam satu area!",  # CHANGED
                    f"   Pertimbangkan cek kualitas jaringan lokal."
                ])
        else:
            # Dynamic label for no-clustering case
            if risk_level == "BOTH":
                high_count = len([c for c in valid_churn_data if c.get('risk_level') == 'HIGH'])
                lowmid_count = len([c for c in valid_churn_data if c.get('risk_level') == 'LOW-MID'])
                no_cluster_label = f"Total Users Ditemukan    : {len(valid_churn_data):,}\n" \
                                f"  ├─ HIGH Risk           : {high_count:,}\n" \
                                f"  └─ LOW-MID Risk        : {lowmid_count:,}"
            elif risk_level == "HIGH":
                no_cluster_label = f"HIGH-Risk Users Ditemukan  : {len(valid_churn_data):,}"
            else:  # LOW-MID
                no_cluster_label = f"LOW-MID Users Ditemukan    : {len(valid_churn_data):,}"
            
            summary_lines.extend([
                "ANALISIS CLUSTERING",
                "━━━━━━━━━━━━━━━",
                no_cluster_label,
                "Analisis Clustering        : Data tidak cukup (perlu ≥5 users)",
                "Distribusi Risk           : Individual users, tidak ada cluster",
                ""
            ])

        # Breakdown segment dasar
        segment_counts = {}
        total_revenue_area = 0
        for item in valid_churn_data:
            seg = item.get('customer_segment', 'Unknown')
            segment_counts[seg] = segment_counts.get(seg, 0) + 1
            total_revenue_area += item.get('revenue', 0)
        
        if segment_counts:
            summary_lines.extend([
                "📊 BREAKDOWN TEN SEGMENTS DI SEKITAR ANDA",
                "━━━━━━━━━━━━━━━"
            ])
            for seg, count in sorted(segment_counts.items(), key=lambda x: x[1], reverse=True):
                summary_lines.append(f"• {seg}: {count:,} users")
            summary_lines.extend([
                "",
                f"Total Revenue Area: Rp {total_revenue_area:,}",
                f"Rata-rata Revenue: Rp {total_revenue_area / len(valid_churn_data):,.0f}/user" if valid_churn_data else "Rp 0/user",
                ""
            ])

        # Info infrastruktur
        summary_lines.extend([
            "🏠 INFO ALAT PRODUKSI",
            "━━━━━━━━━━━━━━━",
            f"Titik ODP Ditemukan : {len(odp_data):,}",
            f"Peta Interaktif     : Visualisasi clustering disertakan",
            ""
        ])
        
        summary_content = "\n".join(summary_lines)
        await send_churn_report_location_with_formatting(bot, chat_id, summary_content)

        # 6. Generate location-based heatmap dengan clustering dan revenue
        await update_progress_message(bot, chat_id, progress_message.message_id, 70, "Generate location clustering heatmap...")
        
        if valid_churn_data:
            output_html_path = await generate_churn_heatmap_html_sharelocation(
                user_id, valid_churn_data, odp_data, latitude, longitude, risk_level, is_live,
                progress_callback=lambda p, s: update_progress_message(bot, chat_id, progress_message.message_id, 70 + p * 0.25, s)
            )

            # 7. Kirim heatmap file
            if os.path.exists(output_html_path):
                file_size_mb = os.path.getsize(output_html_path) / (1024 * 1024)
                await update_progress_message(bot, chat_id, progress_message.message_id, 95, f"Upload clustering map ({file_size_mb:.1f} MB)...")

                input_file = FSInputFile(output_html_path, filename=os.path.basename(output_html_path))
                
                caption_lines = [
                    f"📊 Location Churn CLUSTERING Map dengan Revenue",
                    f" • Lokasi Anda: {latitude:.4f}, {longitude:.4f}",
                    f" • Risk Level: {risk_level}",
                    f" • {len(valid_churn_data):,} churn points",
                    f" • {len(odp_data):,} ODP points"
                ]
                
                if clustering_results:
                    caption_lines.extend([
                        f" • {clustering_results['total_clusters']} cluster ditemukan",
                        f" • Tingkat clustering: {clustering_results['clustering_rate']:.1f}%"
                    ])
                
                if cluster_revenue_summary:
                    total_area_revenue = sum([data['total_revenue'] for data in cluster_revenue_summary.values()])
                    caption_lines.append(f"💰 Revenue area: Rp {total_area_revenue:,}")
                
                caption_lines.append(f"📁 {file_size_mb:.1f} MB")

                await bot.send_document(chat_id, input_file, caption="\n".join(caption_lines))
                
                # Cleanup
                try:
                    os.remove(output_html_path)
                except Exception:
                    pass

        await bot.delete_message(chat_id, progress_message.message_id)

    except Exception as e:
        logging.error(f"Error in location churn clustering analysis: {e}", exc_info=True)
        error_message = "Terjadi kesalahan saat memproses analisis clustering lokasi."
        if progress_message:
            try:
                await bot.edit_message_text(text=error_message, chat_id=chat_id, message_id=progress_message.message_id)
            except Exception:
                await bot.send_message(chat_id, error_message)
        else:
            await bot.send_message(chat_id, error_message)



# Helper function to format extracted data for display
def format_extracted_kv_data_display(extracted_data: list) -> str:
    """Format extracted data into a readable string for user display."""
    if not extracted_data:
        return "Tidak ada data yang berhasil diekstrak."
    
    # Get provider name (assuming all packages are from same provider)
    provider_name = extracted_data[0].get('Provider_Name', 'Unknown')
    
    # Format header
    result = f"✅ Informasi berhasil diekstrak:\n\n"
    result += f"🔖 Provider Name: *{provider_name}*\n\n"
    
    # Format each package
    for i, package in enumerate(extracted_data, 1):
        package_name = package.get('Package_Name', 'Unknown')
        speed = package.get('Speed', 0)
        price = package.get('Price', 0)
        
        # Format price (convert to K format if needed)
        if price >= 1000:
            if price % 1000 == 0:
                price_str = f"{price // 1000}K"
            else:
                price_str = f"{price:,.0f}"
        else:
            price_str = f"{price}"
            
        result += f"📦 *Package {i}:* `{package_name}` - *{speed} Mbps* - `{price_str}`\n"
    
    result += f"\n📍 *Di mana promo ini ditemukan?* Silakan pilih Branch/Kota:"
    return result


async def format_calendar_period_selector(event: Union[Message, CallbackQuery], bot: Bot, user_id: int, chat_id: int):
    """Generic calendar-based period selector for all commands."""
    try:
        # Get current date for context
        current_date = datetime.now()
        current_month_str = current_date.strftime("%Y%m")  # For comparison (e.g., "202507")

        # Determine currently selected month for display based on user state
        stored_period = await get_user_selected_period(user_id)
        current_month = current_date.strftime("%B %Y") # Default fallback

        try:
            if stored_period and stored_period.startswith("RANGE:"):
                # Format: RANGE:20250101-20250131
                # We use the end date to represent the "Month" context displayed to user
                date_part = stored_period.split(":", 1)[1]
                _, end_str = date_part.split("-")
                end_dt = datetime.strptime(end_str, "%Y%m%d")
                current_month = end_dt.strftime("%B %Y")
            elif stored_period:
                # Format: YYYYMM
                dt = datetime.strptime(stored_period, "%Y%m")
                current_month = dt.strftime("%B %Y")
        except Exception:
            pass # Keep default if parsing fails
        
        # Create month selection keyboard (last 12 months)
        keyboard_rows = []
        for i in range(12):
            date_offset = current_date - timedelta(days=30*i)
            period_str = date_offset.strftime("%Y%m")
            
            # Format as MMM-YY (e.g., "Jul-25")
            month_name = date_offset.strftime("%b-%y")
            
            # Add (Now) indicator for current month
            if period_str == current_month_str:
                month_name += " (Now)"
            
            # Add 2 months per row
            if i % 2 == 0:
                keyboard_rows.append([])
            
            keyboard_rows[-1].append(
                InlineKeyboardButton(
                    text=month_name,
                    callback_data=f"select_period_range:{period_str}"
                )
            )
        
        # Add cancel button
        keyboard_rows.append([
            InlineKeyboardButton(text="❌ Batal", callback_data="cancel_calendar_selection")
        ])
        
        keyboard = InlineKeyboardMarkup(inline_keyboard=keyboard_rows)
        
        text = (
            f"📅 *Pilih Periode:*\n\n"
            f"*Langkah:*\n"
            f" 1. Pilih bulan periode\n"
            f" 2. Pilih tanggal mulai\n"
            f" 3. Pilih tanggal akhir\n\n"
            f"*Terpilih saat ini:* {current_month}\n\n"
            f"💡 *Info:*\n"
            f"• `/a3`, `/wok` - Filter hari spesifik\n"
            f"• `/nas`, `/agency` - Data bulanan"
        )
        
        if isinstance(event, CallbackQuery):
            await event.message.edit_text(text, reply_markup=keyboard, parse_mode="Markdown")
        else:
            await event.answer(text, reply_markup=keyboard, parse_mode="Markdown")
            
    except Exception as e:
        logger.error(f"Error in calendar period selector: {e}", exc_info=True)
        
        # Fallback message
        fallback_text = "❌ Terjadi kesalahan saat menampilkan calendar selector"
        if isinstance(event, CallbackQuery):
            await event.message.edit_text(fallback_text)
        else:
            await event.answer(fallback_text)


