async def send_odp_history_search(chat_id, odp_names):
    logger.info(f"User {chat_id} attempting to search ODP names: {odp_names}.")

    results = []
    not_found_odps = []
    for odp_name in odp_names:
        rows = await fetch_odp_history(odp_name)
        if not rows:
            logging.info(f"No data found for {odp_name}")
            not_found_odps.append(odp_name)
            continue  # Skip to the next ODP if no data is found
        results.extend(rows)
    if not results:
        return None, not_found_odps
    return results, not_found_odps


