def build_kab_keyboard(all_kabs: list, selected_kabs: list, correction_mode: bool = False, show_select_all: bool = False):
    """Helper to build the multi-select keyboard."""
    builder = InlineKeyboardBuilder()

    # Sort kabs for consistent display
    for kab_name in sorted(all_kabs):
        # Check if this kab is selected
        is_selected = kab_name in selected_kabs

        # Add checkmark if selected
        text = f"✅ {kab_name}" if is_selected else kab_name

        builder.button(text=text, callback_data=f"kabselect:{kab_name}")

    builder.adjust(3) # 3 columns

    # "Semua Kota" toggle button
    if show_select_all:
        all_selected = set(all_kabs) == set(selected_kabs)
        select_all_text = "☑️ Semua Kota" if all_selected else "⬜ Semua Kota"
        builder.row(InlineKeyboardButton(text=select_all_text, callback_data="kab_select_all"))

    # Logic buttons
    buttons_row = []

    # Show "Selesai" only if at least one is selected
    if selected_kabs:
        buttons_row.append(InlineKeyboardButton(text=f"💾 Selesai ({len(selected_kabs)})", callback_data="kab_done"))

    # Correction toggle (changes text based on mode)
    if correction_mode:
        buttons_row.append(InlineKeyboardButton(text="✏️ Mode Koreksi: ON", callback_data="lapor_correction_request"))
    else:
        buttons_row.append(InlineKeyboardButton(text="✏️ Koreksi", callback_data="lapor_correction_request"))

    builder.row(*buttons_row)
    builder.row(InlineKeyboardButton(text="❌ Batal", callback_data="cancel_flow:lapor"))

    return builder.as_markup()


def build_lapor_branch_keyboard() -> InlineKeyboardMarkup:
    """Build the /lapor branch picker keyboard in 3-column layout (one column per region)."""
    region_order = ["JATENG-DIY", "JATIM", "BALI NUSRA"]
    columns = []
    for region_name in region_order:
        branches = sorted(REGION_BRANCH_MAPPING.get(region_name, []))
        columns.append((region_name, branches))

    # Row 1: Region headers
    rows = [[
        InlineKeyboardButton(text=f"📍{name}", callback_data="none")
        for name, _ in columns
    ]]

    # Branch rows: zip columns, fill shorter ones with empty placeholders
    max_branches = max(len(branches) for _, branches in columns)
    for i in range(max_branches):
        row = []
        for region_name, branches in columns:
            if i < len(branches):
                row.append(InlineKeyboardButton(text=branches[i], callback_data=f"lapor_branch:{branches[i]}"))
            else:
                row.append(InlineKeyboardButton(text=" ", callback_data="none"))
        rows.append(row)

    # ALL Branch row (one per region)
    rows.append([
        InlineKeyboardButton(text=f"📦 ALL", callback_data=f"lapor_allbranch:{name}")
        for name, _ in columns
    ])

    # Cancel button
    rows.append([InlineKeyboardButton(text="❌ Batal", callback_data="cancel_flow:lapor")])

    return InlineKeyboardMarkup(inline_keyboard=rows)


async def build_dedup_index() -> dict:
    """Read the CSV once and return lookup sets for fast duplicate checking.

    Returns a dict with two sets:
        'hash_loc'   : set of (image_hash, location) tuples
        'content_loc': set of (package_name, speed, price, location) tuples
    """
    index = {'hash_loc': set(), 'content_loc': set()}

    def _read():
        try:
            if not os.path.isfile(NEW_CSV_FILE):
                return index
            with open(NEW_CSV_FILE, 'r', encoding='utf-8') as f:
                reader = csv.DictReader(f)
                for row in reader:
                    loc = row.get('found', '').strip()
                    h = row.get('image_hash', '').strip()
                    if h and loc:
                        index['hash_loc'].add((h, loc))
                    pkg = row.get('package_name', '').strip()
                    spd = row.get('speed', '').strip()
                    prc = row.get('price', '').strip()
                    if pkg and spd and prc and loc:
                        index['content_loc'].add((pkg, spd, prc, loc))
        except Exception as e:
            logger.warning(f"Error building dedup index: {e}. Returning empty index.")
        return index

    return await async_run_in_thread(_read)


async def save_to_new_csv(extracted_data: list, user_id: int, username: str, image_path: str, dedup_index: dict = None):
    """Asynchronously saves extracted data to the main CSV file, checking for duplicates.

    Args:
        dedup_index: Pre-built index from build_dedup_index(). When provided,
                     uses in-memory lookup (no CSV re-read) and skips image
                     deletion on duplicate so the shared file stays intact.
    """
    logger.debug("Asynchronously saving extracted data to CSV.")
    timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    
    # Robust data validation and normalization
    if not extracted_data:
        logger.warning("Empty extracted_data provided, creating default entry")
        extracted_data = [{'Provider_Name': 'unknown', 'Package_Name': None, 'Speed': '', 'Price': '', 'Gimmick': ''}]
    
    if isinstance(extracted_data, dict):
        extracted_data = [extracted_data]
    
    # Ensure we have at least one data entry
    if not extracted_data or len(extracted_data) == 0:
        logger.warning("No valid data entries found, creating default entry")
        extracted_data = [{'Provider_Name': 'unknown', 'Package_Name': None, 'Speed': '', 'Price': '', 'Gimmick': ''}]

    # Robust package name extraction with multiple fallbacks
    def get_sanitized_package_name(data_entry):
        """Extract and sanitize package name with robust fallbacks."""
        try:
            # Try Package_Name first
            package_name = data_entry.get('Package_Name')
            
            # If Package_Name is None or empty, try alternative sources
            if not package_name:
                # Try Provider_Name as fallback
                package_name = data_entry.get('Provider_Name')
                
            # If still None or empty, use default
            if not package_name:
                package_name = 'unknown'
                
            # Ensure it's a string
            package_name = str(package_name)
            
            # Sanitize the name
            sanitized = ''.join(c for c in package_name if c.isalnum())
            
            # If sanitization results in empty string, use fallback
            if not sanitized.strip():
                sanitized = 'unknown'
                
            return sanitized.rstrip()
            
        except Exception as e:
            logger.warning(f"Error sanitizing package name: {e}, using 'unknown'")
            return 'unknown'
    
    # Get sanitized name with fallbacks
    sanitized_name = get_sanitized_package_name(extracted_data[0])
    
    # Create filename with fallback pattern
    try:
        summary_filename = f"{sanitized_name}_{user_id}_{timestamp}.jpg"
        summary_image_path = os.path.join(BROSUR_DIR, summary_filename)
    except Exception as e:
        logger.warning(f"Error creating filename, using fallback: {e}")
        summary_filename = f"unknown_{user_id}_{timestamp}.jpg"
        summary_image_path = os.path.join(BROSUR_DIR, summary_filename)

    # Compute hash on temp file BEFORE renaming
    try:
        image_hash = await async_run_in_thread(compute_image_hash, image_path)
    except Exception as e:
        logger.error(f"Error computing image hash: {e}. Using timestamp as fallback.")
        image_hash = f"fallback_{timestamp}_{user_id}"

    # Extract location from first package for duplicate checking
    location = extracted_data[0].get('Found', '').strip() if extracted_data else ''

    # Check file existence with error handling
    try:
        file_exists = await async_run_in_thread(os.path.isfile, NEW_CSV_FILE)
    except Exception as e:
        logger.warning(f"Error checking file existence: {e}. Assuming file doesn't exist.")
        file_exists = False

    # --- Duplicate checking ---
    if dedup_index is not None:
        # Fast path: use pre-built in-memory index (bulk insert)
        try:
            # Check 1: Image hash + location
            if (image_hash, location) in dedup_index['hash_loc']:
                logger.warning(f"[bulk] Duplicate image hash for location '{location}'")
                raise ValueError("Gambar yang sama sudah pernah dilaporkan untuk lokasi ini")

            # Check 2: Content + location
            for package in extracted_data:
                pkg_name = str(package.get('Package_Name', '')).strip()
                pkg_speed = str(package.get('Speed', '')).strip()
                pkg_price = str(package.get('Price', '')).strip()
                if pkg_name and pkg_speed and pkg_price:
                    if (pkg_name, pkg_speed, pkg_price, location) in dedup_index['content_loc']:
                        logger.warning(f"[bulk] Duplicate content {pkg_name}|{pkg_speed}|{pkg_price} for '{location}'")
                        raise ValueError(f"Paket '{pkg_name}' dengan kecepatan {pkg_speed}Mbps dan harga Rp{pkg_price} sudah pernah dilaporkan untuk lokasi ini")
        except ValueError:
            raise
        except Exception as e:
            logger.warning(f"Error during bulk dedup check: {e}. Proceeding without duplicate check.")

    elif file_exists:
        # Original path: read CSV from disk (single-city save)
        try:
            def check_duplicates():
                try:
                    with open(NEW_CSV_FILE, 'r', encoding='utf-8') as f:
                        reader = csv.DictReader(f)
                        for row in reader:
                            row_location = row.get('found', '').strip()

                            # Only check duplicates within same location
                            if row_location == location:
                                # Check 1: Image hash duplicate (same image, same location)
                                if row.get('image_hash') == image_hash:
                                    logger.warning(f"Duplicate image hash found: {image_hash[:8]}... for location '{location}'")
                                    return True, "Gambar yang sama sudah pernah dilaporkan untuk lokasi ini"

                                # Check 2: Content duplicate (package_name + speed + price combination)
                                for package in extracted_data:
                                    pkg_name = str(package.get('Package_Name', '')).strip()
                                    pkg_speed = str(package.get('Speed', '')).strip()
                                    pkg_price = str(package.get('Price', '')).strip()

                                    row_pkg_name = row.get('package_name', '').strip()
                                    row_speed = row.get('speed', '').strip()
                                    row_price = row.get('price', '').strip()

                                    # All three fields must match and not be empty
                                    if (pkg_name and pkg_speed and pkg_price and
                                        pkg_name == row_pkg_name and
                                        pkg_speed == row_speed and
                                        pkg_price == row_price):
                                        logger.warning(f"Duplicate content found: {pkg_name} | {pkg_speed} | {pkg_price} in location '{location}'")
                                        return True, f"Paket '{pkg_name}' dengan kecepatan {pkg_speed}Mbps dan harga Rp{pkg_price} sudah pernah dilaporkan untuk lokasi ini"

                    return False, None
                except Exception as e:
                    logger.warning(f"Error during duplicate check: {e}. Proceeding without duplicate check.")
                    return False, None

            duplicate_found, error_message = await async_run_in_thread(check_duplicates)
            if duplicate_found:
                # Delete temp file since it's a duplicate (safe for single-city saves)
                try:
                    if await async_file_exists(image_path):
                        await async_remove_file(image_path)
                        logger.info(f"Deleted duplicate temp file: {image_path}")
                except Exception as del_err:
                    logger.warning(f"Failed to delete duplicate temp file: {del_err}")

                raise ValueError(error_message or "Data duplikat terdeteksi untuk lokasi ini")
        except ValueError:
            # Re-raise ValueError for duplicate detection (backward compatibility)
            raise
        except Exception as e:
            logger.warning(f"Error during duplicate check process: {e}. Proceeding without duplicate check.")

    # Now rename the file (only if no duplicate found)
    try:
        # Normalize paths for comparison
        abs_image_path = os.path.abspath(image_path)
        abs_summary_path = os.path.abspath(summary_image_path)

        if abs_image_path != abs_summary_path:
            await async_run_in_thread(os.rename, image_path, summary_image_path)
            logger.info(f"Image renamed from {image_path} to {summary_image_path}")
        else:
            logger.debug("Image path matches summary path, skipping rename (already renamed).")
            
    except Exception as e:
        logger.error(f"Error renaming image file: {e}. Using original path.")
        summary_image_path = image_path

    # Robust data normalization function
    def normalize_field_value(value, field_name="unknown"):
        """Normalize field values with type conversion and fallbacks."""
        try:
            if value is None:
                return ''
            
            # Handle list/array types (like Gimmick field)
            if isinstance(value, (list, tuple)):
                # Join list items with comma separator
                try:
                    str_items = [str(item) for item in value if item is not None]
                    return ', '.join(str_items) if str_items else ''
                except:
                    return str(value)
            
            # Convert to string and strip whitespace
            return str(value).strip()
            
        except Exception as e:
            logger.warning(f"Error normalizing field {field_name}: {e}. Using empty string.")
            return ''

    # Robust CSV writing
    def write_csv_data():
        try:
            fieldnames = ['provider_name', 'package_name', 'speed', 'price', 'gimmicks', 'id_telegram', 'username_telegram', 'timestamp', 'source', 'found', 'image_hash']
            
            with open(NEW_CSV_FILE, 'a', newline='', encoding='utf-8') as f:
                writer = csv.DictWriter(f, fieldnames=fieldnames)
                
                if not file_exists:
                    writer.writeheader()
                
                for package in extracted_data:
                    try:
                        # Robust data extraction with fallbacks
                        row_data = {
                            'provider_name': normalize_field_value(package.get('Provider_Name'), 'Provider_Name'),
                            'package_name': normalize_field_value(package.get('Package_Name'), 'Package_Name'),
                            'speed': normalize_field_value(package.get('Speed'), 'Speed'),
                            'price': normalize_field_value(package.get('Price'), 'Price'),
                            'gimmicks': normalize_field_value(package.get('Gimmick'), 'Gimmick'),
                            'id_telegram': str(user_id) if user_id is not None else '',
                            'username_telegram': str(username) if username is not None else '',
                            'timestamp': timestamp,
                            'source': os.path.abspath(summary_image_path) if summary_image_path else '',
                            'found': normalize_field_value(package.get('Found'), 'Found'),
                            'image_hash': image_hash,
                        }
                        
                        writer.writerow(row_data)
                        logger.debug(f"Wrote row for package: {row_data.get('package_name', 'unknown')}")
                        
                    except Exception as row_error:
                        logger.error(f"Error writing individual row: {row_error}. Skipping this entry.")
                        continue
                        
        except Exception as write_error:
            logger.error(f"Fatal error during CSV write operation: {write_error}")
            raise
    
    try:
        await async_run_in_thread(write_csv_data)
        logger.debug("Data saved to CSV successfully.")

        # Update in-memory dedup index so subsequent bulk saves see this entry
        if dedup_index is not None:
            dedup_index['hash_loc'].add((image_hash, location))
            for package in extracted_data:
                pkg_name = str(package.get('Package_Name', '')).strip()
                pkg_speed = str(package.get('Speed', '')).strip()
                pkg_price = str(package.get('Price', '')).strip()
                if pkg_name and pkg_speed and pkg_price:
                    dedup_index['content_loc'].add((pkg_name, pkg_speed, pkg_price, location))

        return summary_image_path, image_hash  # Return renamed path and hash
    except Exception as e:
        logger.error(f"Failed to save data to CSV: {e}")
        raise


async def save_to_corrections_csv(extracted_data: list, user_id: int, username: str, image_path: str, image_hash: str):
    """Save extracted data to corrections CSV with is_need_correction=1 flag."""
    logger.debug("Saving data to corrections CSV.")
    timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    
    # Use same validation logic as main CSV
    if not extracted_data:
        logger.warning("Empty extracted_data for corrections")
        extracted_data = [{'Provider_Name': 'unknown', 'Package_Name': None, 'Speed': '', 'Price': '', 'Gimmick': ''}]
    
    if isinstance(extracted_data, dict):
        extracted_data = [extracted_data]
    
    if not extracted_data or len(extracted_data) == 0:
        extracted_data = [{'Provider_Name': 'unknown', 'Package_Name': None, 'Speed': '', 'Price': '', 'Gimmick': ''}]
    
    # Extract location for duplicate checking
    location = extracted_data[0].get('Found', '').strip() if extracted_data else ''
    
    # Check if corrections file exists
    try:
        file_exists = await async_run_in_thread(os.path.isfile, CORRECTIONS_CSV_FILE)
    except Exception as e:
        logger.warning(f"Error checking corrections file: {e}")
        file_exists = False
    
    # Duplicate checking for corrections CSV (same logic as main)
    if file_exists:
        try:
            def check_duplicates():
                try:
                    with open(CORRECTIONS_CSV_FILE, 'r', encoding='utf-8') as f:
                        reader = csv.DictReader(f)
                        for row in reader:
                            row_location = row.get('found', '').strip()
                            
                            if row_location == location:
                                # Check image hash
                                if row.get('image_hash') == image_hash:
                                    logger.warning(f"Duplicate correction hash: {image_hash[:8]}... for location '{location}'")
                                    return True, "Gambar yang sama sudah pernah dilaporkan untuk koreksi di lokasi ini"
                                
                                # Check content duplicate
                                for package in extracted_data:
                                    pkg_name = str(package.get('Package_Name', '')).strip()
                                    pkg_speed = str(package.get('Speed', '')).strip()
                                    pkg_price = str(package.get('Price', '')).strip()
                                    
                                    row_pkg_name = row.get('package_name', '').strip()
                                    row_speed = row.get('speed', '').strip()
                                    row_price = row.get('price', '').strip()
                                    
                                    if (pkg_name and pkg_speed and pkg_price and
                                        pkg_name == row_pkg_name and 
                                        pkg_speed == row_speed and 
                                        pkg_price == row_price):
                                        logger.warning(f"Duplicate correction content: {pkg_name} | {pkg_speed} | {pkg_price} in '{location}'")
                                        return True, f"Paket '{pkg_name}' sudah pernah dilaporkan untuk koreksi di lokasi ini"
                        
                    return False, None
                except Exception as e:
                    logger.warning(f"Error checking corrections duplicates: {e}")
                    return False, None
            
            duplicate_found, error_message = await async_run_in_thread(check_duplicates)
            if duplicate_found:
                raise ValueError(error_message or "Data duplikat terdeteksi di corrections CSV")
        except ValueError:
            raise
        except Exception as e:
            logger.warning(f"Error during corrections duplicate check: {e}")
    
    # Normalize field value (reuse from main CSV)
    def normalize_field_value(value, field_name="unknown"):
        try:
            if value is None:
                return ''
            if isinstance(value, (list, tuple)):
                try:
                    str_items = [str(item) for item in value if item is not None]
                    return ', '.join(str_items) if str_items else ''
                except:
                    return str(value)
            return str(value).strip()
        except Exception as e:
            logger.warning(f"Error normalizing field {field_name}: {e}")
            return ''
    
    # Write to corrections CSV
    def write_corrections_csv():
        try:
            # Note the extra column: is_need_correction
            fieldnames = ['provider_name', 'package_name', 'speed', 'price', 'gimmicks', 
                         'id_telegram', 'username_telegram', 'timestamp', 'source', 
                         'found', 'image_hash', 'is_need_correction']
            
            with open(CORRECTIONS_CSV_FILE, 'a', newline='', encoding='utf-8') as f:
                writer = csv.DictWriter(f, fieldnames=fieldnames)
                
                if not file_exists:
                    writer.writeheader()
                
                for package in extracted_data:
                    try:
                        row_data = {
                            'provider_name': normalize_field_value(package.get('Provider_Name'), 'Provider_Name'),
                            'package_name': normalize_field_value(package.get('Package_Name'), 'Package_Name'),
                            'speed': normalize_field_value(package.get('Speed'), 'Speed'),
                            'price': normalize_field_value(package.get('Price'), 'Price'),
                            'gimmicks': normalize_field_value(package.get('Gimmick'), 'Gimmick'),
                            'id_telegram': str(user_id) if user_id is not None else '',
                            'username_telegram': str(username) if username is not None else '',
                            'timestamp': timestamp,
                            'source': os.path.abspath(image_path) if image_path else '',
                            'found': normalize_field_value(package.get('Found'), 'Found'),
                            'image_hash': image_hash,
                            'is_need_correction': '1',  # Always 1 for corrections
                        }
                        
                        writer.writerow(row_data)
                        logger.debug(f"Wrote correction row for: {row_data.get('package_name', 'unknown')}")
                        
                    except Exception as row_error:
                        logger.error(f"Error writing correction row: {row_error}")
                        continue
                        
        except Exception as write_error:
            logger.error(f"Fatal error writing corrections CSV: {write_error}")
            raise
    
    try:
        await async_run_in_thread(write_corrections_csv)
        logger.debug("Data saved to corrections CSV successfully.")
    except Exception as e:
        logger.error(f"Failed to save corrections CSV: {e}")
        raise


# Helper functions for async file operations
async def async_file_exists(file_path: str) -> bool:
    """Check if file exists asynchronously."""
    try:
        await aiofiles.os.stat(file_path)
        return True
    except FileNotFoundError:
        return False
    except Exception:
        return False


async def async_remove_file(file_path: str) -> None:
    """Remove file asynchronously."""
    await aiofiles.os.remove(file_path)

