# Assuming you have your logger and client setup elsewhere
logger = logging.getLogger(__name__)

async def make_openai_request_with_fallback(client, messages, model="gpt-5-nano-2025-08-07", max_tokens=8192, temperature=1, max_retries=3, operation_name="AI request"):
    """
    Make OpenAI request designed STRICTLY for Newer Architectures (GPT-5, o1).
    - Uses 'max_completion_tokens' instead of 'max_tokens'.
    - Ignores 'temperature' argument completely (enforces model default).
    """
    for attempt in range(max_retries):
        try:
            logger.debug(f"Attempting {operation_name}, try {attempt + 1}/{max_retries}")
            
            # STATIC NEWER ARCHITECTURE CALL
            # We explicitly do NOT pass 'temperature' to avoid Error 400.
            response = await client.chat.completions.create(
                model=model,
                messages=messages,
                max_completion_tokens=max_tokens, # The new standard parameter
                n=1,
            )
            
            result = response.choices[0].message.content.strip()
            logger.debug(f"{operation_name} successful on attempt {attempt + 1}")
            return True, result, None
            
        except asyncio.TimeoutError:
            logger.warning(f"{operation_name} timed out on attempt {attempt + 1}")
            if attempt == max_retries - 1:
                return False, None, "⏱️ OpenAI tidak merespons dalam waktu yang wajar. Coba lagi nanti."
            await asyncio.sleep(2 ** attempt)
            
        except Exception as e:
            error_str = str(e).lower()
            logger.warning(f"{operation_name} failed on attempt {attempt + 1}: {e}")
            
            # Critical Configuration Errors (Don't retry these)
            if "unsupported" in error_str or "parameter" in error_str:
                 logger.error(f"Critical API Mismatch: {e}")
                 return False, None, f"⚙️ Config Error: {str(e)[:100]}"

            # Standard Error Handling
            if "error code: 500" in error_str or "server_error" in error_str:
                if attempt == max_retries - 1:
                    return False, None, "🔧 Server OpenAI sedang bermasalah."
                await asyncio.sleep(3 * (attempt + 1))
            elif "rate_limit" in error_str:
                if attempt == max_retries - 1:
                    return False, None, "⚡ Terlalu banyak permintaan ke OpenAI."
                await asyncio.sleep(10 * (attempt + 1))
            else:
                if attempt == max_retries - 1:
                    return False, None, f"❌ Kesalahan tidak dikenal: {str(e)[:100]}..."
                await asyncio.sleep(2 ** attempt)
    
    return False, None, "❌ Gagal menghubungi OpenAI."


async def validate_brochure_image(image_path: str) -> Tuple[bool, Optional[str]]:
    """
    Use Gemini to validate if the image is a brochure.
    """
    logger.debug(f"Validating if the image {image_path} is a brochure.")

    try:
        prompt_text = (
            "Is the image a brochure/flyer/marketing materials of internet provider products in Indonesia? "
            "Look for keywords like 'Mbps', 'Internet', 'Wifi', 'Provider'. Answer 'Yes' or 'No' Only."
        )

        # Step 1: Validation
        success, response_text, error_message = await make_gemini_vision_request(prompt_text, image_path)

        if not success:
            return False, error_message

        response_text = response_text.lower()
        if 'yes' in response_text:
            return True, None

        # Step 2: Description (if not a brochure)
        description_prompt = (
            "Describe the image content in 3 words maximum. "
            "Answer only with the <3 words in Bahasa Indonesia>."
        )

        success, description, error_message = await make_gemini_vision_request(description_prompt, image_path)

        if not success:
            return False, "tidak dapat dideskripsikan"

        return False, description

    except Exception as e:
        logger.error(f"Unexpected error: {e}", exc_info=True)
        return False, "kesalahan sistem"


async def extract_information(image_path: str, bot, chat_id) -> Tuple[Optional[List[Dict]], Optional[str]]:
    """Extract information strictly using Gemini vision."""
    logger.debug(f"Extracting information from image {image_path}")

    try:
        prompt_text = (
            "You are an AI model tasked to extract content from Indonesian fixed broadband provider marketing materials. "
            "Please extract the following information from the image:\n"
            "1. Provider_Name (e.g., Indihome, Biznet, Firstmedia, IconNet, MyRepublic)\n"
            "2. Package_Name\n"
            "3. Speed (Note: Sanitize the speed value, e.g., 100Mbps should be 100, and convert any speed unit to Mbps)\n"
            "4. Price (Note: Sanitize the price value, e.g., Rp. 1.000.000 should be 1000000)\n"
            "5. Gimmick (e.g., free installation, discount, bonus channels, etc.)\n"
            "The image may contain multiple products or services. Gather all of them.\n"
            "Return the data <strictly in JSON format> without any additional text."
        )

        success, response_text, error_message = await make_gemini_vision_request(prompt_text, image_path)

        if not success:
            await bot.send_message(chat_id, f"❌ {error_message}")
            return None, error_message

        # JSON Cleaning
        response_text = response_text.replace("```json", "").replace("```", "").strip()
        json_start = response_text.find('[')
        json_end = response_text.rfind(']') + 1
        json_str = response_text[json_start:json_end]

        try:
            extracted_data = json.loads(json_str)
            return extracted_data, response_text
        except json.JSONDecodeError:
            await bot.send_message(chat_id, "❌ Format data AI tidak valid.")
            return None, "JSON parsing failed"

    except Exception as e:
        logger.error(f"Extraction error: {e}", exc_info=True)
        await bot.send_message(chat_id, "❌ Kesalahan sistem.")
        return None, str(e)

async def compress_image_with_timeout(image_path: str, max_size_kb: int = 500, timeout_seconds: int = 30):
    """Compress image with timeout to prevent hanging."""
    logger.debug(f"Starting image compression for {image_path}, max size: {max_size_kb}KB")
    
    def _compress_sync():
        try:
            logger.debug("Opening image for compression...")
            img = Image.open(image_path)
            img_format = img.format if img.format else 'JPEG'
            quality = 85
            
            # Get original size
            original_size = os.path.getsize(image_path) / 1024
            logger.debug(f"Original image size: {original_size:.2f} KB")
            
            if original_size <= max_size_kb:
                logger.debug("Image already within size limit, no compression needed")
                return
            
            # If image is very large, resize it first
            width, height = img.size
            logger.debug(f"Original image dimensions: {width}x{height}")
            
            if width * height > 4000000:  # If larger than ~4MP
                logger.debug("Image is very large, resizing first...")
                ratio = min(2000 / width, 2000 / height)
                new_width = int(width * ratio)
                new_height = int(height * ratio)
                img = img.resize((new_width, new_height), Image.Resampling.LANCZOS)
                logger.debug(f"Resized image to {new_width}x{new_height}")
            
            compression_attempts = 0
            while compression_attempts < 20:  # Prevent infinite loop
                compression_attempts += 1
                logger.debug(f"Compression attempt {compression_attempts}, quality: {quality}")
                
                buffer = io.BytesIO()
                # Convert RGBA to RGB if necessary for JPEG compatibility
                if img.mode in ("RGBA", "P"):
                    logger.debug("Converting image mode for JPEG compatibility...")
                    # Create a white background for transparency
                    background = Image.new("RGB", img.size, (255, 255, 255))
                    if img.mode == "P":
                        img = img.convert("RGBA")
                    background.paste(img, mask=img.split()[-1] if img.mode == "RGBA" else None)
                    img = background
                
                img.save(buffer, format=img_format, quality=quality, optimize=True)
                size_kb = buffer.tell() / 1024
                logger.debug(f"Compressed to {size_kb:.2f} KB")
                
                if size_kb <= max_size_kb or quality <= 20:
                    # Save the final compressed image
                    with open(image_path, 'wb') as f:
                        f.write(buffer.getvalue())
                    logger.debug(f"Image compression completed: {size_kb:.2f} KB with quality={quality}")
                    return
                quality -= 5
                
        except Exception as e:
            logger.error(f"Error during image compression: {e}", exc_info=True)
            raise

    # Run the synchronous compression in a thread pool with timeout
    try:
        await asyncio.wait_for(
            async_run_in_thread(_compress_sync),
            timeout=timeout_seconds
        )
        logger.debug("Image compression completed successfully")
    except asyncio.TimeoutError:
        logger.error(f"Image compression timed out after {timeout_seconds} seconds")
        raise Exception(f"Image compression timed out after {timeout_seconds} seconds")

# Alias for backward compatibility
async def compress_image(image_path: str, max_size_kb: int = 500):
    """Wrapper for compress_image_with_timeout for backward compatibility."""
