async def save_user_coordinates(user_id, latitude, longitude):
    try:
        coords = {
            'latitude': latitude,
            'longitude': longitude
        }
        coords_file = os.path.join(ROUTE_STORAGE_PATH, f"{user_id}_coords.json")
        
        # Use aiofiles to perform asynchronous file writing
        async with aiofiles.open(coords_file, 'w') as f:
            await f.write(json.dumps(coords, indent=4))
        
        logging.info(f"Stored coordinates for user_id {user_id} in {coords_file}.")
    except Exception as e:
        logging.error(f"Failed to store coordinates: {e}")


async def reverse_geocode_to_city(latitude: float, longitude: float) -> Dict[str, str]:
    """
    Performs reverse geocoding using available services based on configuration.
    COMPLETELY BYPASSES all network calls when geocoding is disabled.
    """
    # Default empty location - IMMEDIATE RETURN when geocoding disabled
    default_location = {"village": "", "municipality": "", "county": "", "city": ""}
    
    # COMPLETE BYPASS - No network calls at all when both services are disabled
    if not USE_NOMINATIM_SERVICE and not USE_GOOGLE_MAPS_API:
        logging.info("All reverse geocoding services disabled - returning empty location immediately")
        return default_location
    
    logging.debug(f"Geocoding enabled - starting reverse geocoding for: {latitude}, {longitude}")
    
    # Try Nominatim first (if enabled)
    if USE_NOMINATIM_SERVICE:
        try:
            result = await _reverse_geocode_nominatim(latitude, longitude)
            if result["city"]:  # If we got a city name, consider it successful
                logging.info("Successfully geocoded using Nominatim service")
                return result
            else:
                logging.warning("Nominatim returned empty city name")
        except Exception as e:
            logging.error(f"Nominatim geocoding failed: {e}")
    
    # Try Google Maps API as fallback (if enabled)
    if USE_GOOGLE_MAPS_API:
        try:
            result = await _reverse_geocode_google_maps(latitude, longitude)
            if result["city"]:
                logging.info("Successfully geocoded using Google Maps API")
                return result
            else:
                logging.warning("Google Maps API returned empty city name")
        except Exception as e:
            logging.error(f"Google Maps geocoding failed: {e}")
    
    logging.warning(f"All enabled geocoding services failed for coordinates: {latitude}, {longitude}")
    return default_location


async def _reverse_geocode_nominatim(latitude: float, longitude: float) -> Dict[str, str]:
    """
    Performs reverse geocoding using Nominatim API directly with aiohttp.
    """
    logging.debug("Executing Nominatim reverse geocoding...")
    
    default_location = {"village": "", "municipality": "", "county": "", "city": ""}
    
    # Construct the Nominatim API URL with proper headers
    headers = {'User-Agent': 'RajawaliBot/1.0 (Contact: your-email@example.com)'}
    url = (
        "https://nominatim.openstreetmap.org/reverse"
        f"?lat={latitude}&lon={longitude}&format=json&addressdetails=1&accept-language=id"
    )

    try:
        async with aiohttp.ClientSession() as session:
            async with session.get(url, proxy=PROXY_URL, headers=headers, timeout=10) as response:
                
                if response.status != 200:
                    logging.error(f"Nominatim API request failed with status: {response.status}")
                    return default_location

                data = await response.json()
                
                if data and 'address' in data:
                    address = data['address']
                    city = address.get('city', address.get('state', ''))
                    city_cleaned = unicodedata.normalize('NFKD', city).encode('ascii', 'ignore').decode('ascii').strip()

                    return {
                        "village": address.get('village', ''),
                        "municipality": address.get('municipality', ''),
                        "county": address.get('county', ''),
                        "city": city_cleaned,
                    }
                else:
                    logging.warning(f"Nominatim found no address data for {latitude},{longitude}")
                    return default_location

    except aiohttp.ClientError as e:
        logging.error(f"Aiohttp client error during Nominatim geocoding: {e}")
        return default_location
    except Exception as e:
        logging.error(f"Unexpected error during Nominatim geocoding: {e}")
        return default_location


async def _reverse_geocode_google_maps(latitude: float, longitude: float) -> Dict[str, str]:
    """
    Performs reverse geocoding using Google Maps Geocoding API.
    Requires GOOGLE_MAPS_API_KEY to be set and billing enabled on Google Cloud.
    """
    logging.debug("Executing Google Maps reverse geocoding...")
    
    default_location = {"village": "", "municipality": "", "county": "", "city": ""}
    
    if not GOOGLE_MAPS_API_KEY:
        logging.error("Google Maps API key not configured")
        return default_location
    
    # Construct Google Maps Geocoding API URL
    url = (
        "https://maps.googleapis.com/maps/api/geocode/json"
        f"?latlng={latitude},{longitude}&key={GOOGLE_MAPS_API_KEY}&language=id"
    )

    try:
        async with aiohttp.ClientSession() as session:
            async with session.get(url, proxy=PROXY_URL, timeout=10) as response:
                
                if response.status != 200:
                    logging.error(f"Google Maps API request failed with status: {response.status}")
                    return default_location

                data = await response.json()
                
                if data.get('status') == 'OK' and data.get('results'):
                    # Parse the first result
                    result = data['results'][0]
                    address_components = result.get('address_components', [])
                    
                    # Extract location components
                    location_data = {"village": "", "municipality": "", "county": "", "city": ""}
                    
                    for component in address_components:
                        types = component.get('types', [])
                        name = component.get('long_name', '')
                        
                        if 'locality' in types:
                            location_data['city'] = name
                        elif 'administrative_area_level_2' in types:
                            location_data['county'] = name
                        elif 'administrative_area_level_3' in types:
                            location_data['municipality'] = name
                        elif 'sublocality' in types or 'neighborhood' in types:
                            location_data['village'] = name
                    
                    # Clean city name
                    if location_data['city']:
                        location_data['city'] = unicodedata.normalize('NFKD', location_data['city']).encode('ascii', 'ignore').decode('ascii').strip()
                    
                    return location_data
                else:
                    status = data.get('status', 'UNKNOWN')
                    error_message = data.get('error_message', 'No error message')
                    logging.warning(f"Google Maps API returned status: {status}, message: {error_message}")
                    return default_location

    except aiohttp.ClientError as e:
        logging.error(f"Aiohttp client error during Google Maps geocoding: {e}")
        return default_location
    except Exception as e:
        logging.error(f"Unexpected error during Google Maps geocoding: {e}")
        return default_location


# Utility function to check if reverse geocoding is available
def is_reverse_geocoding_enabled() -> bool:
    """
    Returns True if at least one reverse geocoding service is enabled and properly configured.
    """
    if USE_NOMINATIM_SERVICE:
        return True
    if USE_GOOGLE_MAPS_API and GOOGLE_MAPS_API_KEY:
        return True
    return False


# Function to get available geocoding services status
def get_geocoding_services_status() -> Dict[str, str]:
    """
    Returns the status of available geocoding services for debugging/monitoring.
    """
    status = {}
    
    if USE_NOMINATIM_SERVICE:
        status['nominatim'] = 'enabled'
    else:
        status['nominatim'] = 'disabled'
    
    if USE_GOOGLE_MAPS_API:
        if GOOGLE_MAPS_API_KEY:
            status['google_maps'] = 'enabled'
        else:
            status['google_maps'] = 'enabled_but_no_api_key'
    else:
        status['google_maps'] = 'disabled'
    
    return status


def get_occ_emoji(occ_2):
    """
    Maps occupancy status (occ_2) to corresponding emoji.
    
    Args:
        occ_2 (str): Occupancy status (BLACK, GREEN, YELLOW, ORANGE, RED, etc.)
    
    Returns:
        str: Emoji representation of the occupancy status
    """
    emoji_map = {
        'BLACK': '⚫️',
        'GREEN': '🟢',
        'YELLOW': '🟡',
        'ORANGE': '🟠',
        'RED': '🔴'
    }
    return emoji_map.get(occ_2, '⚪️')


def format_odp_line(odp, distance):
    """
    Formats a single ODP line with emoji, name, distance, and CT0 info.
    Uses right-aligned arrows for clean alignment.
    
    Args:
        odp (dict): ODP data containing odp_name, occ_2, old_ct0_potential_port
        distance (float): Distance in meters
    
    Returns:
        str: Formatted ODP line ready for display
    """
    emoji = get_occ_emoji(odp.get('occ_2', 'OTHER'))
    odp_name = odp['odp_name']
    distance_str = f"{distance:.2f}"
    ct0_count = odp.get('old_ct0_potential_port', 0)
    
    # Base line: "- emoji `ODP-NAME`: XXX.XX m"
    base_line = f"  • {emoji} `{odp_name}` : {distance_str} m"
    ct0_info = f" (*{ct0_count}* port pelanggan CT0)"
    
    # Pad to 45 chars for consistent arrow alignment
    return f"{base_line:3} {ct0_info}"


def build_odp_message(nearest_odps, odp_config):
    """
    Builds the complete ODP results message.
    
    Args:
        nearest_odps (list): List of tuples containing (odp_dict, distance)
        odp_config (dict): Configuration containing expanded_distance_m, initial_distance_m
    
    Returns:
        str: Formatted ODP message ready to send to user
    """
    if nearest_odps:
        odp_lines = [
            format_odp_line(odp, distance) 
            for odp, distance in nearest_odps[:5]
        ]
        
        header = f"✨ *Ditemukan {len(nearest_odps)} ODP terdekat (maks {odp_config['expanded_distance_m']} m):*"
        return header + "\n" + "\n".join(odp_lines)
    else:
        return f"⚠️ Tidak ada ODP ditemukan dalam radius {odp_config['initial_distance_m']}m atau {odp_config['expanded_distance_m']}m dari lokasi Anda."


