def get_status_colors(status):
    """
    Get colors for different ODP statuses in multiple formats
    Returns dict with 'kml' and 'html' color formats
    """
    color_mapping = {
        'BLACK': {'kml': 'ff000000', 'html': '#000000'},
        'GREEN': {'kml': 'ff00ff00', 'html': '#008000'}, 
        'YELLOW': {'kml': 'ff00ffff', 'html': '#FFD700'},
        'ORANGE': {'kml': 'ff0080ff', 'html': '#FF8C00'},
        'RED': {'kml': 'ff0000ff', 'html': '#DC143C'},
    }
    
    default_colors = {'kml': 'ff808080', 'html': '#808080'}
    return color_mapping.get(status.upper(), default_colors)

def get_status_color(status):
    """Get KML format color for status markers"""
    return get_status_colors(status)['kml']

def get_status_bg_color(status):
    """Get HTML format color for status display"""
    return get_status_colors(status)['html']


async def generate_odp_map_kmz(user_id, odp_points, selected_branch_or_region, selected_statuses):
    """
    Generate KMZ file (compressed KML) for ODP Map data with filtering capabilities
    """
    current_date = get_current_date()
    
    # Read user CSV and extract watermark text
    user_csv_path = USER_DATA_FILE
    watermark_text = None

    try:
        with open(user_csv_path, 'r', encoding='utf-8') as csv_file:
            csv_reader = csv.DictReader(csv_file)
            for row in csv_reader:
                if str(row.get('user_id')).strip() == str(user_id).strip():
                    watermark_text = f"{row.get('username')} - {row.get('nik_tsel')}"
                    break
    except Exception as e:
        logging.error(f"Error reading CSV file: {e}")
        raise

    if not watermark_text:
        raise ValueError("User anda belum terdaftar, silahkan lakukan registrasi dengan /register")

    try:
        # Set storage directory path
        storage_dir = ODP_MAP_DIR
        
        # Create directory if it doesn't exist
        os.makedirs(storage_dir, exist_ok=True)
        
        status_str = "_".join(selected_statuses) if isinstance(selected_statuses, list) else str(selected_statuses)
        output_kmz_path = os.path.join(storage_dir, f'odp_map_{selected_branch_or_region}_{status_str}_{current_date}.kmz')

        # Create KML document (same structure as before)
        kml = etree.Element("kml", xmlns="http://www.opengis.net/kml/2.2")
        document = etree.SubElement(kml, "Document")
        
        # Document name and description
        name = etree.SubElement(document, "name")
        name.text = f"ODP Map - {selected_branch_or_region} - {status_str}"
        
        description = etree.SubElement(document, "description")
        description.text = f"ODP Map generated by {watermark_text} on {current_date}"
        
        # Create styles for different statuses
        unique_statuses = list(set([point['status'] for point in odp_points]))
        for status in unique_statuses:
            style = etree.SubElement(document, "Style", id=f"style_{status}")
            icon_style = etree.SubElement(style, "IconStyle")
            color = etree.SubElement(icon_style, "color")
            color.text = get_status_color(status)
            scale = etree.SubElement(icon_style, "scale")
            scale.text = "1.0"
            icon = etree.SubElement(icon_style, "Icon")
            href = etree.SubElement(icon, "href")
            href.text = "http://maps.google.com/mapfiles/kml/shapes/placemark_circle.png"
        
        # Group points by LOS groups for folder organization
        los_groups = {}
        new_status_groups = {}
        
        for point in odp_points:
            los_group = point.get('los_group', 'Unknown')
            new_status = point.get('new_status', 'Unknown')
            
            if los_group not in los_groups:
                los_groups[los_group] = []
            los_groups[los_group].append(point)
            
            if new_status not in new_status_groups:
                new_status_groups[new_status] = []
            new_status_groups[new_status].append(point)
        
        # Create folders for LOS groups
        los_folder = etree.SubElement(document, "Folder")
        los_folder_name = etree.SubElement(los_folder, "name")
        los_folder_name.text = "Filter by LOS Groups"
        
        for los_group, points in los_groups.items():
            folder = etree.SubElement(los_folder, "Folder")
            folder_name = etree.SubElement(folder, "name")
            folder_name.text = f"LOS: {los_group} months ({len(points)} points)"
            
            for point in points:
                placemark = etree.SubElement(folder, "Placemark")
                pm_name = etree.SubElement(placemark, "name")
                pm_name.text = point['odp_name']
                
                pm_description = etree.SubElement(placemark, "description")
                pm_description.text = f"""<![CDATA[
<div style="font-family: Arial, sans-serif; font-size: 8px;">
<table border="1" cellpadding="4" cellspacing="0" style="border-collapse: collapse; width: 100%;">
<tr style="background-color: #f0f0f0;"><td colspan="2"><b style="color: #333;">{point['odp_name']}</b></td></tr>
<tr><td><b>ODP Index:</b></td><td>{point['odp_index']}</td></tr>
<tr><td><b>STO:</b></td><td>{point['sto']}</td></tr>
<tr><td><b>Cluster:</b></td><td>{point['cluster']}</td></tr>
<tr><td><b>Status:</b></td><td><span style="background-color: {get_status_bg_color(point['status'])}; color: white; padding: 2px 6px; border-radius: 3px;">{point['status']}</span></td></tr>
<tr><td><b>New Status:</b></td><td>{point['new_status']}</td></tr>
<tr><td><b>LOS Group:</b></td><td>{point['los_group']}</td></tr>
<tr><td><b>LOS Months:</b></td><td>{point['los_months']}</td></tr>
<tr><td><b>Total Ports:</b></td><td>{point['is_total']}</td></tr>
<tr><td><b>Used Ports:</b></td><td>{point['used']}</td></tr>
<tr><td><b>Available:</b></td><td>{point['avai']}</td></tr>
<tr><td><b>Go Live Date:</b></td><td>{point['golive_date'] or 'N/A'}</td></tr>
<tr><td><b>Last Update:</b></td><td>{point['update_date'] or 'N/A'}</td></tr>
</table>
</div>
"""
                
                style_url = etree.SubElement(placemark, "styleUrl")
                style_url.text = f"#style_{point['status']}"
                
                point_elem = etree.SubElement(placemark, "Point")
                coordinates = etree.SubElement(point_elem, "coordinates")
                coordinates.text = f"{point['longitude']},{point['latitude']},0"
        
        # Create folders for New/Not_New status
        new_folder = etree.SubElement(document, "Folder")
        new_folder_name = etree.SubElement(new_folder, "name")
        new_folder_name.text = "Filter by New/Not_New Status"
        
        for new_status, points in new_status_groups.items():
            folder = etree.SubElement(new_folder, "Folder")
            folder_name = etree.SubElement(folder, "name")
            folder_name.text = f"{new_status} ODPs ({len(points)} points)"
            
            for point in points:
                placemark = etree.SubElement(folder, "Placemark")
                pm_name = etree.SubElement(placemark, "name")
                pm_name.text = point['odp_name']
                
                pm_description = etree.SubElement(placemark, "description")
                pm_description.text = f"""
                <![CDATA[
                <table border="1">
                <tr><td><b>ODP Name</b></td><td>{point['odp_name']}</td></tr>
                <tr><td><b>ODP Index</b></td><td>{point['odp_index']}</td></tr>
                <tr><td><b>STO</b></td><td>{point['sto']}</td></tr>
                <tr><td><b>Cluster</b></td><td>{point['cluster']}</td></tr>
                <tr><td><b>Status</b></td><td>{point['status']}</td></tr>
                <tr><td><b>New Status</b></td><td>{point['new_status']}</td></tr>
                <tr><td><b>LOS Group</b></td><td>{point['los_group']}</td></tr>
                <tr><td><b>LOS Months</b></td><td>{point['los_months']}</td></tr>
                <tr><td><b>Total Ports</b></td><td>{point['is_total']}</td></tr>
                <tr><td><b>Used Ports</b></td><td>{point['used']}</td></tr>
                <tr><td><b>Available</b></td><td>{point['avai']}</td></tr>
                <tr><td><b>Go Live Date</b></td><td>{point['golive_date']}</td></tr>
                <tr><td><b>Last Update</b></td><td>{point['update_date']}</td></tr>
                </table>
                """
                
                style_url = etree.SubElement(placemark, "styleUrl")
                style_url.text = f"#style_{point['status']}"
                
                point_elem = etree.SubElement(placemark, "Point")
                coordinates = etree.SubElement(point_elem, "coordinates")
                coordinates.text = f"{point['longitude']},{point['latitude']},0"
        
        # Generate KML content as bytes
        tree = etree.ElementTree(kml)
        kml_buffer = io.BytesIO()
        tree.write(kml_buffer, pretty_print=True, xml_declaration=True, encoding='UTF-8')
        kml_content = kml_buffer.getvalue()
        kml_buffer.close()
        
        # Create KMZ file (ZIP with KML content)
        with zipfile.ZipFile(output_kmz_path, 'w', zipfile.ZIP_DEFLATED, compresslevel=9) as kmz_file:
            kmz_file.writestr('doc.kml', kml_content)
        
        # Log compression statistics
        if os.path.exists(output_kmz_path):
            original_size = len(kml_content)
            compressed_size = os.path.getsize(output_kmz_path)
            compression_ratio = (1 - compressed_size / original_size) * 100
            
            logging.info(f"ODP Map KMZ file generated successfully: {output_kmz_path}")
            logging.info(f"Compression: {original_size/1024/1024:.1f}MB -> {compressed_size/1024/1024:.1f}MB ({compression_ratio:.1f}% reduction)")
        
        return output_kmz_path

    except Exception as e:
        logging.error(f"Error generating ODP Map KMZ file: {e}")
        raise


async def generate_odp_map_csv(detailed_data, summary_data, selected_branch_or_region, selected_statuses):
    """
    Generate CSV file containing both detailed and summary data for ODP Map
    """
    current_date = get_current_date()
    storage_dir = ODP_MAP_DIR
    
    current_date = get_current_date()
    status_str = "_".join(selected_statuses) if isinstance(selected_statuses, list) else str(selected_statuses)
    csv_filename = f'odp_map_{selected_branch_or_region }_{status_str}_{current_date}.csv'
    csv_path = os.path.join(storage_dir, csv_filename)

    try:
        with open(csv_path, 'w', newline='', encoding='utf-8') as csvfile:
            writer = csv.writer(csvfile)
            
            # Write header info
            writer.writerow(['ODP MAP DATA EXPORT'])
            writer.writerow(['Branch/Region:', selected_branch_or_region])
            writer.writerow(['Status:', status_str])
            writer.writerow(['Export Date:', current_date])
            writer.writerow([])  # Empty row
            
            # Write summary data
            writer.writerow(['=== SUMMARY DATA ==='])
            if summary_data:
                summary_headers = list(summary_data[0].keys())
                writer.writerow(summary_headers)
                for row in summary_data:
                    writer.writerow([row.get(header, '') for header in summary_headers])
            writer.writerow([])  # Empty row
            
            # Write detailed data
            writer.writerow(['=== DETAILED DATA ==='])
            if detailed_data:
                detailed_headers = list(detailed_data[0].keys())
                writer.writerow(detailed_headers)
                for row in detailed_data:
                    writer.writerow([row.get(header, '') for header in detailed_headers])
        
        logging.info(f"CSV file generated successfully: {csv_path}")
        return csv_path
        
    except Exception as e:
        logging.error(f"Error generating CSV file: {e}")
        return None


