# Helper function to create static ODP markers (should be available in your main code)
def create_static_odp_markers(nearest_odps):
    """
    Create simplified ODP data structure for static map markers when OSRM is disabled.
    This ensures ODP points are still visible on the map even without walkable routes.
    """
    static_markers = []
    if nearest_odps:
        for odp_data, distance in nearest_odps:
            static_marker = {
                'odp_name': odp_data.get('odp_name', 'Unknown ODP'),
                'odp_latitude': float(odp_data.get('latitude', 0)),
                'odp_longitude': float(odp_data.get('longitude', 0)),
                'distance': round(distance, 2),
                'route_coordinates': [],  # Empty route path
                'static_mode': True,  # Flag to indicate this is a static marker
                'marker_only': True   # Flag for the frontend to only show marker, no route
            }
            static_markers.append(static_marker)
            logger.debug(f"Created static marker for ODP: {static_marker['odp_name']} at {static_marker['odp_latitude']}, {static_marker['odp_longitude']}")
    
    logger.info(f"Created {len(static_markers)} static ODP markers")
    return static_markers


# Modified generate_nearest_odp_html function to handle OSRM toggle and geocoding bypass
async def generate_nearest_odp_html(user_id, user_latitude, user_longitude, odp_routes, site_marker=None, osrm_enabled=None):
    try:
        # Check global OSRM setting if not explicitly provided
        if osrm_enabled is None:
            osrm_enabled = OSRM_WALKABLE_ROUTES_ENABLED
            
        template_path = os.path.join(os.path.dirname(__file__), 'templates', 'findnearestodp_web.html')
        
        # BULLETPROOF GEOCODING BYPASS - Check configuration first
        geocoding_enabled = USE_NOMINATIM_SERVICE or USE_GOOGLE_MAPS_API
        
        if geocoding_enabled:
            try:
                logger.info(f"Geocoding services enabled - fetching location for user {user_id}")
                location_details = await reverse_geocode_to_city(user_latitude, user_longitude)
                logger.info(f"Geocoding completed for user {user_id}: {location_details}")
            except Exception as e:
                logger.error(f"Geocoding failed for user {user_id}: {e}")
                location_details = {"village": "", "municipality": "", "county": "", "city": ""}
        else:
            # COMPLETE BYPASS - No function call at all
            logger.info(f"All geocoding services disabled - bypassing completely for user {user_id}")
            location_details = {"village": "", "municipality": "", "county": "", "city": ""}
        
        # Extract location components safely
        village = location_details.get("village", "")
        municipality = location_details.get("municipality", "")
        county = location_details.get("county", "")
        city = location_details.get("city", "")
        
        # Sanitize location names
        def sanitize_name(name):
            if not name:
                return ""
            return re.sub(r'[^\w\s-]', '_', str(name)).replace(' ', '_')
        
        sanitized_village = sanitize_name(village)
        sanitized_municipality = sanitize_name(municipality)
        sanitized_county = sanitize_name(county)
        sanitized_city = sanitize_name(city)

        # Generate base filename based on available location data
        if any([sanitized_village, sanitized_municipality, sanitized_county]):
            base_name = f"{sanitized_village}_{sanitized_municipality}_{sanitized_county}_odpterdekat"
        elif sanitized_city:
            base_name = f"{sanitized_city}_{user_id}_odpterdekat"
        else:
            # No location data available - use coordinate-based naming
            coord_lat = str(user_latitude).replace('.', '_').replace('-', 'neg')
            coord_lon = str(user_longitude).replace('.', '_').replace('-', 'neg')
            base_name = f"coord_{coord_lat}_{coord_lon}_{user_id}_odpterdekat"
            
        # Add status indicators to filename for clarity
        status_suffix = []
        if not osrm_enabled:
            status_suffix.append("static")
        if not geocoding_enabled:
            status_suffix.append("nogeo")
        
        if status_suffix:
            base_name += "_" + "_".join(status_suffix)
            
        file_name = f"{base_name}.html"

        output_dir = os.path.join(ROUTE_STORAGE_PATH, str(user_id))
        output_html_path = os.path.join(output_dir, file_name)
        os.makedirs(output_dir, exist_ok=True)

        # Read the HTML template
        with open(template_path, 'r', encoding='utf-8') as template_file:
            html_template = template_file.read()

        # Prepare routes data - handle both OSRM routes and static markers
        if osrm_enabled and odp_routes:
            routes_data = odp_routes  # Full OSRM route data
        elif odp_routes:
            routes_data = odp_routes  # Static marker data when OSRM disabled
        else:
            routes_data = []
        
        # Enhanced logging for debugging
        logger.info(f"HTML Generation Status for user {user_id}:")
        logger.info(f"  - OSRM enabled: {osrm_enabled}")
        logger.info(f"  - Geocoding enabled: {geocoding_enabled}")
        logger.info(f"  - Nominatim enabled: {USE_NOMINATIM_SERVICE}")
        logger.info(f"  - Google Maps enabled: {USE_GOOGLE_MAPS_API}")
        logger.info(f"  - Routes/Markers count: {len(routes_data)}")
        logger.info(f"  - Location resolved: {city if city else 'No location data'}")
        logger.info(f"  - Output filename: {file_name}")
        
        if routes_data and len(routes_data) > 0:
            first_item = routes_data[0]
            is_static = first_item.get('static_mode', False)
            logger.info(f"  - Data type: {'Static markers' if is_static else 'OSRM routes'}")

        # Populate template variables
        populated_html = html_template.replace("{{ user_lat }}", str(user_latitude)) \
                                        .replace("{{ user_lng }}", str(user_longitude)) \
                                        .replace("{{ routes | safe }}", json.dumps(routes_data)) \
                                        .replace("{{ site_marker | safe }}", json.dumps(site_marker if site_marker is not None else {}))

        # Add OSRM status flag to the HTML for frontend handling
        osrm_status_js = f"const OSRM_ENABLED = {str(osrm_enabled).lower()};"
        geocoding_status_js = f"const GEOCODING_ENABLED = {str(geocoding_enabled).lower()};"
        
        # Inject status flags into the HTML
        status_injection = f"<script>{osrm_status_js}\n{geocoding_status_js}</script>\n</body>"
        populated_html = populated_html.replace("</body>", status_injection)

        # --- Watermark Generation ---
        user_csv_path = USER_DATA_FILE
        watermark_text = None
        try:
            with open(user_csv_path, 'r', encoding='utf-8') as csv_file:
                csv_reader = csv.DictReader(csv_file)
                for row in csv_reader:
                    if str(row.get('user_id')).strip() == str(user_id).strip():
                        watermark_text = f"{row.get('username')} - {row.get('nik_tsel')}"
                        break
        except Exception as e:
            logging.error(f"Error reading CSV file: {e}")
            raise

        if not watermark_text:
            raise ValueError("User anda belum terdaftar, silahkan lakukan registrasi dengan /register")

        # Build status indicators for watermark
        status_indicators = []
        if not osrm_enabled:
            status_indicators.append("S")
        if not geocoding_enabled:
            status_indicators.append("NG")
        
        # Generate watermark with status indicators
        if status_indicators:
            watermark_text_with_status = f"{watermark_text} [{' | '.join(status_indicators)}]"
        else:
            watermark_text_with_status = watermark_text
            
        # Generate watermark container with 64 items (8x8 grid)
        watermark_html = ''.join([f'<div class="watermark-item">{watermark_text_with_status}</div>' for _ in range(64)])
        
        # Replace the watermark container placeholder in the template
        populated_html = populated_html.replace('{{ watermark_container }}', watermark_html)

        # Write the populated HTML to the output file
        with open(output_html_path, 'w', encoding='utf-8') as output_file:
            output_file.write(populated_html)

        # Enhanced success logging
        status_parts = []
        if osrm_enabled and routes_data:
            status_parts.append("OSRM routes")
        else:
            status_parts.append("static markers")
        
        if geocoding_enabled:
            status_parts.append(f"location: {city if city else 'failed'}")
        else:
            status_parts.append("no geocoding")
        
        status_msg = " | ".join(status_parts)
        logging.info(f"HTML map generated successfully for user {user_id} ({status_msg}): {output_html_path}")
        return output_html_path

    except Exception as e:
        logging.error(f"Error generating HTML map for user {user_id}: {e}", exc_info=True)
        raise


# Alternative helper function to create a simple static map when OSRM is completely unavailable
async def generate_static_map_html(user_id, user_latitude, user_longitude, nearest_odps, site_marker=None):
    """
    Generate a simple static map without any route calculations.
    This function can be used as a fallback when OSRM is completely unavailable.
    """
    try:
        # Use the create_static_odp_markers function to prepare ODP data
        static_odp_data = create_static_odp_markers(nearest_odps) if nearest_odps else []
        
        # Call the main function with static markers and OSRM disabled
        return await generate_nearest_odp_html(
            user_id, user_latitude, user_longitude, 
            static_odp_data, # Static marker data instead of empty routes
            site_marker=site_marker,
            osrm_enabled=False
        )
        
    except Exception as e:
        logging.error(f"Error generating static map: {e}")
        raise


# =============================================================== #
#  Helper: Google Map URL checker                                 #
# =============================================================== #

def is_incomplete_google_maps_url(text_input: str) -> bool:
    """
    Detect if input is a Google Maps URL but doesn't contain coordinates.
    This includes shortened URLs like maps.app.goo.gl or goo.gl/maps
    """
    text_input = text_input.strip().lower()
    
    # Patterns for various Google Maps URL formats
    google_maps_indicators = [
        'maps.app.goo.gl',
        'goo.gl/maps', 
        'maps.google.com',
        'www.google.com/maps',
        'google.com/maps'
    ]
    
    # Check if it looks like a Google Maps URL
    is_google_maps_url = any(indicator in text_input for indicator in google_maps_indicators)
    
    if not is_google_maps_url:
        return False
    
    # If it's a Google Maps URL, check if it has coordinates
    # Try to parse with CoordinateParser - if it fails, it's incomplete
    try:
        lat, lon = CoordinateParser.parse(text_input)
        return lat is None or lon is None  # Incomplete if no coordinates found
    except:
        return True  # Parsing failed, so it's incomplete


