# Helper: Heatmap Generator
# =============================================================== #

def sanitize_segment_name_for_js(segment_name):
    """
    DEAD SIMPLE: Just keep letters, numbers, and convert spaces to underscores.
    """
    import re
    # Remove all special characters, keep only letters/numbers/spaces
    clean = re.sub(r'[^a-zA-Z0-9 ]', '', str(segment_name))
    # Convert spaces to underscores
    return re.sub(r'\s+', '_', clean).upper()

def escape_for_js_string(text):
    """
    Escape text for safe use in JavaScript string literals.
    """
    return (str(text)
            .replace("\\", "\\\\")
            .replace("'", "\\'")
            .replace('"', '\\"')
            .replace('\n', '\\n')
            .replace('\r', '\\r')
            .replace('&', '\\&')
            .replace('-', '\\-'))


async def generate_cvm_heatmap_html_bysto(user_id: int, data: list, sto_name: str, segment: str, branch_name: str, region_name: str, progress_callback=None):
    """
    Optimized async version for large datasets (30k+ points) using template-based approach.
    """
    try:
        logging.debug(f"=== Starting optimized HTML generation for {len(data)} points ===")
        
        if progress_callback:
            await progress_callback(0, "Menghitung koordinat tengah...")
        
        # Calculate center coordinates
        latitudes = [item['latitude'] for item in data]
        longitudes = [item['longitude'] for item in data]
        
        center_lat = sum(latitudes) / len(latitudes)
        center_lon = sum(longitudes) / len(longitudes)
        
        if progress_callback:
            await progress_callback(10, "Mempersiapkan struktur file...")

        # Generate unique filename
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        clean_segment = segment.replace(" ", "_").replace("&", "and").upper()
        filename = f"cvm_heatmap_{user_id}_{sto_name}_{clean_segment}_{timestamp}.html"
        output_path = os.path.join("maps", filename)

        # Ensure maps directory exists
        os.makedirs("maps", exist_ok=True)

        if progress_callback:
            await progress_callback(20, "Mempersiapkan data untuk template...")

        # Create color mapping for different segments
        segment_colors = {
            'LATE PAYER': '#FF4444',
            'DORMANT USER': '#808080',
            'BILLING & SERVICE COMPLAINANT': '#FF6B35',
            'NETWORK STABILITY ISSUE': '#FF8C42',
            'NON-OPTIMAL EXPERIENCE': '#FFB347',
            'COMPETITOR EXPLORER': '#9B59B6',
            'STABLE USAGE': '#2ECC71',
            'INCREASED USAGE': '#27AE60',
            'DECLINED USAGE': '#E74C3C',
            'EARLY TENURE CUSTOMER': '#3498DB',
        }

        # Prepare segment data for JSON
        segment_data = {}
        for item in data:
            segment_name = item['customer_segment'].upper()
            if segment_name not in segment_data:
                segment_data[segment_name] = []
            
            # Prepare item data with escaped values
            segment_data[segment_name].append({
                'lat': convert_decimal(item['latitude']),
                'lon': convert_decimal(item['longitude']),
                'bb_id': str(item.get('bb_id', 'N/A')).replace("'", "\\'").replace('"', '\\"'),
                'ont_category': str(item.get('ont_category', 'N/A')).replace("'", "\\'").replace('"', '\\"'),
                'city': str(item.get('city', 'N/A')).replace("'", "\\'").replace('"', '\\"'),
                'sto': sto_name,
                'last_payment': str(item.get('last_payment', 'N/A'))
            })

        # Prepare unique segments for filter
        unique_segments = []
        for segment_name in sorted(segment_data.keys()):
            count = len(segment_data[segment_name])
            display_name = segment_name.replace("BILLING & SERVICE COMPLAINANT", "BILLING & SERVICE").replace("COMPETITOR EXPLORER", "COMP EXPLR")[:15]
            unique_segments.append({
                'name': segment_name,
                'displayName': display_name,
                'count': count
            })

        # Determine if filters should be shown
        show_filters = segment.upper() == "ALL" or len(unique_segments) > 1

        if progress_callback:
            await progress_callback(50, "Membaca data pengguna untuk watermark...")

        # Generate watermark
        user_csv_path = USER_DATA_FILE
        watermark_text = None
        try:
            with open(user_csv_path, 'r', encoding='utf-8') as csv_file:
                csv_reader = csv.DictReader(csv_file)
                for row in csv_reader:
                    if str(row.get('user_id')).strip() == str(user_id).strip():
                        watermark_text = f"{row.get('username')} - {row.get('nik_tsel')}"
                        break
        except Exception as e:
            logging.error(f"Error reading CSV file: {e}")
            raise

        if not watermark_text:
            raise ValueError("User anda belum terdaftar, silahkan lakukan registrasi dengan /register")

        # Generate watermark container with 64 items (8x8 grid)
        watermark_html = ''.join([f'<div class="watermark-item">{watermark_text}</div>' for _ in range(64)])

        if progress_callback:
            await progress_callback(70, "Memuat template...")

        # Read template HTML
        template_path = os.path.join(os.path.dirname(__file__), 'templates', 'cvm_heatmap_bysto.html')
        with open(template_path, 'r', encoding='utf-8') as template_file:
            html_template = template_file.read()

        if progress_callback:
            await progress_callback(80, "Mengisi template...")

        selected_period = await get_user_selected_period(user_id)
        start_date, end_date = await get_period_date_range(selected_period)
        
        if end_date:
            # Use the month of the user's selected end_date as the reference "current month"
            current_month_str = end_date.strftime('%Y-%m')
            logging.info(f"Using user's contextual end date for current month: {current_month_str}")
        else:
            # Fallback to the actual current month if no date range is set
            current_month_str = datetime.now().strftime('%Y-%m')
            logging.warning(f"No user date range found, falling back to actual current month: {current_month_str}")

        # Populate template with simple string replacements
        populated_html = html_template.replace("{{ center_lat }}", str(center_lat)) \
                                      .replace("{{ center_lon }}", str(center_lon)) \
                                      .replace("{{ data_count }}", f"{len(data):,}") \
                                      .replace("{{ segment_data_json }}", json.dumps(segment_data)) \
                                      .replace("{{ segment_colors_json }}", json.dumps(segment_colors)) \
                                      .replace("{{ show_filters_json }}", str(show_filters).lower()) \
                                      .replace("{{ unique_segments_json }}", json.dumps(unique_segments)) \
                                      .replace("{{ region_name_upper }}", region_name.upper()) \
                                      .replace("{{ branch_name_upper }}", branch_name.upper()) \
                                      .replace("{{ sto_name_upper }}", sto_name.upper()) \
                                      .replace("{{ segment_display }}", segment.upper() if segment != "ALL" else "ALL SEGMENTS") \
                                      .replace("{{ data_count_formatted }}", f"{len(data):,}") \
                                      .replace("{{ min_lat }}", str(min(latitudes))) \
                                      .replace("{{ min_lon }}", str(min(longitudes))) \
                                      .replace("{{ max_lat }}", str(max(latitudes))) \
                                      .replace("{{ max_lon }}", str(max(longitudes))) \
                                      .replace("{{ watermark_container }}", watermark_html) \
                                      .replace("{{ current_month_str }}", current_month_str)

        if progress_callback:
            await progress_callback(90, "Menyimpan file ke disk...")

        # Write HTML file
        with open(output_path, 'w', encoding='utf-8') as f:
            f.write(populated_html)

        if progress_callback:
            await progress_callback(100, "Pembuatan file selesai!")

        # Verify file was created
        if os.path.exists(output_path):
            file_size = os.path.getsize(output_path)
            logging.debug(f"Optimized file verification: exists=True, size={file_size} bytes")
            if file_size == 0:
                raise Exception("Generated HTML file is empty")
        else:
            raise Exception("HTML file was not created")

        logging.info(f"Optimized Ten Segment heatmap HTML generated: {output_path} ({len(data):,} points)")
        return output_path

    except Exception as e:
        logging.error(f"Error generating optimized Ten Segment heatmap HTML: {e}", exc_info=True)
        raise


async def generate_cvm_heatmap_html_multiple_stos(user_id: int, coordinates: list, sto_names: list, 
                                                  segment: str, branch_name: str, region_name: str,
                                                  progress_callback=None):
    """
    Generate HTML heatmap for multiple STOs with combined data.
    This is a wrapper that adapts the existing generate_cvm_heatmap_html_bysto function.
    """
    # Join STO names for display
    sto_display = "_".join([s.upper() for s in sto_names[:3]])  # Use first 3 STOs for filename
    if len(sto_names) > 3:
        sto_display += f"_and_{len(sto_names)-3}_more"
    
    # Call the existing function with combined STO name
    return await generate_cvm_heatmap_html_bysto(
        user_id, coordinates, sto_display, segment, branch_name, region_name, progress_callback
    )


async def generate_cvm_heatmap_html_sharelocation(user_id: int, cvm_data: list, odp_data: list, latitude: float, longitude: float, segment: str, is_live: bool, progress_callback=None):
    """
    Optimized async version for location-based Ten Segment analysis using template-based approach.
    """
    try:
        logging.debug(f"=== Starting optimized location Ten Segment HTML generation for {len(cvm_data)} Ten Segment points + {len(odp_data)} ODP points ===")
        
        if progress_callback:
            await progress_callback(0, "Mempersiapkan peta berbasis lokasi...")
        
        # Use user location as center
        center_lat = latitude
        center_lon = longitude
        
        if progress_callback:
            await progress_callback(10, "Mempersiapkan struktur file...")

        # Generate unique filename
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        clean_segment = segment.replace(" ", "_").replace("&", "and").upper()
        location_type = "static"
        filename = f"cvm_sharelocation_{user_id}_{clean_segment}_{location_type}_{timestamp}.html"
        output_path = os.path.join("/home/rajawalia3/radityayud/python_project/bot_telegram/maps", filename)

        if progress_callback:
            await progress_callback(20, "Mempersiapkan data untuk template...")

        # Create color mappings
        segment_colors = {
            'LATE PAYER': '#FF4444',
            'DORMANT USER': '#808080',
            'BILLING & SERVICE COMPLAINANT': '#FF6B35',
            'NETWORK STABILITY ISSUE': '#FF8C42',
            'NON-OPTIMAL EXPERIENCE': '#FFB347',
            'COMPETITOR EXPLORER': '#9B59B6',
            'STABLE USAGE': '#2ECC71',
            'INCREASED USAGE': '#27AE60',
            'DECLINED USAGE': '#E74C3C',
            'EARLY TENURE CUSTOMER': '#3498DB',
        }

        odp_color_map = {
            "BLACK": "#000000",
            "GREEN": "#00FF00", 
            "ORANGE": "#FFA500",
            "RED": "#FF0000",
            "YELLOW": "#FFFF00"
        }

        # Prepare Ten Segment segment data for JSON
        cvm_segment_data = {}
        for item in cvm_data:
            segment_name = item.get('customer_segment', segment).upper()
            if segment_name not in cvm_segment_data:
                cvm_segment_data[segment_name] = []
            
            # Prepare item data with escaped values and convert Decimals
            cvm_segment_data[segment_name].append({
                'lat': convert_decimal(item['latitude']),
                'lon': convert_decimal(item['longitude']),
                'bb_id': str(item.get('bb_id', 'N/A')).replace("'", "\\'").replace('"', '\\"'),
                'ont_category': str(item.get('ont_category', 'N/A')).replace("'", "\\'").replace('"', '\\"'),
                'city': str(item.get('city', 'N/A')).replace("'", "\\'").replace('"', '\\"'),
                'sto': str(item.get('sto', 'N/A')).replace("'", "\\'").replace('"', '\\"'),
                'last_payment': str(item.get('last_payment', 'N/A'))
            })

        # Prepare ODP data for JSON
        odp_data_json = []
        for item in odp_data:
            odp_data_json.append({
                'lat': convert_decimal(item['latitude']),
                'lon': convert_decimal(item['longitude']),
                'odp_name': str(item.get('odp_name', 'N/A')).replace("'", "\\'").replace('"', '\\"'),
                'occ_status': str(item.get('occ_2', 'BLACK')),
                'los_months': convert_decimal(item.get('los_odp_month', 0))
            })

        # Prepare unique segments for filter
        unique_segments = []
        for segment_name in sorted(cvm_segment_data.keys()):
            count = len(cvm_segment_data[segment_name])
            display_name = segment_name.replace("BILLING & SERVICE COMPLAINANT", "BILLING & SERVICE").replace("COMPETITOR EXPLORER", "COMP EXPLR")[:15]
            unique_segments.append({
                'name': segment_name,
                'displayName': display_name,
                'count': count
            })

        # Determine if filters should be shown
        show_filters = segment.upper() == "ALL" or len(unique_segments) > 1

        if progress_callback:
            await progress_callback(50, "Membaca data pengguna untuk watermark...")

        # Generate watermark
        user_csv_path = USER_DATA_FILE
        watermark_text = None
        try:
            with open(user_csv_path, 'r', encoding='utf-8') as csv_file:
                csv_reader = csv.DictReader(csv_file)
                for row in csv_reader:
                    if str(row.get('user_id')).strip() == str(user_id).strip():
                        watermark_text = f"{row.get('username')} - {row.get('nik_tsel')}"
                        break
        except Exception as e:
            logging.error(f"Error reading CSV file: {e}")
            raise

        if not watermark_text:
            raise ValueError("User anda belum terdaftar, silahkan lakukan registrasi dengan /register")

        # Generate watermark container with 64 items (8x8 grid)
        watermark_html = ''.join([f'<div class="watermark-item">{watermark_text}</div>' for _ in range(64)])

        if progress_callback:
            await progress_callback(70, "Memuat template...")

        # Read template HTML
        template_path = os.path.join(os.path.dirname(__file__), 'templates', 'cvm_heatmap_location.html')
        with open(template_path, 'r', encoding='utf-8') as template_file:
            html_template = template_file.read()

        if progress_callback:
            await progress_callback(80, "Mengisi template...")

        selected_period = await get_user_selected_period(user_id)
        start_date, end_date = await get_period_date_range(selected_period)
        
        if end_date:
            # Use the month of the user's selected end_date as the reference "current month"
            current_month_str = end_date.strftime('%Y-%m')
            logging.info(f"Using user's contextual end date for current month: {current_month_str}")
        else:
            # Fallback to the actual current month if no date range is set
            current_month_str = datetime.now().strftime('%Y-%m')
            logging.warning(f"No user date range found, falling back to actual current month: {current_month_str}")

        # Populate template with simple string replacements
        populated_html = html_template.replace("{{ center_lat }}", f"{center_lat:.6f}") \
                                      .replace("{{ center_lon }}", f"{center_lon:.6f}") \
                                      .replace("{{ segment_upper }}", segment.upper()) \
                                      .replace("{{ cvm_data_count }}", f"{len(cvm_data):,}") \
                                      .replace("{{ odp_data_count }}", f"{len(odp_data):,}") \
                                      .replace("{{ cvm_segment_data_json }}", json.dumps(cvm_segment_data)) \
                                      .replace("{{ segment_colors_json }}", json.dumps(segment_colors)) \
                                      .replace("{{ odp_data_json }}", json.dumps(odp_data_json)) \
                                      .replace("{{ odp_color_map_json }}", json.dumps(odp_color_map)) \
                                      .replace("{{ show_filters_json }}", str(show_filters).lower()) \
                                      .replace("{{ unique_segments_json }}", json.dumps(unique_segments)) \
                                      .replace("{{ segment_display }}", segment.upper() if segment != "ALL" else "ALL SEGMENTS") \
                                      .replace("{{ cvm_data_count_formatted }}", f"{len(cvm_data):,}") \
                                      .replace("{{ odp_data_count_formatted }}", f"{len(odp_data):,}") \
                                      .replace("{{ watermark_container }}", watermark_html) \
                                      .replace("{{ current_month_str }}", current_month_str)

        if progress_callback:
            await progress_callback(90, "Menyimpan file ke disk...")

        # Write HTML file
        with open(output_path, 'w', encoding='utf-8') as f:
            f.write(populated_html)

        if progress_callback:
            await progress_callback(100, "Pembuatan file selesai!")

        # Verify file was created
        if os.path.exists(output_path):
            file_size = os.path.getsize(output_path)
            logging.debug(f"Optimized location file verification: exists=True, size={file_size} bytes")
            if file_size == 0:
                raise Exception("Generated HTML file is empty")
        else:
            raise Exception("HTML file was not created")

        logging.info(f"Optimized location Ten Segment heatmap HTML generated: {output_path} ({len(cvm_data):,} Ten Segment + {len(odp_data):,} ODP points)")
        return output_path

    except Exception as e:
        logging.error(f"Error generating optimized location Ten Segment heatmap HTML: {e}", exc_info=True)
        raise


# Enhanced heatmap generators with clustering visualization
async def generate_churn_heatmap_html_multiple_stos_with_clustering(
    user_id: int, coordinates: list, sto_names: list, risk_level: str, 
    branch_name: str, region_name: str, clustering_results: dict, 
    df_clustered: pd.DataFrame, basic_summary_data: dict, progress_callback=None):
    """Generate enhanced HTML heatmap with clustering circles and detailed summary data."""
    
    try:
        if progress_callback:
            await progress_callback(0, "Mempersiapkan visualisasi klaster...")
        
        # Calculate center coordinates
        latitudes = [item['latitude'] for item in coordinates]
        longitudes = [item['longitude'] for item in coordinates]
        center_lat = sum(latitudes) / len(latitudes)
        center_lon = sum(longitudes) / len(longitudes)
        
        if progress_callback:
            await progress_callback(10, "Memproses data klaster...")

        # UPDATED: Prepare cluster data with calculated radius
        cluster_data = {}
        if clustering_results and clustering_results['total_clusters'] > 0:
            for i, cluster_detail in enumerate(clustering_results.get('cluster_details', [])):
                cluster_id = f"cluster_{cluster_detail['cluster_id']}"
                
                # Use calculated radius from enhanced analyze_clusters, fallback to 350m
                actual_radius = cluster_detail.get('actual_radius_m', 350)
                
                cluster_data[cluster_id] = {
                    'center': {
                        'lat': float(cluster_detail['lat_center']),
                        'lng': float(cluster_detail['lng_center'])
                    },
                    'radius': int(actual_radius),  # Use calculated radius instead of fixed 300m
                    'user_count': int(cluster_detail['user_count']),
                    # Additional info for enhanced popups
                    'max_distance': int(cluster_detail.get('max_distance_m', 0)),
                    'avg_distance': int(cluster_detail.get('avg_distance_m', 0)),
                    'dominant_sto': cluster_detail.get('dominant_sto', 'Mixed')
                }
                
                logging.info(f"Cluster {cluster_id}: radius={actual_radius}m, users={cluster_detail['user_count']}, max_dist={cluster_detail.get('max_distance_m', 0)}m")

        # The coordinates parameter already contains cluster_id information from the calling function
        enhanced_coordinates = coordinates  # Use the passed coordinates (already enhanced with cluster_id)

        if progress_callback:
            await progress_callback(30, "Mempersiapkan data segmen...")

        # Prepare segment data for JavaScript (same as existing but with cluster info)
        segment_data = {}
        for item in enhanced_coordinates:
            segment_name = item['customer_segment'].upper()
            if segment_name not in segment_data:
                segment_data[segment_name] = []
            
            # Use existing color logic
            risk_colors = {'HIGH': '#FF4444', 'LOW-MID': '#FFA500'}
            segment_colors = {
                'LATE PAYER': '#FF4444',
                'DORMANT USER': '#808080',
                'BILLING & SERVICE COMPLAINANT': '#FF6B35',
                'NETWORK STABILITY ISSUE': '#FF8C42',
                'NON-OPTIMAL EXPERIENCE': '#FFB347',
                'COMPETITOR EXPLORER': '#9B59B6',
                'STABLE USAGE': '#2ECC71',
                'INCREASED USAGE': '#27AE60',
                'DECLINED USAGE': '#E74C3C',
                'EARLY TENURE CUSTOMER': '#3498DB',
            }
            
            item_color = risk_colors.get(item.get('risk_level', ''), segment_colors.get(segment_name, '#808080'))
            
            segment_data[segment_name].append({
                'lat': item['latitude'],
                'lon': item['longitude'],
                'bb_id': str(item.get('bb_id', 'N/A')),
                'city': str(item.get('city', 'N/A')),
                'sto': str(item.get('sto', 'N/A')),
                'risk_level': item.get('risk_level', risk_level),
                'color': item_color,
                'cluster_id': item.get('cluster_id')
            })

        if progress_callback:
            await progress_callback(50, "Mempersiapkan data ringkasan...")

        # Prepare detailed summary data for HTML
        summary_data = {}
        
        # Segment summary
        if basic_summary_data:
            combined_segments = {}
            combined_payment = {'total_count': 0, 'paid_count': 0}
            
            for sto_name, sto_data in basic_summary_data.items():
                if not sto_data:
                    continue
                    
                latest_event_date = max([row.get("event_date", "") for row in sto_data])
                latest_data = [row for row in sto_data if row.get("event_date") == latest_event_date]
                
                for row in latest_data:
                    seg = row.get("customer_segment", "Unknown")
                    user_count = int(row.get("user_count", 0))
                    paid_count = int(row.get("paid_count", 0))
                    
                    if seg not in combined_segments:
                        combined_segments[seg] = {'total': 0, 'high_risk': 0, 'paid': 0}
                    
                    combined_segments[seg]['total'] += user_count
                    combined_segments[seg]['paid'] += paid_count
                    combined_payment['total_count'] += user_count
                    combined_payment['paid_count'] += paid_count
                    
                    if row.get("propensity_group", "") == "03. High":
                        combined_segments[seg]['high_risk'] += user_count
            
            # Calculate rates
            for seg in combined_segments:
                seg_data = combined_segments[seg]
                seg_data['rate'] = (seg_data['high_risk'] / seg_data['total'] * 100) if seg_data['total'] > 0 else 0
            
            summary_data['segments'] = combined_segments
            
            if combined_payment['total_count'] > 0:
                combined_payment['paid_pct'] = (combined_payment['paid_count'] / combined_payment['total_count']) * 100
                summary_data['payment'] = combined_payment

        if progress_callback:
            await progress_callback(70, "Membuat file HTML...")

        # Generate file details
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        clean_risk = risk_level.replace("-", "_").replace(" ", "_").upper()
        sto_display = "_".join([s.upper() for s in sto_names[:3]])
        if len(sto_names) > 3:
            sto_display += f"_and_{len(sto_names)-3}_more"
        
        filename = f"churn_clustering_{user_id}_{sto_display}_{clean_risk}_{timestamp}.html"
        output_path = os.path.join("maps", filename)
        os.makedirs("maps", exist_ok=True)

        if progress_callback:
            await progress_callback(80, "Membaca data pengguna untuk watermark...")

        # Generate watermark (same logic)
        user_csv_path = USER_DATA_FILE
        watermark_text = None
        try:
            with open(user_csv_path, 'r', encoding='utf-8') as csv_file:
                csv_reader = csv.DictReader(csv_file)
                for row in csv_reader:
                    if str(row.get('user_id')).strip() == str(user_id).strip():
                        watermark_text = f"{row.get('username')} - {row.get('nik_tsel')}"
                        break
        except Exception as e:
            logging.error(f"Error reading CSV file: {e}")
            raise

        if not watermark_text:
            raise ValueError("User anda belum terdaftar, silahkan lakukan registrasi dengan /register")

        watermark_html = ''.join([f'<div class="watermark-item">{watermark_text}</div>' for _ in range(64)])

        if progress_callback:
            await progress_callback(90, "Menyusun template yang disempurnakan...")

        # Read enhanced template (use the new clustering template)
        template_path = os.path.join(os.path.dirname(__file__), 'templates', 'churn_clustering_bysto.html')
        with open(template_path, 'r', encoding='utf-8') as template_file:
            html_template = template_file.read()

        # Unique segments for filters
        unique_segments = []
        for segment_name in sorted(segment_data.keys()):
            count = len(segment_data[segment_name])
            display_name = segment_name.replace("BILLING & SERVICE COMPLAINANT", "BILLING & SERVICE").replace("COMPETITOR EXPLORER", "COMP EXPLR")[:15]
            unique_segments.append({
                'name': segment_name,
                'displayName': display_name,
                'count': count
            })

        # Populate enhanced template with all data
        populated_html = html_template.replace("{{ center_lat }}", str(center_lat)) \
                                      .replace("{{ center_lon }}", str(center_lon)) \
                                      .replace("{{ data_count }}", f"{len(coordinates):,}") \
                                      .replace("{{ segment_data_json }}", safe_json_dumps(segment_data)) \
                                      .replace("{{ segment_colors_json }}", safe_json_dumps(segment_colors)) \
                                      .replace("{{ risk_colors_json }}", safe_json_dumps(risk_colors)) \
                                      .replace("{{ clustering_results_json }}", safe_json_dumps(clustering_results or {})) \
                                      .replace("{{ cluster_data_json }}", safe_json_dumps(cluster_data)) \
                                      .replace("{{ summary_data_json }}", safe_json_dumps(summary_data)) \
                                      .replace("{{ show_filters_json }}", str(len(unique_segments) > 1).lower()) \
                                      .replace("{{ unique_segments_json }}", safe_json_dumps(unique_segments)) \
                                      .replace("{{ region_name_upper }}", region_name.upper()) \
                                      .replace("{{ branch_name_upper }}", branch_name.upper()) \
                                      .replace("{{ sto_name_upper }}", sto_display.upper()) \
                                      .replace("{{ risk_level_display }}", risk_level.upper()) \
                                      .replace("{{ data_count_formatted }}", f"{len(coordinates):,}") \
                                      .replace("{{ min_lat }}", str(min(latitudes))) \
                                      .replace("{{ min_lon }}", str(min(longitudes))) \
                                      .replace("{{ max_lat }}", str(max(latitudes))) \
                                      .replace("{{ max_lon }}", str(max(longitudes))) \
                                      .replace("{{ watermark_container }}", watermark_html)

        if progress_callback:
            await progress_callback(95, "Menyimpan file yang disempurnakan...")

        # Write enhanced HTML file
        with open(output_path, 'w', encoding='utf-8') as f:
            f.write(populated_html)

        if progress_callback:
            await progress_callback(100, "Peta klaster yang disempurnakan selesai!")

        logging.info(f"Enhanced churn clustering map generated: {output_path} ({len(coordinates):,} points)")
        return output_path

    except Exception as e:
        logging.error(f"Error generating enhanced clustering map: {e}", exc_info=True)
        raise


