# Alternative version with automatic column optimization
async def send_sto_selection_smart(chat_id: int, bot: Bot, branch_name: str, region_name: str, state: FSMContext = None):
    """
    Smart STO selection that automatically detects flow type and chooses optimal layout.
    """
    try:
        # Detect flow type from state
        flow_type = "cvm"  # default
        if state:
            state_data = await state.get_data()
            flow_type = state_data.get('flow_type', 'cvm')
        
        # Set callback patterns based on flow type
        if flow_type == "churn":
            callback_prefix = "churn_select_sto"
            cancel_callback = "cancel_churn"
        else:
            callback_prefix = "select_sto" 
            cancel_callback = "cancel_cvm"
        
        # Fetch STOs for the selected branch
        stos = await fetch_stos_for_branch(branch_name)
        
        if not stos:
            await bot.send_message(chat_id, f"⚠️ Tidak ada STO ditemukan untuk Branch {branch_name.upper()}.")
            return

        sorted_stos = sorted(stos)
        total_stos = len(sorted_stos)
        
        # Smart column selection based on number of STOs
        if total_stos <= 8:
            columns = 2
        elif total_stos <= 16:
            columns = 3
        else:
            columns = 4
        
        # Build keyboard rows
        keyboard_rows = []
        
        # Add STO buttons
        for i in range(0, total_stos, columns):
            row_stos = sorted_stos[i:i + columns]
            row_buttons = [
                InlineKeyboardButton(
                    text=sto.upper(),
                    callback_data=f"{callback_prefix}:{region_name}:{branch_name}:{sto}"
                )
                for sto in row_stos
            ]
            keyboard_rows.append(row_buttons)
        
        # Add cancel button
        keyboard_rows.append([InlineKeyboardButton(text="❌ Batal", callback_data=cancel_callback)])
        
        keyboard = InlineKeyboardMarkup(inline_keyboard=keyboard_rows)
        
        # Flow-specific message text
        if flow_type == "churn":
            message_text = (
                f"📍 Pilih STO untuk Branch {branch_name.upper()} (Region {region_name.upper()}):\n\n"
                f"💡 Total: {total_stos} STO | Klik untuk memilih (maks. 10)"
            )
        else:
            message_text = f"📍 Pilih STO untuk Branch {branch_name.upper()} (Region {region_name.upper()}):\n\n💡 Total: {total_stos} STO"
        
        await bot.send_message(chat_id, message_text, reply_markup=keyboard)
        
        logging.info(f"Smart STO selection sent for {flow_type} flow with {columns} columns ({total_stos} STOs) for branch {branch_name}")
        
    except Exception as e:
        logging.error(f"Error in smart STO selection for branch {branch_name}: {e}")
        await bot.send_message(chat_id, "⚠️ Terjadi kesalahan saat mengambil data STO.")


