async def send_segment_selection_sto(chat_id: int, bot: 'Bot', sto_name: str, user_id: int, num_columns: int = 2):  # Added user_id parameter
    """
    Sends a message with an inline keyboard to select a customer segment for the given STO.
    Uses 2-column layout for better organization with predefined order.
    """
    try:
        # Get available segments for this STO
        segments = await fetch_available_segments_for_sto(sto_name, user_id)  # Now user_id exists
        
        if not segments:
            await bot.send_message(chat_id, f"⚠️ Tidak ada data segmen customer untuk STO {sto_name.upper()}.")
            return
            
        # Define the specific order (matching your requested sequence)
        ordered_segments = [
            "Early Tenure Customer",           # 01
            "Network Stability Issue",         # 02  
            "Billing & Service Complainant",   # 03
            "Dormant User",                    # 04
            "Late Payer",                      # 05
            "Declined Usage",                  # 06
            "Competitor Explorer",             # 07
            "Stable Usage",                    # 08
            "Increased Usage",                 # 09
            "Non-Optimal Experience"           # 10
        ]
        
        # Filter ordered segments to only include available segments
        available_ordered_segments = [seg for seg in ordered_segments if seg in segments]
        
        # Segment display names with shorter text for better 2-column layout
        segment_short_names = {
            "Early Tenure Customer": "01. Early Tenure",
            "Network Stability Issue": "02. Network Issue",
            "Billing & Service Complainant": "03. Billing & Service",
            "Dormant User": "04. Dormant User", 
            "Late Payer": "05. Late Payer",
            "Declined Usage": "06. Decl Usg",
            "Competitor Explorer": "07. Comp Explr",
            "Stable Usage": "08. Stable Usg",
            "Increased Usage": "09. Incr Usg",
            "Non-Optimal Experience": "10. Non-Optimal"
        }
        
        # Build keyboard rows
        keyboard_rows = []
        
        # Add "All Segments" option FIRST as a full-width button
        all_segments_btn = InlineKeyboardButton(
            text="📊 ALL SEGMENTS", 
            callback_data=f"select_segment:{sto_name}:ALL"
        )
        keyboard_rows.append([all_segments_btn])
        
        # Add segment buttons in 2-column rows (in predefined order)
        for i in range(0, len(available_ordered_segments), num_columns):
            row_segments = available_ordered_segments[i:i + num_columns]
            row_buttons = []
            
            for segment in row_segments:
                button_text = segment_short_names.get(segment, segment)
                callback = f"select_segment:{sto_name}:{segment}"
                btn = InlineKeyboardButton(text=button_text, callback_data=callback)
                row_buttons.append(btn)
            
            keyboard_rows.append(row_buttons)
        
        # Add cancel button as full-width
        cancel_button = InlineKeyboardButton(text="❌ Batal", callback_data="cancel_cvm")
        keyboard_rows.append([cancel_button])
        
        # Create keyboard with inline_keyboard parameter
        keyboard = InlineKeyboardMarkup(inline_keyboard=keyboard_rows)
        
        # Send the message
        message_text = f"👥 Silahkan pilih Customer Segment untuk STO {sto_name.upper()}:"
        
        await bot.send_message(
            chat_id,
            message_text,
            reply_markup=keyboard
        )
        logging.info(f"Segment selection sent with {num_columns} columns for STO {sto_name} ({len(available_ordered_segments)} segments available)")
        
    except Exception as e:
        logger.error(f"Error sending segment selection for STO {sto_name}: {e}")
        await bot.send_message(chat_id, "⚠️ Terjadi kesalahan saat mengambil data segmen.")


