async def store_location_cvm_data(user_id: int, data: dict):
    """Store location Ten Segment data as HTML file using enhanced generator"""
    try:
        logging.info(f"Storing location Ten Segment data for user {user_id}")
        
        # Extract data
        latitude = data.get("latitude", 0)
        longitude = data.get("longitude", 0)
        segment = data.get("segment", "ALL")
        is_live = data.get("is_live", False)
        cvm_data = data.get("cvm_data", [])
        odp_data = data.get("odp_data", [])
        
        # Optional progress callback for large datasets
        async def progress_callback(percent, message):
            logging.debug(f"HTML Generation Progress: {percent}% - {message}")
        
        # Generate HTML file using the enhanced generator
        output_path = await generate_cvm_heatmap_html_sharelocation(
            user_id=user_id,
            cvm_data=cvm_data,
            odp_data=odp_data,
            latitude=latitude,
            longitude=longitude,
            segment=segment,
            is_live=is_live,
            progress_callback=progress_callback
        )
        
        # Also save data as JSON for reference        
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        json_filename = f"cvm_sharelocation_{user_id}_{segment}_{timestamp}.json"
        json_filepath = os.path.join("/home/rajawalia3/radityayud/python_project/bot_telegram/maps", json_filename)
        
        with open(json_filepath, 'w', encoding='utf-8') as f:
            json.dump(data, f, indent=2, default=str)
        
        logging.info(f"Saved location Ten Segment data for user {user_id} to {output_path}")
        return output_path
        
    except Exception as e:
        logging.error(f"Error storing location Ten Segment data: {e}")
        return None


