# --- Building Summary View and HTML View Ten Segment by STO Filter ---
async def format_cvm_data_bysto(chat_id: int, bot: 'Bot', user_id: int, sto_name: str, segment: str, branch_name: str, region_name: str):
    """
    Process Ten Segment data, generate a summary with a horizontal bar chart,
    and produce a heatmap file. This function is production-ready and includes monthly fallback logic.
    """
    progress_message = None
    try:
        logging.debug(f"=== Starting format_cvm_data_bysto for user {user_id} ===")
        logging.debug(f"Parameters: sto_name={sto_name}, segment={segment}, branch_name={branch_name}, region_name={region_name}")

        # 1. Initial Progress Message
        initial_progress = get_loading_bar(0)
        progress_text = f"🔄 Generating Ten Segment Heatmap\n\n{initial_progress}\n\n📊 Menginisialisasi..."
        progress_message = await bot.send_message(chat_id, progress_text)

        # 2. Fetch Summary Data --- MODIFIED WITH FALLBACK LOOP ---
        await update_progress_message(bot, chat_id, progress_message.message_id, 10, "Mengambil data ringkasan...")
        
        months_to_try = await get_last_n_months(user_id, 3)
        months_to_try.reverse()  # Try newest month first
        
        sto_data = None
        logging.info(f"[Ten Segment Summary] Fallback search order: {months_to_try}")
        for month in months_to_try:
            logging.debug(f"Attempting to fetch summary for month: {month}")
            # Assumes fetch_ten_segment_cvm_summary now accepts a 'months' parameter
            result = await fetch_ten_segment_cvm_summary(usr_selected_sto=sto_name, months=[month])
            if result:
                sto_data = result
                logging.info(f"Found summary data in month: {month}")
                break  # Exit loop on first success

        logging.debug(f"Fetched {len(sto_data) if sto_data else 0} summary records from database")

        if not sto_data:
            await bot.edit_message_text(
                text=f"⚠️ Tidak ada data Ten Segment summary untuk STO {sto_name.upper()} dalam 3 bulan terakhir.",
                chat_id=chat_id,
                message_id=progress_message.message_id
            )
            return

        await update_progress_message(bot, chat_id, progress_message.message_id, 20, "Memproses data ringkasan...")

        # 3. Generate Summary Content
        summary_content = ""
        if segment == "ALL":
            all_event_dates = [row.get("event_date", "") for row in sto_data]
            latest_event_date = max(all_event_dates) if all_event_dates else None

            if not latest_event_date:
                await bot.edit_message_text(
                    text=f"⚠️ Tidak dapat menentukan event_date untuk STO {sto_name.upper()}.",
                    chat_id=chat_id,
                    message_id=progress_message.message_id
                )
                return

            latest_data = [row for row in sto_data if row.get("event_date") == latest_event_date]
            segment_groups = {}
            for row in latest_data:
                seg = row.get("customer_segment", "Unknown")
                segment_groups.setdefault(seg, []).append(row)

            total_user_count = sum(int(row.get("user_count", 0)) for row in latest_data)
            total_paid_count = sum(int(row.get("paid_count", 0)) for row in latest_data)
            paid_rate = (total_paid_count / total_user_count) * 100 if total_user_count > 0 else 0.0

            date_display = str(latest_event_date)[:7]

            summary_lines = [
                f"📑 ALL Segment Information by STO",
                "━━━━━━━━━━━━━━━",
                f"🏢 Region     : {region_name.upper()}",
                f"🏣 Branch     : {branch_name.upper()}",
                f"🏠 STO        : {sto_name.upper()}",
                f"🎯 Segments   : ALL ({len(segment_groups)} segments)",
                f"📅 Event Date : {date_display}\n",
                f"👥 Total User   : {total_user_count:,}",
                f"👥 Paid User    : {total_paid_count:,}",
                f"💰 Paid Rate    : {paid_rate:.1f}%\n",
                f"📊 Breakdown by Segment (T: Total | P: Paid | R: Rate):"
            ]

            for seg, seg_data in sorted(segment_groups.items()):
                seg_user_total = sum(int(row.get("user_count", 0)) for row in seg_data)
                seg_paid_total = sum(int(row.get("paid_count", 0)) for row in seg_data)
                seg_rate = (seg_paid_total / seg_user_total) * 100 if seg_user_total > 0 else 0.0

                segment_line = (
                    f"• {seg}\n"
                    f"  (T: {seg_user_total:,} | P: {seg_paid_total:,} | R: {seg_rate:.1f}%)"
                )
                summary_lines.append(segment_line)

            summary_content = "\n".join(summary_lines)

        else:
            filtered_data = [row for row in sto_data if row.get("customer_segment", "").upper() == segment.upper()]

            if not filtered_data:
                await bot.edit_message_text(
                    text=f"⚠️ Tidak ada data untuk STO {sto_name.upper()} - Segment {segment.upper()}.",
                    chat_id=chat_id,
                    message_id=progress_message.message_id
                )
                return

            filtered_data.sort(key=lambda x: x.get("event_date", ""))

            header_lines = [
                f"📑 {segment.upper()} Information by STO",
                "━━━━━━━━━━━━━━━",
                f"🏢 Region     : {region_name.upper()}",
                f"🏣 Branch     : {branch_name.upper()}",
                f"🏠 STO        : {sto_name.upper()}",
                f"🎯 Segment    : {segment.upper()}",
            ]

            cb_chart_lines = ["\n📈 CB Monthly Trend", "━━━━━━━━━━━━━━━"]
            max_bar_length = 20
            max_user_count = max(int(row.get("user_count", 0)) for row in filtered_data) if filtered_data else 0
            cb_scale = (max_user_count / max_bar_length) if max_user_count > 0 else 0

            for row in filtered_data:
                event_date = row.get("event_date", "N/A")
                user_count = int(row.get("user_count", 0))
                try:
                    formatted_date = datetime.strptime(event_date, "%Y%m").strftime("%b-%y")
                except (ValueError, TypeError):
                    formatted_date = event_date
                num_blocks = int(user_count / cb_scale) if cb_scale > 0 else 0
                bar = "█" * num_blocks
                cb_chart_lines.append(f"{formatted_date} ({user_count:,}): {bar}")

            total_user_trend = "📊 Single period"
            if len(filtered_data) >= 2:
                previous_count = int(filtered_data[-2].get("user_count", 0))
                current_count = int(filtered_data[-1].get("user_count", 0))
                if previous_count > 0:
                    change_pct = ((current_count - previous_count) / previous_count) * 100
                    if abs(change_pct) > 0.05:
                        total_user_trend = f"↑ Total User Trend: Increasing ({change_pct:+.1f}%)" if current_count > previous_count else f"↓ Total User Trend: Decreasing ({change_pct:+.1f}%)"
                    else:
                        total_user_trend = f"➡️ Total User Trend: Stable (0.0%)"

            paid_user_trend = "📊 Single period"
            if len(filtered_data) >= 2:
                previous_paid = int(filtered_data[-2].get("paid_count", 0))
                current_paid = int(filtered_data[-1].get("paid_count", 0))
                if previous_paid > 0:
                    paid_change_pct = ((current_paid - previous_paid) / previous_paid) * 100
                    if abs(paid_change_pct) > 0.05:
                        paid_user_trend = f"↑ Paid User Trend: Increasing ({paid_change_pct:+.1f}%)" if current_paid > previous_paid else f"↓ Paid User Trend: Decreasing ({paid_change_pct:+.1f}%)"
                    else:
                        paid_user_trend = f"➡️ Paid User Trend: Stable (0.0%)"

            cb_summary_lines = ["\n📉 Trend Summary (YtD)", "━━━━━━━━━━━━━━━", total_user_trend, paid_user_trend]

            payment_chart_lines = ["\n📈 Payment Trend", "━━━━━━━━━━━━━━━"]
            payment_scale = 100.0 / max_bar_length

            for row in filtered_data:
                event_date = row.get("event_date", "N/A")
                paid_pct_value = float(row.get("paid_pct", 0.0)) * 100.0
                try:
                    formatted_date = datetime.strptime(event_date, "%Y%m").strftime("%b-%y")
                except (ValueError, TypeError):
                    formatted_date = event_date
                num_blocks = int(paid_pct_value / payment_scale) if payment_scale > 0 else 0
                bar = "█" * num_blocks
                payment_chart_lines.append(f"{formatted_date} ({paid_pct_value:.1f}%): {bar}")

            c3mr_trend = "📊 Single period"
            if len(filtered_data) >= 2:
                previous_pct = float(filtered_data[-2].get("paid_pct", 0.0)) * 100.0
                current_pct = float(filtered_data[-1].get("paid_pct", 0.0)) * 100.0
                change_points = current_pct - previous_pct
                if abs(change_points) > 0.05:
                    c3mr_trend = f"↑ C3MR Trend: Increasing ({change_points:+.1f} ppt.)" if change_points > 0 else f"↓ C3MR Trend: Decreasing ({change_points:+.1f} ppt.)"
                else:
                    c3mr_trend = f"➡️ C3MR Trend: Stable (0.0 ppt.)"

            payment_summary_lines = [c3mr_trend]
            all_lines = header_lines + cb_chart_lines + cb_summary_lines + payment_chart_lines + payment_summary_lines
            summary_content = "\n".join(all_lines)

        # 4. Send the Summary Text Message
        await update_progress_message(bot, chat_id, progress_message.message_id, 30, "Mengirim ringkasan...")
        await bot.send_message(chat_id, f"<pre>{summary_content}</pre>", parse_mode='HTML')

        # 5. Fetch Coordinate Data for Heatmap --- MODIFIED WITH FALLBACK LOOP ---
        await update_progress_message(bot, chat_id, progress_message.message_id, 40, "Mengambil data koordinat...")
        
        coordinate_data = None
        # Reuse months_to_try from the summary fetch
        logging.info(f"[Ten Segment Coords] Fallback search order: {months_to_try}")
        for month in months_to_try:
            logging.debug(f"Attempting to fetch coordinates for month: {month}")
            if segment == "ALL":
                result = await fetch_ten_segment_cvm_all_segments(usr_selected_sto=sto_name, user_id=user_id, months=[month])
            else:
                result = await fetch_ten_segment_cvm(usr_selected_sto=sto_name, usr_selected_segment=segment, user_id=user_id, months=[month])
            
            if result:
                coordinate_data = result
                logging.info(f"Found coordinate data in month: {month}")
                break # Exit loop on first success

        logging.debug(f"Fetched {len(coordinate_data) if coordinate_data else 0} coordinate records")

        if not coordinate_data:
            await bot.edit_message_text(
                text="⚠️ Tidak ada data koordinat untuk membuat heatmap dalam 3 bulan terakhir.",
                chat_id=chat_id,
                message_id=progress_message.message_id
            )
            return

        # 6. Process Coordinates
        await update_progress_message(bot, chat_id, progress_message.message_id, 50, "Memproses data koordinat...")
        valid_coordinates = []
        total_coords = len(coordinate_data)

        for i, row in enumerate(coordinate_data):
            if i % 1000 == 0 and total_coords > 5000:
                progress = 50 + (i / total_coords) * 15
                await update_progress_message(bot, chat_id, progress_message.message_id, progress, f"Memproses koordinat ({i:,}/{total_coords:,})...")

            try:
                lat = float(row.get("latitude", 0))
                lon = float(row.get("longitude", 0))
                if lat != 0 and lon != 0 and -90 <= lat <= 90 and -180 <= lon <= 180:
                    valid_coordinates.append({
                        'region': region_name, 'latitude': lat, 'longitude': lon,
                        'customer_segment': row.get("customer_segment", "Unknown"),
                        'sto': row.get("sto", "Unknown"), 'bb_id': row.get("bb_id", "N/A"),
                        'ont_category': row.get("ont_category", "N/A"),
                        'city': row.get("city", "N/A")
                    })
            except (ValueError, TypeError):
                continue

        if not valid_coordinates:
            await bot.edit_message_text(
                text="⚠️ Tidak ada koordinat valid untuk membuat heatmap.",
                chat_id=chat_id,
                message_id=progress_message.message_id
            )
            return

        # 6.5 Fetch Payment Data
        await update_progress_message(bot, chat_id, progress_message.message_id, 65, "Mengambil data pembayaran...")
        
        selected_period = await get_user_selected_period(user_id)
        start_date, end_date = await get_period_date_range(selected_period)
        
        if end_date:
            payment_table = await get_payment_history_table_name(end_date, user_id)
            if payment_table:
                bb_ids = [coord['bb_id'] for coord in valid_coordinates if coord['bb_id'] != 'N/A']
                unique_bb_ids = list(set(bb_ids))
                payment_data = await fetch_payment_data_batched(
                    unique_bb_ids, payment_table,
                    progress_callback=lambda p, s: update_progress_message(
                        bot, chat_id, progress_message.message_id, 65 + p * 0.05, s
                    )
                )
                for coord in valid_coordinates:
                    bb_id = str(coord['bb_id'])
                    coord['last_payment'] = payment_data.get(bb_id, 'N/A')
            else:
                logging.warning("No payment table found, using N/A for all payments")
                for coord in valid_coordinates:
                    coord['last_payment'] = 'N/A'
        else:
            logging.warning("No end_date available, using N/A for all payments")
            for coord in valid_coordinates:
                coord['last_payment'] = 'N/A'

        # 7. Generate and Send Heatmap File
        await update_progress_message(bot, chat_id, progress_message.message_id, 70, f"Membuat file HTML ({len(valid_coordinates):,} titik)...")
        output_html_path = await generate_cvm_heatmap_html_bysto(
            user_id, valid_coordinates, sto_name, segment, branch_name, region_name,
            progress_callback=lambda p, s: update_progress_message(bot, chat_id, progress_message.message_id, 70 + p * 0.2, s)
        )

        if not os.path.exists(output_html_path):
            await bot.edit_message_text(text="⚠️ Gagal membuat file heatmap.", chat_id=chat_id, message_id=progress_message.message_id)
            return

        file_size_mb = os.path.getsize(output_html_path) / (1024 * 1024)
        await update_progress_message(bot, chat_id, progress_message.message_id, 90, f"Mengunggah file ({file_size_mb:.1f} MB)...")

        input_file = FSInputFile(output_html_path, filename=os.path.basename(output_html_path))
        caption_segment = "ALL SEGMENTS" if segment == "ALL" else f"Segment {segment.upper()}"
        caption = f"Ten Segment Heatmap - STO {sto_name.upper()} - {caption_segment}\n\n📊 {len(valid_coordinates):,} data points\n📁 {file_size_mb:.1f} MB"

        await bot.send_document(chat_id, input_file, caption=caption)
        logging.info(f"Ten Segment heatmap sent to user {user_id} for STO {sto_name}, segment {segment}")

        await bot.delete_message(chat_id, progress_message.message_id)

        try:
            os.remove(output_html_path)
            logging.debug(f"Cleaned up HTML file: {output_html_path}")
        except Exception as cleanup_error:
            logging.warning(f"Could not clean up HTML file: {cleanup_error}")

    except Exception as e:
        logging.error(f"Error in format_cvm_data_bysto: {e}", exc_info=True)
        error_message = "⚠️ Terjadi kesalahan saat memproses data Ten Segment. Silahkan hubungi admin."
        if progress_message:
            try:
                await bot.edit_message_text(text=error_message, chat_id=chat_id, message_id=progress_message.message_id)
            except Exception:
                await bot.send_message(chat_id, error_message)
        else:
            await bot.send_message(chat_id, error_message)


async def format_cvm_data_multiple_stos(chat_id: int, bot: 'Bot', user_id: int, sto_names: list, segment: str, branch_name: str, region_name: str):
    """
    Process Ten Segment data for multiple STOs, generate combined heatmap with breakdown by STO.
    Includes monthly fallback logic.
    """
    progress_message = None
    try:
        logging.debug(f"=== Starting format_cvm_data_multiple_stos for user {user_id} ===")
        logging.debug(f"Parameters: sto_names={sto_names}, segment={segment}, branch_name={branch_name}, region_name={region_name}")

        # 1. Initial Progress Message
        initial_progress = get_loading_bar(0)
        sto_list = ", ".join([s.upper() for s in sto_names])
        progress_text = f"🔄 Generating Ten Segment Heatmap for {len(sto_names)} STOs\n\n{initial_progress}\n\n📊 Menginisialisasi..."
        progress_message = await bot.send_message(chat_id, progress_text)

        # 2. Fetch Summary Data for all STOs --- MODIFIED WITH NESTED FALLBACK LOOP ---
        await update_progress_message(bot, chat_id, progress_message.message_id, 10, "Mengambil data ringkasan untuk semua STO...")
        
        months_to_try = await get_last_n_months(user_id, 3)
        months_to_try.reverse() # Try newest month first
        
        all_sto_data = {}
        for sto_name in sto_names:
            sto_data_found = None
            for month in months_to_try:
                # Assumes fetch_ten_segment_cvm_summary accepts 'months'
                result = await fetch_ten_segment_cvm_summary(usr_selected_sto=sto_name, months=[month])
                if result:
                    sto_data_found = result
                    logging.info(f"Found summary data for STO {sto_name} in month: {month}")
                    break  # Found data for this STO, move to the next STO
            if sto_data_found:
                all_sto_data[sto_name] = sto_data_found

        if not all_sto_data:
            await bot.edit_message_text(
                text=f"⚠️ Tidak ada data Ten Segment summary untuk STO yang dipilih dalam 3 bulan terakhir.",
                chat_id=chat_id,
                message_id=progress_message.message_id
            )
            return

        await update_progress_message(bot, chat_id, progress_message.message_id, 20, "Memproses data ringkasan...")

        # 3. Generate Combined Summary Content
        summary_lines = []
        summary_lines.extend([
            f"📊 Combined Ten Segment Report - {len(sto_names)} STOs",
            "━━━━━━━━━━━━━━━",
            f"Region     : {region_name.upper()}",
            f"Branch     : {branch_name.upper()}",
            f"STOs       : {sto_list}",
            f"Segment    : {'ALL SEGMENTS' if segment == 'ALL' else segment.upper()}",
            ""
        ])
        combined_user_total = 0
        combined_paid_total = 0
        sto_summaries = []

        for idx, (sto_name, sto_data) in enumerate(all_sto_data.items()):
            sto_section = []
            if segment == "ALL":
                all_event_dates = [row.get("event_date", "") for row in sto_data]
                latest_event_date = max(all_event_dates) if all_event_dates else None
                if not latest_event_date: continue
                latest_data = [row for row in sto_data if row.get("event_date") == latest_event_date]
                sto_user_total = sum(int(row.get("user_count", 0)) for row in latest_data)
                sto_paid_total = sum(int(row.get("paid_count", 0)) for row in latest_data)
                sto_paid_rate = (sto_paid_total / sto_user_total) * 100 if sto_user_total > 0 else 0.0
                combined_user_total += sto_user_total
                combined_paid_total += sto_paid_total

                date_display = str(latest_event_date)[:7]

                sto_section.extend([
                    f"📍 STO {sto_name.upper()} Summary", "━━━━━━━━━━━━━━━",
                    f"Event Date   : {date_display}",
                    f"Total User   : {sto_user_total:,}", f"Paid User    : {sto_paid_total:,}",
                    f"Paid Rate    : {sto_paid_rate:.1f}%", "", "Breakdown by Segment:"
                ])
                segment_groups = {}
                for row in latest_data:
                    seg = row.get("customer_segment", "Unknown")
                    segment_groups.setdefault(seg, []).append(row)
                for seg, seg_data in sorted(segment_groups.items()):
                    seg_user = sum(int(row.get("user_count", 0)) for row in seg_data)
                    seg_paid = sum(int(row.get("paid_count", 0)) for row in seg_data)
                    seg_rate = (seg_paid / seg_user) * 100 if seg_user > 0 else 0.0
                    sto_section.append(f"• {seg}: {seg_user:,} users ({seg_rate:.1f}% paid)")

            else:
                filtered_data = [row for row in sto_data if row.get("customer_segment", "").upper() == segment.upper()]
                if not filtered_data: continue
                filtered_data.sort(key=lambda x: x.get("event_date", ""))
                sto_section.extend([f"📍 STO {sto_name.upper()} Summary", "━━━━━━━━━━━━━━━"])
                
                sto_section.append("👥 Total User")
                for row in filtered_data:
                    # Cut string to YYYY-MM
                    date_display = str(row.get('event_date', 'N/A'))[:7]
                    sto_section.append(f"• {date_display} : {int(row.get('user_count', 0)):,}")
                
                sto_section.append("\n💵 Paid User")
                for row in filtered_data:
                    date_display = str(row.get('event_date', 'N/A'))[:7]
                    sto_section.append(f"• {date_display} : {int(row.get('paid_count', 0)):,}")
                
                sto_section.append("\n💸 Paid Rate")
                for row in filtered_data:
                    user_count = int(row.get("user_count", 0))
                    paid_count = int(row.get("paid_count", 0))
                    paid_rate = (paid_count / user_count) * 100 if user_count > 0 else 0.0
                    date_display = str(row.get('event_date', 'N/A'))[:7]
                    sto_section.append(f"• {date_display} : {paid_rate:.1f}%")
                
                latest_row = filtered_data[-1]
                combined_user_total += int(latest_row.get("user_count", 0))
                combined_paid_total += int(latest_row.get("paid_count", 0))

                if len(filtered_data) >= 2:
                    trends = []
                    prev_row, curr_row = filtered_data[-2], filtered_data[-1]
                    prev_user, curr_user = int(prev_row.get("user_count", 0)), int(curr_row.get("user_count", 0))
                    if prev_user > 0:
                        change_pct = ((curr_user - prev_user) / prev_user) * 100
                        trends.append(f"↑ Total User Trend: Increasing ({change_pct:+.1f}%)" if change_pct > 0.05 else f"↓ Total User Trend: Decreasing ({change_pct:.1f}%)" if change_pct < -0.05 else f"➡️ Total User Trend: Stable (0.0%)")
                    
                    prev_paid, curr_paid = int(prev_row.get("paid_count", 0)), int(curr_row.get("paid_count", 0))
                    if prev_paid > 0:
                        paid_change_pct = ((curr_paid - prev_paid) / prev_paid) * 100
                        trends.append(f"↑ Paid User Trend: Increasing ({paid_change_pct:+.1f}%)" if paid_change_pct > 0.05 else f"↓ Paid User Trend: Decreasing ({paid_change_pct:.1f}%)" if paid_change_pct < -0.05 else f"➡️ Paid User Trend: Stable (0.0%)")

                    prev_rate = (prev_paid / prev_user) * 100 if prev_user > 0 else 0.0
                    curr_rate = (curr_paid / curr_user) * 100 if curr_user > 0 else 0.0
                    rate_change = curr_rate - prev_rate
                    trends.append(f"↑ C3MR Trend: Increasing ({rate_change:+.1f} ppt.)" if rate_change > 0.05 else f"↓ C3MR Trend: Decreasing ({rate_change:.1f} ppt.)" if rate_change < -0.05 else f"➡️ C3MR Trend: Stable (0.0 ppt.)")
                    
                    if trends:
                        sto_section.append("")
                        sto_section.extend(trends)

            sto_summaries.append("\n".join(sto_section))

        combined_paid_rate = (combined_paid_total / combined_user_total) * 100 if combined_user_total > 0 else 0.0
        summary_lines.extend([
            "📊 COMBINED TOTALS - Latest Date", "━━━━━━━━━━━━━━━",
            f"Total Users  : {combined_user_total:,}", f"Paid Users   : {combined_paid_total:,}",
            f"Overall Rate : {combined_paid_rate:.1f}%", "", ""
        ])
        for idx, summary in enumerate(sto_summaries):
            summary_lines.append(summary)
            if idx < len(sto_summaries) - 1:
                summary_lines.extend(["", ""])
        
        summary_content = "\n".join(summary_lines)

        # 4. Send the Summary
        await update_progress_message(bot, chat_id, progress_message.message_id, 30, "Mengirim ringkasan...")
        await send_long_message(bot, chat_id, [f"<pre>{summary_content}</pre>"], parse_mode='HTML')

        # 5. Fetch Coordinate Data for all STOs --- MODIFIED WITH NESTED FALLBACK LOOP ---
        await update_progress_message(bot, chat_id, progress_message.message_id, 40, "Mengambil data koordinat untuk semua STO...")
        
        all_coordinates = []
        # Reuse months_to_try from the summary fetch
        for idx, sto_name in enumerate(sto_names):
            await update_progress_message(bot, chat_id, progress_message.message_id, 40 + (idx / len(sto_names)) * 20, f"Mengambil data untuk {sto_name.upper()}...")
            
            coords_found_for_sto = None
            for month in months_to_try:
                if segment == "ALL":
                    result = await fetch_ten_segment_cvm_all_segments(usr_selected_sto=sto_name, user_id=user_id, months=[month])
                else:
                    result = await fetch_ten_segment_cvm(usr_selected_sto=sto_name, usr_selected_segment=segment, user_id=user_id, months=[month])
                
                if result:
                    coords_found_for_sto = result
                    logging.info(f"Found coordinate data for STO {sto_name} in month: {month}")
                    break # Found data for this STO, move to next STO
            
            if coords_found_for_sto:
                for coord in coords_found_for_sto:
                    coord['sto_group'] = sto_name
                all_coordinates.extend(coords_found_for_sto)

        if not all_coordinates:
            await bot.edit_message_text(
                text="⚠️ Tidak ada data koordinat untuk membuat heatmap dalam 3 bulan terakhir.",
                chat_id=chat_id,
                message_id=progress_message.message_id
            )
            return

        # 6. Process Coordinates
        await update_progress_message(bot, chat_id, progress_message.message_id, 60, "Memproses data koordinat...")
        valid_coordinates = []
        total_coords = len(all_coordinates)

        for i, row in enumerate(all_coordinates):
            if i % 1000 == 0 and total_coords > 5000:
                progress = 60 + (i / total_coords) * 15
                await update_progress_message(bot, chat_id, progress_message.message_id, progress, f"Memproses koordinat ({i:,}/{total_coords:,})...")

            try:
                lat = float(row.get("latitude", 0))
                lon = float(row.get("longitude", 0))
                if lat != 0 and lon != 0 and -90 <= lat <= 90 and -180 <= lon <= 180:
                    valid_coordinates.append({
                        'region': region_name, 'latitude': lat, 'longitude': lon,
                        'customer_segment': row.get("customer_segment", "Unknown"),
                        'sto': row.get("sto", row.get('sto_group', "Unknown")),
                        'bb_id': row.get("bb_id", "N/A"),
                        'ont_category': row.get("ont_category", "N/A"),
                        'city': row.get("city", "N/A")
                    })
            except (ValueError, TypeError):
                continue

        if not valid_coordinates:
            await bot.edit_message_text(
                text="⚠️ Tidak ada koordinat valid untuk membuat heatmap.",
                chat_id=chat_id,
                message_id=progress_message.message_id
            )
            return

        # 6.5 Fetch Payment Data
        await update_progress_message(bot, chat_id, progress_message.message_id, 75, "Mengambil data pembayaran...")
        
        selected_period = await get_user_selected_period(user_id)
        start_date, end_date = await get_period_date_range(selected_period)
        
        if end_date:
            payment_table = await get_payment_history_table_name(end_date, user_id)
            if payment_table:
                bb_ids = [coord['bb_id'] for coord in valid_coordinates if coord['bb_id'] != 'N/A']
                unique_bb_ids = list(set(bb_ids))
                payment_data = await fetch_payment_data_batched(
                    unique_bb_ids, payment_table,
                    progress_callback=lambda p, s: update_progress_message(
                        bot, chat_id, progress_message.message_id, 75 + p * 0.05, s
                    )
                )
                for coord in valid_coordinates:
                    bb_id = str(coord['bb_id'])
                    coord['last_payment'] = payment_data.get(bb_id, 'N/A')
            else:
                logging.warning("No payment table found, using N/A for all payments")
                for coord in valid_coordinates:
                    coord['last_payment'] = 'N/A'
        else:
            logging.warning("No end_date available, using N/A for all payments")
            for coord in valid_coordinates:
                coord['last_payment'] = 'N/A'

        # 7. Generate Combined Heatmap
        await update_progress_message(bot, chat_id, progress_message.message_id, 80, f"Membuat heatmap gabungan ({len(valid_coordinates):,} titik)...")
        output_html_path = await generate_cvm_heatmap_html_multiple_stos(
            user_id, valid_coordinates, sto_names, segment, branch_name, region_name,
            progress_callback=lambda p, s: update_progress_message(bot, chat_id, progress_message.message_id, 80 + p * 0.15, s)
        )

        if not os.path.exists(output_html_path):
            await bot.edit_message_text(text="⚠️ Gagal membuat file heatmap.", chat_id=chat_id, message_id=progress_message.message_id)
            return

        # 8. Send the heatmap file
        file_size_mb = os.path.getsize(output_html_path) / (1024 * 1024)
        await update_progress_message(bot, chat_id, progress_message.message_id, 95, f"Mengunggah file ({file_size_mb:.1f} MB)...")

        input_file = FSInputFile(output_html_path, filename=os.path.basename(output_html_path))
        caption_segment = "ALL SEGMENTS" if segment == "ALL" else f"Segment {segment.upper()}"
        caption = (
            f"📊 Ten Segment Combined Heatmap\n"
            f" • {len(sto_names)} STOs: {sto_list}\n"
            f" • {caption_segment}\n"
            f" • {len(valid_coordinates):,} data points\n"
            f" • {file_size_mb:.1f} MB"
        )

        await bot.send_document(chat_id, input_file, caption=caption)
        logging.info(f"Combined Ten Segment heatmap sent to user {user_id} for {len(sto_names)} STOs")

        await bot.delete_message(chat_id, progress_message.message_id)

        try:
            os.remove(output_html_path)
            logging.debug(f"Cleaned up HTML file: {output_html_path}")
        except Exception as cleanup_error:
            logging.warning(f"Could not clean up HTML file: {cleanup_error}")

    except Exception as e:
        logging.error(f"Error in format_cvm_data_multiple_stos: {e}", exc_info=True)
        error_message = "⚠️ Terjadi kesalahan saat memproses data Ten Segment. Silahkan hubungi admin."
        if progress_message:
            try:
                await bot.edit_message_text(text=error_message, chat_id=chat_id, message_id=progress_message.message_id)
            except Exception:
                await bot.send_message(chat_id, error_message)
        else:
            await bot.send_message(chat_id, error_message)


async def format_cvm_data_sharelocation(chat_id: int, bot: Bot, user_id: int, latitude: float, longitude: float, segment: str, is_live: bool):
    """
    Process location-based Ten Segment data and generate summary with enhanced loading progress.
    Includes monthly fallback logic for Ten Segment data.
    """
    progress_message = None
    try:
        logging.debug(f"=== Starting format_cvm_data_sharelocation ===")
        logging.debug(f"Parameters: lat={latitude}, lng={longitude}, segment={segment}, is_live={is_live}")
        
        # Initial progress message
        initial_progress = get_loading_bar(0)
        progress_text = f"🔄 Generating Location Ten Segment Heatmap\n\n{initial_progress}\n\n📊 Menginisialisasi..."
        progress_message = await bot.send_message(chat_id, progress_text)
        
        # Fetch Ten Segment data within location radius --- MODIFIED WITH FALLBACK LOOP ---
        await update_progress_message(bot, chat_id, progress_message.message_id, 10, "Mengambil data Ten Segment di sekitar lokasi Anda...")
        
        months_to_try = await get_last_n_months(user_id, 3)
        months_to_try.reverse()  # Try newest month first
        
        cvm_data = None
        logging.info(f"[Ten Segment Location] Fallback search order: {months_to_try}")
        for month in months_to_try:
            logging.debug(f"Attempting to fetch location data for month: {month}")
            # Assumes get_cvm_data_by_location now accepts a 'months' parameter
            result = await get_cvm_data_by_location(latitude, longitude, segment, months=[month])
            if result:
                cvm_data = result
                logging.info(f"Found location data in month: {month}")
                break  # Exit loop on first success

        logging.debug(f"Fetched {len(cvm_data) if cvm_data else 0} Ten Segment records from location")
        
        # Fetch ODP data (remains unchanged as it's not monthly)
        await update_progress_message(bot, chat_id, progress_message.message_id, 20, "Mengambil data ODP di sekitar lokasi Anda...")
        odp_data = await get_odp_data_by_location(latitude, longitude)
        
        logging.debug(f"Fetched {len(odp_data) if odp_data else 0} ODP records from location")
        
        if not cvm_data and not odp_data:
            await bot.edit_message_text(
                chat_id=chat_id,
                message_id=progress_message.message_id,
                text=f"⚠️ Tidak ada data Ten Segment atau ODP dalam radius ±500m dari lokasi Anda dalam 3 bulan terakhir."
            )
            return

        await update_progress_message(bot, chat_id, progress_message.message_id, 30, "Memproses data lokasi...")

        # Process data based on segment selection
        summary_content = ""
        if segment == "ALL":
            segment_groups = {}
            for row in cvm_data:
                seg = row.get("customer_segment", "Unknown")
                segment_groups.setdefault(seg, []).append(row)
            
            total_cvm_count = len(cvm_data)
            total_odp_count = len(odp_data)
            unique_segments = list(segment_groups.keys())
            
            summary_content = (
                f"📑 ALL Segment Information by Location\n"
                f"━━━━━━━━━━━━━━━\n"
                f"Center         : {latitude:.6f}, {longitude:.6f}\n"
                f"Radius         : ±500 meters\n"
                f"Segments       : ALL ({len(unique_segments)} segments)\n"
                f"Customer Count : {total_cvm_count:,}\n"
                f"ODP Count      : {total_odp_count:,}\n\n"
                f"Breakdown by Segment:\n"
            )
            for seg, seg_data in sorted(segment_groups.items()):
                summary_content += f"• {seg} : {len(seg_data):,}\n"
            
        else:
            filtered_data = [row for row in cvm_data if row.get("customer_segment", "").upper() == segment.upper()]
            
            if not filtered_data:
                await bot.edit_message_text(
                    chat_id=chat_id,
                    message_id=progress_message.message_id,
                    text=f"⚠️ Tidak ada data untuk segment {segment.upper()} dalam radius ±500m."
                )
                return
            
            summary_content = (
                f"📑 {segment} Information by Location\n"
                f"━━━━━━━━━━━━━━━\n"
                f"Center         : {latitude:.6f}, {longitude:.6f}\n"
                f"Radius         : ±500 meters\n"
                f"Segment        : {segment.upper()}\n"
                f"Customer Count : {len(filtered_data):,}\n"
                f"ODP Count      : {len(odp_data):,}\n"
            )

        await update_progress_message(bot, chat_id, progress_message.message_id, 40, "Mengirim ringkasan...")

        summary_msg = f"```\n{summary_content}```"
        await bot.send_message(chat_id, summary_msg, parse_mode='MarkdownV2')

        await update_progress_message(bot, chat_id, progress_message.message_id, 50, "Memproses data koordinat...")

        valid_coordinates = []
        total_coords = len(cvm_data)
        for i, row in enumerate(cvm_data):
            if i % 500 == 0 and total_coords > 2000:
                progress = 50 + (i / total_coords) * 15
                await update_progress_message(bot, chat_id, progress_message.message_id, progress, f"Memproses koordinat ({i:,}/{total_coords:,})...")
            
            try:
                lat = float(row.get("latitude", 0))
                lon = float(row.get("longitude", 0))
                if lat != 0 and lon != 0 and -90 <= lat <= 90 and -180 <= lon <= 180:
                    valid_coordinates.append({
                        'latitude': lat, 'longitude': lon,
                        'customer_segment': row.get("customer_segment", "Unknown"),
                        'sto': row.get("sto", "Unknown"),
                        'bb_id': row.get("bb_id", "N/A"),
                        'ont_category': row.get("ont_category", "N/A"),
                        'city': row.get("city", "N/A")
                    })
            except (ValueError, TypeError):
                continue
        
        if not valid_coordinates and not odp_data:
            await bot.edit_message_text(
                chat_id=chat_id, message_id=progress_message.message_id,
                text="⚠️ Tidak ada koordinat valid untuk membuat heatmap."
            )
            return

        # Fetch Payment Data
        await update_progress_message(bot, chat_id, progress_message.message_id, 65, "Mengambil data pembayaran...")
        
        selected_period = await get_user_selected_period(user_id)
        start_date, end_date = await get_period_date_range(selected_period)
        
        if end_date:
            payment_table = await get_payment_history_table_name(end_date, user_id)
            if payment_table:
                bb_ids = [coord['bb_id'] for coord in valid_coordinates if coord['bb_id'] != 'N/A']
                unique_bb_ids = list(set(bb_ids))
                payment_data = await fetch_payment_data_batched(
                    unique_bb_ids, payment_table,
                    progress_callback=lambda p, s: update_progress_message(
                        bot, chat_id, progress_message.message_id, 65 + p * 0.05, s
                    )
                )
                for coord in valid_coordinates:
                    bb_id = str(coord['bb_id'])
                    coord['last_payment'] = payment_data.get(bb_id, 'N/A')
            else:
                logging.warning("No payment table found, using N/A for all payments")
                for coord in valid_coordinates:
                    coord['last_payment'] = 'N/A'
        else:
            logging.warning("No end_date available, using N/A for all payments")
            for coord in valid_coordinates:
                coord['last_payment'] = 'N/A'

        await update_progress_message(bot, chat_id, progress_message.message_id, 70, f"Membuat file HTML ({len(valid_coordinates):,} Ten Segment + {len(odp_data):,} ODP titik)...")

        output_html_path = await generate_cvm_heatmap_html_sharelocation(
            user_id, valid_coordinates, odp_data, latitude, longitude, segment, is_live,
            progress_callback=lambda p, s: update_progress_message(bot, chat_id, progress_message.message_id, 70 + p * 0.2, s)
        )
        
        if not os.path.exists(output_html_path):
            await bot.edit_message_text(
                chat_id=chat_id, message_id=progress_message.message_id,
                text="⚠️ Gagal membuat file heatmap."
            )
            return

        file_size_mb = os.path.getsize(output_html_path) / (1024 * 1024)
        await update_progress_message(bot, chat_id, progress_message.message_id, 90, f"Mengunggah file ({file_size_mb:.1f} MB)...")

        input_file = FSInputFile(output_html_path, filename=os.path.basename(output_html_path))
        
        caption = (f"Ten Segment Heatmap - {'ALL SEGMENTS' if segment == 'ALL' else segment.upper()}\n\n"
                   f"📍 {latitude:.6f}, {longitude:.6f}\n"
                   f"📊 {len(valid_coordinates):,} Ten Segment + {len(odp_data):,} ODP points\n"
                   f"📁 {file_size_mb:.1f} MB")
        
        await update_progress_message(bot, chat_id, progress_message.message_id, 95, "Menyelesaikan unggahan...")
        
        await bot.send_document(chat_id, input_file, caption=caption)
        logger.info(f"Ten Segment heatmap sent to user {user_id} for location {latitude}, {longitude}, segment {segment}")
        
        try:
            await bot.delete_message(chat_id, progress_message.message_id)
        except:
            pass
            
        try:
            os.remove(output_html_path)
            logging.debug(f"Cleaned up HTML file: {output_html_path}")
        except Exception as cleanup_error:
            logging.warning(f"Could not clean up HTML file: {cleanup_error}")

    except Exception as e:
        logger.error(f"Error processing location Ten Segment data: {e}", exc_info=True)
        error_message = "⚠️ Terjadi kesalahan saat memproses data Ten Segment. Silahkan hubungi admin."
        if progress_message:
            try:
                await bot.edit_message_text(
                    chat_id=chat_id, message_id=progress_message.message_id,
                    text=error_message
                )
            except:
                await bot.send_message(chat_id, error_message)
        else:
            await bot.send_message(chat_id, error_message)


async def cvm_generate_report(event: Union[Message, CallbackQuery], bot: Bot):
    """
    Enhanced Ten Segment functionality with maintenance mode check and specific "No Data Found" error handling.
    """
    user_id = event.from_user.id
    chat_id = event.chat.id if isinstance(event, Message) else event.message.chat.id

    try:
        if CVM_MAINTENANCE_MODE:
            maintenance_msg = "Mohon maaf, fitur Ten Segment dalam maintenance 🛠"
            if isinstance(event, CallbackQuery):
                await event.answer("⚠️ Ten Segment dalam maintenance")
                await event.message.edit_text(maintenance_msg)
            else:
                await bot.send_message(chat_id, maintenance_msg)
            return
        
        # This function will eventually trigger one of the format_... functions
        # which may raise a ValueError or another Exception.
        await send_cvm_tracking_selection(event, bot)
        logger.info(f"User {user_id} started Ten Segment flow - tracking method selection sent.")
        
    # This specifically catches the "No Data Found" errors from our format_... functions.
    except ValueError as ve:
        logger.warning(f"Handled a recoverable ValueError for user {user_id}: {ve}")
        # Send the user-friendly message from the exception itself.
        if isinstance(event, CallbackQuery):
            try:
                # Answer the callback first to remove the "loading" state
                await event.answer(f"⚠️ {ve}", show_alert=True)
                # You can optionally edit the message to reflect the final state or leave it.
                # For example, edit it back to a menu.
                # heatmap_keyboard = await get_heatmap_keyboard_for_user(user_id)
                # await event.message.edit_text("Silakan coba lagi dengan filter berbeda.", reply_markup=heatmap_keyboard)
            except Exception as inner_e:
                 logger.error(f"Failed to handle ValueError in CallbackQuery: {inner_e}")
                 await bot.send_message(chat_id, str(ve)) # Fallback to sending a new message
        else:
            await bot.send_message(chat_id, str(ve))

    except Exception as e:
        logger.error(f"Error in cvm_generate_report: {e}", exc_info=True)
        try:
            if isinstance(event, CallbackQuery):
                await event.answer("❌ Terjadi kesalahan sistem", show_alert=True)
                try:
                    heatmap_keyboard = await get_heatmap_keyboard_for_user(user_id)
                    await event.message.edit_text(
                        "🗺️ *Heatmap Analytics*\n\n"
                        "❌ Terjadi kesalahan sistem. Silakan coba lagi.\n\n"
                        "_Dapat juga menggunakan command: /cvm, /churn_",
                        reply_markup=heatmap_keyboard,
                        parse_mode="Markdown"
                    )
                except:
                    main_keyboard = await get_main_keyboard_for_user(user_id)
                    await event.message.edit_text(
                        "🏠 *Menu Utama*\n\nTerjadi kesalahan. Kembali ke menu utama.",
                        reply_markup=main_keyboard,
                        parse_mode="Markdown"
                    )
            else:
                await send_error_message(bot, chat_id)
                
        except Exception as error_handling_exception:
            logger.error(f"Could not send error message: {error_handling_exception}")


