async def send_churn_report_stos_with_formatting(bot: Bot, chat_id: int, summary_content: str, telegram_max_len: int = 4000):
    """
    Specialized function to send churn clustering reports with proper monospace formatting.
    Splits at logical section boundaries to maintain readability.
    """
    try:
        # Define section headers that mark logical boundaries
        section_headers = [
            "📊 Analisis Clustering Churn Risk",
            "RINGKASAN CLUSTERING",
            "💰 PRIORITAS CLUSTER BERDASARKAN REVENUE", 
            "🔥 TOP AREA KONSENTRASI",
            "⚠️ PENILAIAN RISIKO CLUSTERING",
            "📊 RINGKASAN BERDASARKAN TEN SEGMENTS",
            "🏠 INFO ALAT PRODUKSI",
            "💡 ANALISIS DETAIL"
        ]
        
        # Split content into lines
        lines = summary_content.split('\n')
        
        # Group lines into logical sections
        sections = []
        current_section = []
        
        for line in lines:
            # Check if this line starts a new section
            is_section_header = any(line.strip().startswith(header) for header in section_headers)
            
            if is_section_header and current_section:
                # Save current section and start new one
                sections.append('\n'.join(current_section))
                current_section = [line]
            else:
                current_section.append(line)
        
        # Add the last section
        if current_section:
            sections.append('\n'.join(current_section))
        
        # Process sections and combine small ones
        messages_to_send = []
        current_message = ""
        
        for section in sections:
            # Calculate length with code block wrapper
            section_with_wrapper = f"```\n{section}\n```"
            current_with_wrapper = f"```\n{current_message}\n```" if current_message else ""
            combined_content = f"{current_message}\n\n{section}" if current_message else section
            combined_with_wrapper = f"```\n{combined_content}\n```"
            
            # If this section alone is too big, we need to split it further
            if len(section_with_wrapper) > telegram_max_len:
                # Save current message if exists
                if current_message:
                    messages_to_send.append(f"```\n{current_message}\n```")
                    current_message = ""
                
                # Split large section by lines, keeping revenue ranking together
                section_lines = section.split('\n')
                temp_section = ""
                
                for line in section_lines:
                    temp_with_line = f"{temp_section}\n{line}" if temp_section else line
                    temp_with_wrapper = f"```\n{temp_with_line}\n```"
                    
                    if len(temp_with_wrapper) > telegram_max_len:
                        # Send current temp section
                        if temp_section:
                            messages_to_send.append(f"```\n{temp_section}\n```")
                        temp_section = line
                    else:
                        temp_section = temp_with_line
                
                # Add remaining temp section to current message
                if temp_section:
                    current_message = temp_section
                    
            # If combining with current message would be too big, send current first
            elif len(combined_with_wrapper) > telegram_max_len:
                if current_message:
                    messages_to_send.append(f"```\n{current_message}\n```")
                current_message = section
            else:
                # Safe to combine
                current_message = combined_content
        
        # Add final message
        if current_message:
            messages_to_send.append(f"```\n{current_message}\n```")
        
        # Send all messages with proper parse_mode
        for i, message in enumerate(messages_to_send):
            try:
                await bot.send_message(chat_id=chat_id, text=message, parse_mode='Markdown')
                
                # Small delay between messages to avoid rate limiting
                if i < len(messages_to_send) - 1:
                    await asyncio.sleep(0.1)
                    
            except Exception as e:
                logging.error(f"Failed to send churn report chunk {i+1}/{len(messages_to_send)}: {e}")
                # Fallback: send without code blocks
                plain_content = message.replace('```\n', '').replace('\n```', '')
                try:
                    await bot.send_message(chat_id=chat_id, text=plain_content)
                except Exception as fallback_error:
                    logging.error(f"Fallback also failed for chunk {i+1}: {fallback_error}")
        
        logging.info(f"Successfully sent churn report in {len(messages_to_send)} parts")
        
    except Exception as e:
        logging.error(f"Error in send_churn_report_stos_with_formatting: {e}")
        # Ultimate fallback: send as plain text
        try:
            await send_long_message(bot, chat_id, [summary_content])
        except Exception as ultimate_error:
            logging.error(f"Ultimate fallback failed: {ultimate_error}")


