# ============================
async def calculate_driving_distance_async(points: List[Tuple[float, float]], session: aiohttp.ClientSession) -> Optional[float]:
    """
    Asynchronously calculates the driving distance for a sequence of points using aiohttp.

    Args:
        points: A list of (latitude, longitude) tuples in travel order.
        session: An active aiohttp.ClientSession.

    Returns:
        The total route distance in kilometers, or None on failure.
    """
    if len(points) < 2:
        return 0.0

    try:
        coords_str = ";".join([f"{lng},{lat}" for lat, lng in points])
        osrm_url = f"http://router.project-osrm.org/route/v1/driving/{coords_str}?overview=false"
        
        # Use the provided aiohttp session for the request
        async with session.get(osrm_url, proxy=PROXY_URL, timeout=aiohttp.ClientTimeout(total=20)) as response:
            if response.status == 200:
                data = await response.json()
                if data.get('code') == 'Ok' and data.get('routes'):
                    return data['routes'][0]['distance'] / 1000.0  # Return distance in km
                else:
                    logging.warning(f"OSRM API error: {data.get('message')}")
                    return None
            else:
                logging.error(f"OSRM request failed with status {response.status}")
                return None
    except Exception as e:
        logging.error(f"Async OSRM request failed: {e}")
        return None


def create_chained_clusters_with_cache(odp_data: list, start_lat: float, start_lng: float, distance_cache: dict,
                                       max_route_km: float = 5.0, max_odps: int = 50):
    """
    Creates clusters using a pre-calculated distance cache. This is purely CPU-bound.
    """
    if not odp_data:
        return []

    def get_distance(p1, p2):
        cache_key = tuple(sorted((p1, p2)))
        return distance_cache.get(cache_key, geodesic(p1, p2).kilometers)

    unclustered_odps = odp_data.copy()
    final_clusters = []
    current_start_point = (start_lat, start_lng)

    while unclustered_odps:
        seed_odp = min(
            unclustered_odps,
            key=lambda odp: get_distance(
                current_start_point,
                (float(odp.get('latitude', 0)), float(odp.get('longitude', 0)))
            )
        )
        
        unclustered_odps.remove(seed_odp)
        current_cluster = [seed_odp]
        cluster_internal_start_point = (float(seed_odp.get('latitude')), float(seed_odp.get('longitude')))

        while True:
            if not unclustered_odps or len(current_cluster) >= max_odps:
                break

            last_odp_in_cluster = current_cluster[-1]
            last_point_coords = (float(last_odp_in_cluster.get('latitude')), float(last_odp_in_cluster.get('longitude')))

            next_odp = min(
                unclustered_odps,
                key=lambda odp: get_distance(
                    last_point_coords,
                    (float(odp.get('latitude', 0)), float(odp.get('longitude', 0)))
                )
            )

            test_cluster = current_cluster + [next_odp]
            optimized_test_route = optimize_route_order_with_cache(test_cluster, cluster_internal_start_point, distance_cache)
            
            route_points = [cluster_internal_start_point] + [(float(odp['latitude']), float(odp['longitude'])) for odp in optimized_test_route]
            route_length = sum(get_distance(route_points[i], route_points[i+1]) for i in range(len(route_points) - 1))

            if route_length <= max_route_km:
                current_cluster.append(next_odp)
                unclustered_odps.remove(next_odp)
            else:
                break

        optimized_cluster = optimize_route_order_with_cache(current_cluster, cluster_internal_start_point, distance_cache)
        final_clusters.append(optimized_cluster)
        
        end_of_cluster = optimized_cluster[-1]
        current_start_point = (float(end_of_cluster.get('latitude')), float(end_of_cluster.get('longitude')))

    return final_clusters

def optimize_route_order_with_cache(odp_list: list, start_point: tuple, distance_cache: dict):
    """
    Synchronous route optimization using a pre-calculated distance cache.
    """
    if len(odp_list) <= 1:
        return odp_list

    def get_distance(p1, p2):
        cache_key = tuple(sorted((p1, p2)))
        return distance_cache.get(cache_key, geodesic(p1, p2).kilometers)

    unvisited = odp_list.copy()
    route = []
    current_point = start_point
    
    while unvisited:
        nearest_odp = min(
            unvisited,
            key=lambda odp: get_distance(
                current_point,
                (float(odp.get('latitude', 0)), float(odp.get('longitude', 0)))
            )
        )
        
        route.append(nearest_odp)
        unvisited.remove(nearest_odp)
        current_point = (float(nearest_odp.get('latitude', 0)), float(nearest_odp.get('longitude', 0)))
    
    return route

def optimize_route_for_round_trip(odp_list: list, start_point: tuple, distance_cache: dict):
    """Strategic round-trip optimization: closest start, farthest middle, closest end"""
    if len(odp_list) <= 1:
        return odp_list
    
    def get_distance(p1, p2):
        cache_key = tuple(sorted((p1, p2)))
        return distance_cache.get(cache_key, geodesic(p1, p2).kilometers)
    
    # Calculate distances from user location to all ODPs
    odp_distances = []
    for odp in odp_list:
        odp_point = (float(odp.get('latitude', 0)), float(odp.get('longitude', 0)))
        distance = get_distance(start_point, odp_point)
        odp_distances.append((odp, distance))
    
    # Sort by distance from user location
    odp_distances.sort(key=lambda x: x[1])
    
    if len(odp_list) == 2:
        # For 2 ODPs, start with closest, end with farthest
        return [odp_distances[0][0], odp_distances[1][0]]
    
    # Categorize ODPs by distance using 20%/60%/20% thresholds
    total_odps = len(odp_list)
    close_count = max(1, int(total_odps * 0.2))  # At least 1 ODP in close
    far_count = max(1, int(total_odps * 0.6))    # At least 1 ODP in far
    
    close_odps = [item[0] for item in odp_distances[:close_count]]
    far_odps = [item[0] for item in odp_distances[-far_count:]]
    middle_odps = [item[0] for item in odp_distances[close_count:-far_count] if -far_count != 0]
    
    # Handle edge case: if -far_count is 0, middle_odps logic breaks
    if far_count >= total_odps - close_count:
        middle_odps = []
        far_odps = [item[0] for item in odp_distances[close_count:]]
    
    # Strategic selection
    start_odp = close_odps[0]  # Closest to user (shortest start distance)
    
    # Find closest remaining ODP for ending (excluding start_odp)
    remaining_close = [odp for odp in close_odps if odp != start_odp]
    if remaining_close:
        end_odp = remaining_close[0]  # Next closest for return
        middle_section_odps = [odp for odp in odp_list if odp != start_odp and odp != end_odp]
    else:
        # Edge case: only one close ODP, use second closest overall as end
        end_odp = odp_distances[1][0]  # Second closest overall
        middle_section_odps = [odp for odp in odp_list if odp != start_odp and odp != end_odp]
    
    # If no middle section needed
    if not middle_section_odps:
        return [start_odp, end_odp] if len(odp_list) == 2 else [start_odp]
    
    # Optimize middle section using nearest-neighbor
    if len(middle_section_odps) == 1:
        optimized_middle = middle_section_odps
    else:
        # Start middle section from the start_odp location
        current_point = (float(start_odp.get('latitude', 0)), float(start_odp.get('longitude', 0)))
        optimized_middle = []
        remaining_middle = middle_section_odps.copy()
        
        while remaining_middle:
            nearest_odp = min(
                remaining_middle,
                key=lambda odp: get_distance(
                    current_point,
                    (float(odp.get('latitude', 0)), float(odp.get('longitude', 0)))
                )
            )
            
            optimized_middle.append(nearest_odp)
            remaining_middle.remove(nearest_odp)
            current_point = (float(nearest_odp.get('latitude', 0)), float(nearest_odp.get('longitude', 0)))
    
    # Final route: Start → Optimized Middle → End
    return [start_odp] + optimized_middle + [end_odp]

# Keep the old function for backward compatibility
def optimize_route_for_nearest_endpoints(odp_list: list, start_point: tuple, distance_cache: dict):
    """Legacy function - now calls the strategic round-trip optimized version"""
    return optimize_route_for_round_trip(odp_list, start_point, distance_cache)

def create_optimized_clusters_for_endpoints(odp_data: list, start_lat: float, start_lng: float, distance_cache: dict,
                                           max_route_km: float = 5.0, max_odps: int = 50):
    """Create clusters optimized for nearest start and end points"""
    if not odp_data:
        return []

    def get_distance(p1, p2):
        cache_key = tuple(sorted((p1, p2)))
        return distance_cache.get(cache_key, geodesic(p1, p2).kilometers)

    unclustered_odps = odp_data.copy()
    final_clusters = []
    current_start_point = (start_lat, start_lng)

    while unclustered_odps:
        # Find nearest ODP to current start point
        seed_odp = min(
            unclustered_odps,
            key=lambda odp: get_distance(
                current_start_point,
                (float(odp.get('latitude', 0)), float(odp.get('longitude', 0)))
            )
        )
        
        unclustered_odps.remove(seed_odp)
        current_cluster = [seed_odp]
        cluster_internal_start_point = (float(seed_odp.get('latitude')), float(seed_odp.get('longitude')))

        # Build cluster with endpoint optimization
        while True:
            if not unclustered_odps or len(current_cluster) >= max_odps:
                break

            last_odp_in_cluster = current_cluster[-1]
            last_point_coords = (float(last_odp_in_cluster.get('latitude')), float(last_odp_in_cluster.get('longitude')))

            next_odp = min(
                unclustered_odps,
                key=lambda odp: get_distance(
                    last_point_coords,
                    (float(odp.get('latitude', 0)), float(odp.get('longitude', 0)))
                )
            )

            test_cluster = current_cluster + [next_odp]
            optimized_test_route = optimize_route_for_nearest_endpoints(test_cluster, cluster_internal_start_point, distance_cache)
            
            route_points = [cluster_internal_start_point] + [(float(odp['latitude']), float(odp['longitude'])) for odp in optimized_test_route]
            route_length = sum(get_distance(route_points[i], route_points[i+1]) for i in range(len(route_points) - 1))

            if route_length <= max_route_km:
                current_cluster.append(next_odp)
                unclustered_odps.remove(next_odp)
            else:
                break

        # Final optimization for this cluster
        optimized_cluster = optimize_route_for_nearest_endpoints(current_cluster, cluster_internal_start_point, distance_cache)
        final_clusters.append(optimized_cluster)
        
        # Next start point is the end of current cluster
        end_of_cluster = optimized_cluster[-1]
        current_start_point = (float(end_of_cluster.get('latitude')), float(end_of_cluster.get('longitude')))

    return final_clusters
    

def generate_google_maps_url(start_lat: float, start_lng: float, optimized_odp_list: list):
    """
    Generates a Google Maps URL from a PRE-OPTIMIZED list of ODPs.
    """
    try:
        if not optimized_odp_list:
            return None
        
        if not start_lat or not start_lng:
            logging.error("Invalid start coordinates for route generation")
            return None
        
        # Google Maps URL has a limit of start + destination + 23 waypoints.
        limited_odps = optimized_odp_list[:25] # Total 25 points
        
        # No need to re-optimize. The list is assumed to be in the correct order.
        
        waypoints_coords = []
        for odp in limited_odps:
            lat = odp.get('latitude')
            lng = odp.get('longitude')
            if lat and lng:
                try:
                    waypoints_coords.append(f"{float(lat)},{float(lng)}")
                except (ValueError, TypeError):
                    logging.warning(f"Invalid coordinates for ODP {odp.get('odp_name', 'Unknown')}")
                    continue
        
        if not waypoints_coords:
            return None
            
        # Use the more robust URL parameter format
        base_url = "https://www.google.com/maps/dir/?api=1"
        origin = f"{start_lat},{start_lng}"
        
        # The last ODP in the list is the final destination
        destination = waypoints_coords.pop(-1)
        
        # All other ODPs are intermediate waypoints
        waypoints_str = "|".join(waypoints_coords)
        
        url = f"{base_url}&origin={origin}&destination={destination}&waypoints={waypoints_str}&travelmode=driving"
        
        logging.info(f"Generated Google Maps URL with {len(limited_odps)} waypoints.")
        return url
        
    except Exception as e:
        logging.error(f"Error generating Google Maps URL: {e}")
        return None

# === SUMMARY FUNCTIONS ===
# This function is updated to handle a list of clusters.
def generate_cluster_summary(clusters: list):
    """Generate summary report grouped by occ_2 (color status)"""
    try:
        summary = {}
        for i, odps in enumerate(clusters):
            cluster_id = i  # Use index as cluster ID
            occ_groups = {}
            for odp in odps:
                occ_2 = odp.get('occ_2', 'UNKNOWN')
                if occ_2 not in occ_groups:
                    occ_groups[occ_2] = []
                occ_groups[occ_2].append(odp)
            
            summary[cluster_id] = occ_groups
        return summary
        
    except Exception as e:
        logging.error(f"Error generating cluster summary: {e}")
        return {}


# REVISED: This function now formats output inside triple backticks.
def format_rutedjp_summary_message(cluster_id: int, region_name: str, branch_name: str, sto_names: list,
                                   cluster_link_start_point: tuple, optimized_cluster_odps: list, distance_cache: dict):
    """
    Formats a detailed cluster summary using a pre-calculated distance cache.
    This function is synchronous and purely CPU-bound.
    Returns a tuple: (formatted_message_string, google_maps_url_string).
    """
    try:
        total_odps = len(optimized_cluster_odps)
        if total_odps == 0:
            message = f"```\n📍 Cluster {cluster_id}\n━━━━━━━━━━━━━━━\nTidak ada ODP ditemukan dalam cluster ini.\n```"
            return message, None

        # Helper function to look up distances from the pre-calculated cache
        def get_distance(p1, p2):
            cache_key = tuple(sorted((p1, p2)))
            # Fallback to aerial distance if a key is somehow missing
            return distance_cache.get(cache_key, geodesic(p1, p2).kilometers)

        # --- Calculate Distances using the Cache ---
        cluster_start_point = (float(optimized_cluster_odps[0]['latitude']), float(optimized_cluster_odps[0]['longitude']))
        link_distance = get_distance(cluster_link_start_point, cluster_start_point)
        
        internal_route_points = [(float(odp['latitude']), float(odp['longitude'])) for odp in optimized_cluster_odps]
        internal_route_length = sum(get_distance(internal_route_points[i], internal_route_points[i+1]) for i in range(len(internal_route_points) - 1))

        total_segment_length = link_distance + internal_route_length

        # --- Build Message Content ---
        STATUS_ICONS = {'BLACK': '⚫️', 'RED': '🔴', 'ORANGE': '🟠', 'YELLOW': '🟡', 'GREEN': '🟢', 'UNKNOWN': '⚪️'}
        status_order = ['BLACK', 'RED', 'ORANGE', 'YELLOW', 'GREEN']
        
        message_parts = [
            f"📍 Cluster {cluster_id} - Rute DJP",
            "━━━━━━━━━━━━━━━",
            f"Region        : {region_name.upper()}",
            f"Branch        : {branch_name.upper()}",
            f"Daftar STO    : {', '.join(sorted([s.upper() for s in sto_names])) if sto_names else 'N/A'}",
            f"Total ODP     : {total_odps}",
            f"Route Length  : {total_segment_length:.2f}km (Link: {link_distance:.2f}km + Internal: {internal_route_length:.2f}km)",
            "\n",
            "📊 RINGKASAN ODP PER STATUS",
            "━━━━━━━━━━━━━━━"
        ]

        # --- Grouping Logic for Summary and Details ---
        odps_by_sto = defaultdict(lambda: defaultdict(list))
        for odp in optimized_cluster_odps:
            sto = odp.get('sto', 'Unknown')
            occ_2 = odp.get('occ_2', 'UNKNOWN').upper()
            odps_by_sto[sto][occ_2].append(odp)

        # --- Add STO Summary Section ---
        for sto in sorted(odps_by_sto.keys()):
            sto_data = odps_by_sto[sto]
            sto_total = sum(len(odps) for odps in sto_data.values())
            if sto_total > 0:
                message_parts.append(f"STO: {sto.upper()}")
                for status in status_order:
                    count = len(sto_data.get(status, []))
                    if count > 0:
                        percentage = (count / sto_total * 100)
                        message_parts.append(f"• {status}: {count} ODP ({percentage:.1f}%)")
                message_parts.append("")

        # --- Add Detailed ODP List Section ---
        for sto in sorted(odps_by_sto.keys()):
            sto_data = odps_by_sto[sto]
            if any(sto_data.values()): # Check if there are any ODPs for this STO
                message_parts.extend([
                    f"🏗️ DETAIL ODP DALAM CLUSTER (STO: {sto.upper()})",
                    "━━━━━━━━━━━━━━━\n"
                ])
                for status in status_order:
                    odps = sto_data.get(status, [])
                    if odps:
                        icon = STATUS_ICONS.get(status, '⚪️')
                        sample_odp = odps[0]
                        port_info = f"{sample_odp.get('port_avail', 'N/A')}/{sample_odp.get('port_total', 'N/A')}"
                        occ_1_value = sample_odp.get('occ_1')
                        formatted_occ = safe_format_percentage_from_decimal(occ_1_value)
                        message_parts.append(f"{icon} {status} ({len(odps)} ODP) - Port: {port_info} | Occ: {formatted_occ}")
                        
                        odps_by_golive_date = defaultdict(list)
                        for odp in odps:
                            raw_date = odp.get('golive_date', 'N/A')
                            clean_date = 'N/A'
                            if raw_date and str(raw_date) not in ['0000-00-00 00:00:00', 'None', 'N/A']:
                                clean_date = str(raw_date).split(' ')[0]
                            odps_by_golive_date[clean_date].append(odp)

                        for golive_date, grouped_odps in sorted(odps_by_golive_date.items()):
                            message_parts.append(f"  Golive: {golive_date}")
                            for odp in grouped_odps:
                                lat = odp.get('latitude', 'N/A')
                                lng = odp.get('longitude', 'N/A')
                                message_parts.append(f"    • {odp.get('odp_name', 'N/A')} ({lat}, {lng})")
                        message_parts.append("")

        # --- Final Assembly ---
        formatted_message = f"```\n" + "\n".join(message_parts) + "\n```"
        
        # --- Generate multiple URLs if needed ---
        route_urls = []
        waypoint_limit = 9  # Google Maps limit for intermediate points
        chunk_size = waypoint_limit + 1  # 9 waypoints + 1 destination = 10 ODPs per link
        
        # Add the initial link from the user/previous cluster to the start of this cluster
        current_origin_lat, current_origin_lng = cluster_link_start_point

        for i in range(0, len(optimized_cluster_odps), chunk_size):
            chunk = optimized_cluster_odps[i:i + chunk_size]
            if not chunk:
                continue
            
            # Use the single generate_google_maps_url function for each chunk
            url = generate_google_maps_url(current_origin_lat, current_origin_lng, chunk)
            if url:
                route_urls.append(url)
            
            # The next origin is the end of the current chunk
            last_odp_in_chunk = chunk[-1]
            current_origin_lat = float(last_odp_in_chunk['latitude'])
            current_origin_lng = float(last_odp_in_chunk['longitude'])
            
        return formatted_message, route_urls
        
    except Exception as e:
        logging.error(f"Error formatting summary message with cache: {e}", exc_info=True)
        return f"```\n❌ Error generating summary for Cluster {cluster_id}\n```", []


