def format_wok_rutedjp_summary_message(cluster_id: int, region_name: str, branch_name: str, wok_names: list,
                                       cluster_link_start_point: tuple, optimized_cluster_odps: list, distance_cache: dict,
                                       visit_history: dict = None):
    """Format cluster summary message for WOK-level routing with visit history."""
    try:
        total_odps = len(optimized_cluster_odps)
        if total_odps == 0:
            message = f"```\n📍 Cluster {cluster_id}\n━━━━━━━━━━━━━━━\nTidak ada ODP ditemukan dalam cluster ini.\n```"
            return message, None

        def get_distance(p1, p2):
            cache_key = tuple(sorted((p1, p2)))
            return distance_cache.get(cache_key, geodesic(p1, p2).kilometers)

        # Calculate distances
        cluster_start_point = (float(optimized_cluster_odps[0]['latitude']), float(optimized_cluster_odps[0]['longitude']))
        link_distance = get_distance(cluster_link_start_point, cluster_start_point)
        
        internal_route_points = [(float(odp['latitude']), float(odp['longitude'])) for odp in optimized_cluster_odps]
        internal_route_length = sum(get_distance(internal_route_points[i], internal_route_points[i+1]) for i in range(len(internal_route_points) - 1))

        total_segment_length = link_distance + internal_route_length

        # Get current period for display
        current_period = datetime.now().strftime("%b-%Y")

        # Build message
        STATUS_ICONS = {'BLACK': '⚫️', 'RED': '🔴', 'ORANGE': '🟠', 'YELLOW': '🟡', 'GREEN': '🟢', 'UNKNOWN': '⚪️'}
        status_order = ['BLACK', 'RED', 'ORANGE', 'YELLOW', 'GREEN']
        
        message_parts = [
            f"📍 Cluster {cluster_id} - Rute DJP (WOK Level)",
            "━━━━━━━━━━━━━━━",
            f"Region        : {region_name.upper()}",
            f"Branch        : {branch_name.upper()}",
            f"Daftar WOK    : {', '.join(sorted([w.upper() for w in wok_names])) if wok_names else 'N/A'}",
            f"Total ODP     : {total_odps}",
            f"Route Length  : {total_segment_length:.2f}km (Link: {link_distance:.2f}km + Internal: {internal_route_length:.2f}km)",
            "Ket : 🚩 Times Assigned, 🕔 Last Assigned", # Added legend
            "\n",
            "📊 RINGKASAN ODP PER STATUS & WOK",
            "━━━━━━━━━━━━━━━"
        ]

        # Group by WOK and status
        odps_by_wok = defaultdict(lambda: defaultdict(list))
        for odp in optimized_cluster_odps:
            wok = odp.get('wok', 'Unknown')
            occ_2 = odp.get('occ_2', 'UNKNOWN').upper()
            odps_by_wok[wok][occ_2].append(odp)

        # Add WOK summary
        for wok in sorted(odps_by_wok.keys()):
            wok_data = odps_by_wok[wok]
            wok_total = sum(len(odps) for odps in wok_data.values())
            if wok_total > 0:
                message_parts.append(f"WOK: {wok.upper()}")
                for status in status_order:
                    count = len(wok_data.get(status, []))
                    if count > 0:
                        percentage = (count / wok_total * 100)
                        message_parts.append(f"• {status}: {count} ODP ({percentage:.1f}%)")
                message_parts.append("")

        # Add detailed ODP list
        for wok in sorted(odps_by_wok.keys()):
            wok_data = odps_by_wok[wok]
            if any(wok_data.values()):
                message_parts.extend([
                    f"🏗️ DETAIL ODP DALAM CLUSTER (WOK: {wok.upper()})",
                    "━━━━━━━━━━━━━━━\n"
                ])
                for status in status_order:
                    odps = wok_data.get(status, [])
                    if odps:
                        icon = STATUS_ICONS.get(status, '⚪️')
                        sample_odp = odps[0]
                        port_info = f"{sample_odp.get('port_avail', 'N/A')}/{sample_odp.get('port_total', 'N/A')}"
                        occ_1_value = sample_odp.get('occ_1')
                        formatted_occ = safe_format_percentage_from_decimal(occ_1_value)
                        # Added period to the status header
                        message_parts.append(f"{icon} {status} ({len(odps)} ODP) - Port: {port_info} | Occ: {formatted_occ} | Periode: {current_period}")
                        
                        # Group by golive date
                        odps_by_golive_date = defaultdict(list)
                        for odp in odps:
                            raw_date = odp.get('golive_date', 'N/A')
                            clean_date = 'N/A'
                            if raw_date and str(raw_date) not in ['0000-00-00 00:00:00', 'None', 'N/A']:
                                clean_date = str(raw_date).split(' ')[0]
                            odps_by_golive_date[clean_date].append(odp)

                        for golive_date, grouped_odps in sorted(odps_by_golive_date.items()):
                            message_parts.append(f"  Golive: {golive_date}")
                            for odp in grouped_odps:
                                lat = odp.get('latitude', 'N/A')
                                lng = odp.get('longitude', 'N/A')
                                
                                # Construct visit history string
                                visit_info_str = ""
                                if visit_history:
                                    odp_name = odp.get('odp_name')
                                    if odp_name:
                                        visit_data = visit_history.get(odp_name)
                                        if visit_data:
                                            visit_count = visit_data.get('count', 0)
                                            last_date_obj = visit_data.get('last_date')
                                            
                                            if last_date_obj and visit_count > 0:
                                                formatted_date = last_date_obj.strftime("%d-%b")
                                                visit_info_str = f" 🚩 {visit_count}x | 🕔 {formatted_date}"
                                
                                # Append the visit string to the ODP line
                                message_parts.append(f"    • {odp.get('odp_name', 'N/A')} ({lat}, {lng}){visit_info_str}")
                        message_parts.append("")

        formatted_message = f"```\n" + "\n".join(message_parts) + "\n```"
        
        # Generate route URLs
        route_urls = []
        waypoint_limit = 9
        chunk_size = waypoint_limit + 1
        current_origin_lat, current_origin_lng = cluster_link_start_point

        for i in range(0, len(optimized_cluster_odps), chunk_size):
            chunk = optimized_cluster_odps[i:i + chunk_size]
            if not chunk:
                continue
            
            url = generate_google_maps_url(current_origin_lat, current_origin_lng, chunk)
            if url:
                route_urls.append(url)
            
            last_odp_in_chunk = chunk[-1]
            current_origin_lat = float(last_odp_in_chunk['latitude'])
            current_origin_lng = float(last_odp_in_chunk['longitude'])
            
        return formatted_message, route_urls
        
    except Exception as e:
        logging.error(f"Error formatting WOK summary message: {e}", exc_info=True)
        return f"```\n❌ Error generating summary for Cluster {cluster_id}\n```", []

