async def send_filter_selection_for_new_odp(chat_id: int, bot: Bot, state: FSMContext):
    """Send LOS filter selection for new ODPs (2025+ only)"""
    # Initialize filter states
    state_data = await state.get_data()
    if 'selected_los_groups' not in state_data:
        await state.update_data(selected_los_groups=[])
    
    keyboard_rows = []
    
    # LOS Group section header
    keyboard_rows.append([
        InlineKeyboardButton(text="📅 Length of Stay (LOS):", callback_data="dummy")
    ])
    
    # LOS checkboxes - only show 0-3, 3-6, 6-12 for 2025+ data
    los_configs = {
        "0-3": {"text": "0-3 months", "callback_data": "djp_los_toggle_0-3"},
        "3-6": {"text": "3-6 months", "callback_data": "djp_los_toggle_3-6"},
        "6-12": {"text": "6-12 months", "callback_data": "djp_los_toggle_6-12"}
    }
    
    selected_los = state_data.get('selected_los_groups', [])
    
    # Create 2 columns for LOS options
    los_keys = list(los_configs.keys())
    for i in range(0, len(los_keys), 2):
        row = []
        los_key = los_keys[i]
        checkbox = "✅" if los_key in selected_los else "☐"
        row.append(InlineKeyboardButton(
            text=f"{checkbox} {los_configs[los_key]['text']}",
            callback_data=los_configs[los_key]['callback_data']
        ))
        
        if i + 1 < len(los_keys):
            los_key = los_keys[i + 1]
            checkbox = "✅" if los_key in selected_los else "☐"
            row.append(InlineKeyboardButton(
                text=f"{checkbox} {los_configs[los_key]['text']}",
                callback_data=los_configs[los_key]['callback_data']
            ))
        
        keyboard_rows.append(row)
    
    # Control buttons
    keyboard_rows.append([
        InlineKeyboardButton(text="🔄 Reset", callback_data="djp_reset_los_filters"),
        InlineKeyboardButton(text="✅ Continue", callback_data="djp_proceed_location")
    ])
    
    keyboard = InlineKeyboardMarkup(inline_keyboard=keyboard_rows)
    
    await bot.send_message(
        chat_id,
        "Pilih filter Length of Stay (opsional):\n\n⚠️ Jika tidak ada filter yang dipilih, semua data akan ditampilkan:",
        reply_markup=keyboard
    )

