async def send_djp_sto_selection(chat_id: int, bot: Bot, branch_name: str, region_name: str):
    """Send STO selection for DJP route with multiple selection support"""
    try:
        stos = await fetch_stos_for_branch(branch_name)
        
        if not stos:
            await bot.send_message(chat_id, f"⚠️ Tidak ada STO ditemukan untuk branch {branch_name.upper()}")
            return

        sorted_stos = sorted(stos)
        total_stos = len(sorted_stos)
        
        if total_stos <= 8:
            columns = 2
        elif total_stos <= 16:
            columns = 3
        else:
            columns = 4
        
        keyboard_rows = []
        
        for i in range(0, total_stos, columns):
            row_stos = sorted_stos[i:i + columns]
            row_buttons = [
                InlineKeyboardButton(
                    text=sto.upper(),
                    callback_data=f"djp_select_sto:{region_name}:{branch_name}:{sto}"
                )
                for sto in row_stos
            ]
            keyboard_rows.append(row_buttons)
        
        keyboard_rows.append([InlineKeyboardButton(text="❌ Batal", callback_data="cancel_djp")])
        
        keyboard = InlineKeyboardMarkup(inline_keyboard=keyboard_rows)
        
        message_text = (
            f"📍 Pilih STO untuk Branch {branch_name.upper()} (Region {region_name.upper()}):\n\n"
            f"💡 Total: {total_stos} STO | Klik untuk memilih (maks. 10)"
        )
        
        await bot.send_message(chat_id, message_text, reply_markup=keyboard)
        
    except Exception as e:
        logging.error(f"Error sending DJP STO selection: {e}")
        await bot.send_message(chat_id, "⚠️ Terjadi kesalahan saat mengambil data STO")


