# ============================
# Helper: /c3mr
# ============================
def _get_str(row, key):
    val = row.get(key, "")
    if isinstance(val, (bytes, bytearray)):
        try:
            return val.decode('utf-8')
        except:
            return str(val)
    return str(val) if val is not None else ""

async def format_c3mr_reporting_message(start_date, end_date, level):
    """Format C3MR report message based on level."""
    from collections import defaultdict
    
    # Fetch data and determine display parameters
    if level == "area":
        rows = await fetch_c3mr_area_level(start_date, end_date)
        num_dates = 3
        title = "C3MR Report - Area Level"
    elif level == "region":
        rows = await fetch_c3mr_region_level(start_date, end_date)
        num_dates = 1
        title = "C3MR Report - Region Level"
    elif level == "branch":
        rows = await fetch_c3mr_branch_level(start_date, end_date)
        num_dates = 1
        title = "C3MR Report - Branch Level"
    elif level == "wok":
        rows = await fetch_c3mr_wok_level(start_date, end_date)
        num_dates = 1
        title = "C3MR Report - WOK Level"
    else:
        return ["Invalid level"]
    
    if not rows:
        return ["❌ Data tidak tersedia, Silahkan atur ulang tanggal laporan anda dengan /daterange"]
    
    # Group by event_date
    date_groups = defaultdict(list)
    for row in rows:
        event_date = row.get("event_date")

        # Fix 1: Handle Date Bytearray
        if isinstance(event_date, (bytes, bytearray)):
            try:
                event_date = event_date.decode('utf-8')
            except Exception:
                event_date = str(event_date)

        if event_date:
            date_groups[event_date].append(row)
    
    # Get latest N dates
    sorted_dates = sorted(date_groups.keys(), reverse=True)[:num_dates]
    
    if not sorted_dates:
        return ["❌ Data tidak tersedia, Silahkan atur ulang tanggal laporan anda dengan /daterange"]
    
    # Build complete message
    full_message = f"{title}\n{'━' * 15}\n\n"
    
    for event_date in sorted_dates:
        date_data = date_groups[event_date]
        formatted_block = format_c3mr_date_block(date_data, level, event_date)
        full_message += formatted_block + "\n\n"
    
    return [f"```\n{full_message.strip()}\n```"]


def format_c3mr_date_block(rows, level, event_date):
    """Format data block for a single event date."""
    lines = []
    date_str = event_date.strftime('%Y-%m-%d') if hasattr(event_date, 'strftime') else str(event_date)
    lines.append(f"Event Date: {date_str}")
    
    # Format header based on level
    if level == "area":
        lines.append("Ar  Actv_Subs  Unpaid C3MR_M C3MR_M1 MoM_Ppt")
        for row in rows:
            # Fix 2: Decode keys before dictionary lookup
            raw_area = _get_str(row, "area_sales")
            area = AREA_ABBR.get(raw_area, raw_area[:2])
            
            actv_val = row.get("subs") or row.get("sum(subs)") or row.get(2)
            paying_val = row.get("subs_with_payment") or row.get("sum(subs_with_payment)") or row.get(3)
            
            actv = safe_format_integer(actv_val)
            unpaid = safe_format_integer(actv_val - paying_val if actv_val and paying_val else None)
            c3mr = safe_format_percentage_from_decimal(row.get("subs_paying_rate"))
            c3mr_m1 = safe_format_percentage_from_decimal(row.get("subs_paying_rate_m1"))
            mom = format_mom_ppt(row.get("mom_ppt"))
            
            lines.append(f"{area:<3} {actv:>9} {unpaid:>7} {c3mr:>6} {c3mr_m1:>7} {mom:>7}")
    
    elif level == "region":
        lines.append("Ar  Reg  Actv_Subs  Unpaid C3MR_M C3MR_M1 MoM_Ppt")
        for row in rows:
            # Fix 2: Decode keys before dictionary lookup
            raw_area = _get_str(row, "area_sales")
            raw_region = _get_str(row, "region_sales")
            
            area = AREA_ABBR.get(raw_area, raw_area[:2])
            region = REGION_ABBR.get(raw_region, raw_region[:3])
            
            actv_val = row.get("subs") or row.get("sum(subs)") or row.get(3)
            paying_val = row.get("subs_with_payment") or row.get("sum(subs_with_payment)") or row.get(4)
            
            actv = safe_format_integer(actv_val)
            unpaid = safe_format_integer(actv_val - paying_val if actv_val and paying_val else None)
            c3mr = safe_format_percentage_from_decimal(row.get("subs_paying_rate"))
            c3mr_m1 = safe_format_percentage_from_decimal(row.get("subs_paying_rate_m1"))
            mom = format_mom_ppt(row.get("mom_ppt"))
            
            lines.append(f"{area:<3} {region:<4} {actv:>9} {unpaid:>7} {c3mr:>6} {c3mr_m1:>7} {mom:>7}")
    
    elif level == "branch":
        lines.append("Reg  Brch Actv_Subs  Unpaid C3MR_M C3MR_M1 MoM_Ppt")
        for row in rows:
            # Fix 2: Decode keys before dictionary lookup
            raw_region = _get_str(row, "region_sales")
            raw_branch = _get_str(row, "branch")

            region = REGION_ABBR.get(raw_region, raw_region[:3])
            branch = BRANCH_ABBR.get(raw_branch, raw_branch[:3])
            
            actv_val = row.get("subs") or row.get("sum(subs)") or row.get(3)
            paying_val = row.get("subs_with_payment") or row.get("sum(subs_with_payment)") or row.get(4)
            
            actv = safe_format_integer(actv_val)
            unpaid = safe_format_integer(actv_val - paying_val if actv_val and paying_val else None)
            c3mr = safe_format_percentage_from_decimal(row.get("subs_paying_rate"))
            c3mr_m1 = safe_format_percentage_from_decimal(row.get("subs_paying_rate_m1"))
            mom = format_mom_ppt(row.get("mom_ppt"))
            
            lines.append(f"{region:<4} {branch:<4} {actv:>9} {unpaid:>7} {c3mr:>6} {c3mr_m1:>7} {mom:>7}")
    
    elif level == "wok":
        lines.append("Brch  WOK       Actv_Subs  Unpaid C3MR_M C3MR_M1 MoM_Ppt")
        for row in rows:
            # Fix 2: Decode keys before dictionary lookup
            raw_branch = _get_str(row, "branch")
            raw_wok = _get_str(row, "wok")

            branch = BRANCH_ABBR.get(raw_branch, raw_branch[:3])
            wok = WOK_ABBR.get(raw_wok.upper(), raw_wok[:5])
            
            actv_val = row.get("subs") or row.get("sum(subs)") or row.get(3)
            paying_val = row.get("subs_with_payment") or row.get("sum(subs_with_payment)") or row.get(4)
            
            actv = safe_format_integer(actv_val)
            unpaid = safe_format_integer(actv_val - paying_val if actv_val and paying_val else None)
            c3mr = safe_format_percentage_from_decimal(row.get("subs_paying_rate"))
            c3mr_m1 = safe_format_percentage_from_decimal(row.get("subs_paying_rate_m1"))
            mom = format_mom_ppt(row.get("mom_ppt"))
            
            lines.append(f"{branch:<4} {wok:<5} {actv:>9} {unpaid:>6} {c3mr:>6} {c3mr_m1:>6} {mom:>7}")
    
    return "\n".join(lines)


def format_mom_ppt(value):
    """Format MoM percentage points with + sign for positive values."""
    if value is None:
        return "N/A"
    try:
        val = float(value) * 100  # Convert to percentage points
        if val > 0:
            return f"+{val:.2f}%"
        else:
            return f"{val:.2f}%"
    except (ValueError, TypeError):
        return "N/A"


