def get_cache_key(territory_type: str, territory_name: str, date_param: str, data_type: str = "sales") -> str:
    """Generate unique cache key for dashboard data"""
    key_string = f"{data_type}:{territory_type}:{territory_name}:{date_param}"
    return hashlib.md5(key_string.encode()).hexdigest()

async def get_cached_data_async(territory_type: str, territory_name: str, date_param: str, data_type: str = "sales") -> dict:
    """Retrieve cached dashboard data if valid (async)"""
    cache_key = get_cache_key(territory_type, territory_name, date_param, data_type)
    cache_file = CACHE_DIR / f"{cache_key}.pkl"
    
    if not cache_file.exists():
        logger.debug(f"Cache miss: {cache_key}")
        return None
    
    try:
        async with aiofiles.open(cache_file, 'rb') as f:
            content = await f.read()
            cached = pickle.loads(content)
        
        # Check if cache is still valid
        cache_age = time.time() - cached['timestamp']
        if cache_age > CACHE_DURATION:
            logger.info(f"Cache expired ({cache_age/3600:.1f}h old): {cache_key}")
            await asyncio.to_thread(cache_file.unlink)
            return None
        
        logger.info(f"Cache hit ({cache_age/60:.1f}min old): {cache_key}")
        return {
            'data': cached['data']
        }
    
    except Exception as e:
        logger.error(f"Error reading cache: {e}")
        return None

async def save_to_cache_async(territory_type: str, territory_name: str, date_param: str, data: dict, data_type: str = "sales"):
    """Save dashboard data to cache (async)"""
    cache_key = get_cache_key(territory_type, territory_name, date_param, data_type)
    cache_file = CACHE_DIR / f"{cache_key}.pkl"
    
    try:
        cached = {
            'timestamp': time.time(),
            'data': data,
        }
        content = pickle.dumps(cached)
        async with aiofiles.open(cache_file, 'wb') as f:
            await f.write(content)
        logger.info(f"Data cached: {cache_key}")
    except Exception as e:
        logger.error(f"Error saving cache: {e}")


async def fetch_endpoint(session: aiohttp.ClientSession, url: str, params: dict, endpoint: str):
    """Fetch a single endpoint"""
    try:
        async with session.get(
            url,
            params=params,
            timeout=aiohttp.ClientTimeout(total=30)
        ) as response:
            if response.status == 200:
                return await response.json()
            elif response.status == 500:
                logger.warning(f"Endpoint {endpoint} returned status 500 (likely data not available for requested date)")
                return None
            else:
                logger.warning(f"Endpoint {endpoint} returned status {response.status}")
                return None
    except Exception as e:
        logger.error(f"Error fetching {endpoint}: {e}")
        return None

async def scrape_sales_data_async(territory_type: str, territory_name: str, mtd_date: str, previous_mtd_date: str) -> dict:
    """
    Scrapes SALES dashboard data (IO, RE, PS, SF Performance)
    """
    # Check cache first
    cached_current = await get_cached_data_async(territory_type, territory_name, mtd_date, "sales")
    cached_previous = await get_cached_data_async(territory_type, territory_name, previous_mtd_date, "sales")
    
    if cached_current and cached_previous:
        logger.info(f"Using cached sales data for {territory_type}:{territory_name}")
        return {
            'current': cached_current.get('data') if isinstance(cached_current, dict) else cached_current,
            'previous': cached_previous.get('data') if isinstance(cached_previous, dict) else cached_previous,
            'from_cache': True,
        }
    
    base_url = os.getenv("RAJAWALI_URL", "https://demo.example.internal/")
    username = os.getenv("RAJAWALI_USERNAME") or os.getenv("RAJAWALI_DOMAIN")
    password = os.getenv("RAJAWALI_PASSWORD")
    
    dashboard_data_current = {}
    dashboard_data_previous = {}
    
    try:
        import ssl
        ssl_context = ssl.create_default_context()
        ssl_context.check_hostname = False
        ssl_context.verify_mode = ssl.CERT_NONE
        
        connector = aiohttp.TCPConnector(ssl=ssl_context)
        
        async with aiohttp.ClientSession(connector=connector) as session:
            # Login
            login_url = f"{base_url}backend/auth.php"
            login_payload = {"username": username, "password": password}
            
            logger.debug(f"Logging in to fetch sales data...")
            
            async with session.post(
                login_url,
                json=login_payload,
                headers={'Content-Type': 'application/json'},
                timeout=aiohttp.ClientTimeout(total=30)
            ) as login_response:
                
                if login_response.status != 200:
                    logger.error(f"Login failed: {login_response.status}")
                    return {}
                
                response_text = await login_response.text()
                logger.debug(f"Login response: {response_text[:200]}")
            
            logger.debug("Login successful, fetching sales data...")
            
            # Fetch current date data
            current_tasks = []
            for endpoint in EXPECTED_CARD_SALES:
                url = f"{base_url}{endpoint}"
                params = {
                    'mtd_date': mtd_date,
                    'type': territory_type,
                    'name': territory_name
                }
                current_tasks.append(fetch_endpoint(session, url, params, endpoint))
            
            current_results = await asyncio.gather(*current_tasks, return_exceptions=True)
            
            for endpoint, result in zip(EXPECTED_CARD_SALES, current_results):
                if isinstance(result, Exception):
                    logger.error(f"  ✗ Failed current sales {endpoint}: {result}")
                elif result:
                    endpoint_name = endpoint.split('/')[-1].replace('.php', '')
                    dashboard_data_current[endpoint_name] = result
                    logger.debug(f"  ✓ Fetched current sales: {endpoint_name}")
            
            # Fetch previous date data
            previous_tasks = []
            for endpoint in EXPECTED_CARD_SALES:
                url = f"{base_url}{endpoint}"
                params = {
                    'mtd_date': previous_mtd_date,
                    'type': territory_type,
                    'name': territory_name
                }
                previous_tasks.append(fetch_endpoint(session, url, params, endpoint))
            
            previous_results = await asyncio.gather(*previous_tasks, return_exceptions=True)
            
            for endpoint, result in zip(EXPECTED_CARD_SALES, previous_results):
                if isinstance(result, Exception):
                    logger.error(f"  ✗ Failed previous sales {endpoint}: {result}")
                elif result:
                    endpoint_name = endpoint.split('/')[-1].replace('.php', '')
                    dashboard_data_previous[endpoint_name] = result
                    logger.debug(f"  ✓ Fetched previous sales: {endpoint_name}")
            
            logger.info(f"Successfully fetched {len(dashboard_data_current)} current + {len(dashboard_data_previous)} previous sales endpoints")
              
        # Cache the results
        if dashboard_data_current:
            await save_to_cache_async(territory_type, territory_name, mtd_date, dashboard_data_current, "sales")
        if dashboard_data_previous:
            await save_to_cache_async(territory_type, territory_name, previous_mtd_date, dashboard_data_previous, "sales")
        
        return {
            'current': dashboard_data_current,
            'previous': dashboard_data_previous,
            'from_cache': False,
        }
        
    except Exception as e:
        logger.error(f"Sales scraping error: {e}", exc_info=True)
        return {}


async def scrape_driver_data_async(territory_type: str, territory_name: str, periode: str, previous_periode: str) -> dict:
    """
    Scrapes DRIVER dashboard data (Active LIS, HVC, Churn, Speed patterns)
    """
    # Check cache first
    cached_current = await get_cached_data_async(territory_type, territory_name, periode, "driver")
    cached_previous = await get_cached_data_async(territory_type, territory_name, previous_periode, "driver")
    
    if cached_current and cached_previous:
        logger.info(f"Using cached driver data for {territory_type}:{territory_name}")
        return {
            'current': cached_current.get('data') if isinstance(cached_current, dict) else cached_current,
            'previous': cached_previous.get('data') if isinstance(cached_previous, dict) else cached_previous,
            'from_cache': True,
        }
    
    base_url = os.getenv("RAJAWALI_URL", "https://demo.example.internal/")
    username = os.getenv("RAJAWALI_USERNAME") or os.getenv("RAJAWALI_DOMAIN")
    password = os.getenv("RAJAWALI_PASSWORD")
    
    dashboard_data_current = {}
    dashboard_data_previous = {}
    
    try:
        import ssl
        ssl_context = ssl.create_default_context()
        ssl_context.check_hostname = False
        ssl_context.verify_mode = ssl.CERT_NONE
        
        connector = aiohttp.TCPConnector(ssl=ssl_context)
        
        async with aiohttp.ClientSession(connector=connector) as session:
            # Login
            login_url = f"{base_url}backend/auth.php"
            login_payload = {"username": username, "password": password}
            
            logger.debug(f"Logging in to fetch driver data...")
            
            async with session.post(
                login_url,
                json=login_payload,
                headers={'Content-Type': 'application/json'},
                timeout=aiohttp.ClientTimeout(total=30)
            ) as login_response:
                
                if login_response.status != 200:
                    logger.error(f"Login failed: {login_response.status}")
                    return {}
                
                response_text = await login_response.text()
                logger.debug(f"Login response: {response_text[:200]}")
            
            logger.debug("Login successful, fetching driver data...")
            
            # === FETCH CURRENT DRIVER DATA ===
            driver_current_tasks = []
            
            # Endpoints WITH periode parameter
            for endpoint in DRIVER_ENDPOINTS_WITH_PERIODE:
                url = f"{base_url}{endpoint}"
                params = {
                    'periode': periode,
                    'type': territory_type,
                    'name': territory_name,
                    'flag_menu': 'lis'
                }
                # Header summary doesn't need type/name
                if 'get_header_summary' in endpoint:
                    params = {'periode': periode}
                
                driver_current_tasks.append(fetch_endpoint(session, url, params, endpoint))
            
            # Endpoints WITHOUT periode (line charts)
            for endpoint in DRIVER_ENDPOINTS_NO_PERIODE:
                url = f"{base_url}{endpoint}"
                params = {
                    'type': territory_type,
                    'name': territory_name,
                    'flag_los': 'all_los',
                    'flag_speed': 'mbps0'
                }
                driver_current_tasks.append(fetch_endpoint(session, url, params, endpoint))
            
            driver_current_results = await asyncio.gather(*driver_current_tasks, return_exceptions=True)
            
            all_driver_endpoints = DRIVER_ENDPOINTS_WITH_PERIODE + DRIVER_ENDPOINTS_NO_PERIODE
            for endpoint, result in zip(all_driver_endpoints, driver_current_results):
                if isinstance(result, Exception):
                    logger.error(f"  ✗ Failed current driver {endpoint}: {result}")
                elif result:
                    endpoint_name = endpoint.split('/')[-1].replace('.php', '')
                    dashboard_data_current[endpoint_name] = result
                    logger.debug(f"  ✓ Fetched current driver: {endpoint_name}")
            
            # === FETCH PREVIOUS DRIVER DATA ===
            driver_previous_tasks = []
            
            for endpoint in DRIVER_ENDPOINTS_WITH_PERIODE:
                url = f"{base_url}{endpoint}"
                params = {
                    'periode': previous_periode,
                    'type': territory_type,
                    'name': territory_name,
                    'flag_menu': 'lis'
                }
                if 'get_header_summary' in endpoint:
                    params = {'periode': previous_periode}
                
                driver_previous_tasks.append(fetch_endpoint(session, url, params, endpoint))
            
            # Line charts don't have time component for previous data
            # We only fetch them for current period
            
            driver_previous_results = await asyncio.gather(*driver_previous_tasks, return_exceptions=True)
            
            for endpoint, result in zip(DRIVER_ENDPOINTS_WITH_PERIODE, driver_previous_results):
                if isinstance(result, Exception):
                    logger.error(f"  ✗ Failed previous driver {endpoint}: {result}")
                elif result:
                    endpoint_name = endpoint.split('/')[-1].replace('.php', '')
                    dashboard_data_previous[endpoint_name] = result
                    logger.debug(f"  ✓ Fetched previous driver: {endpoint_name}")
            
            logger.info(f"Successfully fetched {len(dashboard_data_current)} current + {len(dashboard_data_previous)} previous driver endpoints")
              
        # Cache the results
        if dashboard_data_current:
            await save_to_cache_async(territory_type, territory_name, periode, dashboard_data_current, "driver")
        if dashboard_data_previous:
            await save_to_cache_async(territory_type, territory_name, previous_periode, dashboard_data_previous, "driver")
        
        return {
            'current': dashboard_data_current,
            'previous': dashboard_data_previous,
            'from_cache': False,
        }
        
    except Exception as e:
        logger.error(f"Driver scraping error: {e}", exc_info=True)
        return {}


async def scrape_collection_data_async(territory_type: str, territory_name: str, mtd_date: str, periode: str, previous_mtd_date: str, previous_periode: str) -> dict:
    """
    Scrapes ALL COLLECTION data:
    1. Charts & Pie (Full Params)
    2. Header Summary (No Territory Params)
    3. Healthy Sales Matrix (Flags 1-6)
    4. 10-Segments (Flags 1-5)
    5. Territory Tables (Area -> City)
    """
    # Check cache first
    cached_current = await get_cached_data_async(territory_type, territory_name, mtd_date, "collection")
    cached_previous = await get_cached_data_async(territory_type, territory_name, previous_mtd_date, "collection")
    
    if cached_current and cached_previous:
        logger.info(f"Using cached collection data for {territory_type}:{territory_name}")
        return {
            'current': cached_current.get('data') if isinstance(cached_current, dict) else cached_current,
            'previous': cached_previous.get('data') if isinstance(cached_previous, dict) else cached_previous,
            'from_cache': True,
        }
    
    base_url = os.getenv("RAJAWALI_URL", "https://demo.example.internal/")
    username = os.getenv("RAJAWALI_USERNAME") or os.getenv("RAJAWALI_DOMAIN")
    password = os.getenv("RAJAWALI_PASSWORD")
    
    dashboard_data_current = {}
    dashboard_data_previous = {}
    
    try:
        import ssl
        ssl_context = ssl.create_default_context()
        ssl_context.check_hostname = False
        ssl_context.verify_mode = ssl.CERT_NONE
        
        connector = aiohttp.TCPConnector(ssl=ssl_context)
        
        async with aiohttp.ClientSession(connector=connector) as session:
            # Login
            login_url = f"{base_url}backend/auth.php"
            login_payload = {"username": username, "password": password}
            
            logger.debug(f"Logging in to fetch collection data...")
            
            async with session.post(
                login_url,
                json=login_payload,
                headers={'Content-Type': 'application/json'},
                timeout=aiohttp.ClientTimeout(total=30)
            ) as login_response:
                
                if login_response.status != 200:
                    logger.error(f"Login failed: {login_response.status}")
                    return {}
            
            logger.debug("Login successful, fetching collection data...")
            
            # --- HELPER: Parameter Builders ---
            def get_std_params(date_val, per_val, flag_val=None):
                # Standard: type/name
                p = {'mtd_date': date_val, 'periode': per_val, 'type': territory_type, 'name': territory_name}
                if flag_val is not None: p['flag'] = str(flag_val)
                return p

            def get_matrix_params(date_val, per_val, flag_val):
                # Matrix: tipe/nama
                return {'mtd_date': date_val, 'periode': per_val, 'tipe': territory_type, 'nama': territory_name, 'flag': str(flag_val)}

            def get_header_params(date_val, per_val):
                # Header: no territory
                return {'mtd_date': date_val, 'periode': per_val}

            # --- HELPER: Build Task List ---
            def build_tasks(target_mtd, target_periode):
                tasks = []
                keys = []

                # Group 1: Standard Charts & Pie (Full Params)
                for endpoint in COLLECTION_ENDPOINTS_FULL_PARAMS:
                    key = endpoint.split('/')[-1].replace('.php', '')
                    url = f"{base_url}{endpoint}"
                    tasks.append(fetch_endpoint(session, url, get_std_params(target_mtd, target_periode), key))
                    keys.append(key)

                # Group 2: Header Summary (No Territory)
                for endpoint in COLLECTION_ENDPOINTS_NO_TERRITORY:
                    key = endpoint.split('/')[-1].replace('.php', '')
                    url = f"{base_url}{endpoint}"
                    tasks.append(fetch_endpoint(session, url, get_header_params(target_mtd, target_periode), key))
                    keys.append(key)

                # Group 3: Healthy Sales Matrix (Flags 1-6)
                for i in range(1, 7):
                    key = f"matrix_flag_{i}"
                    url = f"{base_url}{COLLECTION_ENDPOINT_MATRIX}"
                    tasks.append(fetch_endpoint(session, url, get_matrix_params(target_mtd, target_periode, i), key))
                    keys.append(key)

                # Group 4: 10 Segment Summary (Flags 1-5)
                for i in range(1, 6):
                    key = f"ten_seg_flag_{i}"
                    url = f"{base_url}{COLLECTION_ENDPOINT_10SEGMENT}"
                    tasks.append(fetch_endpoint(session, url, get_std_params(target_mtd, target_periode, i), key))
                    keys.append(key)

                # Group 5: Territory Tables (Area -> City)
                for endpoint in COLLECTION_ENDPOINTS_TERRITORY:
                    key = endpoint.split('/')[-1].replace('.php', '')
                    url = f"{base_url}{endpoint}"
                    tasks.append(fetch_endpoint(session, url, get_std_params(target_mtd, target_periode, '0'), key))
                    keys.append(key)
                
                # Group 6: MTD Date
                tasks.append(fetch_endpoint(session, f"{base_url}{COLLECTION_ENDPOINT_MTD_DATE}", {'periode': target_periode}, "mtd_date"))
                keys.append("mtd_date")
                
                return tasks, keys

            # === EXECUTE CURRENT ===
            current_tasks, current_keys = build_tasks(mtd_date, periode)
            current_results = await asyncio.gather(*current_tasks, return_exceptions=True)
            
            for key, result in zip(current_keys, current_results):
                if isinstance(result, Exception):
                    logger.error(f"  ✗ Failed current collection {key}: {result}")
                elif result:
                    dashboard_data_current[key] = result
            
            # === EXECUTE PREVIOUS ===
            previous_tasks, previous_keys = build_tasks(previous_mtd_date, previous_periode)
            previous_results = await asyncio.gather(*previous_tasks, return_exceptions=True)
            
            for key, result in zip(previous_keys, previous_results):
                if isinstance(result, Exception):
                    logger.error(f"  ✗ Failed previous collection {key}: {result}")
                elif result:
                    dashboard_data_previous[key] = result
                    
            logger.info(f"Successfully fetched {len(dashboard_data_current)} current + {len(dashboard_data_previous)} previous collection endpoints")
              
        # Cache the results
        if dashboard_data_current:
            await save_to_cache_async(territory_type, territory_name, mtd_date, dashboard_data_current, "collection")
        if dashboard_data_previous:
            await save_to_cache_async(territory_type, territory_name, previous_mtd_date, dashboard_data_previous, "collection")
        
        return {
            'current': dashboard_data_current,
            'previous': dashboard_data_previous,
            'from_cache': False,
        }
        
    except Exception as e:
        logger.error(f"Collection scraping error: {e}", exc_info=True)
        return {}


async def scrape_alpro_data_async(territory_type: str, territory_name: str, mtd_date: str, periode: str, previous_mtd_date: str, previous_periode: str) -> dict:
    """
    Scrapes ALPRO (Network Deployment) dashboard data.
    Hierarchy: Area -> Region -> Branch (No WOK/City)
    Variations: Total, Greenfield, Brownfield, PT2, PT3.
    """
    # Check cache first
    cached_current = await get_cached_data_async(territory_type, territory_name, mtd_date, "alpro")
    cached_previous = await get_cached_data_async(territory_type, territory_name, previous_mtd_date, "alpro")
    
    if cached_current and cached_previous:
        logger.info(f"Using cached ALPRO data for {territory_type}:{territory_name}")
        return {
            'current': cached_current.get('data') if isinstance(cached_current, dict) else cached_current,
            'previous': cached_previous.get('data') if isinstance(cached_previous, dict) else cached_previous,
            'from_cache': True,
        }
    
    base_url = os.getenv("RAJAWALI_URL", "https://demo.example.internal/")
    username = os.getenv("RAJAWALI_USERNAME") or os.getenv("RAJAWALI_DOMAIN")
    password = os.getenv("RAJAWALI_PASSWORD")
    
    dashboard_data_current = {}
    dashboard_data_previous = {}
    
    try:
        import ssl
        ssl_context = ssl.create_default_context()
        ssl_context.check_hostname = False
        ssl_context.verify_mode = ssl.CERT_NONE
        
        connector = aiohttp.TCPConnector(ssl=ssl_context)
        
        async with aiohttp.ClientSession(connector=connector) as session:
            # Login
            login_url = f"{base_url}backend/auth.php"
            login_payload = {"username": username, "password": password}
            
            logger.debug(f"Logging in to fetch ALPRO data...")
            
            async with session.post(
                login_url,
                json=login_payload,
                headers={'Content-Type': 'application/json'},
                timeout=aiohttp.ClientTimeout(total=30)
            ) as login_response:
                
                if login_response.status != 200:
                    logger.error(f"Login failed: {login_response.status}")
                    return {}
            
            logger.debug("Login successful, fetching ALPRO data...")

            # --- HELPER: Parameter Builders ---
            def get_std_params(date_val, per_val):
                return {
                    'mtd_date': date_val, 'periode': per_val, 
                    'type': territory_type, 'name': territory_name
                }
            
            # Param for PT2 / PT3 tables
            def get_pt_params(date_val, per_val, pt_type):
                return {
                    'mtd_date': date_val, 'periode': per_val, 
                    'type': pt_type, # 'pt2' or 'pt3'
                    'name': territory_name
                }

            # Param for Golive (Greenfield/Brownfield)
            def get_golive_params(date_val, per_val, category):
                return {
                    'mtd_date': date_val, 'periode': per_val, 
                    'type': territory_type, 'name': territory_name,
                    'flag_cat': category, # total, brownfield, greenfield
                    'flag_los': 'A'
                }

            # --- HELPER: Build Task List ---
            def build_tasks(target_mtd, target_periode):
                tasks = []
                keys = []

                # 1. Headers
                tasks.append(fetch_endpoint(session, f"{base_url}{ALPRO_ENDPOINT_PIE}", get_std_params(target_mtd, target_periode), "pie_ach"))
                keys.append("pie_ach")

                tasks.append(fetch_endpoint(session, f"{base_url}{ALPRO_ENDPOINT_MICRODEMAND}", get_std_params(target_mtd, target_periode), "microdemand"))
                keys.append("microdemand")

                # 2. GoLive Performance (Variations: Total, Brownfield, Greenfield)
                # Logic: Area -> Region Table. Region/Branch -> Branch Table.
                golive_endpoint = ALPRO_ENDPOINT_GOLIVE_REGION if territory_type == 'A' else ALPRO_ENDPOINT_GOLIVE_BRANCH
                
                categories = ['total', 'brownfield', 'greenfield']
                for cat in categories:
                    key_name = f"golive_{cat}"
                    tasks.append(fetch_endpoint(session, f"{base_url}{golive_endpoint}", get_golive_params(target_mtd, target_periode, cat), key_name))
                    keys.append(key_name)

                # 3. Territory Summaries (Standard, PT2, PT3)
                summary_endpoint = ALPRO_ENDPOINT_SUMMARY_REGION if territory_type == 'A' else ALPRO_ENDPOINT_SUMMARY_BRANCH
                
                # Standard
                tasks.append(fetch_endpoint(session, f"{base_url}{summary_endpoint}", get_std_params(target_mtd, target_periode), "summary_std"))
                keys.append("summary_std")
                
                # PT2 & PT3
                for pt in ['pt2', 'pt3']:
                    key_name = f"summary_{pt}"
                    tasks.append(fetch_endpoint(session, f"{base_url}{summary_endpoint}", get_pt_params(target_mtd, target_periode, pt), key_name))
                    keys.append(key_name)

                return tasks, keys

            # === EXECUTE CURRENT ===
            current_tasks, current_keys = build_tasks(mtd_date, periode)
            current_results = await asyncio.gather(*current_tasks, return_exceptions=True)
            
            for key, result in zip(current_keys, current_results):
                if isinstance(result, Exception):
                    logger.error(f"  ✗ Failed current alpro {key}: {result}")
                elif result:
                    dashboard_data_current[key] = result
            
            # === EXECUTE PREVIOUS ===
            previous_tasks, previous_keys = build_tasks(previous_mtd_date, previous_periode)
            previous_results = await asyncio.gather(*previous_tasks, return_exceptions=True)
            
            for key, result in zip(previous_keys, previous_results):
                if isinstance(result, Exception):
                    logger.error(f"  ✗ Failed previous alpro {key}: {result}")
                elif result:
                    dashboard_data_previous[key] = result
                    
            logger.info(f"Successfully fetched {len(dashboard_data_current)} current + {len(dashboard_data_previous)} previous alpro endpoints")
              
        # Cache results
        if dashboard_data_current:
            await save_to_cache_async(territory_type, territory_name, mtd_date, dashboard_data_current, "alpro")
        if dashboard_data_previous:
            await save_to_cache_async(territory_type, territory_name, previous_mtd_date, dashboard_data_previous, "alpro")
        
        return {
            'current': dashboard_data_current,
            'previous': dashboard_data_previous,
            'from_cache': False,
        }
        
    except Exception as e:
        logger.error(f"Alpro scraping error: {e}", exc_info=True)
        return {}


def format_executive_summary(summary_text: str, territory_info: dict, summary_type: str = "sales") -> str:
    """
    Format Gemini summary for Telegram with minimal structure.
    """
    territory_labels = {
        'A': '🌍 Area 3',
        'R': '📍 Regional',
        'B': '🏢 Branch',
        'W': '📊 WOK',
        'K': '🏙️ Kota'
    }
    
    summary_titles = {
        'sales': '📊 Sales Summary',
        'driver': '🚗 Driver Summary',
        'collection': '💰 Collection Summary',
        'alpro': '🎯 Alpro Summary'
    }
    
    source_urls = {
        'sales': 'https://demo.example.internal/sales',
        'driver': 'https://demo.example.internal/driver',
        'collection': 'https://demo.example.internal/collection',
        'alpro': 'https://demo.example.internal/alpro'
    }
    
    territory_label = territory_labels.get(territory_info['type'], territory_info['type'])
    summary_title = summary_titles.get(summary_type, '📊 Executive Summary')
    source_url = source_urls.get(summary_type, 'https://demo.example.internal/')
    
    header = f"""<b>{summary_title}</b>

{territory_label}: <b>{territory_info['name']}</b>
📅 {territory_info['start_date']} → {territory_info['end_date']}

"""
    escaped_summary = html.escape(summary_text)
    formatted_content = f"<pre>{escaped_summary}</pre>"
    footer = f"""
━━━━━━━━━━━━━━━
🤖 Powered by Gemini AI • Source: {source_url} • {datetime.now().strftime('%d/%m/%Y %H:%M WIB')}
"""
    return header + formatted_content + footer


async def fetch_and_show_subterritories(callback: CallbackQuery, bot: Bot, state: FSMContext, level_type: str, branch_name: str):
    """Fetch and display WOK or Kota list for selected branch using hardcoded mappings"""
    
    # Use hardcoded mappings
    if level_type == "W":
        territory_list = BRANCH_TO_WOK_MAPPING.get(branch_name.upper(), [])
        label = "WOK"
        columns = 1
    else:  # level_type == "K"
        territory_list = BRANCH_KAB_MAPPING.get(branch_name.upper(), [])
        label = "Kota"
        columns = 2
    
    if not territory_list:
        await callback.message.answer(f"❌ No {label} found for branch {branch_name}")
        return
    
    # Build keyboard
    keyboard_rows = []
    
    if columns == 1:
        for territory in sorted(territory_list):
            keyboard_rows.append([InlineKeyboardButton(
                text=territory,
                callback_data=f"summary_exec:{level_type}:{territory}"
            )])
    else:
        sorted_territories = sorted(territory_list)
        for i in range(0, len(sorted_territories), 2):
            row = []
            row.append(InlineKeyboardButton(
                text=sorted_territories[i],
                callback_data=f"summary_exec:{level_type}:{sorted_territories[i]}"
            ))
            if i + 1 < len(sorted_territories):
                row.append(InlineKeyboardButton(
                    text=sorted_territories[i + 1],
                    callback_data=f"summary_exec:{level_type}:{sorted_territories[i + 1]}"
                ))
            keyboard_rows.append(row)
    
    keyboard = InlineKeyboardMarkup(inline_keyboard=keyboard_rows)
    
    await bot.edit_message_text(
        f"📊 Pilih {label} untuk {branch_name}:",
        chat_id=callback.message.chat.id,
        message_id=callback.message.message_id,
        reply_markup=keyboard
    )
    
    logger.info(f"Showing {len(territory_list)} {label} for branch {branch_name}")



