async def write_csv_with_lock(df: pd.DataFrame):
    """Overwrite user_data.csv with the given DataFrame, using file-based locking."""
    csv_string = df.to_csv(index=False, lineterminator='\n')
    async with aiofiles.open(USER_DATA_FILE, 'w', encoding='utf-8') as dst:
        await dst.write(csv_string)
    logging.info("write_csv_with_lock: write complete")
    return


# ============================
# Helper function to save user data to CSV
# ============================
async def save_user_data(new_user_data):
    user_data_path = str(USER_DATA_FILE)
    file_exists = os.path.isfile(user_data_path) and os.path.getsize(user_data_path) > 0
    if file_exists:
        existing_df = pd.read_csv(user_data_path, dtype=str)
        new_uid = str(new_user_data.iloc[0]['user_id']).strip()
        if new_uid in existing_df['user_id'].astype(str).str.strip().values:
            logging.warning(f"save_user_data: duplicate user_id {new_uid} blocked at write layer")
            return
        combined = pd.concat([existing_df, new_user_data.astype(str)], ignore_index=True)
    else:
        combined = new_user_data.astype(str)
    async with aiofiles.open(USER_DATA_FILE, 'w', encoding='utf-8') as dst:
        await dst.write(combined.to_csv(index=False, lineterminator='\n'))
    logging.info(f"Successfully saved user data for user_id: {new_user_data.iloc[0]['user_id']}")
    return


# ============================
# Helper function to append a new user record
# ============================
async def append_user_data(user_id, username, nik_tsel, sf_code, user_name, employer, region_level, agency_name):
    global USER_DATA_CACHE, CACHE_TIMESTAMP

    # Guard against duplicate user_id (race condition: double-click, concurrent callbacks)
    await ensure_cache_fresh()
    user_id_str = str(user_id)
    for existing_record in USER_DATA_CACHE.values():
        try:
            existing_uid = str(int(float(existing_record.get('user_id', ''))))
        except (ValueError, TypeError):
            existing_uid = str(existing_record.get('user_id', ''))
        if existing_uid == user_id_str:
            logger.warning(f"Duplicate registration blocked: user_id {user_id} already exists in CSV")
            return

    # Automatically set is_authorized to 'yes' if employer is 'sf', 'admin', or 'ctb'
    safe_employer = (employer or "").strip().lower()

    if safe_employer in ('sf', 'admin', 'ctb'):
        auth_status = 'yes'
    else:
        # TSEL, TIF, TA will default to 'no' initially
        auth_status = 'no'

    # Sanitize free-text fields against CSV formula injection
    safe_user_name = sanitize_csv_value(str(user_name)) if user_name else user_name
    safe_username = f"@{username}" if username and not username.startswith('@') else username

    new_user = pd.DataFrame({
        'user_id': [str(user_id)],
        'username': [safe_username],
        'nik_tsel': [nik_tsel],
        'user_level': ['user'],
        'region_level': [region_level],
        'is_authorized': [auth_status],
        'employer': [safe_employer],
        'sf_code': [sf_code],
        'user_name': [safe_user_name],
        'agency_name': [agency_name],
        'registered_at': [datetime.now().isoformat()]
    })
    
    # Now async
    await save_user_data(new_user)
    
    # Invalidate cache after registration
    USER_DATA_CACHE = {}
    CACHE_TIMESTAMP = 0

    logger.info(f"Appended user data: ID={user_id}, Employer={safe_employer}, Auth={auth_status}, Region={region_level}, Agency={agency_name}")
    logger.info(f"DEBUG: Username being saved: '{username}'")


# ================================================================================ #
# ============================ Helper: Escape Backticks ========================== #
# ================================================================================ # 
def format_pre_block_markdown_v2(text_content: str) -> str:
    """
    Formats the given text content as a MarkdownV2 pre-formatted code block.
    """
    escaped_content_for_block = text_content.replace('`', '\\`')
    return f"```\n{escaped_content_for_block}\n```"

# ================================================================================ #
# ============================ Helper: Chucking Message ========================== #
# ================================================================================ # 
def split_message(text: str, max_length: int = 4000) -> List[str]:
    """
    Splits a message into chunks. If original was a code block, re-wraps chunks.
    max_length applies to content (text inside ``` or plain text).
    """
    original_was_code_block = False
    content_to_split = text

    if text.startswith("```\n") and text.endswith("\n```"):
        original_was_code_block = True
        content_to_split = text[4:-4]

    lines = content_to_split.split("\n")
    content_chunks = []
    current_chunk_content = ""

    for line in lines:
        candidate_chunk_text = (current_chunk_content + "\n" + line) if current_chunk_content else line
        
        if len(candidate_chunk_text) > max_length:
            if current_chunk_content.strip():
                content_chunks.append(current_chunk_content)
            current_chunk_content = line 
        else:
            current_chunk_content = candidate_chunk_text
            
    if current_chunk_content.strip():
        content_chunks.append(current_chunk_content)

    final_content_chunks = [chk for chk in content_chunks if chk.strip()]

    if not final_content_chunks and not content_to_split.strip():
         return [format_pre_block_markdown_v2("")] if original_was_code_block else []


    if original_was_code_block:
        # format_pre_block_markdown_v2 handles escaping and wrapping for each content chunk
        return [format_pre_block_markdown_v2(chunk_content) for chunk_content in final_content_chunks]
    else:
        return final_content_chunks


# ============================
# Helper: Function to find a user by @telegram for potential deletion
# ============================ 
async def find_user_for_deletion(username_to_find: str, requester_user_id: int):
    """
    Finds a user by username for deletion, checks if they exist and if the requester is trying to delete themselves (cache version).
    """
    try:
        # Basic username format validation
        if not username_to_find or not username_to_find.startswith('@'):
            return None, None, "Format username tidak valid (harus diawali dengan '@')."

        # Ensure cache is fresh
        await ensure_cache_fresh()
        
        # Clean username for search (remove @ prefix for comparison)
        search_username = username_to_find.lstrip('@')
        
        # Find the user in cache
        found_user = None
        for user_id, user_record in USER_DATA_CACHE.items():
            # Compare usernames (handle both @username and username formats)
            stored_username = user_record.get('username', '').strip()
            if stored_username == username_to_find or stored_username.lstrip('@') == search_username:
                found_user = user_record
                break
        
        if not found_user:
            # Escape username for message display
            escaped_username = escape_markdown_v2(username_to_find)
            return None, None, f"Pengguna dengan username `{escaped_username}` tidak ditemukan."
        
        registrant_id_str = found_user['user_id']
        found_username = found_user['username']
        
        # Check for self-deletion attempt
        if requester_user_id == int(registrant_id_str):
            return None, None, "Anda tidak bisa menghapus user anda sendiri."
        
        # User found and is not the requester
        return registrant_id_str, found_username, None  # Return ID, username, and no error
        
    except Exception as e:
        logger.error(f"Error in find_user_for_deletion: {e}")
        return None, None, "Terjadi kesalahan saat mencari user."


# ============================ 
# Find Nearest Site & ODP
# ============================ 
def find_nearest_odp(user_latitude, user_longitude, odps, radius=250, mode='foot', offline_mode=True):
    try:
        odp_aerial_distances = []
        user_coords = (user_latitude, user_longitude)

        # Calculate aerial distances
        for odp in odps:
            odp_coords = (odp['latitude'], odp['longitude'])
            aerial_distance = geodesic(user_coords, odp_coords).meters
            if aerial_distance <= radius:
                odp_aerial_distances.append((odp, aerial_distance))

        # Sort by aerial distance
        odp_aerial_distances.sort(key=lambda x: x[1])

        # Skip OSRM if offline_mode is enabled
        if offline_mode:
            logging.info(f"Offline mode enabled. Returning top ODPs based on aerial distances.")
            return odp_aerial_distances[:5]

        # If online, calculate ground distances
        proxies = {
            'http': 'http://proxy.example.internal:8080',
            'https': 'http://proxy.example.internal:8080'
        }

        odp_ground_distances = []
        for odp, _ in odp_aerial_distances[:20]:
            osrm_url = f"https://router.project-osrm.org/route/v1/foot/{user_longitude},{user_latitude};{odp['longitude']},{odp['latitude']}?overview=false"
            response = requests.get(osrm_url, proxies=proxies, verify=False)

            if response.status_code == 200:
                route_data = response.json()
                if 'routes' in route_data and len(route_data['routes']) > 0:
                    ground_distance = route_data['routes'][0]['distance']
                    if ground_distance <= radius:
                        odp_ground_distances.append((odp, ground_distance))
            else:
                logging.warning(f"OSRM request failed for ODP {odp['odp_name']} (status {response.status_code}).")

        odp_ground_distances.sort(key=lambda x: x[1])

        logging.info(f"Found {len(odp_ground_distances)} ODPs within {radius} meters ground distance.")
        return odp_ground_distances[:5]
    except Exception as e:
        logging.error(f"Error in find_nearest_odp: {e}")
        return []
    
def find_nearest_site(user_latitude, user_longitude, sites, radius=1000):
    """
    Finds the nearest site from site_eznet_wireless within a 1000 m aerial radius.
    Cleans the 'kabupaten' field and returns a tuple (site, distance) if found, otherwise None.
    """
    try:
        user_coords = (user_latitude, user_longitude)
        site_aerial_distances = []
        for site in sites:
            site_coords = (site['latitude'], site['longitude'])
            aerial_distance = geodesic(user_coords, site_coords).meters
            if aerial_distance <= radius:
                site_aerial_distances.append((site, aerial_distance))
        site_aerial_distances.sort(key=lambda x: x[1])
        if site_aerial_distances:
            return site_aerial_distances[0]  # Return the nearest site (site, distance)
        else:
            return None
    except Exception as e:
        logging.error(f"Error in find_nearest_site: {e}")
        return None
    

# ============================ 
# Calculating Walking Routes
# ============================ 

async def calculate_routes(user_id, user_latitude, user_longitude, nearest_odps, offline_mode=False):
    routes = []
    
    # Create one session to reuse for all requests
    async with aiohttp.ClientSession() as session:
        # Try to send initial loading message with timeout protection
        loading_message = None
        loading_message_id = None
        
        try:
            loading_message = await asyncio.wait_for(
                bot_aiogram.send_message(user_id, get_loading_bar(0)), 
                timeout=10
            )
            loading_message_id = loading_message.message_id
            logging.info(f"Loading message sent for user {user_id}")
        except Exception as e:
            logging.warning(f"Could not send loading message for user {user_id}: {e}")
            loading_message = None
            loading_message_id = None
        
        total_odps = len(nearest_odps)
        
        for index, (odp, ground_distance) in enumerate(nearest_odps):
            try:
                odp_latitude = float(odp.get('latitude'))
                odp_longitude = float(odp.get('longitude'))
                user_location = (user_latitude, user_longitude)
                odp_location = (odp_latitude, odp_longitude)

                distance_straight = geodesic(user_location, odp_location).meters
                route_geometry = [[user_latitude, user_longitude], [odp_latitude, odp_longitude]]
                route_distance = distance_straight

                # Only make OSRM calls if not in offline mode
                if not offline_mode:
                    osrm_url = f"https://router.project-osrm.org/route/v1/foot/{user_longitude},{user_latitude};{odp_longitude},{odp_latitude}?geometries=geojson&overview=full"
                    
                    try:
                        # Async request using the session, with proxy and timeout
                        async with session.get(osrm_url, proxy=PROXY_URL, timeout=aiohttp.ClientTimeout(total=15)) as response:
                            if response.status == 200:
                                route_data = await response.json()
                                if 'routes' in route_data and route_data['routes']:
                                    route_geometry_raw = route_data['routes'][0]['geometry']['coordinates']
                                    route_distance = float(route_data['routes'][0]['distance'])
                                    # Flip [lon, lat] to [lat, lon]
                                    route_geometry = [[coord[1], coord[0]] for coord in route_geometry_raw]
                                    logging.debug(f"OSRM route calculated for ODP {odp.get('odp_name', 'Unknown')} - distance: {route_distance}m")
                            else:
                                logging.warning(f"OSRM request failed with status {response.status} for user {user_id}, ODP: {odp.get('odp_name', 'Unknown')}")
                    except asyncio.TimeoutError:
                        logging.warning(f"OSRM request timeout for user {user_id}, ODP: {odp.get('odp_name', 'Unknown')}")
                    except Exception as e:
                        logging.error(f"OSRM request error for user {user_id}, ODP: {odp.get('odp_name', 'Unknown')}: {e}")

                routes.append({
                    'route': route_geometry,
                    'distance': route_distance,
                    'destination': [odp_latitude, odp_longitude],
                    'name': odp.get('odp_name', 'Unknown'),
                    'distance_straight': distance_straight,
                    'avai': int(odp.get('avai', 0)),
                    'occ_2': str(odp.get('occ_2', 'N/A'))
                })

                # Update progress every 2nd ODP to reduce API calls and avoid rate limiting
                if loading_message and loading_message_id and (index + 1) % 2 == 0:
                    progress_percentage = ((index + 1) / total_odps) * 100
                    try:
                        await asyncio.wait_for(
                            bot_aiogram.edit_message_text(
                                chat_id=user_id,
                                message_id=loading_message_id,
                                text=f"🔄 Calculating routes...\n\n{get_loading_bar(progress_percentage)}\n\n📍 Processing {index + 1}/{total_odps} ODPs"
                            ),
                            timeout=5
                        )
                        logging.debug(f"Progress updated for user {user_id}: {progress_percentage:.0f}%")
                    except asyncio.TimeoutError:
                        logging.warning(f"Progress update timeout for user {user_id}")
                    except Exception as e:
                        logging.warning(f"Could not update progress for user {user_id}: {e}")

            except Exception as e:
                logging.error(f"Error processing ODP {odp.get('odp_name', 'Unknown')} for user {user_id}: {e}")
                continue  # Continue to the next ODP

        # Send final completion message with timeout protection
        if loading_message and loading_message_id:
            try:
                await asyncio.wait_for(
                    bot_aiogram.edit_message_text(
                        chat_id=user_id,
                        message_id=loading_message_id,
                        text="✅ Rute selesai dibuat!"
                    ),
                    timeout=10
                )
                logging.info(f"Route calculation completed for user {user_id}")
            except asyncio.TimeoutError:
                logging.warning(f"Final message update timeout for user {user_id}")
            except Exception as e:
                logging.warning(f"Could not send completion message for user {user_id}: {e}")
        
        logging.info(f"Routes successfully calculated for user {user_id} with {len(routes)} routes (offline_mode: {offline_mode})")

        # Store routes in database if any were calculated
        if routes:
            try:
                store_routes_in_db(user_id, routes)
                logging.debug(f"Routes stored in database for user {user_id}")
            except Exception as e:
                logging.error(f"Error storing routes in database for user {user_id}: {e}")

    return routes


def store_routes_in_db(user_id, routes):
    try:
        # Define the file path using the user_id
        file_path = os.path.join(ROUTE_STORAGE_PATH, f"{user_id}_routes.json")
        
        # Save the routes as JSON
        with open(file_path, 'w') as f:
            json.dump(routes, f, indent=4)
        
        logging.info(f"Stored routes for user_id {user_id} in {file_path}.")
    except Exception as e:
        logging.error(f"Failed to store routes in the file: {e}")


# ================================================= #
# Helper: Normalize                                 #
# ================================================= #
def normalize_speed(speed):
    if speed is None or speed == '':
        return '-'
    
    # Handle numeric values (float/int)
    if isinstance(speed, (int, float)):
        return f"{int(speed)} Mbps"
    
    # Convert to string and extract numeric part
    speed = str(speed)
    match = re.search(r'(\d+)', speed.replace(',', ''))
    if match:
        return f"{match.group(1)} Mbps"
    return speed

def normalize_price(price):
    # Handle None and empty values
    if price is None or price == '':
        return '-'
    
    # Convert to string if it's not already
    price = str(price)
    
    # Remove non-digit, non-comma/dot characters, then format as Rp. X.XXX.XXX
    digits = re.sub(r'[^\d]', '', price)
    if digits:
        return "{:,} IDR".format(int(digits)).replace(",", ".")
    return price

