# Utility: Log
# ================================================= #
async def log_user_interaction(user_id: int, username: str, command: str, interaction_type: str):
    timestamp = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    log_entry = f"[{timestamp}] User ID: {user_id}, User Name: {username}, Type: {interaction_type}, Command: {command}\n"

    # Append the log entry to the file
    try:
        os.makedirs(os.path.dirname(LOG_FILE_PATH), exist_ok=True)
        async with aiofiles.open(LOG_FILE_PATH, mode="a") as log_file:
            await log_file.write(log_entry)
        logger.info(f"Logged interaction: {log_entry.strip()}")
    except Exception as e:
        logger.error(f"Failed to write log entry: {e}")


