# Helper function to extract user and chat info
def extract_user_chat_info(query_or_message: Union[Message, CallbackQuery]) -> tuple[int, int]:
    """Extract user_id and chat_id from Message or CallbackQuery"""
    if isinstance(query_or_message, Message):
        user_id = query_or_message.from_user.id
        chat_id = query_or_message.chat.id
    elif isinstance(query_or_message, CallbackQuery):
        user_id = query_or_message.from_user.id
        chat_id = query_or_message.message.chat.id
    else:
        raise ValueError("Invalid query_or_message type")
    
    return user_id, chat_id


# Helper function to answer callback queries
async def answer_callback_if_needed(query_or_message: Union[Message, CallbackQuery]) -> None:
    """Answer callback query if the input is a CallbackQuery"""
    if isinstance(query_or_message, CallbackQuery):
        await query_or_message.answer()


