async def a3_reporting(query_or_message: Union[Message, CallbackQuery], bot: Bot, 
                      user_id: int, chat_id: int, *args, **kwargs):
    
    selected_period = await get_user_selected_period(user_id)

    if selected_period is None:
        await bot.send_message(chat_id, "⚠️ Anda belum memilih periode laporan. Silakan pilih periode terlebih dahulu.")
        return

    start_date, end_date = await get_period_date_range(selected_period)  # Use updated function
    
    if start_date is None or end_date is None:
        await bot.send_message(chat_id, "❌ Format periode tidak valid. Silakan pilih periode yang benar.")
        return
    
    await bot.send_message(chat_id, "🔄 Mohon tunggu, data sedang diquery...")
    
    try:
        # Pass start_date and end_date instead of selected_period
        messages = await format_a3_summary_message(start_date, end_date)
        if not messages:
            await send_error_message(bot, chat_id, "Query tidak dapat dilakukan, mohon hubungi admin atau coba beberapa saat lagi.")
            return
        
        # Send messages
        if isinstance(messages, list):
            for msg in messages:
                escaped_message = escape_markdown_v2(msg)
                await bot.send_message(chat_id, escaped_message, parse_mode='MarkdownV2')
        else:
            escaped_message = escape_markdown_v2(messages)
            await bot.send_message(chat_id, escaped_message, parse_mode='MarkdownV2')
        
        await send_disclaimer(bot, chat_id)
        
    except Exception as e:
        logging.error(f"Error in a3_reporting: {e}")
        await send_error_message(bot, chat_id)


