# =================================================================
# Churn Heatmap Class
# =================================================================
class ChurnClusteringAnalyzer:
    """
    Analyzes geographic clustering patterns of high-risk churn users.
    """
    
    def __init__(self, radius_meters: int = 300, min_cluster_size: int = 5):
        """
        Initialize clustering analyzer.
        
        Args:
            radius_meters: Clustering radius in meters (default 300m)
            min_cluster_size: Minimum users in a cluster to be considered significant
        """
        self.radius_meters = radius_meters
        self.min_cluster_size = min_cluster_size
        # Convert meters to approximate degrees (rough approximation: 1 degree ≈ 111km)
        self.radius_degrees = radius_meters / 111000
        
    def calculate_radius_radians(self) -> float:
        """
        Calculate radius in radians for haversine distance in DBSCAN.
        
        Returns:
            Radius in radians for DBSCAN eps parameter
        """
        # For haversine distance, radius should be in radians
        # Earth radius in meters
        earth_radius_m = 6371000  # meters
        
        # Convert radius from meters to radians
        radius_radians = self.radius_meters / earth_radius_m
        
        logging.info(f"RADIUS CALCULATION: {self.radius_meters}m = {radius_radians:.8f} radians")
        return radius_radians
        
    def prepare_data(self, df: pd.DataFrame, filter_high_risk: bool = True) -> pd.DataFrame:
        """
        Prepare data for clustering analysis.
        
        Args:
            df: DataFrame with columns: bb_id, latitude, longitude, risk_level, sto, etc.
            filter_high_risk: Whether to filter for high-risk users only
            
        Returns:
            DataFrame prepared for clustering
        """
        # If latlong column exists, parse it
        if 'latlong' in df.columns and 'latitude' not in df.columns:
            df[['latitude', 'longitude']] = df['latlong'].str.split(',', expand=True).astype(float)
        
        # Filter high-risk users only if requested
        if filter_high_risk:
            high_risk_users = df[df['risk_level'].isin(['HIGH', 'VERY_HIGH', 'CRITICAL'])].copy()
        else:
            high_risk_users = df.copy()
        
        # Remove rows with invalid coordinates
        high_risk_users = high_risk_users.dropna(subset=['latitude', 'longitude'])
        
        # Remove zero coordinates
        high_risk_users = high_risk_users[
            (high_risk_users['latitude'] != 0) & 
            (high_risk_users['longitude'] != 0)
        ]
        
        logging.info(f"Prepared {len(high_risk_users)} users for clustering analysis (filter_high_risk={filter_high_risk})")
        return high_risk_users
    
    def perform_clustering(self, df: pd.DataFrame) -> pd.DataFrame:  # COMPLETELY REWRITTEN
        """
        Perform DBSCAN clustering on high-risk user coordinates.
        
        Args:
            df: DataFrame with latitude, longitude columns
            
        Returns:
            DataFrame with added cluster_id column
        """
        if len(df) < self.min_cluster_size:
            df['cluster_id'] = -1  # No clusters possible
            logging.info(f"Insufficient data for clustering: {len(df)} < {self.min_cluster_size}")
            return df
        
        # ADDED: Calculate coordinate bounds for debugging
        lat_min, lat_max = df['latitude'].min(), df['latitude'].max()
        lng_min, lng_max = df['longitude'].min(), df['longitude'].max()
        
        # ADDED: Calculate approximate area coverage
        lat_span_km = abs(lat_max - lat_min) * 111  # degrees to km
        lng_span_km = abs(lng_max - lng_min) * 111 * np.cos(np.radians(df['latitude'].mean()))
        
        logging.info(f"GEOGRAPHIC COVERAGE:")
        logging.info(f"  - Latitude span: {lat_span_km:.2f} km")
        logging.info(f"  - Longitude span: {lng_span_km:.2f} km")
        logging.info(f"  - Area coverage: ~{lat_span_km:.1f} x {lng_span_km:.1f} km")
        
        # Use proper radius in radians for haversine distance
        radius_radians = self.calculate_radius_radians()
        
        logging.info(f"CLUSTERING PARAMETERS:")
        logging.info(f"  - Target radius: {self.radius_meters}m")
        logging.info(f"  - DBSCAN eps: {radius_radians:.8f} radians")
        logging.info(f"  - Min samples: {self.min_cluster_size}")
        logging.info(f"  - Total points: {len(df)}")
        
        # Prepare coordinates for DBSCAN
        coordinates = df[['latitude', 'longitude']].values
        
        # Perform DBSCAN clustering with proper parameters
        dbscan = DBSCAN(
            eps=radius_radians,  # Use radius in radians (not degrees!)
            min_samples=self.min_cluster_size,
            metric='haversine',  # Great circle distance
            algorithm='ball_tree'
        )
        
        # Convert to radians for haversine distance
        coordinates_rad = np.radians(coordinates)
        cluster_labels = dbscan.fit_predict(coordinates_rad)
        
        df['cluster_id'] = cluster_labels
        
        # ADDED: Calculate cluster statistics with debugging
        n_clusters = len(set(cluster_labels)) - (1 if -1 in cluster_labels else 0)
        n_noise = list(cluster_labels).count(-1)
        
        # ADDED: Analyze cluster sizes
        if n_clusters > 0:
            cluster_sizes = []
            for cluster_id in set(cluster_labels):
                if cluster_id != -1:
                    cluster_size = list(cluster_labels).count(cluster_id)
                    cluster_sizes.append(cluster_size)
            
            logging.info(f"CLUSTERING RESULTS:")
            logging.info(f"  - Clusters found: {n_clusters}")
            logging.info(f"  - Noise points: {n_noise}")
            logging.info(f"  - Cluster sizes: {sorted(cluster_sizes, reverse=True)}")
            logging.info(f"  - Largest cluster: {max(cluster_sizes)} users")
            
            # ADDED: WARNING for suspiciously large clusters
            if max(cluster_sizes) > len(df) * 0.5:
                logging.warning(f"⚠️ SUSPICIOUS: Largest cluster contains {max(cluster_sizes)}/{len(df)} ({max(cluster_sizes)/len(df)*100:.1f}%) of all users!")
                logging.warning(f"⚠️ This suggests radius might be too large for geographic area")
        
        return df
    
    def analyze_clusters(self, df: pd.DataFrame) -> Dict:
        """
        Analyze clustering results and generate statistics with accurate boundary calculation.
        
        Args:
            df: DataFrame with cluster_id column
            
        Returns:
            Dictionary with clustering analysis results including actual cluster radii
        """
        # Separate clustered and non-clustered users
        clustered_users = df[df['cluster_id'] != -1]
        noise_users = df[df['cluster_id'] == -1]
        
        # Cluster statistics with enhanced boundary calculation
        cluster_details = []
        
        if len(clustered_users) > 0:
            for cluster_id in clustered_users['cluster_id'].unique():
                cluster_points = clustered_users[clustered_users['cluster_id'] == cluster_id]
                
                # Basic statistics
                user_count = len(cluster_points)
                lat_center = cluster_points['latitude'].mean()
                lng_center = cluster_points['longitude'].mean()
                lat_spread = cluster_points['latitude'].std()
                lng_spread = cluster_points['longitude'].std()
                
                # Dominant STO
                dominant_sto = cluster_points['sto'].mode().iloc[0] if len(cluster_points['sto'].mode()) > 0 else 'Mixed'
                
                # ENHANCED: Calculate actual cluster boundary radius
                max_distance_from_center = 0
                avg_distance_from_center = 0
                distances = []
                
                for _, point in cluster_points.iterrows():
                    try:
                        # Calculate distance from center to this point
                        distance = geodesic(
                            (lat_center, lng_center), 
                            (point['latitude'], point['longitude'])
                        ).meters
                        distances.append(distance)
                        max_distance_from_center = max(max_distance_from_center, distance)
                    except Exception as e:
                        logging.warning(f"Distance calculation error for cluster {cluster_id}: {e}")
                        continue
                
                if distances:
                    avg_distance_from_center = sum(distances) / len(distances)
                    
                    # Calculate percentile distances for better boundary estimation
                    distances_sorted = sorted(distances)
                    p90_distance = distances_sorted[int(0.9 * len(distances_sorted))] if distances_sorted else 0
                    p95_distance = distances_sorted[int(0.95 * len(distances_sorted))] if distances_sorted else 0
                else:
                    avg_distance_from_center = 0
                    p90_distance = 0
                    p95_distance = 0
                
                # SMART RADIUS CALCULATION: 
                # Use 95th percentile + buffer, but cap at reasonable maximum
                if p95_distance > 0:
                    # Use 95th percentile + 10% buffer, minimum 300m (our target), maximum 800m
                    calculated_radius = min(max(p95_distance * 1.1, 300), 800)
                else:
                    # Fallback to target radius if calculation fails
                    calculated_radius = 350  # Slightly larger than target 300m
                
                cluster_detail = {
                    'cluster_id': cluster_id,
                    'user_count': user_count,
                    'lat_center': round(lat_center, 6),
                    'lng_center': round(lng_center, 6),
                    'lat_spread': round(lat_spread, 6) if not pd.isna(lat_spread) else 0,
                    'lng_spread': round(lng_spread, 6) if not pd.isna(lng_spread) else 0,
                    'dominant_sto': dominant_sto,
                    # Accurate radius calculations
                    'actual_radius_m': round(calculated_radius, 0),  # For visualization
                    'max_distance_m': round(max_distance_from_center, 0),  # Furthest point
                    'avg_distance_m': round(avg_distance_from_center, 0),  # Average distance
                    'p90_distance_m': round(p90_distance, 0),  # 90th percentile
                    'p95_distance_m': round(p95_distance, 0),  # 95th percentile
                }
                
                cluster_details.append(cluster_detail)
                
                # ENHANCED LOGGING for debugging
                logging.info(f"Cluster {cluster_id}: {user_count} users, "
                            f"center: ({lat_center:.4f}, {lng_center:.4f}), "
                            f"actual radius: {calculated_radius:.0f}m, "
                            f"max distance: {max_distance_from_center:.0f}m")
        
        # Convert to DataFrame for easy sorting
        if cluster_details:
            cluster_stats_df = pd.DataFrame(cluster_details)
            cluster_stats_df = cluster_stats_df.sort_values('user_count', ascending=False)
            cluster_stats = cluster_stats_df.to_dict('records')
        else:
            cluster_stats = []
        
        # Overall statistics
        total_users = len(df)
        clustered_count = len(clustered_users)
        clustering_rate = (clustered_count / total_users * 100) if total_users > 0 else 0
        
        # Determine maximum cluster concentration
        max_cluster_size = max([c['user_count'] for c in cluster_stats]) if cluster_stats else 0
        
        # Significant clusters (above average size)
        avg_cluster_size = sum([c['user_count'] for c in cluster_stats]) / len(cluster_stats) if cluster_stats else 0
        significant_clusters = [c for c in cluster_stats if c['user_count'] >= max(avg_cluster_size, self.min_cluster_size)]
        
        # ENHANCED: Add radius distribution statistics
        if cluster_stats:
            actual_radii = [c['actual_radius_m'] for c in cluster_stats]
            radius_stats = {
                'min_radius_m': min(actual_radii),
                'max_radius_m': max(actual_radii),
                'avg_radius_m': round(sum(actual_radii) / len(actual_radii), 0)
            }
            logging.info(f"Cluster radius distribution: min={radius_stats['min_radius_m']}m, "
                        f"max={radius_stats['max_radius_m']}m, avg={radius_stats['avg_radius_m']}m")
        else:
            radius_stats = {'min_radius_m': 0, 'max_radius_m': 0, 'avg_radius_m': 0}
        
        analysis_results = {
            'total_high_risk_users': total_users,
            'clustered_users': clustered_count,
            'isolated_users': len(noise_users),
            'clustering_rate': clustering_rate,
            'total_clusters': len(cluster_stats),
            'significant_clusters': len(significant_clusters),
            'max_cluster_size': max_cluster_size,
            'avg_cluster_size': avg_cluster_size,
            'cluster_details': cluster_stats,
            'significant_cluster_details': significant_clusters,
            'radius_stats': radius_stats
        }
        
        return analysis_results

# =================================================================
# Additional Helper Functions for Coordinate Processing
# =================================================================

class CoordinateParser:
    """Centralized coordinate parsing utility class"""
    
    PATTERNS = {
        'dms': re.compile(
            r"^\s*(?P<lat_deg>\d+)°(?P<lat_min>\d+)'(?P<lat_sec>\d+(?:\.\d+)?)\"?(?P<lat_dir>[NS])\s+"
            r"(?P<lon_deg>\d+)°(?P<lon_min>\d+)'(?P<lon_sec>\d+(?:\.\d+)?)\"?(?P<lon_dir>[EW])\s*$"
        ),
        'google_maps': re.compile(
            r"https://www\.google\.com/maps(?:/[^?]*)?(?:@(-?\d+\.\d+),(-?\d+\.\d+)|\?q=(-?\d+\.\d+),(-?\d+\.\d+))"
        ),
        'decimal': re.compile(
            r"^\s*(-?\d+(?:\.\d+)?),\s*(-?\d+(?:\.\d+)?)\s*$"
        )
    }
    
    @staticmethod
    def dms_to_decimal(degrees: str, minutes: str, seconds: str, direction: str) -> float:
        """Convert DMS coordinates to decimal"""
        decimal = float(degrees) + float(minutes) / 60 + float(seconds) / 3600
        return -decimal if direction in ['S', 'W'] else decimal
    
    @classmethod
    def parse(cls, text_input: str) -> Tuple[Optional[float], Optional[float]]:
        """Parse coordinates from various text formats"""
        if not text_input or not text_input.strip():
            return None, None
            
        text_input = text_input.strip()
        
        # Try Google Maps first
        google_match = cls.PATTERNS['google_maps'].search(text_input)
        if google_match:
            try:
                lat_str = google_match.group(1) or google_match.group(3)
                lon_str = google_match.group(2) or google_match.group(4)
                if lat_str and lon_str:
                    return float(lat_str), float(lon_str)
            except (ValueError, TypeError):
                pass
        
        # Try decimal coordinates
        decimal_match = cls.PATTERNS['decimal'].match(text_input)
        if decimal_match:
            try:
                lat_str, lon_str = decimal_match.groups()
                return float(lat_str), float(lon_str)
            except (ValueError, TypeError):
                pass
        
        # Try DMS coordinates
        dms_match = cls.PATTERNS['dms'].match(text_input)
        if dms_match:
            try:
                lat = cls.dms_to_decimal(
                    dms_match.group("lat_deg"), dms_match.group("lat_min"),
                    dms_match.group("lat_sec"), dms_match.group("lat_dir")
                )
                lon = cls.dms_to_decimal(
                    dms_match.group("lon_deg"), dms_match.group("lon_min"),
                    dms_match.group("lon_sec"), dms_match.group("lon_dir")
                )
                return lat, lon
            except (ValueError, TypeError):
                pass
        
        return None, None
    
    @staticmethod
    def validate_coordinates(latitude: float, longitude: float) -> bool:
        """Validate coordinate ranges"""
        if latitude is None or longitude is None:
            return False
        return -90 <= latitude <= 90 and -180 <= longitude <= 180


