@dp.message(CommandStart())
async def start_command(message: types.Message, state: FSMContext, bot: Bot):
    """Enhanced start command that sets personalized commands"""
    try:
        user_id = message.from_user.id
        chat_id = message.chat.id
        live_username = message.from_user.username or message.from_user.first_name or ""
        # Sync username if user changed their Telegram @username
        if await is_user_registered(user_id):
            await sync_username_if_changed(user_id, live_username)
        username = await get_username(user_id)

        await log_user_interaction(user_id, username, "/start", "Command")

        current_state = await state.get_state()
        if current_state is not None:
            logger.info(f"User {user_id} used /start to restart from state: {current_state}")
            await state.clear()

        # 🆕 Set personalized commands for this user
        await set_personalized_bot_commands(bot, user_id, chat_id)

        # Get personalized keyboard
        markup = await get_main_keyboard_for_user(user_id)
        
        # Get user status for personalized welcome message
        is_registered, employer = await get_user_registration_status(user_id)
        
        if not is_registered:
            welcome_text = (
                f"*Selamat datang di Bot Indihome Area 3* 👋🏼\n\n"
                f"🔐 *Anda belum terdaftar*\\. Silakan melakukan pendaftaran terlebih dahulu dengan menekan tombol Register di bawah\\.\n\n"
                f"💡 *Tip:* Setelah registrasi disetujui, gunakan /start untuk melihat fitur yang tersedia\\.\n"
            )
        else:
            employer_names = {
                "tsel": "Telkomsel",
                "sf": "Sales Force", 
                "ta": "Telkom Akses",
                "tif": "Telkom Infra",
                "ctb": "Collection Team",
                "admin": "Admin"
            }
            
            employer_display = employer_names.get(employer, employer.upper() if employer else "Unknown")

            # Enrich greeting with name + title from domain table for TSEL/TIF/TA
            domain_greeting_name = ""
            if employer in ("tsel", "tif", "ta"):
                try:
                    user_record = await get_cached_user_data(user_id)
                    nik_tsel_val = user_record.get('nik_tsel', '') if user_record else ''
                    if nik_tsel_val and not nik_tsel_val.startswith("UID_"):
                        domain_info = await lookup_nik_in_domain(nik_tsel_val)
                        if domain_info:
                            domain_greeting_name = domain_info.get('name', '')
                            domain_title = domain_info.get('title', '')
                            if domain_title:
                                employer_display = f"{employer_display}"
                except Exception as e:
                    logger.debug(f"Domain lookup for /start enrichment failed: {e}")

            safe_username = escape_markdown_v2(username)
            safe_employer_display = escape_markdown_v2(employer_display)

            if domain_greeting_name:
                safe_greeting_name = escape_markdown_v2(domain_greeting_name)
                welcome_text = (
                    f"*Selamat datang {safe_greeting_name} di Bot Indihome Area 3* 👋🏼\n\n"
                    f"👤 *User:* {safe_username}\n"
                    f"🏢 *Role:* {safe_employer_display}\n\n"
                    f"💡 *Tip:* Gunakan /start untuk kembali ke menu utama\\.\n\n"
                )
            else:
                welcome_text = (
                    f"*Selamat datang di Bot Indihome Area 3* 👋🏼\n\n"
                    f"👤 *User:* {safe_username}\n"
                    f"🏢 *Role:* {safe_employer_display}\n\n"
                    f"💡 *Tip:* Gunakan /start untuk kembali ke menu utama\\.\n\n"
                )
        
        await message.answer(welcome_text, reply_markup=markup, parse_mode=ParseMode.MARKDOWN_V2)
        
        logger.info(f"Start command executed for user {user_id} ({username}) - "
                   f"Registered: {is_registered}, Employer: {employer}")
        
    except Exception as e:
        logger.error(f"Error in start_command_with_dynamic_commands: {e}", exc_info=True)
        
        # Fallback
        try:
            fallback_markup = InlineKeyboardMarkup(inline_keyboard=[
                [InlineKeyboardButton(text="🔐 Register", callback_data="registration")]
            ])
            await message.answer(
                "Terjadi kesalahan, tetapi bot masih berjalan\\. Silakan coba registrasi jika belum terdaftar\\.",
                reply_markup=fallback_markup,
                parse_mode=ParseMode.MARKDOWN_V2
            )
        except:
            await message.answer("Terjadi kesalahan, bot sedang di-restart. Silakan coba lagi.")
        
        await state.clear()


