@dp.callback_query(F.data.startswith("reregister_confirm:"))
async def handle_reregister_confirm(call: CallbackQuery, state: FSMContext):
    """Handles re-registration confirmation from 'Daftar Ulang' button."""
    choice = call.data.split(":")[1]
    if choice == "yes":
        user_id = call.from_user.id
        # Store flag for deferred deletion — old record will be deleted at final save step
        await state.update_data(reregistration_pending_delete=True)
        invalidate_domain_lookup_cache()  # Clear domain cache on re-registration
        logger.info(f"User {user_id} initiated re-registration. Old record will be deleted at final save.")
        await call.message.edit_reply_markup(reply_markup=None)
        await user_registration_start(call, state)
    else:
        await call.message.edit_text("Pendaftaran dibatalkan.")
    await call.answer()


async def user_registration_start(message_or_call, state: FSMContext, user_id=None, username=None):
    """Starts the registration flow."""
    # Extract user info from the correct source
    if isinstance(message_or_call, CallbackQuery):
        user_id = message_or_call.from_user.id
        username = message_or_call.from_user.username or message_or_call.from_user.first_name or "N/A"
        target_message = message_or_call.message  # For sending/editing messages
    else:  # Message
        user_id = message_or_call.from_user.id
        username = message_or_call.from_user.username or message_or_call.from_user.first_name or "N/A"
        target_message = message_or_call

    if await is_user_registered(user_id):
        # Fetch user's current registration data
        user_data = await get_cached_user_data(user_id)
        
        if user_data:
            # Extract and format data
            db_username = user_data.get('username', 'N/A')
            # Ensure username has @ prefix if it's not N/A
            if db_username and db_username != 'N/A' and not db_username.startswith('@'):
                db_username = f"@{db_username}"
            
            nik = user_data.get('nik_tsel', '').strip() or 'N/A'
            region = user_data.get('region_level', '').strip().upper() or 'N/A'
            employer = user_data.get('employer', '').strip().upper() or 'N/A'
            sf_code = user_data.get('sf_code', '').strip() or 'N/A'
            agency = user_data.get('agency_name', '').strip() or 'N/A'
            
            info_message = (
                f"✅ Anda sudah terdaftar.\n\n"
                f"*Data Registrasi Anda:*\n"
                f"```\n"
                f"• Username   : {db_username}\n"
                f"• User ID    : {user_id}\n"
                f"• NIK        : {nik}\n"
                f"• Region     : {region}\n"
                f"• Employer   : {employer}\n"
                f"• SF Code    : {sf_code}\n"
                f"• Agency     : {agency}\n"
                f"```"
            )
        else:
            # Fallback if data fetch fails
            info_message = "✅ Anda sudah terdaftar."

        reregister_keyboard = InlineKeyboardMarkup(
            inline_keyboard=[[
                InlineKeyboardButton(text="🔄 Daftar Ulang", callback_data="reregister_confirm:yes"),
                InlineKeyboardButton(text="❌ Batal", callback_data="reregister_confirm:no")
            ]]
        )
        await target_message.answer(info_message, parse_mode='Markdown', reply_markup=reregister_keyboard)
        return

    await state.update_data(user_id=user_id, username=username)

    keyboard = InlineKeyboardMarkup(
        inline_keyboard=[
            [
                InlineKeyboardButton(text="TSEL", callback_data="reg_employer:TSEL"),
                InlineKeyboardButton(text="TIF", callback_data="reg_employer:TIF")
            ],
            [
                InlineKeyboardButton(text="TA", callback_data="reg_employer:TA"),
                InlineKeyboardButton(text="CTB", callback_data="reg_employer:CTB")
            ],
            [
                InlineKeyboardButton(text="SF", callback_data="reg_employer:SF"),
                InlineKeyboardButton(text="Admin", callback_data="reg_employer:Admin")
            ],
            [InlineKeyboardButton(text="❌ Batal", callback_data="cancel_flow:registration")]
        ]
    )
    await target_message.answer("📥 Proses pendaftaran. Silakan pilih status kepegawaian Anda:", reply_markup=keyboard)
    await state.set_state(UserRegistration.awaiting_employee_status)


