@dp.message(NikFillFlow.awaiting_nik_fill, F.text)
async def handle_nik_fill(message: Message, state: FSMContext, bot: Bot):
    """Handles NIK input from users who were forced to fill their NIK."""
    nik_input = message.text.strip()
    user_id = message.from_user.id

    # Get user's employer from cache
    user_record = await get_cached_user_data(user_id)
    if not user_record:
        await message.reply("❌ Data pengguna tidak ditemukan. Silakan hubungi admin.")
        await state.clear()
        return

    employer = user_record.get('employer', 'tsel').upper()

    # Validate NIK using existing validator
    is_valid, error_message = await validate_nik_tsel(nik_input, employer)

    if not is_valid:
        nik_cancel_kb = InlineKeyboardMarkup(inline_keyboard=[
            [InlineKeyboardButton(text="❌ Batal", callback_data="cancel_nik_fill")]
        ])
        await message.reply(
            f"❌ {error_message}\n\n"
            f"✍🏼 Silakan masukkan NIK {employer} Anda yang valid:",
            reply_markup=nik_cancel_kb
        )
        return

    # Save NIK to CSV
    success = await update_user_nik(user_id, nik_input)
    if success:
        await message.reply(
            f"✅ NIK berhasil disimpan: *{nik_input}*. Silakan ulangi perintah Anda.",
            parse_mode='Markdown'
        )
    else:
        await message.reply("❌ Gagal menyimpan NIK. Silakan coba lagi atau hubungi admin.")

    await state.clear()


