# Optional: Batch validation function for multiple inputs
async def validate_multiple_inputs(sf_codes: list[str] = None, nik_data: list[tuple[str, str]] = None) -> dict:
    """
    Async batch validation function for multiple inputs.
    Args:
        sf_codes: List of SF codes to validate
        nik_data: List of tuples (nik, employer) to validate
    Returns: dict with validation results
    """
    results = {
        'sf_codes': [],
        'nik_tsels': []
    }
    
    # Validate SF codes concurrently
    if sf_codes:
        sf_tasks = [validate_sf_code(code) for code in sf_codes]
        sf_results = await asyncio.gather(*sf_tasks)
        results['sf_codes'] = list(zip(sf_codes, sf_results))
    
    # Validate NIK data concurrently
    if nik_data:
        nik_tasks = [validate_nik_tsel(nik, employer) for nik, employer in nik_data]
        nik_results = await asyncio.gather(*nik_tasks)
        results['nik_tsels'] = list(zip(nik_data, nik_results))
    
    return results


