@dp.callback_query(UserRegistration.awaiting_agency_name, F.data.startswith("reg_agency:"))
async def process_agency_selection(call: CallbackQuery, state: FSMContext):
    """Finalizes registration for SF and Admin-Agency."""
    agency_choice = call.data.split(":")[1]
    await state.update_data(agency_name=agency_choice)
    data = await state.get_data()

    # Deferred deletion for re-registration: delete old record right before saving new one
    if data.get('reregistration_pending_delete'):
        deleted = await delete_own_user_record(data.get('user_id'))
        if deleted:
            logger.info(f"Re-registration: deleted old record for user {data.get('user_id')} before saving new one.")

    await append_user_data(
        user_id=data.get('user_id'),
        username=data.get('username'),
        nik_tsel="",
        sf_code=data.get('sf_code', ""),
        user_name=data.get('user_name', ""),
        employer=data.get('employer'),
        region_level="",
        agency_name=agency_choice
    )

    # Update personalized commands after registration
    await set_personalized_bot_commands(call.bot, data.get('user_id'), call.message.chat.id)
    
    await state.clear()
    await call.message.edit_text("✅ *Pendaftaran selesai.*\n\n Ketik /start untuk memulai bot.", parse_mode='Markdown')
    logger.info(f"Registration complete for {data.get('employer')} user {data.get('user_id')}.")
    await call.answer()


