# Region selection handler (replaces the text input)
@dp.callback_query(UserRegistration.awaiting_region, F.data.startswith("reg_region:"))
async def process_region_selection(call: CallbackQuery, state: FSMContext):
    """Handles region selection via inline buttons."""
    global USER_DATA_CACHE, CACHE_TIMESTAMP

    region_choice = call.data.split(":")[1]
    if region_choice not in ("JATENG-DIY", "JATIM", "BALI NUSRA", "OTHER"):
        await call.answer("❌ Region tidak valid.", show_alert=True)
        return
    data = await state.get_data()
    employer = data.get('employer')

    # Compute nik_tsel BEFORE writing to CSV so CSV and notification use the same key
    nik_tsel_val = data.get('nik_tsel', "")
    if employer in ['tsel', 'tif', 'ta'] and not nik_tsel_val:
        # Use user_id as fallback pending approval key so notification still fires
        nik_tsel_val = f"UID_{data.get('user_id')}"

    # Deferred deletion for re-registration: delete old record right before saving new one
    if data.get('reregistration_pending_delete'):
        deleted = await delete_own_user_record(data.get('user_id'))
        if deleted:
            logger.info(f"Re-registration: deleted old record for user {data.get('user_id')} before saving new one.")

    await append_user_data(
        user_id=data.get('user_id'),
        username=data.get('username'),
        nik_tsel=nik_tsel_val,
        sf_code="",
        user_name=data.get('user_name', ""),
        employer=employer,
        region_level=region_choice.lower(),
        agency_name=""
    )

    # Update personalized commands after registration
    await set_personalized_bot_commands(call.bot, data.get('user_id'), call.message.chat.id)

    await state.clear()

    if employer in ['admin', 'ctb']:
        await call.message.edit_text("✅ *Pendaftaran Selesai*\n\nAnda sekarang dapat menggunakan bot.", parse_mode='Markdown')
        logger.info(f"Registration complete for {employer.upper()} user {data.get('user_id')}. Auto-authorized.")
    else:
        await call.message.edit_text(
            "⏳ *Pendaftaran Selesai*\n\n"
            "Pendaftaran Anda telah berhasil disubmit.\n"
            "Silakan menunggu *persetujuan dari admin* untuk menggunakan seluruh fitur bot.\n\n"
            "📩 Anda akan menerima notifikasi setelah admin memproses pendaftaran Anda.\n\n"
            "⏰ *Batas Waktu:* Maksimal 3x24 jam",
            parse_mode='Markdown'
        )
        logger.info(f"Registration complete for {employer.upper()} user {data.get('user_id')}. Awaiting approval.")
        nik_verified = data.get('nik_verified')  # True, False, or None
        await notify_super_users(data.get('user_id'), data.get('username'), nik_tsel_val, region_choice, call.bot, nik_verified=nik_verified)
    
    await call.answer()


