# --- Admin Approval and Deletion ---
@dp.message(Command("approve"))
async def approve_registration(message: Message, state: FSMContext):
    """Command for super_users to approve registrations. Users can self-approve."""
    nik_tsel = message.text.split(' ', 1)[1] if len(message.text.split(' ', 1)) > 1 else None
    if not nik_tsel:
        await message.reply("📋 *Penggunaan:* `/approve <nik_pengguna>`", parse_mode='Markdown')
        return

    # In demo mode: Allow self-approval for pending registrations
    pending_info = PENDING_APPROVALS.get(nik_tsel)
    if pending_info and pending_info.get('user_id') == message.from_user.id:
        logger.info(f"Allowing self-approval for user {message.from_user.id}, NIK {nik_tsel}")
    elif not await is_super_user(message.from_user.id):
        await message.reply("❌ Anda tidak memiliki izin untuk perintah ini.")
        return

    # Remove from pending approvals if exists (stop auto-reject timer)
    if nik_tsel in PENDING_APPROVALS:
        del PENDING_APPROVALS[nik_tsel]
        logger.info(f"Removed NIK {nik_tsel} from pending approvals (manual approval)")

    result, registrant_id, username = await approve_user_notification(nik_tsel)
    if result:
        await message.reply(f"✅ *Persetujuan Berhasil*\n\nPengguna *{username}* (NIK: `{nik_tsel}`) telah disetujui.", parse_mode='Markdown')
        if registrant_id:
            try:
                # Update commands for approved user
                await set_personalized_bot_commands(message.bot, registrant_id, registrant_id)
                
                await message.bot.send_message(
                    registrant_id, 
                    "🎉 *Selamat!*\n\n✅ Pendaftaran Anda telah *disetujui* oleh admin.\n\nKetik /start untuk memulai menggunakan bot.", 
                    parse_mode='Markdown'
                )
            except Exception as e:
                logger.error(f"Failed to notify registrant {registrant_id}: {e}")
    elif username:
        await message.reply(f"ℹ️ *Status:* Pengguna *{username}* (NIK: `{nik_tsel}`) sudah ter-approve sebelumnya.", parse_mode='Markdown')
    else:
        await message.reply(f"❌ *Error:* Pengguna dengan NIK `{nik_tsel}` tidak ditemukan dalam sistem.", parse_mode='Markdown')

@dp.message(Command("reject"))
async def reject_registration(message: Message, state: FSMContext):
    """Command for super_users to reject registrations with reason. Users can self-reject."""
    global USER_DATA_CACHE, CACHE_TIMESTAMP

    # Parse command: /reject <nik> <reason>
    parts = message.text.split(' ', 2)
    if len(parts) < 2:
        await message.reply(
            "📋 *Penggunaan:* `/reject <nik_pengguna> <alasan_penolakan>`\n\n"
            "*Contoh:* `/reject 99119 Data tidak lengkap atau tidak sesuai`",
            parse_mode='Markdown'
        )
        return

    nik_tsel = parts[1]
    reject_reason = parts[2] if len(parts) > 2 else "Alasan tidak disebutkan"

    # In demo mode: Allow self-rejection for pending registrations
    pending_info = PENDING_APPROVALS.get(nik_tsel)
    if pending_info and pending_info.get('user_id') == message.from_user.id:
        logger.info(f"Allowing self-rejection for user {message.from_user.id}, NIK {nik_tsel}")
    elif not await is_super_user(message.from_user.id):
        await message.reply("❌ Anda tidak memiliki izin untuk perintah ini.")
        return

    # Remove from pending approvals if exists (stop auto-reject timer)
    if nik_tsel in PENDING_APPROVALS:
        del PENDING_APPROVALS[nik_tsel]
        logger.info(f"Removed NIK {nik_tsel} from pending approvals (manual rejection)")

    # Find user by NIK and get their information
    try:
        await ensure_cache_fresh()
        user_found = None
        registrant_id = None
        username = None
        
        for user_record in USER_DATA_CACHE.values():
            if user_record.get('nik_tsel') == nik_tsel:
                user_found = user_record
                registrant_id = int(float(user_record.get('user_id', 0)))
                username = user_record.get('username', 'Unknown')
                break

        if not user_found:
            await message.reply(f"❌ *Error:* Pengguna dengan NIK `{nik_tsel}` tidak ditemukan dalam sistem.", parse_mode='Markdown')
            return

        # Check if user is already approved (has user_level)
        is_authorized = user_found.get('is_authorized', 'no') or 'no'
        if is_authorized.lower() == 'yes':
            await message.reply(f"ℹ️ *Status:* Pengguna *{username}* (NIK: `{nik_tsel}`) sudah ter-autorisasi dalam sistem.", parse_mode='Markdown')
            return
        
        # Actually delete user from CSV file (with file locking)
        # Use user_id (not NIK) to avoid deleting other users who share the same NIK
        try:
            csv_file = USER_DATA_FILE
            if os.path.exists(csv_file):
                df = pd.read_csv(csv_file, dtype=str)

                # Remove the specific user by user_id (unique), not by NIK (may not be unique)
                df_filtered = df[df['user_id'].astype(str).str.strip() != str(registrant_id)]

                # Save back to CSV with locking
                await write_csv_with_lock(df_filtered)
                logger.info(f"Successfully deleted user_id {registrant_id} (NIK {nik_tsel}) from CSV file")
            
            # Invalidate cache after deletion
            USER_DATA_CACHE = {}
            CACHE_TIMESTAMP = 0
            
        except Exception as csv_error:
            logger.error(f"Error deleting user from CSV: {csv_error}")
            await message.reply(f"⚠️ *Warning:* User logically rejected but CSV deletion failed: {str(csv_error)}", parse_mode='Markdown')
        
        # Send rejection notification to admin/super_user
        await message.reply(
            f"❌ *Penolakan Berhasil*\n\n"
            f"Pengguna *{username}* (NIK: `{nik_tsel}`) telah ditolak.\n"
            f"*Alasan:* {reject_reason}",
            parse_mode='Markdown'
        )
        
        # Send rejection notification to user
        if registrant_id:
            try:
                rejection_message = (
                    f"❌ *Pendaftaran Ditolak*\n\n"
                    f"Maaf, pendaftaran Anda telah *ditolak* oleh admin.\n\n"
                    f"*Alasan penolakan:*\n"
                    f"{reject_reason}\n\n"
                    f"💡 *Saran:* Silakan hubungi admin untuk informasi lebih lanjut atau daftar ulang dengan data yang benar.\n\n"
                )
                await message.bot.send_message(registrant_id, rejection_message, parse_mode='Markdown')
                logger.info(f"Rejection notification sent to user {registrant_id}")
            except Exception as e:
                logger.error(f"Failed to notify rejected user {registrant_id}: {e}")
                await message.reply(f"⚠️ *Peringatan:* Penolakan berhasil, tetapi gagal mengirim notifikasi ke pengguna: {str(e)}", parse_mode='Markdown')
            
    except Exception as e:
        logger.error(f"Error in reject_registration: {e}")
        await message.reply(f"❌ *Error:* Terjadi kesalahan sistem: {str(e)}", parse_mode='Markdown')


@dp.message(Command("delete"))
async def delete_user(message: Message, state: FSMContext):
    """Command for super_users to delete users by username."""
    if not await is_super_user(message.from_user.id):
        await message.reply("❌ Anda tidak memiliki izin untuk perintah ini.")
        return

    username_to_delete = message.text.split(' ', 1)[1] if len(message.text.split(' ', 1)) > 1 else None
    if not username_to_delete or not username_to_delete.startswith('@'):
        await message.reply("Penggunaan: /delete @username_target")
        return

    registrant_id_str, found_username, error_message = await find_user_for_deletion(username_to_delete, message.from_user.id)
    if error_message:
        await message.reply(f"❌ {error_message}")
        return

    keyboard = InlineKeyboardMarkup(
        inline_keyboard=[[
            InlineKeyboardButton(text="🔴 Ya, Hapus", callback_data=f"confirm_delete:{found_username}"),
            InlineKeyboardButton(text="🟢 Batal", callback_data="confirm_delete:cancel")    
        ]]
    )

    await message.reply(
        f"⚠️ *KONFIRMASI* ⚠️\nAnda yakin ingin menghapus pengguna: {escape_markdown_v2(found_username)} ?\n\nTindakan ini tidak dapat dibatalkan.",
        reply_markup=keyboard,
        parse_mode='Markdown'
    )

@dp.callback_query(F.data.startswith("confirm_delete:"))
async def handle_delete_confirmation(call: CallbackQuery, state: FSMContext):
    """Handles the confirmation for user deletion."""
    if not await is_super_user(call.from_user.id):
        await call.answer("❌ Anda tidak memiliki izin.", show_alert=True)
        return

    action = call.data.split(":", 1)[1]
    await call.message.edit_reply_markup(reply_markup=None)

    if action == "cancel":
        await call.message.edit_text("👍 Penghapusan pengguna dibatalkan.")
    else:
        username_to_delete = action
        await call.message.edit_text(f"⏳ Memproses penghapusan untuk `{escape_markdown_v2(username_to_delete)}`...")
        
        registrant_id_str, _, find_error = await find_user_for_deletion(username_to_delete, call.from_user.id)
        if find_error:
            await call.message.edit_text(f"❌ Gagal menghapus: {escape_markdown_v2(find_error)}")
            return

        if await perform_user_deletion(username_to_delete):
            await call.message.edit_text(f"✅ Pengguna {escape_markdown_v2(username_to_delete)} berhasil dihapus.")
            if registrant_id_str:
                try:
                    await call.bot.send_message(int(registrant_id_str), "❌ Akun Anda telah dihapus oleh admin.")
                except Exception as e:
                    logger.error(f"Failed to notify deleted user {registrant_id_str}: {e}")
        else:
            await call.message.edit_text(f"❌ Gagal menghapus pengguna {escape_markdown_v2(username_to_delete)} karena kesalahan internal.")
    await call.answer()


