# --- List all registered users ---
@dp.message(Command("registered"))
@require_admin_access
async def registered(message: Message, state: FSMContext):
    """Lists all registered users, grouped by region. (Admin only)"""
    try:
        user_data = await read_user_data_async()
        
        if user_data is None or user_data.empty:
            await message.reply("Gagal membaca data pengguna atau tidak ada pengguna terdaftar.")
            return

        # Clean all columns that should be text to prevent data type errors.
        user_data['region_level'] = user_data['region_level'].fillna('Unknown').astype(str)
        # ADDED: Clean the 'username' column to handle missing usernames (NaN values).
        user_data['username'] = user_data['username'].fillna('N/A').astype(str)
        
        grouped_data = user_data.groupby('region_level')['username'].apply(list).to_dict()

        def region_sort_key(region):
            return (1, region) if region.upper() in {"UNKNOWN", "OTHER"} else (0, region)

        message_content = "⤵️ *Daftar Pengguna Terdaftar:*\n\n"
        for region in sorted(grouped_data.keys(), key=region_sort_key):
            message_content += f"*{escape_markdown_v2(region.upper())}*\n"
            # This loop is now safe because 'username' is guaranteed to be a string.
            for idx, username in enumerate(grouped_data[region], 1):
                message_content += f"{idx}\\. {escape_markdown_v2(username)}\n"
            message_content += "\n"
        
        # Ensure your helper function sends with parse_mode="MarkdownV2"
        await send_long_message(message.bot, message.chat.id, [message_content],parse_mode="MarkdownV2")
        
    except Exception as e:
        logger.error(f"Error in /registered command: {e}", exc_info=True)
        await message.answer(f"❌ Terjadi kesalahan saat mengambil daftar pengguna.\nError: {e}")


