@dp.callback_query(AdminBroadcast.awaiting_target_type, F.data.startswith("sendmsg_target:"))
async def process_target_type(call: CallbackQuery, state: FSMContext):
    """Processes the broadcast target type selection."""
    target_type = call.data.split(":")[1]
    await state.update_data(target_type=target_type)
    
    prompts = {
        "all": "➡️ Silakan ketik pesan untuk dikirim ke *semua pengguna*:",
        "region_level": "➡️ Masukkan nama Region target (e.g., `JATENG-DIY`, `JATIM`):",
        "employer": "➡️ Masukkan tipe Employer target (e.g., `tsel`, `sf`, `admin`):",
        "username": "➡️ Masukkan `Username` target (e.g., `@targetuser`):"
    }

    if target_type in prompts:
        # It's good practice to set the parse mode explicitly
        await call.message.edit_text(
            prompts[target_type] + "\n\n_(Ketik /cancel untuk membatalkan)_",
            parse_mode="Markdown"
        )
        await state.set_state(AdminBroadcast.awaiting_broadcast_message if target_type == "all" else AdminBroadcast.awaiting_target_value)
    elif target_type == "agency_name":
        agency_names = await run_sync_in_thread(get_agency_names)
        if not agency_names:
            await call.message.edit_text("❌ Tidak dapat memuat daftar agency.")
            await state.clear()
            return
            
        # All InlineKeyboardButton calls now use keyword arguments
        keyboard = InlineKeyboardMarkup(
            inline_keyboard=[
                [InlineKeyboardButton(text=agency, callback_data=f"sendmsg_agencyvalue:{agency}")] for agency in sorted(agency_names)
            ] + [[InlineKeyboardButton(text="❌ Batal", callback_data="cancel_flow:broadcast")]]
        )
        await call.message.edit_text("🏢 Silakan pilih `Nama Agency` target:", reply_markup=keyboard, parse_mode="Markdown")
        await state.set_state(AdminBroadcast.awaiting_target_agency_selection)
    
    await call.answer()

@dp.message(AdminBroadcast.awaiting_target_value, F.text)
async def process_target_value(message: Message, state: FSMContext):
    """Receives the target value (e.g., region name) and asks for the message."""
    target_value = message.text.strip()
    if not target_value: return

    data = await state.get_data()
    target_type = data.get('target_type')

    if target_type == 'username' and not target_value.startswith('@'):
        await message.reply("⚠️ Format username tidak valid. Harus diawali dengan '@'. Coba lagi:")
        return

    await state.update_data(target_value=target_value)
    await state.set_state(AdminBroadcast.awaiting_broadcast_message)
    # The '\\.' correctly escapes the dot for MarkdownV2. Ensure you use that parse_mode.
    await message.reply(
        f"➡️ Target diatur ke *{escape_markdown_v2(target_type)}: {escape_markdown_v2(target_value)}*\\. Sekarang, ketik pesan yang ingin dikirim:",
        parse_mode="MarkdownV2"
    )

@dp.callback_query(AdminBroadcast.awaiting_target_agency_selection, F.data.startswith("sendmsg_agencyvalue:"))
async def process_target_agency_selection(call: CallbackQuery, state: FSMContext):
    """Receives the target agency and asks for the message."""
    agency_name = call.data.split(":", 1)[1]
    await state.update_data(target_value=agency_name)
    await state.set_state(AdminBroadcast.awaiting_broadcast_message)
    # The '\\.' correctly escapes the dot for MarkdownV2. Ensure you use that parse_mode.
    await call.message.edit_text(
        f"➡️ Target diatur ke *Agency: {escape_markdown_v2(agency_name)}*\\. Sekarang, ketik pesan yang ingin dikirim:",
        parse_mode="MarkdownV2"
    )
    await call.answer()

@dp.message(AdminBroadcast.awaiting_broadcast_message, F.text)
async def process_broadcast_message(message: Message, state: FSMContext):
    """Receives the final message and broadcasts it."""
    broadcast_content = message.text
    data = await state.get_data()
    target_type = data.get('target_type')
    target_value = data.get('target_value')
    await state.clear()

    # Using the new centralized async function.
    user_data_df = await read_user_data_async()

    if user_data_df is None:
        await message.reply("⚠️ Gagal memuat data pengguna untuk broadcast.")
        return

    for col in ['region_level', 'employer', 'agency_name', 'username']:
        if col in user_data_df.columns:
            user_data_df[col] = user_data_df[col].fillna('').astype(str)

    target_df = pd.DataFrame()
    if target_type == 'all':
        target_df = user_data_df
    elif target_value:
        target_df = user_data_df[user_data_df[target_type].str.casefold() == target_value.casefold()]

    if target_df.empty:
        await message.reply("⚠️ Tidak ada pengguna yang cocok dengan target.")
        return

    target_user_ids = [int(uid) for uid in target_df['user_id'].dropna().unique()]
    status_message = await message.reply(f"⏳ Mengirim pesan ke {len(target_user_ids)} pengguna...")

    success_count, fail_count = 0, 0
    
    # Using asyncio.gather for fast, concurrent broadcasting.
    tasks = [message.bot.send_message(user_id, broadcast_content) for user_id in target_user_ids]
    results = await asyncio.gather(*tasks, return_exceptions=True)

    for result in results:
        if isinstance(result, Exception):
            fail_count += 1
            logger.warning(f"Failed to send broadcast message: {result}")
        else:
            success_count += 1

    await status_message.edit_text(
        f"✅ Pesan selesai dikirim\\.\n- Berhasil: {success_count}\n- Gagal: {fail_count}",
        parse_mode="MarkdownV2"
    )


