@dp.callback_query(F.data.startswith("select_region:"))
@authorized_only_employer("tsel")
async def handle_wok_region_selection(call: CallbackQuery, bot: Bot):
    """Handles region selection within the WOK flow."""
    await call.answer()
    user_id = call.from_user.id
    selected_region = call.data.split(":", 1)[1]
    
    await call.message.edit_reply_markup()
    
    # Fix: Get period and convert to date range (following a3_reporting pattern)
    selected_period = await get_user_selected_period(user_id)
    
    if selected_period is None:
        await bot.send_message(call.message.chat.id, "⚠️ Anda belum memilih periode laporan. Silakan pilih periode terlebih dahulu.")
        return

    start_date, end_date = await get_period_date_range(selected_period)
    
    if start_date is None or end_date is None:
        await bot.send_message(call.message.chat.id, "❌ Format periode tidak valid. Silakan pilih periode yang benar.")
        return
    
    await bot.send_message(call.message.chat.id, "🔄 Mohon tunggu, data sedang diquery...")
    
    try:
        # Fix: Call with correct parameters (start_date, end_date, selected_region)
        messages = await format_wok_summary_message(start_date, end_date, selected_region)
        
        if not messages:
            await send_error_message(bot, call.message.chat.id, "Query tidak dapat dilakukan, mohon hubungi admin atau coba beberapa saat lagi.")
            return
        
        # Send messages with proper escaping (following a3_reporting pattern)
        if isinstance(messages, list):
            for msg in messages:
                escaped_message = escape_markdown_v2(msg)
                await bot.send_message(call.message.chat.id, escaped_message, parse_mode='MarkdownV2')
        else:
            escaped_message = escape_markdown_v2(messages)
            await bot.send_message(call.message.chat.id, escaped_message, parse_mode='MarkdownV2')
        
        await send_disclaimer(bot, call.message.chat.id)
        
    except Exception as e:
        logging.error(f"Error in handle_wok_region_selection: {e}")
        await send_error_message(bot, call.message.chat.id)


