@dp.callback_query(F.data.startswith("toggle_wok:"))
async def handle_wok_toggle(call: CallbackQuery, bot: Bot, state: FSMContext):
    """Handles toggling WOK selection on/off"""
    await call.answer()
    
    # Parse callback data: "toggle_wok:region:wok"
    parts = call.data.split(":", 2)
    if len(parts) != 3:
        await bot.send_message(call.message.chat.id, "❌ Format data tidak valid.")
        return
    
    region = parts[1]
    wok = parts[2]
    
    # Get current state data
    data = await state.get_data()
    selected_woks = data.get('selected_woks', [])
    wok_list = data.get('wok_list', [])
    
    # Toggle WOK selection
    if wok in selected_woks:
        selected_woks.remove(wok)
        logger.debug(f"[WOK Toggle] Removed {wok} from selection")
    else:
        selected_woks.append(wok)
        logger.debug(f"[WOK Toggle] Added {wok} to selection")
    
    # Update state
    await state.update_data(selected_woks=selected_woks)
    
    # Recreate keyboard with updated selection
    keyboard = await create_wok_selection_keyboard(wok_list, selected_woks, region)
    
    text = f"Region: {region}\n\n" \
           f"Pilih WOK yang diinginkan (bisa lebih dari satu):\n"
    
    if selected_woks:
        text += f"\n\n✅ Terpilih: {', '.join(selected_woks)}"
    
    escaped_text = escape_markdown_v2(text)
    await call.message.edit_text(escaped_text, parse_mode='MarkdownV2', reply_markup=keyboard)


@dp.callback_query(F.data.startswith("continue_wok:"))
async def handle_continue_wok_selection(call: CallbackQuery, bot: Bot, state: FSMContext):
    """Handles continuing with selected WOKs"""
    await call.answer()
    user_id = call.from_user.id
    chat_id = call.message.chat.id
    
    # Get current state data
    data = await state.get_data()
    chosen_region = data.get('chosen_region')
    selected_woks = data.get('selected_woks', [])
    
    if not selected_woks:
        await call.answer("⚠️ Pilih minimal satu WOK terlebih dahulu!", show_alert=True)
        return
    
    # Clear state
    await state.clear()
    
    await call.message.edit_reply_markup()
    
    # Call with selected WOKs
    await agency_reporting(call, bot, user_id, chat_id, chosen_region=chosen_region, chosen_woks=selected_woks, state=state)


