@dp.message(CalcPDDFlow.awaiting_msisdn_input)
async def handle_calcpdd_msisdn_input(message: Message, bot: Bot, state: FSMContext):
    """Handle MSISDN input and check CSI score."""
    user_input = message.text.strip()
    
    # Normalize MSISDN
    normalized_msisdn = None
    if user_input.startswith("+62"):
        normalized_msisdn = "62" + user_input[3:]
    elif user_input.startswith("62"):
        normalized_msisdn = user_input
    elif user_input.startswith("0"):
        normalized_msisdn = "62" + user_input[1:]
    else:
        keyboard = InlineKeyboardMarkup(inline_keyboard=[
            [InlineKeyboardButton(text="❌ Batal", callback_data="cancel_flow:calcpdd")]
        ])
        await message.answer(
            "❌ Format nomor tidak valid.\n\n"
            "Silahkan input dengan format:\n"
            " • `628119999999`\n"
            " • `081199999999`\n"
            " • `+62811999999`",
            reply_markup=keyboard,
            parse_mode="Markdown"
        )
        return
    
    # Validate only digits after normalization
    if not normalized_msisdn.isdigit():
        keyboard = InlineKeyboardMarkup(inline_keyboard=[
            [InlineKeyboardButton(text="❌ Batal", callback_data="cancel_flow:calcpdd")]
        ])
        await message.answer(
            "❌ Input hanya boleh berisi angka.\n\n"
            "Silahkan input dengan format:\n"
            " 628119999999\n"
            " 081199999999\n"
            " +62811999999",
            reply_markup=keyboard,
            parse_mode="Markdown"
        )
        return
    
    # Get latest CSI table dynamically
    csi_table = await get_latest_csi_table()

    # Query demo backend for CSI score
    demo_result = demo_backend.get_csi_score_for_msisdn(normalized_msisdn)
    results = [demo_result]

    # Define the common keyboard with new options
    pdd_options_keyboard = InlineKeyboardMarkup(inline_keyboard=[
        [InlineKeyboardButton(text="1 Bln", callback_data="calcpdd_duration:1"),
         InlineKeyboardButton(text="2 Bln + 0", callback_data="calcpdd_duration:2_0")],
        [InlineKeyboardButton(text="3 Bln + 0", callback_data="calcpdd_duration:3_0"),
         InlineKeyboardButton(text="6 Bln + 1", callback_data="calcpdd_duration:6_1")],
        [InlineKeyboardButton(text="12 Bln + 3", callback_data="calcpdd_duration:12_3"),
         InlineKeyboardButton(text="12 Bln + 5", callback_data="calcpdd_duration:12_5")],
        [InlineKeyboardButton(text="❌ Batal", callback_data="cancel_flow:calcpdd")]
    ])

    try:
        if results:
            msisdn = results[0]["msisdn"]
            csi_score = float(results[0]["default_probability_score"])

            # Store in state
            await state.update_data(calcpdd_msisdn=msisdn, calcpdd_csi_score=csi_score)

            # Check risk level
            if csi_score < CSI_HIGH_RISK_THRESHOLD:

                # Log to CSV
                await log_msisdn_pdd_check(
                    user_id=message.from_user.id,
                    username=await get_username(message.from_user.id),
                    msisdn=msisdn,
                    csi_score=csi_score,
                    risk_level="Low Risk"
                )

                # Low risk -> Still show calculator
                await message.answer(
                    f"🧮 *Kalkulator PDD* \n\n"
                    f" • MSISDN : {msisdn}\n"
                    f" • CSI : {csi_score:.2f} → *Tidak Perlu PDD* ✅\n\n"
                    f"Dibawah ini *hanya* untuk simulasi\n"
                    f"Pilih durasi kontrak:\n",
                    reply_markup=pdd_options_keyboard,
                    parse_mode="Markdown"
                )

            else:

                # Log to CSV
                await log_msisdn_pdd_check(
                    user_id=message.from_user.id,
                    username=await get_username(message.from_user.id),
                    msisdn=msisdn,
                    csi_score=csi_score,
                    risk_level="High Risk"
                )

                # High risk - continue to duration selection
                await message.answer(
                    f"🧮 *Kalkulator PDD* \n\n"
                    f" • MSISDN : {msisdn}\n"
                    f" • CSI : {csi_score:.2f} → *Perlu PDD*❗️\n\n"
                    f"Pilih durasi kontrak:",
                    reply_markup=pdd_options_keyboard,
                    parse_mode="Markdown"
                )
        else:
            # Log to CSV
            await log_msisdn_pdd_check(
                user_id=message.from_user.id,
                username=await get_username(message.from_user.id),
                msisdn=normalized_msisdn,
                csi_score=None,
                risk_level="Not Found"
            )

            # MSISDN not found - continue with warning
            await state.update_data(calcpdd_msisdn=normalized_msisdn, calcpdd_csi_score=None)

            await message.answer(
                f"🧮 *Kalkulator PDD* \n\n"
                f" • MSISDN : {normalized_msisdn}\n"
                f" • CSI : Nomor tidak tercatat di sistem → *Perlu PDD*❗️\n\n"
                f"Pilih durasi kontrak:",
                reply_markup=pdd_options_keyboard,
                parse_mode="Markdown"
            )
    except Exception as e:
        logging.error(f"Error checking MSISDN CSI: {e}", exc_info=True)
        await message.answer(
            "❌ Terjadi kesalahan saat memeriksa nomor. Silahkan coba lagi."
        )
        await state.clear()


