@dp.callback_query(F.data.startswith("calcpdd_select_month:"))
async def handle_calcpdd_month_selection(call: CallbackQuery, bot: Bot, state: FSMContext):
    """Handle month selection and show day picker."""
    await call.answer()
    
    period_str = call.data.split(":")[1]
    year = int(period_str[:4])
    month = int(period_str[4:6])
    
    # Get number of days in selected month
    import calendar
    max_day = calendar.monthrange(year, month)[1]
    
    # Create day selection keyboard
    keyboard_rows = []
    for day in range(1, max_day + 1):
        if (day - 1) % 7 == 0:
            keyboard_rows.append([])
        keyboard_rows[-1].append(
            InlineKeyboardButton(
                text=str(day),
                callback_data=f"calcpdd_select_day:{year}{month:02d}{day:02d}"
            )
        )
    
    # Add back and cancel buttons
    keyboard_rows.append([
        InlineKeyboardButton(text="🔙 Kembali", callback_data="calcpdd_back_to_month"),
        InlineKeyboardButton(text="❌ Batal", callback_data="cancel_flow:calcpdd")
    ])
    
    keyboard = InlineKeyboardMarkup(inline_keyboard=keyboard_rows)
    
    month_name = datetime(year, month, 1).strftime("%B %Y")
    await call.message.edit_text(
        f"📅 *Pilih Tanggal PS*\n\nBulan: {month_name}\n\nPilih tanggal:",
        reply_markup=keyboard,
        parse_mode="Markdown"
    )


