@dp.message(CalcPDDFlow.awaiting_price_input)
async def handle_calcpdd_price_input(message: Message, bot: Bot, state: FSMContext):
    """Handle price input and calculate PDD."""
    try:
        price = int(message.text.replace(".", "").replace(",", "").replace(" ", ""))
    except ValueError:
        await message.answer(f"❌ Input tidak valid. Silahkan masukkan angka ({PDD_MIN_PRICE} - {PDD_MAX_PRICE})")
        return
    
    if price < PDD_MIN_PRICE or price > PDD_MAX_PRICE:
        await message.answer(f"❌ Harga di luar range. Silahkan input harga antara {PDD_MIN_PRICE} - {PDD_MAX_PRICE}")
        return
    
    # Get stored data
    data = await state.get_data()
    duration = data.get("calcpdd_duration")
    duration_key = data.get("calcpdd_duration_key", str(duration))
    ps_date = data.get("calcpdd_ps_date")

    # Calculate PDD (Default: ONT 30k, PSB FREE)
    default_ont = PDD_SEWA_ONT_30
    default_psb = PDD_BIAYA_PSB_NORMAL

    result = calculate_pdd(price, ps_date, duration, ont_price=default_ont, psb_price=default_psb)
    formatted_result = format_pdd_result(result, ps_date, price, duration, ont_price=default_ont, psb_price=default_psb, duration_key=duration_key)

    # Create Adjustment Keyboard
    keyboard = create_pdd_adjustment_keyboard(
        selected_ont=default_ont,
        selected_psb=default_psb,
        harga_paket=price,
        ps_date_str=ps_date.strftime("%Y-%m-%d"),
        duration=duration,
        duration_key=duration_key
    )
    
    await message.answer(formatted_result, reply_markup=keyboard, parse_mode="Markdown")
    
    # Clear state
    await state.clear()


@dp.callback_query(F.data.startswith("pdd_adj:"))
async def pdd_adjustment_handler(callback: CallbackQuery, bot: Bot):
    """Handle PDD adjustments (ONT or PSB changes)."""
    try:
        # Parse callback data: pdd_adj:ONT:PSB:PRICE:DATE:DUR_KEY:TIMESTAMP
        parts = callback.data.split(":")
        ont_price = int(parts[1])
        psb_price = int(parts[2])
        harga_paket = int(parts[3])
        ps_date_str = parts[4]
        duration_key = parts[5]
        calc_duration, _ = CALCPDD_OPTIONS.get(duration_key, (int(duration_key), f"{duration_key} Bulan"))
        duration = calc_duration
        created_ts = int(parts[6])
        
        # Check expiration
        now_ts = int(datetime.now().timestamp())
        if now_ts - created_ts > PDD_KEYBOARD_EXPIRY_HOURS * 3600:
            await callback.answer("⏰ Kalkulasi ini sudah kedaluwarsa. Silahkan gunakan /calcpdd lagi.", show_alert=True)
            return
        
        # Parse date
        ps_date = datetime.strptime(ps_date_str, "%Y-%m-%d")

        # Check if this exact combination is already selected to avoid flicker/api calls
        # (Simplified check: just look for checkmarks in current keyboard if needed, 
        # but recalculating is cheap here)
        
        # Recalculate
        result = calculate_pdd(harga_paket, ps_date, duration, ont_price=ont_price, psb_price=psb_price)
        formatted_result = format_pdd_result(result, ps_date, harga_paket, duration, ont_price=ont_price, psb_price=psb_price, duration_key=duration_key)

        # Update keyboard (preserve original timestamp)
        keyboard = create_pdd_adjustment_keyboard(ont_price, psb_price, harga_paket, ps_date_str, duration, created_ts, duration_key=duration_key)
        
        # Edit message
        if callback.message.text != formatted_result: # Only edit if content changed
             await callback.message.edit_text(
                formatted_result,
                parse_mode="Markdown",
                reply_markup=keyboard
            )
        else:
             # Just update markup if text is same (unlikely due to math, but good practice)
             await callback.message.edit_reply_markup(reply_markup=keyboard)
        
        await callback.answer()
        
    except Exception as e:
        logger.error(f"Error in PDD adjustment: {e}", exc_info=True)
        await callback.answer("❌ Error updating calculation", show_alert=True)


