@dp.callback_query(F.data.startswith("start_summarize:"))
@authorized_only_employer("tsel")
async def summarize_type_handler(callback: CallbackQuery, bot: Bot, state: FSMContext):
    """Route to specific summarize flow (sales, driver, collection, alpro)"""
    await callback.answer()
    
    summary_type = callback.data.split(":")[1]
    user_id = callback.from_user.id
    chat_id = callback.message.chat.id
    
    await log_user_interaction(user_id, await get_username(user_id), f"/summarize_{summary_type}", "CallbackQuery")
    
    await bot.delete_message(chat_id=chat_id, message_id=callback.message.message_id)
    
    try:
        # Get user's date range
        period = await get_user_selected_period(user_id)
        
        if period.startswith("RANGE:"):
            dates = period.replace("RANGE:", "").split("-")
            start_date = datetime.strptime(dates[0], "%Y%m%d")
            end_date = datetime.strptime(dates[1], "%Y%m%d")
            date_display = f"{start_date.strftime('%d/%m/%Y')} - {end_date.strftime('%d/%m/%Y')}"
        else:
            # FIX: Default to YESTERDAY (data lag consideration)
            end_date = datetime.now() - timedelta(days=1)
            start_date = end_date.replace(day=1)
            date_display = f"{start_date.strftime('%d/%m/%Y')} - {end_date.strftime('%d/%m/%Y')}"
        
        # Calculate previous period properly
        previous_month_end = (start_date - timedelta(days=1))
        # Store dates and summary type in state
        await state.update_data(
            summary_type=summary_type,
            summary_start_date=start_date.strftime("%Y-%m-%d"),
            summary_end_date=end_date.strftime("%Y-%m-%d"),
            summary_previous_date=previous_month_end.strftime("%Y-%m-%d"),
            summary_periode=end_date.strftime("%Y%m"),
            summary_previous_periode=previous_month_end.strftime("%Y%m")
        )
        
        # === DYNAMIC KEYBOARD CONSTRUCTION ===
        # Base buttons available for ALL reports
        buttons = [
            [InlineKeyboardButton(text="🌍 Area 3", callback_data="summary_level:A:AREA+3")],
            [InlineKeyboardButton(text="📍 Regional", callback_data="summary_level:R")],
            [InlineKeyboardButton(text="🏢 Branch", callback_data="summary_level:B")],
        ]
        
        # Only add WOK and City for NON-ALPRO reports
        if summary_type != "alpro":
            buttons.append([InlineKeyboardButton(text="📊 WOK", callback_data="summary_level:W")])
            buttons.append([InlineKeyboardButton(text="🏙️ Kota", callback_data="summary_level:K")])

        keyboard = InlineKeyboardMarkup(inline_keyboard=buttons)
        
        # === FIXED LABEL LOGIC ===
        label_map = {
            "sales": "Sales",
            "driver": "Driver",
            "collection": "Collection",
            "alpro": "Alpro (Deployment)"
        }
        # Default to capitalize if not found (e.g. "Collection")
        summary_label = label_map.get(summary_type, summary_type.capitalize())
        
        await bot.send_message(
            chat_id=chat_id,
            text=f"📊 <b>{summary_label} Summary</b>\n\nSilahkan pilih level teritori:\n📅 {date_display}",
            reply_markup=keyboard,
            parse_mode="HTML"
        )
        
    except Exception as e:
        logger.error(f"Error in summarize_type_handler: {e}", exc_info=True)
        await send_error_message(bot, chat_id)


