@dp.callback_query(F.data.startswith("summary_exec:"))
async def execute_summary_generation(callback: CallbackQuery, bot: Bot, state: FSMContext, territory_type: str = None, territory_name: str = None):
    """Execute the summary generation"""
    await callback.answer()
    
    # Parse callback data if not provided
    if territory_type is None:
        parts = callback.data.split(":", 2)
        territory_type = parts[1]
        territory_name = parts[2]
    
    chat_id = callback.message.chat.id

    # Delete the selection message
    await bot.delete_message(chat_id, callback.message.message_id)
    
    # Show waiting message
    waiting_msg = await bot.send_message(
        chat_id,
        "⏳ Mohon tunggu (10-30 detik) sedang membuat summary..."
    )
    
    try:
        # Get data from state
        data = await state.get_data()
        summary_type = data.get('summary_type', 'sales')
        end_date = data.get('summary_end_date')
        previous_date = data.get('summary_previous_date')
        start_date = data.get('summary_start_date')
        periode = data.get('summary_periode')
        previous_periode = data.get('summary_previous_periode')

        logger.info(f"Generating {summary_type} summary for {territory_type}:{territory_name}")
        logger.info(f"Date range: {start_date} to {end_date}")

        # Use demo backend for summary data
        result = demo_backend.summary_payload(summary_type, territory_type, territory_name)

        dashboard_data = {'current': result.get('current', {}), 'previous': result.get('previous', {})}

        # Generate summary with Gemini or use fallback
        logger.info(f"Generating {summary_type} summary with Gemini")

        try:
            if not os.getenv("GEMINI_API_KEY"):
                summary_text = demo_backend.fallback_summary_text(
                    summary_type=summary_type,
                    territory_name=territory_name,
                    start_date=start_date,
                    end_date=end_date,
                    payload=dashboard_data,
                )
                raise StopIteration

            genai.configure(api_key=os.getenv("GEMINI_API_KEY"))
            model = genai.GenerativeModel(GEMINI_API_MODEL)
            
            generation_config = genai.GenerationConfig(
                temperature=0.9,
                max_output_tokens=8192
            )
            
            safety_settings = [
                {"category": "HARM_CATEGORY_HARASSMENT", "threshold": "BLOCK_MEDIUM_AND_ABOVE"},
                {"category": "HARM_CATEGORY_HATE_SPEECH", "threshold": "BLOCK_MEDIUM_AND_ABOVE"},
                {"category": "HARM_CATEGORY_SEXUALLY_EXPLICIT", "threshold": "BLOCK_MEDIUM_AND_ABOVE"},
                {"category": "HARM_CATEGORY_DANGEROUS_CONTENT", "threshold": "BLOCK_MEDIUM_AND_ABOVE"}
            ]
            
            # Choose prompt based on summary type
            if summary_type == "sales":

                prompt = f"""You are EXPERT DATA ANALYST of TELKOMSEL/INDIHOME; Analyze this INDIHOME SALES data and create an executive summary in Bahasa Indonesia.

            Territory Context:
            - {territory_name} (Type: {territory_type})
            - Period: {start_date} to {end_date}
            - Data comparison with: {previous_date}
            - HIDE the "Data Comparison with" and territory "Type" information to user

            Format Guidelines:
            - Output RAW TEXT ONLY - no markdown formatting (**bold**, *italic*, etc.), targets 200-400 words
            - Use bullet points (•), numbering (1, 2, 3), and indentation
            - Add professional emojis for section headers
            - Show actual numbers and percentages

            Number Formatting:
            - Percentages: Use comma for decimal (e.g., 12,5% NOT 125% or 12.5%)
            - Large numbers: Use dot as thousand separator (e.g., 1.234.567 NOT 1234567)
            - Always format numbers properly (e.g: 1.234.567 for millions, 12,5% for percentages)

            **MAIN DATA SOURCE (Dashboard Data):**
            {json.dumps(dashboard_data, indent=1)}

            Domain Knowledge Reference:
            - IO = Input Order (pesanan pemasangan)
            - RE = Registered Order (IO yang valid)
            - PS = Put in Service (berhasil terpasang)
            - SF = Sales Force (tenaga penjual)
            - MoM = Month over Month comparison
            - DoD = Day over Day (daily) comparison
            - YoY = Year on Year comparison
            - FF = Fulfillment
            - Conversion rate = (PS / IO or RE) * 100%
            - SF Tiers (lowest to highest): Black → Bronze → Silver → Gold → Platinum → Diamond
            - Territory hierarchy: Area → Region → Branch → WOK → City

            Required Sections:
            1. RINGKASAN - Executive Summary with explicit numbers (IO, RE, PS, conversion rates)
            2. TREND - Trend analysis with comparisons (MoM, YoY, DoD)

            Optional Sections (add what's interesting):
            - Top performers (channels, products, speeds)
            - Sales Force insights
            - Anomalies or opportunities

            Things To Avoid:
            - Information not in source data
            - Explaining abbreviations not in Domain Knowledge
            - Translating: "Channel" and "Sales Force" to Indonesian
            - Giving Recommendations
            """

            elif summary_type == "driver":
                prompt = f"""You are EXPERT DATA ANALYST of TELKOMSEL/INDIHOME; Analyze this INDIHOME CUSTOMER data and create an executive summary in Indonesian.

            Territory Context:
            - {territory_name} (Type: {territory_type})
            - Period: {start_date} to {end_date}
            - Comparison Period: {previous_periode}
            - HIDE the "Comparison Period" and territory "Type" information to user
            - IMPORTANT: Driver data typically has 1-2 month lag. Current date is {datetime.now().strftime('%Y-%m-%d')}, See latest available data from `Dashboard Data` below.

            Format Guidelines:
            - Output RAW TEXT ONLY - no markdown formatting (**bold**, *italic*, etc.), targets 150-350 words
            - Use bullet points (•), numbering (1, 2, 3), and indentation
            - Add professional emojis for section headers
            - Show actual numbers and percentages

            Number Formatting:
            - Percentages: Use comma for decimal (e.g., 0,73% NOT 073% or 0.73%)
            - Large numbers: Use dot as thousand separator (e.g., 39.721 NOT 39721)
            - Always format numbers properly (e.g: 1.234.567 for millions, 12,5% for percentages)

            **MAIN DATA SOURCE (Dashboard Data):**
            {json.dumps(dashboard_data, indent=1)}

            Domain Knowledge Reference:
            - Active LIS = Active Line-in-Service (customers with billing and internet usage)
            - HVC Tiers: Regular (LoS <6mo, ARPU <100k), Gold (LoS >6mo, ARPU 100-499K), Platinum (LoS >6mo, ARPU 500-999K), Diamond (LoS >6mo, ARPU >1000K)
            - LoS Grouping: NEW SALES (<1mo), SALES (1-3mo), NEW SUBS (3-6mo), EXISTING SUBS (6-12mo), LOYAL SUBS (>12mo)
            - Speed Tiers: kolom2 (≤10 Mbps), kolom3 (20-40), kolom4 (50), kolom5 (50-100), kolom6 (>100)
            - MoM calculation: (_now - _pre) / _pre * 100%
            - CT0 = silent churn, CAPS = official churn request
            - Territory hierarchy: Area → Region → Branch → WOK → City

            Required Sections; Focus analysis on most recent non-zero data, not current period zeros:
            1. RINGKASAN - Executive Summary with explicit numbers (Growth, CT0, CAPS, Active LIS, etc.)
            2. TREND - Trend analysis with historical patterns and comparison (MoM, YoY)

            Optional Sections (add what's interesting):
            - Speed preferences and changes
            - HVC tier migration
            - Churn analysis
            - LoS distribution
            - Anomalies or opportunities

            Things To Avoid:
            - Information not in source data
            - Explaining abbreviations not in Domain Knowledge
            - Mentioning "data parsial" repeatedly for current period zeros
            - Translating "Customer Performance" to Indonesian
            - Giving Recommendations
            """

            elif summary_type == "collection":
                prompt = f"""You are EXPERT DATA ANALYST of TELKOMSEL/INDIHOME; Analyze this INDIHOME COLLECTION & HEALTHY SALES data and create an executive summary in Bahasa Indonesia.

            Territory Context:
            - {territory_name} (Type: {territory_type})
            - Period: {start_date} to {end_date}
            - Comparison Period: {previous_periode}
            - HIDE the "Comparison Period" and territory "Type" information to user
            - IMPORTANT: Collection data typically has 1-day lag. Current date is {datetime.now().strftime('%Y-%m-%d')}, See latest available data from `Dashboard Data` below.

            Format Guidelines:
            - Output RAW TEXT ONLY - no markdown formatting (**bold**, *italic*, etc.), targets 250-450 words
            - Format Currency numbers in "Rp." prefix with proper decimal formatting (e.g: Rp. 423.251.000)
            - Use bullet points (•), numbering, and indentation
            - Add professional emojis for section headers
            - Show actual numbers and percentages

            Number Formatting:
            - Percentages: Use comma for decimal (e.g., 15,8% NOT 158% or 15.8%)
            - Large numbers: Use dot as thousand separator (e.g., 423.251.000)
            - Always format numbers in Indonesian style (comma=decimal, dot=thousands)

            **MAIN DATA SOURCE (Dashboard Data):**
            {json.dumps(dashboard_data, indent=1)}

            Domain Knowledge Reference:
            - LoS: Length-of-stay (Lama berlangganan)
            - HVC Tiers: Regular (LoS <6mo, ARPU <100k), Gold (LoS >6mo, ARPU 100-499K), Platinum (LoS >6mo, ARPU 500-999K), Diamond (LoS >6mo, ARPU >1000K)
            - 10 Segments detail:
               00. Non HSI -> Non-Internet user (Safe to Ignore)
               01. Early Tenure Users -> User who has just becoming customer (<6 Month LoS user)
               02. Network Stability Issue -> System detected network instability
               03. Billing & Service Complaints -> User who issues tickets due to service or billing complaints
               04. Dormant Users -> Inactive user (No Internet usage)
               05. Late Payers -> User who have habits to pay late (pay at 21th-5th day next month)
               06. Declined Usage -> User with declining Internet usage
               07. Competitors Explorers -> User who actively browse competitor app/websites.
               08. Stable Usage -> Healthy user who have stable Internet usage
               09. Increased Usage -> Healthy user who have Increasing Internet usage
               10. Non-Optimal Experience -> User who doesn't have dominant profile, nor Healthy (Stable/Incresing Usage).
            - Territory hierarchy: Area → Region → Branch → WOK (Wilayah Operasional Kerja) → City

            - LoS Segment:
               • `linechart_los_segment1`: NEW CUSTOMERS (Age < 3 Months). High churn risk.
               • `linechart_los_segment2`: TRANSITIONING (Age 3-12 Months).
               • `linechart_los_segment3`: LOYAL CUSTOMERS (Age > 12 Months). Stable.

            - Healthy Sales Matrix (Keys: matrix_flag_X):
               • This is COHORT DATA showing customer "Survival Rate" over time (M0, M1, M2...).
               • Flag 1: All Channel | Flag 2: AGENCY | Flag 3: B2B2C & OTHERS
               • Flag 4: GRAPARI     | Flag 5: SOBI AFFILIATE | Flag 6: WEB&APP
               • Insight Logic: High % = Good. Steep drop from previous month = Bad/Churn.
            
            - 10 Segment Summary (Keys: ten_seg_flag_X):
               • Flag 1: All Customer
               • Flag 2: Regular (Non HVC) - Lowest Tier
               • Flag 3,4,5: Gold, Platinum, Diamond HVC (High Value Customers)

            Required Sections; Focus analysis on most recent non-zero data, not current period zeros:
            1. 📊 RINGKASAN EXECUTIVE
               - Overall Collection Achievement (from pie/header).
               - Total Collection Amount (Nominal).

            2. 🧬 QUALITY OF SALES (COHORT ANALYSIS)
               - Analyze `matrix_flag_1` (All) vs Specific Channels (`matrix_flag_2` to `6`).
               - **Critical Drop-off:** At which specific month (M1, M2, or M3) does the biggest % drop happen?
               - **Channel Comparison:** Explicitly name the **Healthiest Channel** (Highest retention) vs **Riskiest Channel** (Lowest retention/Fastest drop).
               - *Example insight:* "Agency channel shows highest risk, dropping to 60% retention by Month 2, whereas Grapari remains strong at 90%."

            3. ⚠️ CUSTOMER 10 SEGMENT RISK PROFILE
               - Which segments (out of the 10 segments) has worse collection rate, and at which risk-profile?
               - How much paid and unpaid actual number and ratios?

            4. 📈 TREND & TERRITORY
               - MoM Growth.
               - Mention best/worst performing sub-territories (Region/Branch/City) if data permits.

            Things To Avoid:
            - General statements like "sales are good." Be specific: "Retention drops 20% in Month 2."
            - Explaining technical terms (Flag 1, Flag 2) - use Business Names.
            - Translating "Collection" to Indonesian.
            """

            elif summary_type == "alpro":
                prompt = f"""You are EXPERT DATA ANALYST of TELKOMSEL/INDIHOME; Analyze this ALPRO (Alat Produksi / Network Deployment) data and create an executive summary in Bahasa Indonesia.

            Territory Context:
            - {territory_name} (Type: {territory_type})
            - Period: {start_date} to {end_date}
            - Comparison Period: {previous_periode}
            - HIDE the "Comparison Period" and territory "Type" information to user

            Format Guidelines:
            - Output RAW TEXT ONLY - no markdown formatting (**bold**, *italic*, etc.), targets 200-400 words
            - Use bullet points (•), numbering, and indentation
            - Add professional emojis for section headers
            - Show actual numbers and percentages

            Number Formatting:
            - Percentages: Use comma for decimal (e.g., 0,73% NOT 073% or 0.73%)
            - Large numbers: Use dot as thousand separator (e.g., 39.721 NOT 39721)
            - Always format numbers properly (e.g: 1.234.567 for millions, 12,5% for percentages)

            **MAIN DATA SOURCE (Dashboard Data):**
            {json.dumps(dashboard_data, indent=1)}

            Domain Knowledge Reference:
            - ALPRO = Alat Produksi (Network Infrastructure/ODP).
            - GoLive = Process of activating new network coverage (ODP).
            - Microdemand = Potential customer demand spots.
            - ACH = Achievement vs Target.
            
            - Deployment Types (Crucial):
              • **Greenfield**: New network deployment in empty areas (Expansion).
              • **Brownfield**: Modernization or capacity addition in existing areas.
              • **PT2**: Provisioning type 2 -> A smaller deployment type that extending the optical network from existing ODC to New ODP (mostly to brownfield)
              • **PT3**: Provisioning type 3 -> Bigger deployment type that deploys bigger-capacity cable from OLT to ODC to ODP using feeder+distribution cable (mostly to greenfield)
            
            - Data Keys:
              • `golive_total`: Overall GoLive performance.
              • `golive_greenfield` / `golive_brownfield`: Specific breakdown.
              • `summary_pt2` / `summary_pt3`: Project Type summaries.

            Required Sections:
            1. 🏗️ RINGKASAN DEPLOYMENT (GoLive)
               - Overall Achievement (ACH) & Total Port Deployment (`golive_total`).
               - **Strategy Check:** Compare **Greenfield** vs **Brownfield**. Which one is dominating the current deployment? (e.g. "Focus bulan ini adalah modernisasi Brownfield sebesar 70%...").

            2. 📍 MICRODEMAND & POTENTIAL
               - Review `microdemand` data. Where are the high potential spots? 

            3. 🎯 ALPRO (ODP) OCCUPANCY REPORT
               - Highlight Occupancy status with Explicit numbers (e.g: How many BLACK/GREEN/YELLOW/ORANGE/RED ODP on that period within that location)

            4. 🗺️ TERRITORY & PROJECT PERFORMANCE
               - Analyze `golive_total` to find best/worst performing sub-territories.
               - Highlight any significant stats from `summary_pt2` or `summary_pt3` if distinct from the main trend.

            Things To Avoid:
            - Information not in source data.
            - Giving Recommendations.
            """
            
            else:
                # Fallback for unknown types
                await bot.edit_message_text(
                    f"❌ Unknown summary type: {summary_type}",
                    chat_id=chat_id,
                    message_id=waiting_msg.message_id
                )
                return
            
            logger.debug("Calling Gemini API...")
            
            loop = asyncio.get_event_loop()
            response = await asyncio.wait_for(
                loop.run_in_executor(
                    None,
                    lambda: model.generate_content(
                        prompt,
                        generation_config=generation_config,
                        safety_settings=safety_settings
                    )
                ),
                timeout=60.0
            )
            
            summary_text = response.text
            logger.debug("Gemini response received successfully")

        except StopIteration:
            logger.info("Using demo/local fallback executive summary text")
        except asyncio.TimeoutError:
            logger.error("Gemini API timeout after 60 seconds")
            await bot.edit_message_text(
                "❌ AI analysis timed out after 60 seconds. Please try again.",
                chat_id=chat_id,
                message_id=waiting_msg.message_id
            )
            return
        except Exception as gemini_error:
            logger.error(f"Gemini API error: {gemini_error}", exc_info=True)
            await bot.edit_message_text(
                f"❌ Error calling AI service: {str(gemini_error)}",
                chat_id=chat_id,
                message_id=waiting_msg.message_id
            )
            return
        
        # --- [FIXED SENDING LOGIC] ---
        territory_info = {
            'type': territory_type,
            'name': territory_name,
            'start_date': start_date,
            'end_date': end_date
        }
        
        # Generate the standard formatted message first
        formatted_summary = format_executive_summary(summary_text, territory_info, summary_type)
        
        # CHECK LENGTH
        if len(formatted_summary) <= 4096:
            # Case 1: Message fits in one bubble (Standard)
            await bot.edit_message_text(
                text=formatted_summary,
                chat_id=chat_id,
                message_id=waiting_msg.message_id,
                parse_mode="HTML"
            )
        else:
            # Case 2: Message is too long -> Split SAFELY
            await bot.delete_message(chat_id, waiting_msg.message_id)
            
            # 1. Send Header Manually
            header = f"<b>📊 {summary_type.capitalize()} Summary</b>\n{territory_info['name']}\n📅 {start_date} - {end_date}"
            await bot.send_message(chat_id, header, parse_mode="HTML")
            
            # 2. Split the RAW TEXT (not the HTML) into safe chunks
            import html
            raw_escaped_text = html.escape(summary_text)
            
            # Use 3800 chars to leave room for <pre> tags
            chunk_size = 3800 
            chunks = [raw_escaped_text[i:i+chunk_size] for i in range(0, len(raw_escaped_text), chunk_size)]
            
            # 3. Send each chunk wrapped in its OWN <pre> tag
            for i, chunk in enumerate(chunks):
                msg_part = f"<pre>{chunk}</pre>"
                # Add page number if multiple parts
                if len(chunks) > 1:
                    msg_part += f"\n<i>(Part {i+1}/{len(chunks)})</i>"
                
                await bot.send_message(chat_id, msg_part, parse_mode="HTML")
                
            # 4. Send Footer Manually
            footer = f"🤖 Powered by Gemini AI • {datetime.now().strftime('%H:%M WIB')}"
            await bot.send_message(chat_id, footer, parse_mode="HTML")
        
        logger.info(f"{summary_type.capitalize()} summary generated successfully")
        
    except Exception as e:
        logger.error(f"Error generating summary: {e}", exc_info=True)
        try:
            await bot.edit_message_text(f"❌ Error: {str(e)}", chat_id, waiting_msg.message_id)
        except:
            await bot.send_message(chat_id, f"❌ Error: {str(e)}")


