@measure_performance("order_tracking")
@dp.message(Command("id"))
@authorized_only_employer("tsel","sf","admin","ta","tif","ctb") 
async def id_command_handler(message: Message, bot: Bot):
    """Handles the /id command with arguments."""
    user_id = message.from_user.id
    chat_id = message.chat.id
    command_parts = message.text.split(' ', 1)
    

    if len(command_parts) < 2:
        await message.answer(
            "⚠️ Penggunaan:\n"
            "  1. `/id AO...` (New Sales)\n"
            "  2. `/id MO..` (Modification)\n"
            "  3. `/id DM..` (UNSC)\n"
            "  4. `/id WO...` (WO Number)\n"
            "  5. `/id 152...` (No Inet)",
            parse_mode="Markdown"
        )
        return

    input_value = command_parts[1].strip()
    order_id, wonum, bb_id = None, None, None

    if input_value.upper().startswith(("AO", "MO", "DM")): 
        order_id = input_value
    elif input_value.upper().startswith("WO"): 
        wonum = input_value
    elif input_value.isdigit(): 
        bb_id = input_value
    else:
        await message.reply("Format ID tidak dikenal.")
        return
    
    if (order_id and ORDERID_MAINTENANCE_MODE) or \
       (wonum and WOID_MAINTENANCE_MODE) or \
       (bb_id and NOINET_MAINTENANCE_MODE):
        await message.reply("Mohon maaf, fitur ini sedang dalam maintenance 🛠")
        return

    await log_user_interaction(user_id, await get_username(user_id), f"/id {input_value}", "Command")
    
    # Call order_history with the correct parameter order
    await order_history(
        message,        
        bot,
        user_id,
        chat_id,
        order_id_value=order_id,
        wonum_value=wonum,
        bb_id_value=bb_id
    )

