    # Check for maintenance mode (you can add these flags if needed)
    # if TICKET_MAINTENANCE_MODE:
    #     await message.reply("Mohon maaf, fitur ini sedang dalam maintenance 🛠")
    #     return

    await log_user_interaction(user_id, await get_username(user_id), f"/ticket {input_value}", "Command")
    
    # Call ticket_history with the correct parameter order
    await ticket_history(
        message,        
        bot,
        user_id,
        chat_id,
        bb_id_value=bb_id,
        ticket_id_value=ticket_id
    )


