# --- Cek ODP history with direct input support ---
@measure_performance("cek_odp_history_entry")
@dp.message(Command("cekodp"))
@authorized_only_employer("tsel","sf","admin","ta","tif","ctb")
async def cekodp_command_handler(message: Message, state: FSMContext, bot: Bot):
    """Entry point for /cekodp command with optional direct arguments."""
    user_id = message.from_user.id
    await log_user_interaction(user_id, await get_username(user_id), "/cekodp", "Command")
    
    # Clear any existing state to ensure command takes priority
    current_state = await state.get_state()
    if current_state:
        logger.info(f"[CEKODP COMMAND] Clearing existing state: {current_state} for user {user_id}")
        await state.clear()
    
    logger.info(f"[CEKODP COMMAND] Message from user {user_id}: '{message.text}'")
    
    # Check if this is a command with direct arguments
    command_parts = message.text.split(' ', 1)
    logger.info(f"[CEKODP COMMAND] Command parts count: {len(command_parts)}")
    
    if len(command_parts) > 1:
        # Direct ODP input provided: /cekodp ODP-ABL-FB/07
        odp_input = command_parts[1].strip()
        logger.info(f"[CEKODP COMMAND] ✓ Direct input detected! Processing: '{odp_input}'")
        await handle_cekodp_direct_input(message, state, odp_input)
        return
    
    # No direct input, proceed with interactive mode
    logger.info(f"[CEKODP COMMAND] No direct input. Entering interactive mode for user {user_id}")
    await cek_odp_report(message, state, bot)


