@measure_performance("cek_odp_direct_input")
@authorized_only_employer("tsel","sf","admin","ta","tif","ctb")
async def handle_cekodp_direct_input(message: Message, state: FSMContext, odp_input: str):
    """Handles direct ODP input like /cekodp ODP-ABL-FB/07,ODP-ABL-FB/08"""
    user_id = message.from_user.id
    bot = message.bot
    
    logger.info(f"[DIRECT INPUT] User {user_id} submitted direct ODP lookup: '{odp_input}'")
    
    # Normalize input: remove extra whitespace
    odp_input = re.sub(r'\s+', ' ', odp_input).strip().upper()
    logger.info(f"[DIRECT INPUT] Normalized input: '{odp_input}'")
    
    # Split by comma and clean
    odp_names = [name.strip() for name in odp_input.split(",")]
    logger.info(f"[DIRECT INPUT] Parsed ODPs: {odp_names} (count: {len(odp_names)})")
    
    # Validate max 10 ODPs
    if len(odp_names) > 10:
        await message.answer(
            f"❌ Terlalu banyak ODP yang diminta. Maksimal 10 ODP, Anda mengirim {len(odp_names)} ODP. Silahkan coba lagi."
        )
        logger.warning(f"[DIRECT INPUT] User {user_id} requested {len(odp_names)} ODPs, exceeds limit of 10")
        await state.clear()
        return
    
    # Check that each ODP name starts with "ODP-"
    VALID_PATTERN = re.compile(r"^[a-zA-Z][a-zA-Z0-9/-]*$")
    invalid_odp_names = [name for name in odp_names if not VALID_PATTERN.match(name) and '-' in name]
    if invalid_odp_names:
        await message.answer(
            f"❌ Nama ODP tidak valid: {', '.join(invalid_odp_names)}. Silahkan ketik /cekodp untuk mencoba lagi."
        )
        logger.error(f"[DIRECT INPUT] User {user_id} sent invalid ODP names: {invalid_odp_names}")
        await state.clear()
        return

    # Notify the user that the search is in progress
    await message.answer(f"🔄 Mohon tunggu, sedang mencari data untuk `{', '.join(odp_names)}`...", parse_mode='markdown')
    logger.info(f"[DIRECT INPUT] Processing {len(odp_names)} ODPs for user {user_id}")

    # Perform the ODP history search
    try:
        results, not_found_odps = await send_odp_history_search(message.chat.id, odp_names)
        logger.info(f"[DIRECT INPUT] Search completed - Results: {len(results)}, Not found: {len(not_found_odps)}")
    except Exception as e:
        logger.error(f"[DIRECT INPUT] Error during ODP search for user {user_id}: {e}", exc_info=True)
        await message.answer("❌ Terjadi kesalahan saat mencari data ODP. Silahkan coba lagi nanti.")
        await state.clear()
        return

    # Check if results are valid
    if not results:
        await message.answer("❌ Data ODP tidak ditemukan. Silahkan ketik /cekodp untuk mencoba lagi.")
        logger.error(f"[DIRECT INPUT] No valid results found for ODP input by user {user_id}: {odp_names}.")
        await state.clear()
        return

    # Notify the user if any ODPs were not found
    if not_found_odps:
        await message.answer(f"❌ Data tidak ditemukan untuk ODP: {', '.join(not_found_odps)}.")
        logger.info(f"[DIRECT INPUT] Notified user {user_id} about not found ODPs: {not_found_odps}")

    # Group results by ODP name to keep same ODP data together
    odp_groups = {}
    for result in results:
        odp_name = result.get('odp_name', 'unknown')
        if odp_name not in odp_groups:
            odp_groups[odp_name] = []
        odp_groups[odp_name].append(result)
    
    logger.info(f"[DIRECT INPUT] Grouped {len(results)} results into {len(odp_groups)} ODP groups")

    # Send one message per ODP (with all its date records grouped together)
    try:
        logger.info(f"[DIRECT INPUT] Sending {len(odp_groups)} messages (one per ODP) to user {user_id}")
        for idx, (odp_name, odp_results) in enumerate(odp_groups.items(), 1):
            formatted_message = await format_odp_history(odp_results)
            
            await send_long_message(
                bot,
                chat_id=user_id,
                messages_iterable=[formatted_message],
                parse_mode='MarkdownV2'
            )
            logger.info(f"[DIRECT INPUT] Sent message {idx}/{len(odp_groups)} for ODP '{odp_name}' to user {user_id}")
            
            # Small delay between messages to prevent rate limiting
            await asyncio.sleep(0.3)
            
        logger.info(f"[DIRECT INPUT] Successfully sent all {len(odp_groups)} ODP messages to user {user_id}")
    except Exception as e:
        logger.error(f"[DIRECT INPUT] Failed to send formatted ODP results to user {user_id}: {e}", exc_info=True)
        await message.answer("❌ Gagal mengirim hasil pencarian. Silahkan coba lagi nanti.")
    finally:
        await state.clear()


@measure_performance("cek_odp_history_main")
@dp.message(FeaturesFlow.awaiting_odp_name, F.text)
async def handle_odp_input(message: Message, state: FSMContext, bot: Bot):
    """Handles the text input when in the 'awaiting_odp_name' state (interactive mode)."""
    user_id = message.from_user.id
    
    # Safety guard: prevent processing commands in this handler
    if message.text.startswith('/'):
        logger.warning(f"[HANDLE_ODP_INPUT] Command detected in interactive state for user {user_id}: '{message.text}'. Ignoring and clearing state.")
        await state.clear()
        return
    
    logger.info(f"[HANDLE_ODP_INPUT] User {user_id} submitted ODP input: '{message.text}'")
    
    odp_input = re.sub(r'\s+', ' ', message.text).strip().upper()
    logger.info(f"[HANDLE_ODP_INPUT] Normalized input: '{odp_input}'")

    # Split the input into multiple ODP names
    odp_names = [name.strip() for name in odp_input.split(",")]
    logger.info(f"[HANDLE_ODP_INPUT] Parsed {len(odp_names)} ODPs: {odp_names}")

    # Validate max 10 ODPs
    if len(odp_names) > 10:
        await message.answer(
            f"❌ Terlalu banyak ODP yang diminta. Maksimal 10 ODP, Anda mengirim {len(odp_names)} ODP. Silahkan ketik /cekodp untuk mencoba lagi."
        )
        logger.warning(f"[HANDLE_ODP_INPUT] User {user_id} requested {len(odp_names)} ODPs, exceeds limit of 10")
        await state.clear()
        return

    # Check that each ODP name starts with "ODP-"
    VALID_PATTERN = re.compile(r"^[a-zA-Z][a-zA-Z0-9/-]*$")
    invalid_odp_names = [name for name in odp_names if not VALID_PATTERN.match(name) and '-' in name]
    if invalid_odp_names:
        await message.answer(
            f"❌ Nama ODP tidak valid: {', '.join(invalid_odp_names)}. Silahkan ketik /cekodp untuk mencoba lagi."
        )
        logger.error(f"[HANDLE_ODP_INPUT] User {user_id} sent invalid ODP names: {invalid_odp_names}")
        await state.clear()
        return

    # Notify the user that the search is in progress
    await message.answer(f"🔄 Mohon tunggu, sedang mencari data untuk `{', '.join(odp_names)}`...", parse_mode='markdown')
    logger.info(f"[HANDLE_ODP_INPUT] Processing {len(odp_names)} ODPs for user {user_id}")

    # Perform the ODP history search
    try:
        results, not_found_odps = await send_odp_history_search(message.chat.id, odp_names)
        logger.info(f"[HANDLE_ODP_INPUT] Search completed - Results: {len(results)}, Not found: {len(not_found_odps)}")
    except Exception as e:
        logger.error(f"[HANDLE_ODP_INPUT] Error during ODP search for user {user_id}: {e}", exc_info=True)
        await message.answer("❌ Terjadi kesalahan saat mencari data ODP. Silahkan coba lagi nanti.")
        await state.clear()
        return

    # Check if results are valid
    if not results:
        await message.answer("❌ Data ODP tidak ditemukan. Silahkan ketik /cekodp untuk mencoba lagi.")
        logger.error(f"[HANDLE_ODP_INPUT] No valid results found for ODP input by user {user_id}: {odp_names}.")
        await state.clear()
        return

    # Notify the user if any ODPs were not found
    if not_found_odps:
        await message.answer(f"❌ Data tidak ditemukan untuk ODP: {', '.join(not_found_odps)}.")
        logger.info(f"[HANDLE_ODP_INPUT] Notified user {user_id} about not found ODPs: {not_found_odps}")

    # Group results by ODP name to keep same ODP data together
    odp_groups = {}
    for result in results:
        odp_name = result.get('odp_name', 'unknown')
        if odp_name not in odp_groups:
            odp_groups[odp_name] = []
        odp_groups[odp_name].append(result)
    
    logger.info(f"[HANDLE_ODP_INPUT] Grouped {len(results)} results into {len(odp_groups)} ODP groups")

    # Send one message per ODP (with all its date records grouped together)
    try:
        logger.info(f"[HANDLE_ODP_INPUT] Sending {len(odp_groups)} messages (one per ODP) to user {user_id}")
        for idx, (odp_name, odp_results) in enumerate(odp_groups.items(), 1):
            formatted_message = await format_odp_history(odp_results)

            await send_long_message(
                bot,
                chat_id=user_id,
                messages_iterable=[formatted_message],
                parse_mode='MarkdownV2'
            )
            logger.info(f"[HANDLE_ODP_INPUT] Sent message {idx}/{len(odp_groups)} for ODP '{odp_name}' to user {user_id}")
            
            # Small delay between messages to prevent rate limiting
            await asyncio.sleep(0.3)
            
        logger.info(f"[HANDLE_ODP_INPUT] Successfully sent all {len(odp_groups)} ODP messages to user {user_id}")
    except Exception as e:
        logger.error(f"[HANDLE_ODP_INPUT] Failed to send formatted ODP results to user {user_id}: {e}", exc_info=True)
        await message.answer("❌ Gagal mengirim hasil pencarian. Silahkan coba lagi nanti.")
    finally:
        await state.clear()


