@dp.message(Command("odpterdekat"))
@authorized_only_employer("tsel","sf","admin","ta","tif","ctb")
async def odpterdekat_command_handler(message: Message, bot: Bot, state: FSMContext):
    """Handles the /odpterdekat command, supporting direct coordinate arguments."""
    await log_user_interaction(message.from_user.id, await get_username(message.from_user.id), "/odpterdekat", "Command")
    
    if ODPTERDEKAT_MAINTENANCE_MODE:
        await message.answer("🛠 Mohon maaf, fitur Cari ODP terdekat sedang dalam maintenance.")
        return
    
    command_parts = message.text.split(' ', 1)
    if len(command_parts) > 1:
        # Direct coordinate input: /odpterdekat -7.000,110.000
        await odpterdekat_direct_input_handler(message, bot, state, command_parts[1].strip())
    else:
        # Interactive mode: ask for location
        await odpterdekat_interactive_setup(message, bot, state)


