@measure_performance("odp_terdekat_direct_input")
@authorized_only_employer("tsel","sf","admin","ta","tif","ctb")
async def odpterdekat_direct_input_handler(message: Message, bot: Bot, state: FSMContext, location_input: str):
    """Enhanced direct ODP lookup with selective visual guidance for Google Maps URLs only"""
    user_id = message.from_user.id
    chat_id = message.chat.id
    progress_manager = None
    
    # Check registration first
    if not await is_user_registered(user_id):
        await state.set_state(UserRegistration.awaiting_employee_status)
        
        # Build keyboard for aiogram 3.x
        keyboard_buttons = []
        row = []
        for i, status in enumerate(["TSEL", "TIF", "TA", "CTB", "SF", "Admin"]):
            row.append(InlineKeyboardButton(text=status, callback_data=status))
            if (i + 1) % 2 == 0:  # 2 columns
                keyboard_buttons.append(row)
                row = []
        if row:  # Add remaining buttons
            keyboard_buttons.append(row)
        
        # Add cancel button
        keyboard_buttons.append([InlineKeyboardButton(text="❌ Batal", callback_data="cancel_registration")])
        
        keyboard = InlineKeyboardMarkup(inline_keyboard=keyboard_buttons)
        
        await bot.send_message(
            chat_id, 
            "📥 Anda belum terdaftar. Silahkan pilih status karyawan Anda untuk memulai pendaftaran:",
            reply_markup=keyboard
        )
        logger.debug(f"User {user_id} not registered. Registration started via direct lookup.")
        return
    
    try:
        # Parse coordinates using centralized parser
        user_latitude, user_longitude = CoordinateParser.parse(location_input)
        
        if user_latitude is None or user_longitude is None:
            # Check if this is an incomplete Google Maps URL
            if is_incomplete_google_maps_url(location_input):
                # Send error message for Google Maps URL without coordinates
                await message.answer("⚠️ Link Google Maps yang Anda berikan tidak mengandung koordinat yang dapat dibaca. Silahkan gunakan link Google Maps dengan koordinat atau format koordinat (contoh: `-7.000,110.000`).", parse_mode="Markdown")
                
                # Send visual guidance image for Google Maps URLs
                try:
                    sample_image_path = "/home/rajawalia3/radityayud/python_project/bot_telegram/templates/sample_google_map_url.png"
                    if os.path.exists(sample_image_path):
                        image_file = FSInputFile(sample_image_path, filename="sample_google_map_url.png")
                        await bot.send_photo(
                            chat_id, 
                            image_file, 
                            caption="📍 Contoh cara mendapatkan link Google Maps dengan koordinat yang benar:\n\n" +
                                   "✅ Gunakan link seperti: https://www.google.com/maps/@-7.406,112.773,15z\n" +
                                   "❌ Hindari link pendek seperti: https://maps.app.goo.gl/...\n\n" +
                                   "Atau gunakan koordinat langsung, misal: `-7.000,112.0000`", parse_mode="Markdown"
                        )
                        logger.info(f"Visual guidance image sent to user {user_id} for incomplete Google Maps URL")
                    else:
                        logger.warning(f"Sample image not found at: {sample_image_path}")
                except Exception as e:
                    logger.error(f"Error sending visual guidance image to user {user_id}: {e}")
            else:
                # Regular parsing error (not Google Maps URL) - no image
                await message.answer("⚠️ Format tidak valid. Silahkan gunakan link Google Maps atau koordinat desimal (contoh: `-7.000,110.000`).", parse_mode="Markdown")
                logger.info(f"Regular parsing error for user {user_id}, no image sent")
            
            await state.clear()
            return
        
        # Validate coordinates
        if not CoordinateParser.validate_coordinates(user_latitude, user_longitude):
            # Regular validation error - no image needed
            await message.answer("⚠️ Lokasi tidak valid atau di luar jangkauan. Pastikan format benar.")
            await state.clear()
            return
        
        # Additional validation: Check if coordinates are likely in Indonesia
        # Indonesia latitude: approximately -11 to 6, longitude: approximately 95 to 141
        if not (-11 <= user_latitude <= 6 and 95 <= user_longitude <= 141):
            await message.answer(
                f"⚠️ *Peringatan Koordinat di Luar Indonesia*\n\n"
                f"Koordinat yang Anda berikan (`{user_latitude},{user_longitude}`) kemungkinan *bukan di Indonesia*.\n\n"
                f"📍 Indonesia berada di:\n"
                f"• Latitude: -11° hingga 6°\n"
                f"• Longitude: 95° hingga 141°\n\n"
                f"💡 Apakah Anda lupa tanda minus (-) untuk latitude?\n"
                f"Contoh: `-7.273,112.816` bukan `7.273,112.816`",
                parse_mode="Markdown"
            )
            await state.clear()
            return
        
        logger.info(f"Parsed coordinates from parameter: {user_latitude}, {user_longitude}")
        
        # Confirm location
        latitude_clean = str(user_latitude).replace(".", "\\.")
        longitude_clean = str(user_longitude).replace(".", "\\.")
        await message.answer(f"✅ Lokasi diterima\\: `{user_latitude},{user_longitude}`", parse_mode="MarkdownV2")
        logger.info(f"User {user_id} location accepted via parameter: {user_latitude}, {user_longitude}")
        
        # Start loading UI with ProgressMessageManager
        try:
            processing_msg = await bot.send_message(
                chat_id, "🔍 **Memulai pencarian ODP...**", parse_mode="Markdown"
            )
            progress_manager = ProgressMessageManager(bot, chat_id, processing_msg.message_id)
        except Exception as e:
            logger.warning(f"Could not send progress message: {e}")
            # Fallback to simple message
            await message.answer("🔄 Mencari ODP dalam area sekitar koordinat Anda...")
        
        # Use configuration for search parameters
        odp_config = SearchConfig.ODP_SEARCH
        site_config = SearchConfig.SITE_SEARCH
        
        # Update progress
        if progress_manager:
            await progress_manager.update_progress(15, "Mencari ODP di sekitar...", "search")
        
        # Search for ODPs
        min_lat = user_latitude - odp_config['radius_deg_direct']
        max_lat = user_latitude + odp_config['radius_deg_direct']
        min_lon = user_longitude - odp_config['radius_deg_direct']
        max_lon = user_longitude + odp_config['radius_deg_direct']
        
        loop = asyncio.get_event_loop()
        
        # Update progress
        if progress_manager:
            await progress_manager.update_progress(25, "Melakukan Query di Database...", "search")
        
        odps_in_box = await loop.run_in_executor(
            None, get_odps_in_bounding_box, min_lat, max_lat, min_lon, max_lon
        )

        logger.info(f"[DEBUG] ODPs fetched: {len(odps_in_box) if odps_in_box else 0}")
        logger.info(f"[DEBUG] About to process ODPs...")
        
        if not odps_in_box:
            logger.info(f"No ODPs found in bounding box for user {user_id}, will continue to show warning message")
            # Don't return early - let it continue to build proper warning message
            nearest_odps = []  # Set to empty list
        else:
            # Update progress
            if progress_manager:
                await progress_manager.update_progress(40, f"Menemukan {len(odps_in_box)} ODP, Menghitung jarak...", "analysis")
            
            # Find nearest ODPs
            nearest_odps = await loop.run_in_executor(
                None, find_nearest_odp, user_latitude, user_longitude, odps_in_box, odp_config['initial_distance_m']
            )
            
            if not nearest_odps:
                if progress_manager:
                    await progress_manager.update_progress(50, f"Memperluas radius pencarian {odp_config['expanded_distance_m']}m...", "search")
                else:
                    await message.answer(f"Tidak ada ODP dalam radius {odp_config['initial_distance_m']}m, menghitung jarak hingga {odp_config['expanded_distance_m']}m...")
                
                nearest_odps = await loop.run_in_executor(
                    None, find_nearest_odp, user_latitude, user_longitude, odps_in_box, odp_config['expanded_distance_m']
                )
        
        # Site search with progress updates
        site_marker = None
        perform_site_search = True
        
        if perform_site_search:
            if progress_manager:
                await progress_manager.update_progress(60, "Mencari Sites EZnet...", "search")
            
            logger.info("Performing site search using bounding box (direct lookup)...")
            
            min_site_lat = user_latitude - site_config['radius_deg_direct']
            max_site_lat = user_latitude + site_config['radius_deg_direct']
            min_site_lon = user_longitude - site_config['radius_deg_direct']
            max_site_lon = user_longitude + site_config['radius_deg_direct']
            
            sites_in_box = await loop.run_in_executor(
                None, get_sites_in_bounding_box, min_site_lat, max_site_lat, min_site_lon, max_site_lon
            )
            
            if sites_in_box:
                if progress_manager:
                    await progress_manager.update_progress(70, f"Menemukan {len(sites_in_box)} site, mencari yang terdekat...", "analysis")
                
                nearest_site_result = await loop.run_in_executor(
                    None, find_nearest_site, user_latitude, user_longitude, sites_in_box, site_config['distance_1_m']
                )
                
                if not nearest_site_result:
                    if progress_manager:
                        await progress_manager.update_progress(75, f"Memperluas radius pencarian ke {site_config['distance_2_m']}m...", "search")
                    else:
                        await message.answer(f"Tidak ditemukan Site Eligible Eznet Wireless dalam radius {site_config['distance_1_m']}m, memperluas pencarian ke {site_config['distance_2_m']}m... ⏳")
                    
                    nearest_site_result = await loop.run_in_executor(
                        None, find_nearest_site, user_latitude, user_longitude, sites_in_box, site_config['distance_2_m']
                    )
                
                if nearest_site_result:
                    site, site_distance = nearest_site_result
                    site_message = f"✨ *Ditemukan Site Eligible Eznet Wireless terdekat:*\n • `{site['site_id']}`: {site_distance:.2f} m"
                    site_marker = {
                        "latitude": site['latitude'], 
                        "longitude": site['longitude'], 
                        "radius": site_config['distance_1_m'], 
                        "distance": site_distance
                    }
                else:
                    site_message = f"⚠️ Tidak ada Site Eligible Eznet Wireless ditemukan dalam radius {site_config['distance_1_m']}m atau {site_config['distance_2_m']}m."
            else:
                site_message = f"⚠️ Tidak ada Site ditemukan dalam area pencarian (~{site_config['radius_deg_direct']*111:.1f}km)."
        else:
            site_message = "ℹ️ Pencarian Site Eznet Wireless dinonaktifkan."
        
        # Build and send combined message (REFACTORED)
        odp_message = build_odp_message(nearest_odps, odp_config)
        combined_message = odp_message + "\n\n" + site_message
        
        if not OSRM_WALKABLE_ROUTES_ENABLED:
            combined_message += "\n\n📍 Karena suatu kendala, rute berjalan kaki dinonaktifkan."
        
        # Add hint message only when results are found
        if nearest_odps:
            # Extract all ODP names and join them with commas
            # nearest_odps is a list of tuples: (odp_dict, distance)
            odp_names_list = [odp[0]['odp_name'] for odp in nearest_odps]
            odp_names_joined = ','.join(odp_names_list)
            combined_message += f"\n\n🔍 Cek detail ODP dan CT0nya dengan `/cekodp {odp_names_joined}`"
        
        await message.answer(combined_message, parse_mode="Markdown")
        
        # Generate routes and map with progress updates
        routes = []
        if nearest_odps and OSRM_WALKABLE_ROUTES_ENABLED:
            if progress_manager:
                await progress_manager.update_progress(80, "Menghitung jalur darat...", "analysis")
            
            try:
                routes = await calculate_routes(user_id, user_latitude, user_longitude, nearest_odps)
            except Exception as e:
                logger.error(f"Error calculating routes for user {user_id}: {e}", exc_info=True)
                routes = []
        
        # Generate HTML map
        if nearest_odps or (perform_site_search and site_marker):
            if progress_manager:
                await progress_manager.update_progress(90, "Membuat peta...", "report")
            
            try:
                logger.info(f"User {user_id} - Starting HTML generation...")
                output_html_path = await generate_nearest_odp_html(
                    user_id, user_latitude, user_longitude, routes,
                    site_marker=site_marker if perform_site_search else None
                )
                logger.info(f"User {user_id} - HTML generation completed. Path: {output_html_path}")
                
                if os.path.exists(output_html_path):
                    if progress_manager:
                        await progress_manager.update_progress(100, "Mengirim file...", "upload", delay=0.5)
                    
                    logger.info(f"User {user_id} - HTML file exists, sending document...")
                    input_file = FSInputFile(output_html_path, filename=os.path.basename(output_html_path))
                    map_caption = "📌 Berikut peta ODP terdekat."
                    if perform_site_search and site_marker:
                        map_caption += " Termasuk lokasi Site Eligible Eznet Wireless."
                    if not OSRM_WALKABLE_ROUTES_ENABLED:
                        map_caption += " (Mode peta statis - tanpa rute berjalan kaki)"
                    
                    await bot.send_document(chat_id, input_file, caption=map_caption)
                    logger.info(f"Nearest ODP/Site map sent to user {user_id} via direct lookup.")
                    
                    # Complete progress (deletes message)
                    if progress_manager:
                        await progress_manager.complete_progress(True, "Berhasil!")
                else:
                    logger.error(f"User {user_id} - Generated HTML file not found at: {output_html_path}")
                    if progress_manager:
                        await progress_manager.complete_progress(False, "Peta tidak dapat dibuat. File tidak ditemukan.")
                    else:
                        await message.answer("⚠️ Peta tidak dapat dibuat. File tidak ditemukan.")
            except Exception as e:
                logger.error(f"Error generating/sending map for user {user_id}: {e}", exc_info=True)
                if progress_manager:
                    await progress_manager.complete_progress(False, "Terjadi kesalahan saat membuat atau mengirim peta.")
                else:
                    await message.answer("⚠️ Terjadi kesalahan saat membuat atau mengirim peta.")
        elif nearest_odps:
            if progress_manager:
                await progress_manager.complete_progress(True, "Pencarian selesai! Lihat hasil di atas.")
            await message.answer("⚠️ Rute ODP tidak bisa dirender, namun ODP ditemukan (lihat list di atas).")
        else:
            if progress_manager:
                await progress_manager.complete_progress(False, "Tidak ada ODP atau Site ditemukan di area tersebut.")
            logger.info(f"User {user_id} - No HTML generation: no ODPs found and no site markers.")
    
    except Exception as e:
        logger.error(f"Error in odpterdekat_direct_input_handler for user {user_id}: {e}", exc_info=True)
        if progress_manager:
            await progress_manager.complete_progress(False, "Terjadi kesalahan saat memproses lokasi.")
        else:
            await message.answer("⚠️ Terjadi kesalahan saat memproses lokasi.")
    finally:
        await state.clear()


async def odpterdekat_interactive_setup(event: Union[Message, CallbackQuery], bot: Bot, state: FSMContext):
    """Sets up interactive location request for ODP search"""
    user_id = event.from_user.id
    chat_id = event.chat.id if isinstance(event, Message) else event.message.chat.id
    
    await state.set_state(FeaturesFlow.awaiting_share_location)
    logger.debug(f"State set to awaiting_share_location for user {user_id}")
    
    # Create location prompt message with OSRM status
    location_prompt = (
        "🌎 *Untuk mencari ODP terdekat, kirimkan salah satu:*\n\n"
        " 1. Lokasi via 'Share Location' 📍\n"
        " 2. Koordinat (contoh: -7.000,110.000)\n"
        " 3. Link Google Maps 🌐"
    )
    
    if not OSRM_WALKABLE_ROUTES_ENABLED:
        location_prompt += "\n\n📍 Info: Karena suatu kendala, rute berjalan kaki dinonaktifkan"
    
    msg = await bot.send_message(
        chat_id,
        location_prompt,
        reply_markup=get_cancel_keyboard(flow_type="odp_terdekat"),
        parse_mode='Markdown'
    )

    await state.update_data(location_prompt_msg_id=msg.message_id)
    logger.info(f"User {user_id} prompted for location input in /odpterdekat.")


@measure_performance("odp_terdekat_non_direct")
@dp.message(FeaturesFlow.awaiting_share_location, F.content_type.in_({ContentType.TEXT, ContentType.LOCATION}))
async def odpterdekat_location_state_handler(message: Message, bot: Bot, state: FSMContext):
    """Enhanced location handler with comprehensive loading UI and CoordinateParser class"""
    user_id = message.from_user.id
    chat_id = message.chat.id
    progress_manager = None
    
    # Initialize variables and progress tracking
    user_latitude, user_longitude = None, None
    
    try:
        # Parse location from message
        if message.content_type == ContentType.LOCATION:
            user_latitude = message.location.latitude
            user_longitude = message.location.longitude
            logger.info(f"Location received from user {user_id}: {user_latitude}, {user_longitude}")
        
        elif message.content_type == ContentType.TEXT:
            text_input = message.text.strip()
            logger.info(f"DEBUG: Parsing text input for user {user_id}: '{text_input}'")
            
            try:
                user_latitude, user_longitude = CoordinateParser.parse(text_input)
                logger.info(f"DEBUG: Parser returned: lat={user_latitude}, lon={user_longitude}")
                
                if user_latitude is None or user_longitude is None:
                    await message.answer("⚠️ Format tidak valid. Silahkan gunakan link Google Maps atau koordinat desimal (contoh: `-7.000,110.000`).", parse_mode="Markdown")
                    return
                    
                logger.info(f"Parsed coordinates: {user_latitude}, {user_longitude}")
            except Exception as e:
                logger.error(f"Failed to parse input '{text_input}': {e}")
                await message.answer("⚠️ Format koordinat tidak valid. Silahkan coba lagi.")
                return
        
        # Validate coordinates using CoordinateParser
        if not CoordinateParser.validate_coordinates(user_latitude, user_longitude):
            await message.answer("⚠️ Koordinat di luar rentang yang valid. Silahkan periksa kembali.")
            logger.error(f"Invalid coordinate range: {user_latitude}, {user_longitude}")
            return
        
        # Confirm location received
        await message.answer(f"✅ Lokasi diterima: `{user_latitude},{user_longitude}`", parse_mode="MarkdownV2")
        
        # Step 1: Start loading UI with ProgressMessageManager
        try:
            processing_msg = await bot.send_message(
                chat_id, "🔍 **Memulai pencarian ODP & Sites...**", parse_mode="Markdown"
            )
            progress_manager = ProgressMessageManager(bot, chat_id, processing_msg.message_id)
        except Exception as e:
            logger.warning(f"Could not send initial progress message: {e}")
            progress_manager = None
        
        # Step 2: Search for ODPs with progress updates
        if progress_manager:
            await progress_manager.update_progress(10, "Mencari ODP di sekitar...", "search")
        
        # Configuration for search areas
        odp_config = SearchConfig.ODP_SEARCH
        site_config = SearchConfig.SITE_SEARCH
        
        # Search for ODPs
        min_lat = user_latitude - odp_config['radius_deg_direct']
        max_lat = user_latitude + odp_config['radius_deg_direct']
        min_lon = user_longitude - odp_config['radius_deg_direct']
        max_lon = user_longitude + odp_config['radius_deg_direct']
        
        loop = asyncio.get_event_loop()
        
        # Update progress
        if progress_manager:
            await progress_manager.update_progress(20, "Melakukan Query di Database...", "search")
        
        odps_in_box = await loop.run_in_executor(
            None, get_odps_in_bounding_box, min_lat, max_lat, min_lon, max_lon
        )
        
        if not odps_in_box:
            if progress_manager:
                await progress_manager.complete_progress(False, "Tidak ada ODP ditemukan dalam area pencarian.")
            else:
                await message.answer("⚠️ Tidak ada ODP ditemukan dalam area pencarian.")
            await state.clear()
            return

        # Update progress
        if progress_manager:
            await progress_manager.update_progress(35, f"Menemukan {len(odps_in_box)} ODP, menghitung jarak...", "analysis")

        # Find nearest ODPs
        nearest_odps = await loop.run_in_executor(
            None, find_nearest_odp, user_latitude, user_longitude, odps_in_box, odp_config['initial_distance_m']
        )
        
        if not nearest_odps:
            if progress_manager:
                await progress_manager.update_progress(45, f"Memperluas radius pencarian ke {odp_config['expanded_distance_m']}m...", "search")
            
            nearest_odps = await loop.run_in_executor(
                None, find_nearest_odp, user_latitude, user_longitude, odps_in_box, odp_config['expanded_distance_m']
            )

        # Step 3: Site search with progress updates
        site_marker = None
        perform_site_search = True
        
        if perform_site_search:
            if progress_manager:
                await progress_manager.update_progress(55, "Mencari Sites EZnet..", "search")
            
            logger.info("Performing site search using bounding box...")
            
            min_site_lat = user_latitude - site_config['radius_deg_direct']
            max_site_lat = user_latitude + site_config['radius_deg_direct']
            min_site_lon = user_longitude - site_config['radius_deg_direct']
            max_site_lon = user_longitude + site_config['radius_deg_direct']
            
            sites_in_box = await loop.run_in_executor(
                None, get_sites_in_bounding_box, min_site_lat, max_site_lat, min_site_lon, max_site_lon
            )
            
            if sites_in_box:
                if progress_manager:
                    await progress_manager.update_progress(65, f"Menemukan {len(sites_in_box)} site, mencari yang terdekat...", "analysis")
                
                nearest_site_result = await loop.run_in_executor(
                    None, find_nearest_site, user_latitude, user_longitude, sites_in_box, site_config['distance_1_m']
                )
                
                if not nearest_site_result:
                    if progress_manager:
                        await progress_manager.update_progress(70, f"Memperluas pencarian site menjadi {site_config['distance_2_m']}m...", "search")
                    
                    nearest_site_result = await loop.run_in_executor(
                        None, find_nearest_site, user_latitude, user_longitude, sites_in_box, site_config['distance_2_m']
                    )
                
                if nearest_site_result:
                    site, site_distance = nearest_site_result
                    site_message = f"✨ *Ditemukan Site Eligible Eznet Wireless terdekat:*\n- `{site['site_id']}`: {site_distance:.2f} m"
                    site_marker = {
                        "latitude": site['latitude'], 
                        "longitude": site['longitude'], 
                        "radius": site_config['distance_1_m'], 
                        "distance": site_distance
                    }
                else:
                    site_message = f"⚠️ Tidak ada Site Eligible Eznet Wireless ditemukan dalam radius {site_config['distance_1_m']}m atau {site_config['distance_2_m']}m."
            else:
                site_message = f"⚠️ Tidak ada Site ditemukan dalam area pencarian."
        else:
            site_message = "ℹ️ Pencarian Site Eznet Wireless dinonaktifkan."

        # Step 4: Route calculation with progress updates
        routes = []
        if nearest_odps and OSRM_WALKABLE_ROUTES_ENABLED:
            if progress_manager:
                await progress_manager.update_progress(75, "Menghitung jalur darat...", "analysis")
            
            try:
                routes = await calculate_routes(user_id, user_latitude, user_longitude, nearest_odps)
            except Exception as e:
                logger.error(f"Error calculating routes for user {user_id}: {e}")
                routes = []
                if progress_manager:
                    await progress_manager.update_progress(80, "Route calculation failed, using static markers...", "analysis")

        # Step 5: Generate results message
        if progress_manager:
            await progress_manager.update_progress(85, "Menyiapkan hasil...", "report")

        logger.info(f"[STEP 5] Building message - ODPs found: {len(nearest_odps) if nearest_odps else 0}")
        
        # Build Combined Message
        if nearest_odps:
            # ODPs found - build normal message
            logger.info(f"[STEP 5] Building message for {len(nearest_odps)} ODPs found")

            odp_message = build_odp_message(nearest_odps, odp_config)
            combined_message = odp_message + "\n\n" + site_message
            
            if not OSRM_WALKABLE_ROUTES_ENABLED:
                combined_message += "\n\n📍 Karena suatu kendala, rute berjalan kaki dinonaktifkan."
            
            # Extract all ODP names and join them with commas
            # nearest_odps is a list of tuples: (odp_dict, distance)
            odp_names_list = [odp[0]['odp_name'] for odp in nearest_odps]
            odp_names_joined = ','.join(odp_names_list)
            combined_message += f"\n\n🔍 Cek detail ODP dan CT0nya dengan `/cekodp {odp_names_joined}`"
        else:
            # No ODPs found - build warning message
            logger.info(f"[STEP 5] Building message for NO ODPs found")
            combined_message = f"❌ *Tidak ada ODP ditemukan* dalam radius {odp_config['expanded_distance_m']}m dari koordinat `{user_latitude},{user_longitude}`\n\n"
            combined_message += site_message
            combined_message += f"\n\n💡 *Tips:*\n"
            combined_message += f"• Pastikan koordinat sudah benar\n"
            combined_message += f"• Contoh koordinat yang benar: `-7.273,112.816`"
        
        logger.info(f"[STEP 5] Message built, length: {len(combined_message)} chars")
        logger.debug(f"[STEP 5] Message content:\n{combined_message}")
        
        # Send results message with explicit error handling
        try:
            logger.info(f"[STEP 5] Attempting to send message to user {user_id}")
            await message.answer(combined_message, parse_mode="Markdown")
            logger.info(f"[STEP 5] Message successfully sent to user {user_id}")
        except Exception as send_error:
            logger.error(f"[STEP 5] ❌ Failed to send message: {send_error}", exc_info=True)
            # Try without markdown
            try:
                plain_message = combined_message.replace("*", "").replace("`", "")
                await message.answer(plain_message)
                logger.info(f"[STEP 5] Fallback plain message sent")
            except Exception as fallback_error:
                logger.error(f"[STEP 5] ❌ Fallback also failed: {fallback_error}", exc_info=True)
                raise

        # Step 6: Generate HTML map with progress updates
        if nearest_odps or (perform_site_search and site_marker):
            if progress_manager:
                await progress_manager.update_progress(90, "Generating interactive map...", "report")
            
            try:
                output_html_path = await generate_nearest_odp_html(
                    user_id, user_latitude, user_longitude, routes,
                    site_marker=site_marker if perform_site_search else None
                )
                
                if progress_manager:
                    await progress_manager.update_progress(95, "Preparing map file...", "upload")
                
                if os.path.exists(output_html_path):
                    input_file = FSInputFile(output_html_path, filename=os.path.basename(output_html_path))
                    map_caption = "📌 Berikut peta ODP terdekat."
                    if perform_site_search and site_marker:
                        map_caption += " Termasuk lokasi Site Eligible Eznet Wireless."
                    if not OSRM_WALKABLE_ROUTES_ENABLED:
                        map_caption += " (Mode peta statis - tanpa rute berjalan kaki)"
                    
                    # Final progress update
                    if progress_manager:
                        await progress_manager.update_progress(100, "Mengirim file...", "upload", delay=0.5)
                    
                    await bot.send_document(chat_id, input_file, caption=map_caption)
                    logger.info(f"Nearest ODP/Site map sent to user {user_id}.")
                    
                    # Complete progress (deletes message)
                    if progress_manager:
                        await progress_manager.complete_progress(True, "Berhasil!")
                else:
                    logger.error(f"Generated HTML file not found at: {output_html_path}")
                    if progress_manager:
                        await progress_manager.complete_progress(False, "Peta tidak dapat dibuat. File tidak ditemukan.")
                    else:
                        await message.answer("⚠️ Peta tidak dapat dibuat. File tidak ditemukan.")
            except Exception as e:
                logger.error(f"Error generating/sending map for user {user_id}: {e}")
                if progress_manager:
                    await progress_manager.complete_progress(False, "Terjadi kesalahan saat membuat atau mengirim peta.")
                else:
                    await message.answer("⚠️ Terjadi kesalahan saat membuat atau mengirim peta.")
        elif nearest_odps:
            if progress_manager:
                await progress_manager.complete_progress(True, "Pencarian selesai! Lihat hasil di atas.")
            await message.answer("⚠️ Rute ODP tidak bisa dirender, namun ODP ditemukan (lihat list di atas).")
        else:
            if progress_manager:
                await progress_manager.complete_progress(False, "Tidak ada ODP atau Site ditemukan di area tersebut.")

    except Exception as e:
        logger.error(f"Error in odpterdekat_location_state_handler for user {user_id}: {e}", exc_info=True)
        
        # Update progress message with error
        if progress_manager:
            await progress_manager.complete_progress(False, "Terjadi kesalahan saat memproses lokasi.")
        else:
            await message.answer("⚠️ Terjadi kesalahan saat memproses lokasi.")
    finally:
        await state.clear()


