@dp.message(Command("odpmap"))
@dp.callback_query(F.data == "odpmap")
@authorized_only_employer("tsel")
async def odp_map_handler(
    event: Union[Message, CallbackQuery],  # Accept both types
    bot: Bot,
    state: FSMContext
):
    """
    Handle ODP Map selection - start with branch/region selection
    """
    user_id = event.from_user.id
    chat_id = event.message.chat.id if isinstance(event, CallbackQuery) else event.chat.id
    
    # Handle CallbackQuery answer
    if isinstance(event, CallbackQuery):
        await event.answer()
        
        # Delete previous message for callback
        await bot.delete_message(
            chat_id=chat_id,
            message_id=event.message.message_id
        )
    
    try:
        await bot.send_message(
            chat_id,
            "📍 Pilih Branch/Region untuk ODP Map..."
        )
        logger.debug(f"User {user_id}: ODP Map feature initiated.")

        # Get user data for filtering
        user_data = await get_user_data(user_id)
        region_filter = None

        # Send branch selection with ACTIVE region callback prefix
        await send_branch_selection(
            chat_id, 
            bot, 
            callback_prefix="odpmap_select_branch",
            region_callback_prefix="odpmap_select_region",
            selected_region=region_filter
        )
        
        await state.set_state(FeaturesFlow.odp_map_branch_selection)

    except Exception as e:
        logger.error(f"Error in odp_map_handler: {e}", exc_info=True)
        await send_error_message(bot, chat_id)


@dp.callback_query(F.data.startswith("odpmap_select_region:"))
@authorized_only_employer("tsel")
async def odpmap_region_selection_handler(
    callback_query: CallbackQuery,
    bot: Bot,
    state: FSMContext
):
    """
    Handle region selection for ODP Map
    """
    await callback_query.answer()
    
    try:
        selected_region = callback_query.data.split(":")[1]
        
        # Get branches for selected region
        branches = REGION_BRANCH_MAPPING.get(selected_region, [])
        
        if not branches:
            await bot.send_message(
                callback_query.message.chat.id,
                f"⚠️ Region {selected_region} tidak ditemukan"
            )
            await state.clear()
            return
        
        # Store selected region and branches in state
        await state.update_data(
            selected_region=selected_region,
            selected_branches=branches
        )
        
        # Delete the branch selection message
        await bot.delete_message(
            chat_id=callback_query.message.chat.id,
            message_id=callback_query.message.message_id
        )
        
        branch_list = ", ".join(branches)
        await bot.send_message(
            callback_query.message.chat.id,
            f"📍 Region: {selected_region}\n📋 Branches: {branch_list}\n\n🎯 Pilih Status ODP:"
        )
        
        # Send status selection
        await send_status_selection(callback_query.message.chat.id, bot)
        
        await state.set_state(FeaturesFlow.odp_map_status_selection)
        
    except Exception as e:
        logger.error(f"Error in odpmap_region_selection_handler: {e}")
        await send_error_message(bot, callback_query.message.chat.id)
        await state.clear()


