@dp.callback_query(F.data.startswith("odpmap_los_toggle_"))
@authorized_only_employer("tsel")
async def odpmap_los_toggle_handler(
    callback_query: CallbackQuery,
    bot: Bot,
    state: FSMContext
):
    """
    Handle LOS group toggle
    """
    await callback_query.answer()
    
    try:
        los_group = callback_query.data.replace("odpmap_los_toggle_", "")
        
        state_data = await state.get_data()
        selected_los = state_data.get('selected_los_groups', [])
        
        if los_group in selected_los:
            selected_los.remove(los_group)
        else:
            selected_los.append(los_group)
        
        await state.update_data(selected_los_groups=selected_los)
        
        # Update the message
        await update_filter_message(callback_query.message.chat.id, callback_query.message.message_id, bot, state)
        
    except Exception as e:
        logger.error(f"Error in odpmap_los_toggle_handler: {e}")


