@dp.callback_query(F.data == "odpmap_generate")
@authorized_only_employer("tsel")
async def odpmap_generate_handler(
    callback_query: CallbackQuery,
    bot: Bot,
    state: FSMContext
):
    """
    Generate ODP Map with KMZ and CSV files
    """
    await callback_query.answer()
    
    output_kmz_path = None
    csv_path = None
    
    try:
        state_data = await state.get_data()
        
        # Get selection data
        selected_region = state_data.get('selected_region')
        selected_branches = state_data.get('selected_branches')
        selected_branch = state_data.get('selected_branch')
        selected_statuses = state_data.get('selected_statuses', [])
        selected_los_groups = state_data.get('selected_los_groups', [])
        selected_new_status = state_data.get('selected_new_status', [])
        
        # Determine display info and branch filter
        if selected_region and selected_branches:
            display_info = f"{selected_region}"
            branch_filter = selected_branches
        elif selected_branch:
            display_info = f"{selected_branch}"
            branch_filter = [selected_branch]
        else:
            await bot.send_message(
                callback_query.message.chat.id,
                "⚠️ Error: Branch/Region tidak terpilih. Silahkan ulangi dari awal."
            )
            await state.clear()
            return
        
        # Delete filter selection message
        await bot.delete_message(
            chat_id=callback_query.message.chat.id,
            message_id=callback_query.message.message_id
        )
        
        # Send processing message
        progress_msg = await bot.send_message(
            callback_query.message.chat.id,
            "📍 Mohon tunggu, ODP Map sedang dirender..."
        )
        
        # Create progress manager
        progress_manager = ProgressMessageManager(
            bot, callback_query.message.chat.id, progress_msg.message_id
        )
        
        await progress_manager.update_progress(10, "Mengambil data summary...", "analysis")
        
        # Fetch summary data
        summary_data = await fetch_summary_odp_map_data(
            branch_filter, selected_statuses, selected_los_groups, selected_new_status
        )
        
        await progress_manager.update_progress(25, "Memformat data summary...", "analysis")
        
        # Send summary data immediately
        if summary_data:
            # Determine if this is a region selection (multiple branches)
            is_region_selection = bool(selected_region and selected_branches)
            
            summary_text = await format_summary_odp_map_data(summary_data, is_region_selection)
            escaped_summary_text = html.escape(summary_text)
            
            status_text = " & ".join(selected_statuses)
            los_text = ", ".join(selected_los_groups) if selected_los_groups else "All"
            new_text = ", ".join(selected_new_status) if selected_new_status else "All"
            
            header = (
                f"📊 <b>ODP Map Summary:</b>\n\n"
                f"<b> • {display_info}</b>\n"
                f"<b> • Status:</b> {status_text}\n"
                f"<b> • LOS Groups:</b> {los_text}\n"
                f"<b> • Year Groups:</b> {new_text}\n"
                "____________________\n"
            )
            
            content = f"<pre>{escaped_summary_text}</pre>"
            full_message = header + content
            
            if len(full_message) <= 4096:
                await bot.send_message(callback_query.message.chat.id, full_message, parse_mode="HTML")
            else:
                await bot.send_message(callback_query.message.chat.id, header, parse_mode="HTML")
                available_length = 4096 - len("<pre></pre>")
                content_chunks = split_text(escaped_summary_text, available_length)
                for chunk in content_chunks:
                    await bot.send_message(callback_query.message.chat.id, f"<pre>{chunk}</pre>", parse_mode="HTML")
        else:
            await bot.send_message(callback_query.message.chat.id, "⚠️ Tidak ada data summary ODP Map untuk ditampilkan.")

        await progress_manager.update_progress(50, "Mengambil data detail untuk peta...", "analysis")
        
        # Fetch detailed data for map
        data = await fetch_odp_map_data(
            branch_filter, selected_statuses, selected_los_groups, selected_new_status
        )
        if not data:
            await progress_manager.complete_progress(False, "Tidak ada data ODP Map untuk ditampilkan di peta")
            await state.clear()
            return

        await progress_manager.update_progress(70, "Memformat data untuk peta...", "analysis")

        odp_points = await format_odp_map_data(data)
        if not odp_points:
            await progress_manager.complete_progress(False, "Data ODP tidak memiliki koordinat yang valid")
            await state.clear()
            return

        await progress_manager.update_progress(85, "Membuat peta KMZ (compressed)...", "analysis")

        # Generate KMZ map
        output_kmz_path = await generate_odp_map_kmz(
            callback_query.from_user.id, odp_points, display_info, selected_statuses
        )
        
        await progress_manager.update_progress(95, "Membuat file CSV...", "analysis")
        
        # Generate CSV file
        csv_path = await generate_odp_map_csv(data, summary_data, display_info, selected_statuses)
        
        await progress_manager.complete_progress(True, "Proses selesai!")
        
        # File size limit (45MB to leave buffer under Telegram's 50MB limit)
        max_file_size = 45 * 1024 * 1024
        
        # Send KMZ file with size validation
        if output_kmz_path and os.path.exists(output_kmz_path):
            file_size = os.path.getsize(output_kmz_path)
            
            if file_size > max_file_size:
                await bot.send_message(
                    callback_query.message.chat.id,
                    f"⚠️ KMZ file terlalu besar ({file_size/1024/1024:.1f}MB). "
                    f"Silahkan gunakan filter lebih spesifik untuk mengurangi data."
                )
            else:
                try:
                    input_file = FSInputFile(output_kmz_path, filename=os.path.basename(output_kmz_path))
                    await bot.send_document(
                        callback_query.message.chat.id, 
                        input_file, 
                        caption="📍 Berikut ODP Map dalam format KMZ (Google Earth - Compressed)."
                    )
                except Exception as e:
                    logger.error(f"Failed to send KMZ file: {e}")
                    await bot.send_message(
                        callback_query.message.chat.id,
                        "⚠️ Gagal mengirim file KMZ. File mungkin terlalu besar."
                    )
        else:
            await bot.send_message(callback_query.message.chat.id, "⚠️ Peta KMZ tidak dapat dibuat. Silahkan hubungi admin.")

        # Send CSV file with size validation
        if csv_path and os.path.exists(csv_path):
            file_size = os.path.getsize(csv_path)
            
            if file_size > max_file_size:
                await bot.send_message(
                    callback_query.message.chat.id,
                    f"⚠️ CSV file terlalu besar ({file_size/1024/1024:.1f}MB). "
                    f"Silahkan gunakan filter lebih spesifik untuk mengurangi data."
                )
            else:
                try:
                    csv_file = FSInputFile(csv_path, filename=os.path.basename(csv_path))
                    await bot.send_document(
                        callback_query.message.chat.id, 
                        csv_file, 
                        caption="📊 Data ODP Map dalam format CSV."
                    )
                except Exception as e:
                    logger.error(f"Failed to send CSV file: {e}")
                    await bot.send_message(
                        callback_query.message.chat.id,
                        "⚠️ Gagal mengirim file CSV. File mungkin terlalu besar."
                    )
        else:
            await bot.send_message(callback_query.message.chat.id, "⚠️ File CSV tidak dapat dibuat.")

    except Exception as e:
        logger.error(f"Error in odpmap_generate_handler: {e}", exc_info=True)
        await send_error_message(bot, callback_query.message.chat.id)
    
    finally:
        # Guaranteed cleanup - Always runs regardless of success/failure
        if output_kmz_path and os.path.exists(output_kmz_path):
            try:
                os.remove(output_kmz_path)
                logger.info(f"Cleaned up temporary KMZ file: {output_kmz_path}")
            except Exception as e:
                logger.error(f"Failed to delete temporary KMZ file: {e}")
        
        if csv_path and os.path.exists(csv_path):
            try:
                os.remove(csv_path)
                logger.info(f"Cleaned up temporary CSV file: {csv_path}")
            except Exception as e:
                logger.error(f"Failed to delete temporary CSV file: {e}")
        
        await state.clear()


