@dp.callback_query(F.data.startswith("select_sto:"))
async def handle_cvm_sto_selection(call: CallbackQuery, state: FSMContext):
    """Handles multiple STO selection with toggle behavior."""
    try:
        _, region_name, branch_name, sto_name = call.data.split(":", 3)
        
        # Set state to selecting_multiple_stos
        await state.set_state(FeaturesFlow.selecting_multiple_stos)
        
        # Get current state data
        state_data = await state.get_data()
        selected_stos = state_data.get('selected_stos', [])
        
        # Toggle STO selection
        if sto_name in selected_stos:
            selected_stos.remove(sto_name)
            await call.answer()
        else:
            # Check if already at max limit (10)
            if len(selected_stos) >= 10:
                await call.answer("⚠️ Maksimal 10 STO dapat dipilih", show_alert=True)
                return
            selected_stos.append(sto_name)
            await call.answer()
        
        # Update state data
        await state.update_data(
            selected_stos=selected_stos,
            selected_branch=branch_name,
            selected_region=region_name
        )
        
        # Build updated message
        stos = await fetch_stos_for_branch(branch_name)
        
        if stos:
            sorted_stos = sorted(stos)
            total_stos = len(sorted_stos)
            
            # Smart column selection based on number of STOs (matching send_sto_selection_smart)
            if total_stos <= 8:
                columns = 2  # 2 columns for small lists
            elif total_stos <= 16:
                columns = 3  # 3 columns for medium lists
            else:
                columns = 4  # 4 columns for large lists
            
            # Build keyboard rows
            keyboard_rows = []
            
            # Add STO buttons with smart columns
            for i in range(0, total_stos, columns):
                row_stos = sorted_stos[i:i + columns]
                row_buttons = []
                for sto in row_stos:
                    # Add checkmark if selected
                    prefix = "✅ " if sto in selected_stos else ""
                    btn_text = f"{prefix}{sto.upper()}"
                    btn_callback = f"select_sto:{region_name}:{branch_name}:{sto}"
                    row_buttons.append(InlineKeyboardButton(text=btn_text, callback_data=btn_callback))
                keyboard_rows.append(row_buttons)
            
            # Add action buttons if STOs are selected
            if selected_stos:
                sto_list = ", ".join([s.upper() for s in selected_stos])
                message_text = (
                    f"📍 Pilih STO untuk Branch {branch_name.upper()} (Region {region_name.upper()}):\n\n"
                    f"💡 Total: {total_stos} STO | Dipilih: {len(selected_stos)} STO\n\n"
                    f"STO Dipilih: {sto_list}\n\n"
                    f"Jika anda sudah yakin, silahkan klik tombol \"Lanjut\" dibawah."
                )
                
                # Add action buttons
                action_buttons = [
                    InlineKeyboardButton(text="✅ Lanjut", callback_data="cvm_proceed_to_segment"),
                    InlineKeyboardButton(text="↩️ Kembali", callback_data=f"cvm_select_branch:{branch_name}"),
                    InlineKeyboardButton(text="❌ Batal", callback_data="cancel_cvm")
                ]
                keyboard_rows.append(action_buttons)
            else:
                message_text = (
                    f"📍 Pilih STO untuk Branch {branch_name.upper()} (Region {region_name.upper()}):\n\n"
                    f"💡 Total: {total_stos} STO | Klik untuk memilih (maks. 10)"
                )
                
                # Add cancel button
                keyboard_rows.append([InlineKeyboardButton(text="❌ Batal", callback_data="cancel_cvm")])
            
            keyboard = InlineKeyboardMarkup(inline_keyboard=keyboard_rows)
            
            await call.message.edit_text(message_text, reply_markup=keyboard)
        else:
            await send_sto_selection_smart(call.message.chat.id, call.bot, branch_name, region_name, state)
            
    except Exception as e:
        logger.error(f"Error in Ten Segment STO selection: {e}", exc_info=True)
        await call.answer("⚠️ Terjadi kesalahan", show_alert=True)


