@dp.message(Command("rutedjp"))
@dp.callback_query(F.data == "rutedjp")
@authorized_only_employer("tsel")
async def rutedjp_entrypoint(event: Union[Message, CallbackQuery], bot: Bot, state: FSMContext):
    """Entry point for DJP Route Generation feature"""
    await log_user_interaction(event.from_user.id, await get_username(event.from_user.id), "/rutedjp", type(event).__name__)
    
    if isinstance(event, CallbackQuery):
        await event.answer()
        chat_id = event.message.chat.id
        message = event.message
    else:
        chat_id = event.chat.id
        message = event
    
    try:
        await state.set_state(DJPRouteFlow.assignment_type_selection)
        
        welcome_text = (
            "🗺️ *Rute DJP Generator - WOK Level*\n\n"
            "Pilih jenis assignment:\n\n"
            "🔄 *Automatic Assignment*: Pilih WOK dan filter ODP otomatis\n"
            "✏️ *Manual Assignment*: Input manual daftar ODP specific\n"
        )
        
        keyboard = InlineKeyboardMarkup(inline_keyboard=[
            [
                InlineKeyboardButton(text="🔄 Automatic Assignment", callback_data="djp_auto_assignment"),
                InlineKeyboardButton(text="✏️ Manual Assignment", callback_data="djp_manual_assignment")
            ],
            [InlineKeyboardButton(text="❌ Cancel", callback_data="cancel_djp")]
        ])
        
        if isinstance(event, CallbackQuery):
            await message.edit_text(welcome_text, reply_markup=keyboard, parse_mode="Markdown")
        else:
            await message.answer(welcome_text, reply_markup=keyboard, parse_mode="Markdown")
        
    except Exception as e:
        logging.error(f"Error in rutedjp entrypoint: {e}")
        await message.answer("⚠️ Terjadi kesalahan saat memulai DJP Route Generator")

