@dp.callback_query(F.data.startswith("djp_select_wok:"))
async def handle_djp_wok_selection(call: CallbackQuery, state: FSMContext):
    """Handle WOK selection with toggle behavior"""
    try:
        _, region_name, branch_name, wok_name = call.data.split(":", 3)
        await call.answer()
        
        state_data = await state.get_data()
        selected_woks = state_data.get('selected_woks', [])
        
        if wok_name in selected_woks:
            selected_woks.remove(wok_name)
        else:
            if len(selected_woks) >= 5:
                await call.answer("⚠️ Maksimal 5 WOK dapat dipilih", show_alert=True)
                return
            selected_woks.append(wok_name)
        
        await state.update_data(selected_woks=selected_woks)
        
        # Update keyboard
        woks = await run_sync_in_thread(get_wok_for_branch, branch_name)
        if woks:
            keyboard_rows = []
            
            for wok in woks:
                prefix = "✅ " if wok in selected_woks else ""
                btn_text = f"{prefix}{wok.upper()}"
                btn_callback = f"djp_select_wok:{region_name}:{branch_name}:{wok}"
                keyboard_rows.append([InlineKeyboardButton(text=btn_text, callback_data=btn_callback)])
            
            if selected_woks:
                wok_list = ", ".join([w.upper() for w in selected_woks])
                message_text = (
                    f"📍 Pilih WOK untuk Branch {branch_name.upper()} (Region {region_name.upper()}):\n\n"
                    f"💡 Total: {len(woks)} WOK | Dipilih: {len(selected_woks)} WOK\n\n"
                    f"WOK Dipilih: {wok_list}\n\n"
                    f"Jika sudah yakin, klik \"Lanjut\""
                )
                
                action_buttons = [
                    InlineKeyboardButton(text="✅ Lanjut", callback_data="djp_proceed_status_filter"),
                    InlineKeyboardButton(text="↩️ Kembali", callback_data=f"djp_auto_select_branch:{branch_name}"),
                    InlineKeyboardButton(text="❌ Cancel", callback_data="cancel_djp")
                ]
                keyboard_rows.append(action_buttons)
            else:
                message_text = (
                    f"📍 Pilih WOK untuk Branch {branch_name.upper()} (Region {region_name.upper()}):\n\n"
                    f"💡 Total: {len(woks)} WOK | Klik untuk memilih (maks. 5)"
                )
                keyboard_rows.append([InlineKeyboardButton(text="❌ Cancel", callback_data="cancel_djp")])
            
            keyboard = InlineKeyboardMarkup(inline_keyboard=keyboard_rows)
            await call.message.edit_text(message_text, reply_markup=keyboard)
            
    except Exception as e:
        logging.error(f"Error in WOK selection: {e}")
        await call.answer("⚠️ Terjadi kesalahan", show_alert=True)

async def send_djp_status_selection(chat_id: int, bot: Bot):
    """Send status selection keyboard specifically for DJP route"""
    keyboard_rows = []
    
    # Individual statuses (2 per row)
    individual_statuses = ["BLACK", "GREEN", "YELLOW", "ORANGE", "RED"]
    for i in range(0, len(individual_statuses), 2):
        row = []
        row.append(InlineKeyboardButton(
            text=f"{'⚫' if individual_statuses[i] == 'BLACK' else '🟢' if individual_statuses[i] == 'GREEN' else '🟡' if individual_statuses[i] == 'YELLOW' else '🟠' if individual_statuses[i] == 'ORANGE' else '🔴'} {individual_statuses[i]}",
            callback_data=f"djp_status_{individual_statuses[i]}"
        ))
        if i + 1 < len(individual_statuses):
            row.append(InlineKeyboardButton(
                text=f"{'⚫' if individual_statuses[i+1] == 'BLACK' else '🟢' if individual_statuses[i+1] == 'GREEN' else '🟡' if individual_statuses[i+1] == 'YELLOW' else '🟠' if individual_statuses[i+1] == 'ORANGE' else '🔴'} {individual_statuses[i+1]}",
                callback_data=f"djp_status_{individual_statuses[i+1]}"
            ))
        keyboard_rows.append(row)
    
    # Composite statuses (1 per row for better readability)
    keyboard_rows.append([
        InlineKeyboardButton(
            text="⚫🟢 Black & Green",
            callback_data="djp_status_BLACK_GREEN"
        )
    ])
    keyboard_rows.append([
        InlineKeyboardButton(
            text="🟡🟠 Yellow & Orange",
            callback_data="djp_status_YELLOW_ORANGE"
        )
    ])
    
    keyboard = InlineKeyboardMarkup(inline_keyboard=keyboard_rows)
    
    await bot.send_message(
        chat_id,
        "Pilih status ODP yang ingin ditampilkan:",
        reply_markup=keyboard
    )

