@dp.message(F.text, DJPRouteFlow.manual_odp_input)
async def handle_manual_odp_input(message: Message, state: FSMContext):
    """Handle manual ODP input"""
    try:
        # Parse ODP names from input
        odp_input = message.text.strip()
        odp_names = [name.strip() for name in odp_input.split(",") if name.strip()]
        
        if not odp_names:
            await message.answer("⚠️ Silahkan input minimal satu nama ODP yang valid.")
            return
        
        # Validate and get ODP data
        processing_msg = await message.answer("🔄 Memvalidasi dan mengambil data ODP...")
        
        odp_data = await get_odp_data_manual_assignment(odp_names)
        
        if not odp_data:
            await processing_msg.edit_text("❌ Tidak ada ODP yang valid ditemukan. Silahkan input nama ODP yang valid.")
            return
        
        found_names = [odp['odp_name'] for odp in odp_data]
        missing_names = [name for name in odp_names if name not in found_names]
        
        if missing_names:
            missing_list = ", ".join(missing_names)
            if len(odp_data) == 0:
                await processing_msg.edit_text(f"❌ Semua ODP tidak ditemukan: {missing_list}\n\nSilahkan input nama ODP yang valid.")
                return
            else:
                await processing_msg.edit_text(f"⚠️ {len(missing_names)} ODP tidak ditemukan: {missing_list}\n\n✅ Melanjutkan dengan {len(odp_data)} ODP yang ditemukan.")
        else:
            await processing_msg.edit_text(f"✅ Semua {len(odp_data)} ODP berhasil ditemukan!")
        
        # Store data and proceed to location sharing
        await state.update_data(manual_odp_data=odp_data)
        await state.set_state(DJPRouteFlow.location_sharing)
        
        keyboard = types.ReplyKeyboardMarkup(
            keyboard=[[types.KeyboardButton(text="📍 Share My Location", request_location=True)]],
            resize_keyboard=True,
            one_time_keyboard=True
        )
        
        await message.answer(
            "📍 **Bagikan Lokasi Anda**\n\n"
            "Untuk membuat rute optimal, silakan bagikan lokasi Anda saat ini:",
            reply_markup=keyboard,
            parse_mode="Markdown"
        )
        
    except Exception as e:
        logging.error(f"Error handling manual ODP input: {e}")
        await message.answer("⚠️ Terjadi kesalahan saat memproses input ODP")

