#

@measure_performance("location_analysis")
@dp.message(F.location)
async def handle_location_reception(message: Message, state: FSMContext, bot: Bot):
    """Handles receiving a location for Ten Segment, churn analysis, and GTM."""
    
    # Get current state to check if we're in GTM flow
    current_state = await state.get_state()
    data = await state.get_data()

    logger.info(f"📍 Location handler triggered - Live: {bool(message.location.live_period)}")
    logger.info(f"📍 Location received - Live: {bool(message.location.live_period)}, State: {current_state}")
    logger.info(f"🔧 Session ID in state: {data.get('gtm_session_id')}")
    logger.info(f"🔧 Active sessions: {list(active_location_tasks.keys())}")
    
     
    # EXISTING: Your original logic for static locations only
    if "location_churn_risk_level" in data:
        # This is for churn flow
        try:
            latitude = message.location.latitude
            longitude = message.location.longitude
            is_live = bool(message.location.live_period)  # Will always be False here
            risk_level = data.get("location_churn_risk_level")

            # Remove the one-time keyboard
            await message.answer("✅ Lokasi diterima, memproses analisis churn risk...", reply_markup=types.ReplyKeyboardRemove())

            await format_churn_data_sharelocation(
                chat_id=message.chat.id,
                bot=bot,
                user_id=message.from_user.id,
                latitude=latitude,
                longitude=longitude,
                risk_level=risk_level,
                is_live=is_live
            )
            await state.clear()
            logger.info(f"User {message.from_user.id} completed churn location flow for risk level {risk_level}.")
        except Exception as e:
            logger.error(f"Error processing received churn location: {e}", exc_info=True)
            await message.answer("⚠️ Terjadi kesalahan saat memproses lokasi Anda.")
            
    elif "location_tracking_segment" in data:
        # This is for Ten Segment flow
        try:
            latitude = message.location.latitude
            longitude = message.location.longitude
            is_live = bool(message.location.live_period)  # Will always be False here
            segment = data.get("location_tracking_segment")

            # Remove the one-time keyboard
            await message.answer("✅ Lokasi diterima, memproses data...", reply_markup=types.ReplyKeyboardRemove())

            await format_cvm_data_sharelocation(
                chat_id=message.chat.id,
                bot=bot,
                user_id=message.from_user.id,
                latitude=latitude,
                longitude=longitude,
                segment=segment,
                is_live=is_live
            )
            await state.clear()
            logger.info(f"User {message.from_user.id} completed Ten Segment Location flow for segment {segment}.")
        except Exception as e:
            logger.error(f"Error processing received Ten Segment location: {e}", exc_info=True)
            await message.answer("⚠️ Terjadi kesalahan saat memproses lokasi Anda.")

    elif current_state == FeaturesFlow.awaiting_share_location:
        # This is for ODP terdekat flow
        await odpterdekat_location_state_handler(message, bot, state)
    
    else:
        # This location message is not for any known flow
        logger.debug(f"Received location from {message.from_user.id} not matching any flow. State: {current_state}, Live: {message.location.live_period}")
        return



