@dp.message(Command("lapor"))
@dp.callback_query(F.data == "img_report")
@authorized_only_employer("tsel", "tif", "ta", "sf", "admin")
async def lapor_entrypoint(event: Union[Message, CallbackQuery], state: FSMContext, bot: Bot):
    """Entry point for the /lapor command."""
    chat_id = event.message.chat.id if isinstance(event, CallbackQuery) else event.chat.id
    await log_user_interaction(event.from_user.id, await get_username(event.from_user.id), "/lapor", type(event).__name__)
    
    # Check maintenance mode
    if LAPOR_KOMPETITOR_MAINTENANCE_MODE:
        if isinstance(event, CallbackQuery):
            await event.answer("🛠 Mohon maaf, fitur Lapor Kompetitor sedang dalam maintenance.", show_alert=True)
        else:
            await bot.send_message(chat_id, "🛠 Mohon maaf, fitur Lapor Kompetitor sedang dalam maintenance.")
        return
    
    # CallbackQuery.answer() is already handled by the decorator
    
    if not await is_user_registered(event.from_user.id):
        await bot.send_message(chat_id, "Anda harus terdaftar untuk menggunakan fitur ini. Silakan /register terlebih dahulu.")
        return
        
    await state.set_state(FeaturesFlow.awaiting_image)
    msg = await bot.send_message(chat_id, "📸 Silakan kirim gambar material promo kompetitor.", reply_markup=get_cancel_keyboard(flow_type="lapor"))
    await state.update_data(lapor_prompt_msg_id=msg.message_id)


@dp.message(FeaturesFlow.awaiting_image, F.photo)
async def handle_photo_upload(message: Message, state: FSMContext, bot: Bot):
    """Handles the photo upload, validation, and information extraction."""
    # Check maintenance mode even during FSM flow
    if LAPOR_KOMPETITOR_MAINTENANCE_MODE:
        await message.answer("🛠 Mohon maaf, fitur Lapor Kompetitor sedang dalam maintenance.")
        await state.clear()
        return
    
    user_id = message.from_user.id
    chat_id = message.chat.id
    progress_manager = None
    temp_image_path = os.path.join(BROSUR_DIR, f"temp_{user_id}_{datetime.now().strftime('%Y%m%d%H%M%S')}.jpg")
    
    logger.info(f"Starting image processing for user {user_id}, temp path: {temp_image_path}")

    try:
        # Initialize ProgressMessageManager
        processing_msg = await message.answer("📸 **Memulai pemrosesan gambar...**", parse_mode="Markdown")
        progress_manager = ProgressMessageManager(bot, chat_id, processing_msg.message_id)
        
        # Progress 1: Download image (20%)
        await progress_manager.update_progress(20, "Mengunduh gambar...", "download")
        await bot.download(message.photo[-1], destination=temp_image_path)
        
        # Progress 2: Compress image (40%)
        await progress_manager.update_progress(40, "Mengompres gambar...", "image")
        await compress_image_with_timeout(temp_image_path, max_size_kb=1000)
        
        # Progress 3: Validate image (60%)
        await progress_manager.update_progress(60, "Memvalidasi gambar...", "analysis")
        is_brochure, result_or_error = await validate_brochure_image(temp_image_path)
        if not is_brochure:
            await progress_manager.complete_progress(False, f"Gagal Validasi: {result_or_error}")
            await state.clear()
            return

        # Progress 4: Extract information (80%)
        await progress_manager.update_progress(80, "Mengekstrak informasi...", "analysis")
        extracted_data, _ = await extract_information(temp_image_path, bot, chat_id)
        if not extracted_data:
            await progress_manager.complete_progress(False, "Gagal Ekstraksi Data. Coba gambar yang lebih jelas.")
            await state.clear()
            return
        
        # Progress 5: Finalizing (100%)
        await progress_manager.update_progress(100, "Menyelesaikan...", "report", delay=0.5)
        
        await state.update_data(
            extracted_data_for_location=extracted_data,
            image_path_for_location=temp_image_path,
            user_id_for_location=user_id,
            username_for_location=(message.from_user.username or await get_username(user_id))
        )
        await state.set_state(FeaturesFlow.awaiting_branch)

        markup = build_lapor_branch_keyboard()

        # Format extracted data for display
        formatted_message = format_extracted_kv_data_display(extracted_data)
        await state.update_data(lapor_original_text=formatted_message)

        # Complete progress and replace with final message
        if progress_manager:
            await progress_manager.complete_progress(True, "Berhasil memproses gambar!")

        # Send the final message with extracted data
        await bot.send_message(
            chat_id=chat_id,
            text=formatted_message,
            reply_markup=markup,
            parse_mode="Markdown"
        )
        logger.info(f"Image processing completed successfully for user {user_id}")

    except Exception as e:
        if progress_manager:
            await progress_manager.complete_progress(False, f"Terjadi kesalahan fatal: {e}")
        else:
            await message.answer(f"❌ Terjadi kesalahan fatal: {e}")
        
        logger.error(f"Fatal error in handle_photo for user {user_id}: {e}", exc_info=True)
        await state.clear()
    finally:
        current_state_info = await state.get_state()
        if current_state_info != FeaturesFlow.awaiting_branch:
            # Make file operations async
            if await async_file_exists(temp_image_path):
                await async_remove_file(temp_image_path)
                logger.debug(f"Cleaned up temp file on failure: {temp_image_path}")


