@dp.callback_query(FeaturesFlow.awaiting_branch, F.data.startswith("lapor_allbranch:"))
async def handle_lapor_allbranch_selection(call: CallbackQuery, state: FSMContext, bot: Bot):
    """Handles ALL Branch selection — shows confirmation before saving."""
    if LAPOR_KOMPETITOR_MAINTENANCE_MODE:
        await call.answer("🛠 Mohon maaf, fitur Lapor Kompetitor sedang dalam maintenance.", show_alert=True)
        await state.clear()
        return

    try:
        region_name = call.data.split(":", 1)[1]
        branches = REGION_BRANCH_MAPPING.get(region_name, [])
        if not branches:
            await call.answer("⚠️ Region tidak ditemukan.", show_alert=True)
            return

        # Aggregate all cities from all branches in this region
        all_kabs = []
        for branch in branches:
            all_kabs.extend(BRANCH_KAB_MAPPING.get(branch, []))

        if not all_kabs:
            await call.answer("⚠️ Tidak ada Kota/Kabupaten untuk region ini.", show_alert=True)
            await state.clear()
            return

        # Store data for confirmation
        await state.update_data(
            lapor_confirm_type="allbranch",
            lapor_confirm_region=region_name,
            lapor_confirm_kabs=all_kabs,
            selected_branch_for_location=f"{region_name} (ALL)"
        )
        await state.set_state(FeaturesFlow.awaiting_lapor_confirm)

        kab_list = ", ".join(sorted(all_kabs))
        confirm_keyboard = InlineKeyboardMarkup(inline_keyboard=[
            [InlineKeyboardButton(text="✅ Ya, Simpan", callback_data="lapor_confirm_yes"),
             InlineKeyboardButton(text="❌ Batal", callback_data="lapor_confirm_no")]
        ])

        await call.answer()
        await call.message.edit_text(
            f"⚠️ **Konfirmasi Penyimpanan**\n\n"
            f"Region: **{region_name} (ALL Branch)**\n"
            f"Total: **{len(all_kabs)} kota**\n\n"
            f"📍 {kab_list}\n\n"
            f"Apakah Anda yakin ingin menyimpan data ke semua kota di atas?",
            reply_markup=confirm_keyboard,
            parse_mode="Markdown"
        )

    except Exception as e:
        logger.error(f"Error in lapor allbranch selection: {e}", exc_info=True)
        await call.answer("Terjadi kesalahan, coba lagi.", show_alert=True)
        await state.clear()


