async def intelligence_functionality(event: Union[Message, CallbackQuery], bot: Bot, state: FSMContext, force_new_message=False):
    """Core logic to read data and start the /info FSM."""

    if isinstance(event, CallbackQuery) and not force_new_message:
        await event.answer()

    chat_id = event.message.chat.id if isinstance(event, CallbackQuery) else event.chat.id
    
    try:
        # Keep your existing CSV loading logic for the interactive menu
        df = await run_sync_in_thread(pd.read_csv, NEW_CSV_FILE, dtype=str, on_bad_lines='skip')
        df['found'] = df['found'].str.strip()
        city_to_branch = {city: branch for branch, cities in BRANCH_KAB_MAPPING.items() for city in cities}
        df = df[df['found'].isin(city_to_branch.keys())].copy()
        
        if df.empty:
            await bot.send_message(chat_id, "📑 Data kompetitor belum tersedia. Silakan /lapor untuk mengisi data.")
            return

        df['branch'] = df['found'].map(city_to_branch)
        available_branches = sorted(df['branch'].unique())

        await state.update_data(provider_data_json=df.to_json(orient='records'))

        # --- UPDATED BUTTON LOGIC ---
        builder = InlineKeyboardBuilder()
        for branch in available_branches:
            builder.button(text=branch, callback_data=f"infobranch:{branch}")
        builder.adjust(2)
        
        # [NEW] Add the Download Button
        builder.row(InlineKeyboardButton(text="⬇️ Unduh Tabel", callback_data="download_competitor_matrix"))
        
        builder.row(InlineKeyboardButton(text="❌ Batal", callback_data="cancel_flow:info"))
        
        message_text = "🏢 Pilih salah satu Branch untuk melihat data kompetitor:"
        
        if force_new_message:
            await bot.send_message(chat_id, message_text, reply_markup=builder.as_markup(), parse_mode="Markdown")
        else:
            if isinstance(event, CallbackQuery):
                await event.message.edit_text(message_text, reply_markup=builder.as_markup())
            else:
                await bot.send_message(chat_id, message_text, reply_markup=builder.as_markup())

        await state.set_state(FeaturesFlow.awaiting_branch)
        logger.info(f"Info branch selection shown to user {event.from_user.id}")

    except FileNotFoundError:
        await bot.send_message(chat_id, "📑 Data kompetitor belum tersedia.")
    except Exception as e:
        logger.error(f"Error in /info flow: {e}", exc_info=True)
        await bot.send_message(chat_id, "❌ Gagal membaca data kompetitor.")


@dp.callback_query(F.data == "download_competitor_matrix")
async def handle_download_matrix(call: CallbackQuery, bot: Bot):
    """
    Generates the HTML Matrix from MySQL (via intelligence.app) and sends it.
    """
    # Check maintenance mode if needed
    timestamp=datetime.now().strftime('%Y%m%d%H%M%S')

    if INFO_KOMPETITOR_MAINTENANCE_MODE:
        await call.answer("🛠 Mohon maaf, fitur sedang maintenance.", show_alert=True)
        return

    await call.answer("⏳ Sedang mengambil data...", show_alert=False)
    
    # 1. Send status message because DB Query + HTML Gen takes time
    status_msg = await call.message.answer(
        "⏳ <b>Sedang menghubungkan ke Database & membuat tabel...</b>\n"
        "<i>Mohon tunggu sebentar (estimasi 5-10 detik)...</i>", 
        parse_mode="HTML"
    )

    try:
        # 2. Run heavy task in thread to prevent blocking bot
        file_buffer = await run_sync_in_thread(get_matrix_file_object)

        if file_buffer is None:
            await status_msg.edit_text("❌ Database kosong atau gagal mengambil data.")
            return

        # 3. Send file
        input_file = BufferedInputFile(file_buffer.read(), filename=f"Competitor_Matrix_Analysis_{timestamp}.html")
        
        await bot.send_document(
            chat_id=call.message.chat.id,
            document=input_file,
            caption=(
                "<b>💡 Tip: Buka dengan browser Desktop (Laptop/PC) untuk pengalaman terbaik.</b>"
            ),
            parse_mode="HTML"
        )
        
        # 4. Delete waiting message
        await status_msg.delete()
        
    except Exception as e:
        logger.error(f"Error generating matrix html: {e}", exc_info=True)
        await status_msg.edit_text(f"❌ Gagal membuat tabel: {str(e)}")


@dp.callback_query(FeaturesFlow.awaiting_branch, F.data.startswith("infobranch:"))
async def handle_info_branch_selection(call: CallbackQuery, state: FSMContext):
    """Handles branch selection for the INFO flow."""
    # Check maintenance mode during FSM flow
    if INFO_KOMPETITOR_MAINTENANCE_MODE:
        await call.answer("🛠 Mohon maaf, fitur Info Kompetitor sedang dalam maintenance.", show_alert=True)
        await state.clear()
        return
    
    selected_branch = call.data.split(":", 1)[1]
    await state.update_data(selected_branch=selected_branch)
    
    user_data = await state.get_data()
    df = pd.read_json(user_data['provider_data_json'], orient='records', dtype=str)
    df['branch'] = df['found'].map({city: branch for branch, cities in BRANCH_KAB_MAPPING.items() for city in cities})

    cities_with_data = sorted(df[df['branch'] == selected_branch]['found'].unique())
    
    if not cities_with_data:
        await call.message.edit_text("⚠️ Tidak ada data untuk Branch ini.")
        await state.clear()
        await call.answer()
        return

    builder = InlineKeyboardBuilder()
    for city in cities_with_data:
        builder.button(text=f"🏙️ {city}", callback_data=f"infocity:{city}")
    builder.adjust(3)
    builder.row(
        InlineKeyboardButton(text="⬅️ Kembali", callback_data="info_back_to_branches"),
        InlineKeyboardButton(text="❌ Batal", callback_data="cancel_flow:info")
    )
    
    await call.message.edit_text(
        f"*📍 Branch :* {escape_markdown_v2(selected_branch)}\n*Pilih Kota/Kabupaten :*",
        reply_markup=builder.as_markup(),
        parse_mode=ParseMode.MARKDOWN_V2
    )
    await state.set_state(FeaturesFlow.awaiting_kab)
    await call.answer()


@dp.callback_query(FeaturesFlow.awaiting_kab, F.data.startswith("infocity:"))
async def handle_info_city_selection(call: CallbackQuery, state: FSMContext, bot: Bot):
    """Handles city selection and displays the competitor data for the INFO flow."""
    
    # Check maintenance mode during FSM flow
    if INFO_KOMPETITOR_MAINTENANCE_MODE:
        await call.answer("🛠 Mohon maaf, fitur Info Kompetitor sedang dalam maintenance.", show_alert=True)
        await state.clear()
        return
    
    selected_city = call.data.split(":", 1)[1]
    user_data = await state.get_data()
    
    json_data = user_data['provider_data_json']
    selected_branch = user_data.get('selected_branch', 'N/A')

    try:
        df = pd.read_json(io.StringIO(json_data), orient='records', convert_dates=False)
    except ValueError:
        # Fallback if io fails or data is weird
        df = pd.read_json(json_data, orient='records', convert_dates=False)

    city_df = df[df['found'] == selected_city].copy()

    if city_df.empty:
        await call.answer("❌ Data tidak ditemukan untuk kota ini", show_alert=True)
        return

    # Delete the previous menu or edit to loading
    await call.message.edit_text("🔄 Sedang memuat data...")
    
    # Handle timestamp conversion 
    city_df['timestamp'] = city_df['timestamp'].fillna('').astype(str).str.strip().str.strip('"\'')
    input_timestamp_format = '%Y%m%d%H%M%S'
    city_df['timestamp_dt'] = pd.to_datetime(city_df['timestamp'], format=input_timestamp_format, errors='coerce')
    
    recap_lines = []
    for provider, group in city_df.groupby('provider'):
        recap_lines.append(f"📡 {provider.upper()}")
        recap_lines.append("━━━━━━━━━━━━━━━")

        for _, row in group.iterrows():
            if pd.notna(row['timestamp_dt']):
                formatted_date = row['timestamp_dt'].strftime('%y-%b')
            else:
                formatted_date = 'N/A'
            
            package_line = (f"{row.get('package_name', '-')} | "
                            f"{normalize_speed(row.get('speed', '-'))} | "
                            f"{normalize_price(row.get('price', '-'))} | "
                            f"{row.get('gimmicks', '-')} | "
                            f"{formatted_date}")
            recap_lines.append(package_line)
        recap_lines.append("")

    recap_text = "\n".join(recap_lines)
    
    # Define Header
    header = f"📍 *Kota/Kabupaten:* {escape_markdown_v2(selected_city)}\n📍 *Branch:* {escape_markdown_v2(selected_branch)}\n"
    
    # Define Block (This typically adds ``` at start and end)
    formatted_block = format_pre_block_markdown_v2(recap_text)
    
    # Define Keyboard
    keyboard = InlineKeyboardMarkup(
        inline_keyboard=[
            [
                InlineKeyboardButton(text="⬅️ Pilih Kota Lain", callback_data=f"infobranch:{selected_branch}"),
                InlineKeyboardButton(text="🏢 Pilih Branch Lain", callback_data="info_back_to_branches")
            ],
            [InlineKeyboardButton(text="❌ Selesai", callback_data="cancel_flow:info")]
        ]
    )

    # 1. Send the Header first (It is short, no need for splitting)
    #    We delete the "Loading..." message first to ensure clean output order
    await call.message.delete() 
    await bot.send_message(call.message.chat.id, header, parse_mode=ParseMode.MARKDOWN_V2)

    # 2. Send the large Table using your helper function
    #    We pass the keyboard here so it attaches to the VERY LAST chunk of the table.
    await send_long_message(
        bot=bot,
        chat_id=call.message.chat.id,
        messages_iterable=[formatted_block], 
        parse_mode=ParseMode.MARKDOWN_V2,
        reply_markup=keyboard
    )
    
    await state.set_state(FeaturesFlow.awaiting_branch)
    await call.answer()
    

