# --- Universal cancel button handler ---
@dp.callback_query(F.data.startswith("cancel_flow:"))
async def cancel_current_flow(call: CallbackQuery, state: FSMContext, bot: Bot):
    """Universal handler for cancel buttons in FSM flows with cleanup."""
    flow_type = call.data.split(":", 1)[1]
    current_state = await state.get_state()
    
    # Special cleanup for lapor flow - delete temp image
    if flow_type == "lapor" and current_state:
        try:
            user_data = await state.get_data()
            temp_image_path = user_data.get('image_path_for_location')
            
            if temp_image_path and await async_file_exists(temp_image_path):
                await async_remove_file(temp_image_path)
                logger.info(f"Deleted temp file on cancel: {temp_image_path}")
        except Exception as e:
            logger.warning(f"Failed to delete temp file on cancel: {e}")
    
    # Clear state
    if current_state:
        await state.clear()
        logger.info(f"User {call.from_user.id} cancelled {flow_type} flow from state {current_state}")
    
    await call.message.edit_text(f"❌ Proses {flow_type} telah dibatalkan.")
    await call.answer(f"Proses {flow_type} dibatalkan")


@dp.callback_query(F.data == "none")
async def handle_dummy_callback(call: CallbackQuery):
    """Handles placeholder buttons by just answering the callback."""
    await call.answer("Tombol ini hanya untuk tampilan.", show_alert=False)


# This handler should be the last callback handler.
@dp.callback_query()
async def unknown_callback_handler(call: CallbackQuery):
    """Catches any button clicks that are not handled above."""
    logger.warning(f"Unhandled callback from user {call.from_user.id} with data: {call.data}")
    await call.answer("Perintah tidak dikenal atau sudah tidak valid.", show_alert=True)
    try:
        await call.message.edit_text("Aksi sudah tidak valid atau telah selesai.")
    except TelegramBadRequest as e:
        if "message is not modified" in str(e).lower():
            # Message content is exactly the same, ignore
            pass
        else:
            # Re-raise other bad request errors
            raise

@dp.message()
async def unknown_command_handler(message: Message):
    """Catches any text that isn't a recognized command or state."""
    await message.reply("Maaf, saya tidak mengerti perintah itu. Silakan gunakan /start untuk melihat menu.")


# =================================================================
# 7. Main Application Runner
# =================================================================

async def initialize_cache_on_startup():
    """Call this when your bot starts up."""
    invalidate_cache()
    await get_cached_user_data(0)  # Load initial cache
    logger.info("Bot started with fresh cache")


async def on_startup(bot: Bot):
    """Startup hook - called when bot starts"""
    logger.info("🚀 Bot startup sequence initiated...")
    
    # Your CSV initialization can go here if needed
    initialize_project_structure()

    await initialize_cache_on_startup()

    # Migrate CSV schema if needed (must run before recovery)
    await migrate_csv_add_registered_at()

    logger.info("🤖 Setting bot commands...")
    try:
        await asyncio.wait_for(set_bot_commands(bot), timeout=20.0)
        logger.info("✅ Bot commands set successfully")
    except asyncio.TimeoutError:
        logger.error("❌ Timeout setting bot commands")
    except Exception as e:
        logger.error(f"❌ Failed to set commands: {e}")

    # Recover pending approvals lost on restart and start cleanup task
    await recover_pending_approvals_on_startup(bot)
    asyncio.create_task(cleanup_pending_approvals())
    logger.info("✅ Pending approvals recovery and cleanup task started")


async def on_shutdown(bot: Bot):
    """
    Handles graceful shutdown of the bot.
    """
    logging.warning("🔌 Shutting down bot...")

    # Close the bot's session
    await bot.session.close()
    logging.info("🔌 Bot session closed.")


def create_proxy_session():
    """Create proxy-compatible session for aiogram"""
    return AiohttpSession(
        proxy=PROXY_URL,
        timeout=60  # Simple number, not ClientTimeout object
    )

async def main():
    """Main function to configure and run the bot."""
    # Setup logging
    logging.basicConfig(
        level=logging.INFO,
        format='%(asctime)s - %(name)s - %(levelname)s - [%(filename)s:%(lineno)d] - %(message)s',
        handlers=[
            logging.FileHandler(LOG_FILE_PATH, encoding='utf-8'),
            logging.StreamHandler(sys.stdout)
        ]
    )

    initialize_project_structure()

    # Create bot session with proxy
    session = create_proxy_session()
    bot = Bot(token=BOT_TOKEN, session=session, default=DefaultBotProperties(parse_mode="HTML"))

    # Test bot connection
    try:
        me = await bot.get_me()
        logger.info(f"✅ Successfully connected to Telegram API as @{me.username} (ID: {me.id})")
        logger.info(f"🌐 Using proxy: {PROXY_URL}")
    except Exception as e:
        logger.critical(f"❌ CRITICAL: Failed to connect to Telegram API. Error: {e}")
        await bot.session.close()
        return

    # --- Database Initialization ---
    # Note: Database operations are handled by demo_backend
    # No database pool initialization needed

    # Register hooks (on_shutdown is already safe)
    dp.startup.register(on_startup)
    dp.shutdown.register(on_shutdown)


    # The finally block is no longer needed as shutdown is handled by the hook
    logger.info("🔄 Starting bot polling...")
    await dp.start_polling(bot, allowed_updates=dp.resolve_used_update_types())


if __name__ == "__main__":
 
    # Start bot
    asyncio.run(main())
